        try buf.appendSlice(allocator, ",");
        try json_util.appendJsonInt(&buf, allocator, "failure_transcriber", @intCast(stt_metrics.failure_transcriber));
        try buf.appendSlice(allocator, ",");
        try json_util.appendJsonInt(&buf, allocator, "failure_empty_transcript", @intCast(stt_metrics.failure_empty_transcript));
        try buf.appendSlice(allocator, "},");
    }
    {
        const image_metrics = multimodal.imageFlowMetricsSnapshot();
        try json_util.appendJsonKey(&buf, allocator, "multimodal");
        try buf.appendSlice(allocator, "{");
        try json_util.appendJsonInt(&buf, allocator, "image_markers_detected", @intCast(image_metrics.image_markers_detected));
        try buf.appendSlice(allocator, ",");
        try json_util.appendJsonInt(&buf, allocator, "messages_with_image_markers", @intCast(image_metrics.messages_with_image_markers));
        try buf.appendSlice(allocator, ",");
        try json_util.appendJsonInt(&buf, allocator, "image_parts_prepared", @intCast(image_metrics.image_parts_prepared));
        try buf.appendSlice(allocator, ",");
        try json_util.appendJsonInt(&buf, allocator, "image_parts_failed", @intCast(image_metrics.image_parts_failed));
        try buf.appendSlice(allocator, ",");
        try json_util.appendJsonInt(&buf, allocator, "image_markers_ignored", @intCast(image_metrics.image_markers_ignored));
        try buf.appendSlice(allocator, "},");
    }

    try json_util.appendJsonKey(&buf, allocator, "ops");
    try buf.appendSlice(allocator, ops_json);
    try buf.appendSlice(allocator, "}");
    return buf.toOwnedSlice(allocator);
}

fn sseErrorEvent(allocator: std.mem.Allocator, code: []const u8, msg: []const u8) ![]u8 {
    const error_frame = try sseErrorFrame(allocator, code, msg);
    defer allocator.free(error_frame);
    const done_frame = try sseDoneFrame(allocator, null, null);
    defer allocator.free(done_frame);

    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll(error_frame);
    try w.writeAll(done_frame);
    return buf.toOwnedSlice(allocator);
}

fn ownershipLockConflictJsonPayload(allocator: std.mem.Allocator, conflict: *const OwnershipLockConflictInfo) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("{\"error\":\"ownership_lock_conflict\",\"message\":\"user is active on another node, retry shortly\",\"retry_after_ms\":");
    try w.print("{d}", .{conflict.retry_after_ms});
    try w.writeAll(",\"owner_instance_id\":");
    if (conflict.owner_instance_id) |owner_id| {
        try w.writeByte('"');
        try jsonEscapeInto(w, owner_id);
        try w.writeByte('"');
    } else {
        try w.writeAll("null");
    }
    try w.writeAll(",\"lease_until_s\":");
    if (conflict.lease_until_s) |lease_until_s| {
        try w.print("{d}", .{lease_until_s});
    } else {
        try w.writeAll("null");
    }
    try w.writeAll("}");
    return buf.toOwnedSlice(allocator);
}

fn sseOwnershipLockConflictEvent(allocator: std.mem.Allocator, conflict: *const OwnershipLockConflictInfo) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: error\ndata: {\"type\":\"error\",\"code\":\"ownership_lock_conflict\",\"message\":\"user is active on another node, retry shortly\",\"retry_after_ms\":");
    try w.print("{d}", .{conflict.retry_after_ms});
    try w.writeAll(",\"owner_instance_id\":");
    if (conflict.owner_instance_id) |owner_id| {
        try w.writeByte('"');
        try jsonEscapeInto(w, owner_id);
        try w.writeByte('"');
    } else {
        try w.writeAll("null");
    }
    try w.writeAll(",\"lease_until_s\":");
    if (conflict.lease_until_s) |lease_until_s| {
        try w.print("{d}", .{lease_until_s});
    } else {
        try w.writeAll("null");
    }
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sendSseOwnershipLockConflictResponse(stream: anytype, allocator: std.mem.Allocator, conflict: *const OwnershipLockConflictInfo) void {
    sendChunkedSseHeaderRetryAfter(stream, "409 Conflict", conflict.retryAfterSecs()) catch return;
    const error_fallback = "event: error\ndata: {\"type\":\"error\",\"code\":\"ownership_lock_conflict\",\"message\":\"user is active on another node, retry shortly\",\"retry_after_ms\":250,\"owner_instance_id\":null,\"lease_until_s\":null}\n\n";
    const error_owned = sseOwnershipLockConflictEvent(allocator, conflict) catch null;
    defer if (error_owned) |frame| allocator.free(frame);
    const error_frame: []const u8 = if (error_owned) |frame| frame else error_fallback;
    sendChunkedSseFrame(stream, error_frame) catch return;

    const done_fallback = "event: done\ndata: {\"type\":\"done\"}\n\n";
    const done_owned = sseDoneFrame(allocator, null, null) catch null;
    defer if (done_owned) |frame| allocator.free(frame);
    const done_frame: []const u8 = if (done_owned) |frame| frame else done_fallback;
    sendChunkedSseFrame(stream, done_frame) catch return;
    finishChunkedSse(stream) catch {};
}

fn ownershipLockConflictJsonRouteResponse(allocator: std.mem.Allocator, conflict: *const OwnershipLockConflictInfo) RouteResponse {
    const body = ownershipLockConflictJsonPayload(allocator, conflict) catch
        "{\"error\":\"ownership_lock_conflict\",\"message\":\"user is active on another node, retry shortly\",\"retry_after_ms\":250,\"owner_instance_id\":null,\"lease_until_s\":null}";
    return .{
        .status = "409 Conflict",
        .body = body,
        .retry_after_secs = conflict.retryAfterSecs(),
    };
}

fn ownershipLockConflictSseRouteResponse(allocator: std.mem.Allocator, conflict: *const OwnershipLockConflictInfo) RouteResponse {
    const fallback = "event: error\ndata: {\"type\":\"error\",\"code\":\"ownership_lock_conflict\",\"message\":\"ownership lock conflict\",\"retry_after_ms\":250,\"owner_instance_id\":null,\"lease_until_s\":null}\n\nevent: done\ndata: {\"type\":\"done\"}\n\n";
    const event_owned = sseOwnershipLockConflictEvent(allocator, conflict) catch null;
    defer if (event_owned) |value| allocator.free(value);
    const done_owned = sseDoneFrame(allocator, null, null) catch null;
    defer if (done_owned) |value| allocator.free(value);

    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    w.writeAll(if (event_owned) |value| value else "event: error\ndata: {\"type\":\"error\",\"code\":\"ownership_lock_conflict\",\"message\":\"user is active on another node, retry shortly\",\"retry_after_ms\":250,\"owner_instance_id\":null,\"lease_until_s\":null}\n\n") catch return .{
        .status = "409 Conflict",
        .body = fallback,
        .content_type = "text/event-stream; charset=utf-8",
        .retry_after_secs = conflict.retryAfterSecs(),
    };
    w.writeAll(if (done_owned) |value| value else "event: done\ndata: {\"type\":\"done\"}\n\n") catch return .{
        .status = "409 Conflict",
        .body = fallback,
        .content_type = "text/event-stream; charset=utf-8",
        .retry_after_secs = conflict.retryAfterSecs(),
    };
    const owned = buf.toOwnedSlice(allocator) catch fallback;
    return .{
        .status = "409 Conflict",
        .body = owned,
        .content_type = "text/event-stream; charset=utf-8",
        .retry_after_secs = conflict.retryAfterSecs(),
    };
}

const SSE_TOKEN_CHUNK_SIZE: usize = 96;
const SSE_KEEPALIVE_FRAME: []const u8 = "event: progress\ndata: {\"type\":\"progress\",\"phase\":\"thinking\",\"state\":\"update\",\"label\":\"Still working on the reply\",\"heartbeat\":true}\n\n";
const SSE_KEEPALIVE_INTERVAL_MS: u64 = if (builtin.is_test) 25 else 10_000;
const SSE_KEEPALIVE_POLL_MS: u64 = if (builtin.is_test) 5 else 250;

fn sseStatusFrame(allocator: std.mem.Allocator, content: []const u8) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: status\ndata: {\"type\":\"statusResponse\",\"content\":\"");
    try jsonEscapeInto(w, content);
    try w.writeAll("\"}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseProgressFrame(
    allocator: std.mem.Allocator,
    phase: []const u8,
    state: []const u8,
    label: []const u8,
    tool: ?[]const u8,
    iteration: ?u32,
    duration_ms: ?u64,
) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);

    try w.writeAll("event: progress\ndata: {\"type\":\"progress\",\"phase\":\"");
    try jsonEscapeInto(w, phase);
    try w.writeAll("\",\"state\":\"");
    try jsonEscapeInto(w, state);
    try w.writeAll("\",\"label\":\"");
    try jsonEscapeInto(w, label);
    try w.writeAll("\"");
    if (tool) |tool_name| {
        try w.writeAll(",\"tool\":\"");
        try jsonEscapeInto(w, tool_name);
        try w.writeAll("\"");
    }
    if (iteration) |value| {
        try w.print(",\"iteration\":{d}", .{value});
    }
    if (duration_ms) |value| {
        try w.print(",\"duration_ms\":{d}", .{value});
    }
    if (std.mem.eql(u8, label, "Still working on the reply")) {
        try w.writeAll(",\"heartbeat\":true");
    }
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseReasoningSummaryFrame(
    allocator: std.mem.Allocator,
    summary: []const u8,
    phase: ?[]const u8,
    tool: ?[]const u8,
    iteration: ?u32,
) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);

    try w.writeAll("event: reasoning_summary\ndata: {\"type\":\"reasoning_summary\",\"summary\":\"");
    try jsonEscapeInto(w, summary);
    try w.writeAll("\"");
    if (phase) |phase_name| {
        try w.writeAll(",\"phase\":\"");
        try jsonEscapeInto(w, phase_name);
        try w.writeAll("\"");
    }
    if (tool) |tool_name| {
        try w.writeAll(",\"tool\":\"");
        try jsonEscapeInto(w, tool_name);
        try w.writeAll("\"");
    }
    if (iteration) |value| {
        try w.print(",\"iteration\":{d}", .{value});
    }
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseSystemNoticeFrame(
    allocator: std.mem.Allocator,
    kind: []const u8,
    severity: []const u8,
    message: []const u8,
    detail: ?[]const u8,
    run_id: ?[]const u8,
) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);

    try w.writeAll("event: system_notice\ndata: {\"type\":\"system_notice\",\"kind\":\"");
    try jsonEscapeInto(w, kind);
    try w.writeAll("\",\"severity\":\"");
    try jsonEscapeInto(w, severity);
    try w.writeAll("\",\"message\":\"");
    try jsonEscapeInto(w, message);
    try w.writeAll("\"");
    if (detail) |detail_text| {
        try w.writeAll(",\"detail\":\"");
        try jsonEscapeInto(w, detail_text);
        try w.writeAll("\"");
    }
    if (run_id) |rid| {
        try w.writeAll(",\"run_id\":\"");
        try jsonEscapeInto(w, rid);
        try w.writeAll("\"");
    }
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn SseProgressObserver(comptime StreamType: type) type {
    return struct {
        allocator: std.mem.Allocator,
        stream: *StreamType,
        stream_failed: bool = false,
        last_emit_ms: i64 = 0,
        last_emit_hash: u64 = 0,
        last_reasoning_emit_ms: i64 = 0,
        last_reasoning_hash: u64 = 0,

        const Self = @This();
        const DEDUPE_WINDOW_MS: i64 = 250;
        const REASONING_DEDUPE_WINDOW_MS: i64 = 450;

        const vtable = Observer.VTable{
            .record_event = recordEvent,
            .record_metric = recordMetric,
            .flush = flush,
            .name = name,
        };

        fn init(allocator: std.mem.Allocator, stream: *StreamType) Self {
            return .{
                .allocator = allocator,
                .stream = stream,
            };
        }

        fn observer(self: *Self) Observer {
            return .{
                .ptr = @ptrCast(self),
                .vtable = &vtable,
            };
        }

        fn resolve(ptr: *anyopaque) *Self {
            return @ptrCast(@alignCast(ptr));
        }

        fn shouldSuppressDuplicate(
            self: *Self,
            phase: []const u8,
            state: []const u8,
            label: []const u8,
            tool: ?[]const u8,
            iteration: ?u32,
        ) bool {
            var hasher = std.hash.Wyhash.init(0);
            hasher.update(phase);
            hasher.update(state);
            hasher.update(label);
            if (tool) |tool_name| hasher.update(tool_name);
            if (iteration) |value| {
                var iter_buf: [16]u8 = undefined;
                const iter_text = std.fmt.bufPrint(&iter_buf, "{d}", .{value}) catch "";
                hasher.update(iter_text);
            }
            const hash = hasher.final();
            const now_ms = std.time.milliTimestamp();
            if (self.last_emit_hash == hash and now_ms - self.last_emit_ms < DEDUPE_WINDOW_MS) return true;
            self.last_emit_hash = hash;
            self.last_emit_ms = now_ms;
            return false;
        }

        fn emit(
            self: *Self,
            phase: []const u8,
            state: []const u8,
            label: []const u8,
            tool: ?[]const u8,
            iteration: ?u32,
            duration_ms: ?u64,
        ) void {
            if (self.stream_failed) return;
            if (self.shouldSuppressDuplicate(phase, state, label, tool, iteration)) return;
            const frame = sseProgressFrame(self.allocator, phase, state, label, tool, iteration, duration_ms) catch |err| {
                log.warn("chat.stream.progress encode failed phase={s} state={s}: {}", .{ phase, state, err });
                return;
            };
            defer self.allocator.free(frame);
            self.stream.sendFrame(frame) catch |err| {
                log.warn("chat.stream.progress emit failed phase={s} state={s}: {}", .{ phase, state, err });
                self.stream_failed = true;
                return;
            };
        }

        fn shouldSuppressReasoningSummary(
            self: *Self,
            summary: []const u8,
            phase: ?[]const u8,
            tool: ?[]const u8,
            iteration: ?u32,
        ) bool {
            var hasher = std.hash.Wyhash.init(0);
            hasher.update(summary);
            if (phase) |phase_name| hasher.update(phase_name);
            if (tool) |tool_name| hasher.update(tool_name);
            if (iteration) |value| {
                var iter_buf: [16]u8 = undefined;
                const iter_text = std.fmt.bufPrint(&iter_buf, "{d}", .{value}) catch "";
                hasher.update(iter_text);
            }
            const hash = hasher.final();
            const now_ms = std.time.milliTimestamp();
            if (self.last_reasoning_hash == hash and now_ms - self.last_reasoning_emit_ms < REASONING_DEDUPE_WINDOW_MS) {
                return true;
            }
            self.last_reasoning_hash = hash;
            self.last_reasoning_emit_ms = now_ms;
            return false;
        }

        fn emitReasoningSummary(
            self: *Self,
            summary: []const u8,
            phase: ?[]const u8,
            tool: ?[]const u8,
            iteration: ?u32,
        ) void {
            if (self.stream_failed) return;
            if (self.shouldSuppressReasoningSummary(summary, phase, tool, iteration)) return;
            const frame = sseReasoningSummaryFrame(self.allocator, summary, phase, tool, iteration) catch |err| {
                log.warn("chat.stream.reasoning_summary encode failed phase={s}: {}", .{ phase orelse "n/a", err });
                return;
            };
            defer self.allocator.free(frame);
            self.stream.sendFrame(frame) catch |err| {
                log.warn("chat.stream.reasoning_summary emit failed phase={s}: {}", .{ phase orelse "n/a", err });
                self.stream_failed = true;
                return;
            };
        }

        fn emitStage(self: *Self, stage: []const u8, iteration: ?u32, duration_ms: ?u64, count: ?u32) void {
            _ = count;
            if (std.mem.eql(u8, stage, "turn_start")) {
                self.emit("thinking", "start", "Gathering context", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "memory_enrich")) {
                self.emit("thinking", "update", "Retrieving memory", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "turn_compaction") or std.mem.eql(u8, stage, "compact_trim")) {
                self.emit("thinking", "update", "Trimming context", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "build_provider_messages")) {
                self.emit("thinking", "update", "Preparing model request", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "response_cache_hit")) {
                self.emit("compose", "update", "Using cached response", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "parse_provider_response")) {
                self.emit("thinking", "update", "Processing model response", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "dispatch_tools")) {
                self.emit("tool", "update", "Running tools", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "tool_reflection")) {
                self.emit("thinking", "update", "Reflecting on tool results", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "compose_final_reply")) {
                self.emit("compose", "update", "Preparing final reply", null, iteration, duration_ms);
                return;
            }
            if (std.mem.eql(u8, stage, "finalize_no_tools")) {
                self.emit("finalize", "update", "Finalizing reply", null, iteration, duration_ms);
                return;
            }
        }

        fn recordEvent(ptr: *anyopaque, event: *const ObserverEvent) void {
            const self = resolve(ptr);
            switch (event.*) {
                .llm_request => {
                    self.emit("thinking", "start", "Thinking", null, null, null);
                    // iter20: no templated reasoning_summary here. progress
                    // event above carries the "Thinking" status.
                },
                .llm_response => |e| {
                    if (e.success) {
                        self.emit("compose", "update", "Model response received", null, null, e.duration_ms);
                    } else {
                        self.emit("finalize", "error", "Model request failed", null, null, e.duration_ms);
                    }
                },
                .tool_call_start => |e| {
                    var label_buf: [256]u8 = undefined;
                    const label = if (e.activity_label) |al|
                        (if (e.files) |files| (if (files.len > 0)
                            (std.fmt.bufPrint(&label_buf, "{s}: {s}", .{ al, files[0] }) catch al)
                        else
                            al) else (if (e.command) |cmd|
                            (std.fmt.bufPrint(&label_buf, "{s}: {s}", .{ al, cmd[0..@min(cmd.len, 60)] }) catch al)
                        else
                            al))
                    else
                        (std.fmt.bufPrint(&label_buf, "Using {s}", .{e.tool}) catch "Using tool");
                    self.emit("tool", "start", label, e.tool, null, null);
                    // iter20: only surface as reasoning when there's a real
                    // agent-generated activity_label. Template "Using <tool>"
                    // goes only to the progress/tool_start channel above.
                    if (e.activity_label != null) {
                        self.emitReasoningSummary(label, "tool", e.tool, null);
                    }
                },
                .tool_call => |e| {
                    var label_buf: [192]u8 = undefined;
                    const label = if (e.success)
                        (std.fmt.bufPrint(&label_buf, "{s} completed", .{e.tool}) catch "Tool completed")
                    else
                        (std.fmt.bufPrint(&label_buf, "{s} failed", .{e.tool}) catch "Tool failed");
                    self.emit("tool", if (e.success) "done" else "error", label, e.tool, null, e.duration_ms);
                },
                .tool_iterations_exhausted => self.emit("finalize", "error", "Tool iteration limit reached", null, null, null),
                .turn_stage => |e| self.emitStage(e.stage, e.iteration, e.duration_ms, e.count),
                .turn_complete => self.emit("finalize", "done", "Response ready", null, null, null),
                .task_update => |e| {
                    var label_buf: [192]u8 = undefined;
                    const label = std.fmt.bufPrint(&label_buf, "Task {s}: {s}", .{ e.task_id, e.status }) catch "Task update";
                    self.emit("task", "update", label, null, null, null);
                },
                .narration_frame => |e| {
                    // Route real thinking narration (native reasoning_content or
                    // sidecar-generated) to the SSE reasoning_summary stream so
                    // the UI can show actual thought content instead of generic
                    // stage labels. Previously this was silently dropped.
                    const phase_str: []const u8 = switch (e.frame_type) {
                        .thinking => "thinking",
                        .tool_start => "tool",
                        .tool_done => "tool",
                        .waiting => "waiting",
                        .plan_step => "thinking",
                        .listening => "listening",
                        .speaking => "speaking",
                        .error_recovery => "error_recovery",
                    };
                    self.emitReasoningSummary(e.message, phase_str, null, null);
                },
                .system_notice => |e| {
                    // Binding rule: no silent fallback. Emit a distinct
                    // `event: system_notice` SSE frame so the frontend can
                    // render as chrome (toast/badge), not as reply text.
                    if (self.stream_failed) return;
                    const frame = sseSystemNoticeFrame(self.allocator, e.kind, e.severity, e.message, e.detail, e.run_id) catch return;
                    defer self.allocator.free(frame);
                    self.stream.sendFrame(frame) catch {
                        self.stream_failed = true;
                        return;
                    };
                },
                else => {},
            }
        }

        fn recordMetric(_: *anyopaque, _: *const observability.ObserverMetric) void {}
        fn flush(_: *anyopaque) void {}
        fn name(_: *anyopaque) []const u8 {
            return "sse_progress";
        }
    };
}

fn sseReplyStartFrame(
    allocator: std.mem.Allocator,
    stream_kind: []const u8,
    delivery_mode: []const u8,
    live: bool,
) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: reply_start\ndata: {\"type\":\"reply_start\",\"stream_kind\":\"");
    try jsonEscapeInto(w, stream_kind);
    try w.writeAll("\",\"delivery_mode\":\"");
    try jsonEscapeInto(w, delivery_mode);
    try w.writeAll("\",\"live\":");
    try w.writeAll(if (live) "true" else "false");
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseReadyFrame(allocator: std.mem.Allocator, session_key: []const u8) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: ready\ndata: {\"type\":\"ready\",\"session_key\":\"");
    try jsonEscapeInto(w, session_key);
    try w.writeAll("\"}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseErrorFrame(allocator: std.mem.Allocator, code: []const u8, msg: []const u8) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: error\ndata: {\"type\":\"error\",\"code\":\"");
    try jsonEscapeInto(w, code);
    try w.writeAll("\",\"message\":\"");
    try jsonEscapeInto(w, msg);
    try w.writeAll("\"}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseSubagentCompletionFrame(
    allocator: std.mem.Allocator,
    event_id: []const u8,
    session_key: []const u8,
    content: []const u8,
) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: subagent_completion\ndata: {\"type\":\"subagent_completion\",\"event_id\":\"");
    try jsonEscapeInto(w, event_id);
    try w.writeAll("\",\"session_key\":\"");
    try jsonEscapeInto(w, session_key);
    try w.writeAll("\",\"content\":\"");
    try jsonEscapeInto(w, content);
    try w.writeAll("\"}\n\n");
    return buf.toOwnedSlice(allocator);
}

fn sseTokenFrame(allocator: std.mem.Allocator, delta: []const u8, seq: usize) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: token\ndata: {\"delta\":\"");
    try jsonEscapeInto(w, delta);
    try w.writeAll("\",\"content\":\"");
    try jsonEscapeInto(w, delta);
    try w.print("\",\"seq\":{d},\"stream_kind\":\"final_reply\",\"live\":false}}\n\n", .{seq});
    return buf.toOwnedSlice(allocator);
}

/// V1.11 hardening (2026-05-07) — audio_reply SSE frame for the zaki_app
/// channel. When the agent emits an `[AUDIO:/abs/path]\n<text>` reply
/// (because tts_audio was on AND ttsAudioChannelSupported returned true
/// for zaki_app), this frame carries the synthesized audio to the FE
/// before the `done` frame. FE plays it via an `<audio>` tag with the
/// base64 data URL.
///
/// Frame shape:
///   event: audio_reply
///   data: {"type":"audio_reply","audio":"<base64>","format":"mp3","bytes":<n>}
fn sseAudioReplyFrame(
    allocator: std.mem.Allocator,
    audio_b64: []const u8,
    format: []const u8,
    raw_bytes: usize,
) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: audio_reply\ndata: {\"type\":\"audio_reply\",\"format\":\"");
    try jsonEscapeInto(w, format);
    try w.writeAll("\",\"bytes\":");
    try w.print("{d}", .{raw_bytes});
    try w.writeAll(",\"audio\":\"");
    try w.writeAll(audio_b64);
    try w.writeAll("\"}\n\n");
    return buf.toOwnedSlice(allocator);
}

/// Detect the `[AUDIO:/abs/path]\n` marker the agent prepends to a reply
/// when TTS synthesis succeeded for an audio-capable channel. Returns the
/// extracted absolute path and the visible text body. Returns null when
/// the marker isn't present or is malformed (no closing `]` or no newline).
const AudioReplyMarker = struct {
    audio_path: []const u8,
    visible_text: []const u8,
};

fn extractAudioReplyMarker(reply: []const u8) ?AudioReplyMarker {
    const prefix = "[AUDIO:";
    if (!std.mem.startsWith(u8, reply, prefix)) return null;
    const after_prefix = reply[prefix.len..];
    const close_idx = std.mem.indexOfScalar(u8, after_prefix, ']') orelse return null;
    const path_slice = after_prefix[0..close_idx];
    if (path_slice.len == 0) return null;
    // Reject paths with NUL or newline — defense against an extractor that
    // somehow produced them (shouldn't happen; tts_synthesize_fn writes to
    // /tmp with deterministic shapes).
    for (path_slice) |c| {
        if (c == 0 or c == '\n' or c == '\r') return null;
    }
    // Body starts after the optional newline that follows `]`.
    var body_start = prefix.len + close_idx + 1;
    if (body_start < reply.len and reply[body_start] == '\n') body_start += 1;
    const visible = if (body_start < reply.len) reply[body_start..] else "";
    return .{ .audio_path = path_slice, .visible_text = visible };
}

fn sseDoneFrame(allocator: std.mem.Allocator, session_id: ?[]const u8, message_id: ?i64) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: done\ndata: {\"type\":\"done\"");
    if (session_id) |sid| {
        try w.writeAll(",\"session_id\":\"");
        try jsonEscapeInto(w, sid);
        try w.writeAll("\"");
    }
    if (message_id) |mid| {
        try w.print(",\"message_id\":\"{d}\"", .{mid});
    }
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

/// V1.11 (2026-05-07) — `done` frame variant that signals "tools ran but
/// no direct text reply this turn." Frontend uses the `tool_only_turn:true`
/// flag to render a clean inline acknowledgment instead of the prior
/// fabricated-placeholder fallback (the dead "[tools ran, no direct reply…]"
/// string removed v1.14.13). Same identity contract as `sseDoneFrame`
/// (session_id + message_id optional) — only the extra flag differs.
fn sseDoneFrameToolOnly(allocator: std.mem.Allocator, session_id: ?[]const u8, message_id: ?i64) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    try w.writeAll("event: done\ndata: {\"type\":\"done\",\"tool_only_turn\":true");
    if (session_id) |sid| {
        try w.writeAll(",\"session_id\":\"");
        try jsonEscapeInto(w, sid);
        try w.writeAll("\"");
    }
    if (message_id) |mid| {
        try w.print(",\"message_id\":\"{d}\"", .{mid});
    }
    try w.writeAll("}\n\n");
    return buf.toOwnedSlice(allocator);
}

/// V1.11 (2026-05-07) — emitted when the model returned tool_calls without
/// a final text reply (or the agent loop hit max_tool_iterations before
/// producing text). Replaces the prior pattern of substituting a
/// fabricated placeholder string into the token stream, which surfaced as
/// jarring placeholder text in the chat UI ("[tools ran, no direct
/// reply…]"). The structured event lets the frontend render a small,
/// honest "ZAKI ran tools" acknowledgment rather than fake assistant text.
///
/// Why this is correct: the fabricated placeholder string was being
/// inserted as if it were an assistant message. It wasn't — it was a UX
/// papercut. Now the SSE contract carries the truth (tool_only_turn) and
/// the frontend chooses how to render it. The dead placeholder const was
/// removed at v1.14.13 Step 5.
fn sseToolOnlySummaryFrame(allocator: std.mem.Allocator) ![]u8 {
    return allocator.dupe(u8, "event: tool_only_summary\ndata: {\"type\":\"tool_only_summary\"}\n\n");
}

fn sseChatPayload(allocator: std.mem.Allocator, text: []const u8, session_id: []const u8) ![]u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(allocator);
    const w = buf.writer(allocator);
    const message_id = std.time.milliTimestamp();

    const reply_start = try sseReplyStartFrame(allocator, "final_reply", "buffered_replay", false);
    defer allocator.free(reply_start);
    try w.writeAll(reply_start);

    var start: usize = 0;
    var seq: usize = 0;
    while (start < text.len) : (start += SSE_TOKEN_CHUNK_SIZE) {
        const end = @min(start + SSE_TOKEN_CHUNK_SIZE, text.len);
        const token_frame = try sseTokenFrame(allocator, text[start..end], seq);
        defer allocator.free(token_frame);
        try w.writeAll(token_frame);
        seq += 1;
    }
    const done_frame = try sseDoneFrame(allocator, session_id, message_id);
    defer allocator.free(done_frame);
    try w.writeAll(done_frame);
    return buf.toOwnedSlice(allocator);
}

fn LockedSseStream(comptime StreamType: type) type {
    return struct {
        stream: StreamType,
        mutex: std.Thread.Mutex = .{},
        closed: std.atomic.Value(bool) = std.atomic.Value(bool).init(false),

        const Self = @This();

        fn init(stream: StreamType) Self {
            return .{ .stream = stream };
        }

        fn sendHeader(self: *Self, status: []const u8) !void {
            self.mutex.lock();
            defer self.mutex.unlock();
            if (self.closed.load(.acquire)) return error.BrokenPipe;
            try sendChunkedSseHeader(self.stream, status);
        }

        fn sendFrame(self: *Self, frame: []const u8) !void {
            self.mutex.lock();
            defer self.mutex.unlock();
            if (self.closed.load(.acquire)) return error.BrokenPipe;
            try sendChunkedSseFrame(self.stream, frame);
        }

        fn finish(self: *Self) !void {
            self.mutex.lock();
            defer self.mutex.unlock();
            if (self.closed.swap(true, .acq_rel)) return;
            try finishChunkedSse(self.stream);
        }

        fn markClosed(self: *Self) void {
            _ = self.closed.swap(true, .acq_rel);
        }

        /// Type-erased sendFrame for use with LiveSseCtx function pointer.
        fn sendFrameErased(ptr: *anyopaque, frame: []const u8) anyerror!void {
            const self: *Self = @ptrCast(@alignCast(ptr));
            return self.sendFrame(frame);
        }
    };
}

fn SseKeepalive(comptime LockedStreamType: type) type {
    return struct {
        stream: *LockedStreamType,
        stop_flag: std.atomic.Value(bool) = std.atomic.Value(bool).init(false),

        const Self = @This();

        fn init(stream: *LockedStreamType) Self {
            return .{ .stream = stream };
        }

        fn stop(self: *Self) void {
            self.stop_flag.store(true, .release);
        }

        fn run(self: *Self) void {
            var waited_ms: u64 = 0;
            while (!self.stop_flag.load(.acquire)) {
                std.Thread.sleep(SSE_KEEPALIVE_POLL_MS * std.time.ns_per_ms);
                if (self.stop_flag.load(.acquire)) break;
                waited_ms += SSE_KEEPALIVE_POLL_MS;
                if (waited_ms < SSE_KEEPALIVE_INTERVAL_MS) continue;
                waited_ms = 0;
                self.stream.sendFrame(SSE_KEEPALIVE_FRAME) catch {
                    self.stream.markClosed();
                    self.stop();
                    break;
                };
            }
        }
    };
}

fn sendChunkedSseHeader(stream: anytype, status: []const u8) !void {
    var header_buf: [512]u8 = undefined;
    const header = try std.fmt.bufPrint(
        &header_buf,
        "HTTP/1.1 {s}\r\nContent-Type: text/event-stream\r\nCache-Control: no-cache\r\nConnection: keep-alive\r\nTransfer-Encoding: chunked\r\nX-Accel-Buffering: no\r\n\r\n",
        .{status},
    );
    try stream.writeAll(header);
}

fn sendChunkedSseHeaderRetryAfter(stream: anytype, status: []const u8, retry_after_secs: u16) !void {
    var header_buf: [640]u8 = undefined;
    const header = try std.fmt.bufPrint(
        &header_buf,
        "HTTP/1.1 {s}\r\nContent-Type: text/event-stream\r\nCache-Control: no-cache\r\nConnection: keep-alive\r\nTransfer-Encoding: chunked\r\nX-Accel-Buffering: no\r\nRetry-After: {d}\r\n\r\n",
        .{ status, @max(@as(u16, 1), retry_after_secs) },
    );
    try stream.writeAll(header);
}

fn sendChunkedSseFrame(stream: anytype, frame: []const u8) !void {
    var prefix_buf: [32]u8 = undefined;
    const prefix = try std.fmt.bufPrint(&prefix_buf, "{x}\r\n", .{frame.len});
    try stream.writeAll(prefix);
    try stream.writeAll(frame);
    try stream.writeAll("\r\n");
}

fn finishChunkedSse(stream: anytype) !void {
    try stream.writeAll("0\r\n\r\n");
}

fn sendSseErrorResponse(stream: anytype, allocator: std.mem.Allocator, status: []const u8, code: []const u8, msg: []const u8) void {
    sendChunkedSseHeader(stream, status) catch return;
    sendSseErrorFrames(stream, allocator, code, msg);
}

fn sendSseErrorFrames(stream: anytype, allocator: std.mem.Allocator, code: []const u8, msg: []const u8) void {
    const error_fallback = "event: error\ndata: {\"type\":\"error\",\"code\":\"chat_failed\",\"message\":\"chat failed\"}\n\n";
    const error_owned = sseErrorFrame(allocator, code, msg) catch null;
    defer if (error_owned) |frame| allocator.free(frame);
    const error_frame: []const u8 = if (error_owned) |frame| frame else error_fallback;
    sendChunkedSseFrame(stream, error_frame) catch return;

    const done_fallback = "event: done\ndata: {\"type\":\"done\"}\n\n";
    const done_owned = sseDoneFrame(allocator, null, null) catch null;
    defer if (done_owned) |frame| allocator.free(frame);
    const done_frame: []const u8 = if (done_owned) |frame| frame else done_fallback;
    sendChunkedSseFrame(stream, done_frame) catch return;

    finishChunkedSse(stream) catch {};
}

fn sendLockedSseErrorFrames(stream: anytype, allocator: std.mem.Allocator, code: []const u8, msg: []const u8) void {
    const error_fallback = "event: error\ndata: {\"type\":\"error\",\"code\":\"chat_failed\",\"message\":\"chat failed\"}\n\n";
    const error_owned = sseErrorFrame(allocator, code, msg) catch null;
    defer if (error_owned) |frame| allocator.free(frame);
    const error_frame: []const u8 = if (error_owned) |frame| frame else error_fallback;
    stream.sendFrame(error_frame) catch {
        stream.markClosed();
        return;
    };

    const done_fallback = "event: done\ndata: {\"type\":\"done\"}\n\n";
    const done_owned = sseDoneFrame(allocator, null, null) catch null;
    defer if (done_owned) |frame| allocator.free(frame);
    const done_frame: []const u8 = if (done_owned) |frame| frame else done_fallback;
    stream.sendFrame(done_frame) catch {
        stream.markClosed();
        return;
    };

    stream.finish() catch stream.markClosed();
}

const ChatStreamSessionKeyError = error{
    InvalidSessionKey,
    SessionKeyUserMismatch,
    InvalidSessionLane,
    MissingSessionKey,
};

const ChatStreamTenantLane = enum {
    main,
    thread,
    task,
    cron,
};

const ChatStreamSessionKeyRejection = enum {
    missing,
    invalid,
    wrong_user,
    invalid_lane,
};

fn sessionKeyOwnedByUser(session_key: []const u8, user_id: []const u8) bool {
    var prefix_buf: [128]u8 = undefined;
    const prefix = std.fmt.bufPrint(&prefix_buf, "agent:zaki-bot:user:{s}:", .{user_id}) catch return false;
    return std.mem.startsWith(u8, session_key, prefix);
}

fn sessionKeyHasAllowedTenantLane(session_key: []const u8, user_id: []const u8) bool {
    return tenantLaneFromSessionKey(session_key, user_id) != null;
}

fn tenantLaneFromSessionKey(session_key: []const u8, user_id: []const u8) ?ChatStreamTenantLane {
    var prefix_buf: [128]u8 = undefined;
    const prefix = std.fmt.bufPrint(&prefix_buf, "agent:zaki-bot:user:{s}:", .{user_id}) catch return null;
    if (!std.mem.startsWith(u8, session_key, prefix)) return null;
    const lane = session_key[prefix.len..];
    if (std.mem.eql(u8, lane, "main")) return .main;
    if (std.mem.startsWith(u8, lane, "thread:") and lane.len > "thread:".len) return .thread;
    if (std.mem.startsWith(u8, lane, "task:") and lane.len > "task:".len) return .task;
    if (std.mem.startsWith(u8, lane, "cron:") and lane.len > "cron:".len) return .cron;
    return null;
}

fn recordChatStreamLane(state: *GatewayState, session_key: []const u8, user_id: []const u8, tenant_enabled: bool) void {
    const lane_opt = if (tenant_enabled) tenantLaneFromSessionKey(session_key, user_id) else blk: {
        if (std.mem.eql(u8, session_key, "main")) break :blk ChatStreamTenantLane.main;
        if (std.mem.startsWith(u8, session_key, "thread:")) break :blk ChatStreamTenantLane.thread;
        if (std.mem.startsWith(u8, session_key, "task:")) break :blk ChatStreamTenantLane.task;
        if (std.mem.startsWith(u8, session_key, "cron:")) break :blk ChatStreamTenantLane.cron;
        break :blk null;
    };
    const lane = lane_opt orelse return;
    switch (lane) {
        .main => _ = state.chat_stream_lane_main_total.fetchAdd(1, .monotonic),
        .thread => _ = state.chat_stream_lane_thread_total.fetchAdd(1, .monotonic),
        .task => _ = state.chat_stream_lane_task_total.fetchAdd(1, .monotonic),
        .cron => _ = state.chat_stream_lane_cron_total.fetchAdd(1, .monotonic),
    }
}

fn recordChatStreamSessionKeyRejection(state: *GatewayState, reason: ChatStreamSessionKeyRejection) void {
    switch (reason) {
        .missing => _ = state.chat_stream_session_key_missing_total.fetchAdd(1, .monotonic),
        .invalid => _ = state.chat_stream_session_key_invalid_total.fetchAdd(1, .monotonic),
        .wrong_user => _ = state.chat_stream_session_key_wrong_user_total.fetchAdd(1, .monotonic),
        .invalid_lane => _ = state.chat_stream_session_key_invalid_lane_total.fetchAdd(1, .monotonic),
    }
}

fn resolveChatStreamSessionKey(
    body: []const u8,
    user_id: []const u8,
    tenant_enabled: bool,
    require_explicit_session_key: bool,
    fallback_buf: []u8,
) ChatStreamSessionKeyError![]const u8 {
    const requested = jsonStringField(body, "session_key");
    if (requested) |raw| {
        const trimmed = std.mem.trim(u8, raw, " \t\r\n");
        if (trimmed.len == 0 or trimmed.len > 255) return error.InvalidSessionKey;
        if (std.mem.indexOfAny(u8, trimmed, "\r\n") != null) return error.InvalidSessionKey;
        if (tenant_enabled) {
            if (!sessionKeyOwnedByUser(trimmed, user_id)) return error.SessionKeyUserMismatch;
            if (!sessionKeyHasAllowedTenantLane(trimmed, user_id)) return error.InvalidSessionLane;
        }
        return trimmed;
    }
    if (require_explicit_session_key) return error.MissingSessionKey;
    return zaki_session.userMainSessionKey(fallback_buf, user_id);
}

fn resolveChatEventsSessionKey(
    target: []const u8,
    user_id: []const u8,
    tenant_enabled: bool,
) ChatStreamSessionKeyError![]const u8 {
    const requested = parseQueryParam(target, "session_key") orelse return error.MissingSessionKey;
    const trimmed = std.mem.trim(u8, requested, " \t\r\n");
    if (trimmed.len == 0 or trimmed.len > 255) return error.InvalidSessionKey;
    if (std.mem.indexOfAny(u8, trimmed, "\r\n") != null) return error.InvalidSessionKey;
    if (tenant_enabled) {
        if (!sessionKeyOwnedByUser(trimmed, user_id)) return error.SessionKeyUserMismatch;
        if (!sessionKeyHasAllowedTenantLane(trimmed, user_id)) return error.InvalidSessionLane;
    }
    return trimmed;
}

fn handleApiChatEventsSseConnection(
    root_allocator: std.mem.Allocator,
    req_allocator: std.mem.Allocator,
    stream: anytype,
    raw_request: []const u8,
    method: []const u8,
    base_path: []const u8,
    state: *GatewayState,
    config_opt: ?*const Config,
    session_mgr_opt: ?*session_mod.SessionManager,
) bool {
    _ = root_allocator;
    if (!std.mem.eql(u8, base_path, "/api/v1/chat/events")) return false;

    if (!validateInternalServiceToken(raw_request, state)) {
        sendSseErrorResponse(stream, req_allocator, "401 Unauthorized", "unauthorized", "unauthorized");
        return true;
    }
    if (!std.mem.eql(u8, method, "GET")) {
        sendSseErrorResponse(stream, req_allocator, "405 Method Not Allowed", "method_not_allowed", "method not allowed");
        return true;
    }
    if (state.draining.load(.acquire)) {
        sendSseErrorResponse(stream, req_allocator, "503 Service Unavailable", "gateway_draining", "gateway draining, retry shortly");
        return true;
    }

    const header_user_id = extractZakiUserId(raw_request);
    const user_id = resolveGatewayRequestUserId(state, header_user_id, null, true) catch |err| {
        const response = switch (err) {
            error.MissingUserId => .{ "400 Bad Request", "missing_user_id", "missing X-Zaki-User-Id" },
            error.UserCellUserMismatch => .{ "403 Forbidden", "wrong_user_cell", "request does not belong to this user cell" },
        };
        sendSseErrorResponse(stream, req_allocator, response[0], response[1], response[2]);
        return true;
    };

    if (state.role == .broker) {
        prepareBrokerUserForRouting(req_allocator, state, user_id) catch |err| {
            if (isIdentityUserNotFound(err)) {
                sendSseErrorResponse(stream, req_allocator, "404 Not Found", "unknown_user_id", "unknown user id");
                return true;
            }
            sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "provisioning_failed", "user provisioning failed");
            return true;
        };
        const target = extractRequestTarget(raw_request) orelse base_path;
        brokerProxyChatStreamSseConnection(
            req_allocator,
            stream,
            state,
            raw_request,
            method,
            target,
            user_id,
        );
        return true;
    }

    var user_ctx = resolveUserContext(req_allocator, state, user_id) catch {
        sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "invalid_user", "invalid user");
        return true;
    };
    defer user_ctx.deinit(req_allocator);

    var prep_guard = state.user_preparation_gate.acquire(user_ctx.user_id) catch {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "preparation_gate_failed", "user preparation gate failed");
        return true;
    };
    defer prep_guard.deinit();

    ensureUserDirectories(&user_ctx) catch {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "provisioning_failed", "user provisioning failed");
        return true;
    };
    ensureUserProvisioned(state, &user_ctx) catch |err| {
        if (isIdentityUserNotFound(err)) {
            sendSseErrorResponse(stream, req_allocator, "404 Not Found", "unknown_user_id", "unknown user id");
            return true;
        }
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "provisioning_failed", "user provisioning failed");
        return true;
    };
    scaffoldUserWorkspace(req_allocator, &user_ctx);
    prep_guard.release();

    var ownership_lock = maybeAcquireTenantOwnershipLock(req_allocator, state, user_ctx.user_id, user_ctx.user_root) catch {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "tenant_lock_failed", "tenant ownership lock failed");
        return true;
    };
    defer ownership_lock.deinit();
    switch (ownership_lock) {
        .disabled => {},
        .acquired => {},
        .conflict => |*conflict| {
            recordTenantLockConflict(state, .chat_stream_sse);
            sendSseOwnershipLockConflictResponse(stream, req_allocator, conflict);
            return true;
        },
    }

    const target = extractRequestTarget(raw_request) orelse base_path;
    const session_key = resolveChatEventsSessionKey(target, user_id, state.tenant_enabled) catch |err| {
        const code: []const u8 = switch (err) {
            error.InvalidSessionKey => "invalid_session_key",
            error.SessionKeyUserMismatch => "session_key_user_mismatch",
            error.InvalidSessionLane => "invalid_session_lane",
            error.MissingSessionKey => "missing_session_key",
        };
        const msg: []const u8 = switch (err) {
            error.InvalidSessionKey => "invalid session_key",
            error.SessionKeyUserMismatch => "session_key must belong to the authenticated user",
            error.InvalidSessionLane => "session_key must use lane main|thread:<id>|task:<id>|cron:<id>",
            error.MissingSessionKey => "session_key is required",
        };
        sendSseErrorResponse(stream, req_allocator, "400 Bad Request", code, msg);
        return true;
    };

    var completion_session_mgr: ?*session_mod.SessionManager = null;
    if (state.tenant_enabled) {
        const cfg = config_opt orelse {
            sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "tenant_config_missing", "tenant runtime unavailable");
            return true;
        };
        const tenant_runtime = getTenantRuntime(state, cfg, &user_ctx) catch |err| {
            if (err == error.ExecutionDelegated) {
                sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "execution_delegated", "broker mode does not execute locally");
            } else {
                sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "tenant_runtime_failed", "tenant runtime init failed");
            }
            return true;
        };
        completion_session_mgr = &tenant_runtime.session_mgr;
    } else if (session_mgr_opt) |sm| {
        completion_session_mgr = sm;
    } else {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "session_store_unavailable", "session manager unavailable");
        return true;
    }

    const sm = completion_session_mgr.?;
    var sse_stream = LockedSseStream(@TypeOf(stream)).init(stream);
    sse_stream.sendHeader("200 OK") catch return true;

    // V1.10-D / streaming-robustness — guarantee chunked-transfer
    // termination on EVERY exit path. See the longer comment on the
    // /chat/stream handler below. Same idempotent-finish pattern; same
    // protection against ERR_INCOMPLETE_CHUNKED_ENCODING when a mid-
    // stream `catch return true` would otherwise leave the chunked
    // encoding unterminated.
    defer {
        sse_stream.finish() catch |err| {
            log.warn("sse.finish_in_defer endpoint=completion error={s} session={s}", .{ @errorName(err), session_key });
            sse_stream.markClosed();
        };
    }

    const ready_owned = sseReadyFrame(req_allocator, session_key) catch null;
    defer if (ready_owned) |frame| req_allocator.free(frame);
    const ready_frame: []const u8 = if (ready_owned) |frame| frame else "event: ready\ndata: {\"type\":\"ready\"}\n\n";
    sse_stream.sendFrame(ready_frame) catch return true;

    var subscriber = AppEventsSubscriber{};
    defer subscriber.deinit(state.allocator);
    state.app_event_subscribers.register(user_id, session_key, &subscriber) catch {
        sendLockedSseErrorFrames(&sse_stream, req_allocator, "subscription_failed", "failed to attach live completion subscription");
        return true;
    };
    defer state.app_event_subscribers.unregister(user_id, session_key, &subscriber);

    const pending_completion_events = sm.loadCompletionEvents(session_key) catch &.{};
    defer if (pending_completion_events.len > 0) {
        memory_mod.freeCompletionEvents(sm.allocator, @constCast(pending_completion_events));
    };
    for (pending_completion_events) |event| {
        const frame = sseSubagentCompletionFrame(req_allocator, event.id, event.session_id, event.content) catch {
            sendLockedSseErrorFrames(&sse_stream, req_allocator, "stream_encode_failed", "failed to encode completion frame");
            return true;
        };
        sse_stream.sendFrame(frame) catch {
            req_allocator.free(frame);
            sse_stream.markClosed();
            return true;
        };
        req_allocator.free(frame);
        subscriber.markDelivered(state.allocator, event.id) catch {};
        sm.deleteCompletionEvent(event.id) catch {};
    }

    while (!state.shutdown_requested.load(.acquire)) {
        const result = subscriber.waitForEvent(SSE_KEEPALIVE_INTERVAL_MS * std.time.ns_per_ms);
        switch (result) {
            .timeout => {
                sse_stream.sendFrame(SSE_KEEPALIVE_FRAME) catch {
                    sse_stream.markClosed();
                    return true;
                };
            },
            .closed => break,
            .event => |event| {
                defer {
                    var owned = event;
                    owned.deinit(state.allocator);
                }
                const frame = sseSubagentCompletionFrame(req_allocator, event.id, event.session_key, event.content) catch {
                    sendLockedSseErrorFrames(&sse_stream, req_allocator, "stream_encode_failed", "failed to encode completion frame");
                    return true;
                };
                sse_stream.sendFrame(frame) catch {
                    req_allocator.free(frame);
                    sse_stream.markClosed();
                    return true;
                };
                req_allocator.free(frame);
                // S4.12 / S4.13 — chat/events delivery silent catches closed.
                // markDelivered failure → subscriber's watermark stays behind →
                // user gets the same event again on reconnect (duplicate reply).
                // deleteCompletionEvent failure → row stays in the table, same
                // event re-delivers across reconnects AND the table grows
                // unbounded. Both now log with event + session keys; neither
                // is fatal to the current SSE connection (delivery already
                // happened), so we continue the loop.
                subscriber.markDelivered(state.allocator, event.id) catch |err|
                    log.warn("chat.events.markDelivered_failed session={s} event_id={s} err={s}", .{ session_key, event.id, @errorName(err) });
                sm.deleteCompletionEvent(event.id) catch |err| {
                    lane_metrics.recordCompletionEventDeleteFailure();
                    log.warn("chat.events.deleteCompletionEvent_failed session={s} event_id={s} err={s}", .{ session_key, event.id, @errorName(err) });
                };
            },
        }
    }

    subscriber.close();
    sse_stream.finish() catch sse_stream.markClosed();
    return true;
}

// ── Live SSE Streaming Context ──────────────────────────────────────
//
// Used when delivery_mode is "live": the agent's stream_callback pipes
// token chunks directly to the SSE client via sseTokenFrame + LockedSseStream.
// The seq counter is shared by pointer so it increments across callbacks.

const LiveSseCtx = struct {
    stream_ptr: *anyopaque,
    sendFrameFn: *const fn (ptr: *anyopaque, frame: []const u8) anyerror!void,
    allocator: std.mem.Allocator,
    seq: *usize,
    /// Set to true on send failure (e.g. client disconnect). Once set,
    /// subsequent tokens are skipped to avoid wasting compute.
    client_gone: *bool,
    /// Paced sink for inter-chunk delays (human-pacing). When non-null,
    /// liveStreamCallback writes through this instead of sendFrameFn directly.
    paced_sink: ?*gateway_run_events.PacedFrameSink = null,
    /// Buffer for incomplete UTF-8 byte sequences that straddle a provider
    /// chunk boundary. Max unfinished codepoint is 3 bytes (a 4-byte UTF-8
    /// codepoint minus its lead byte). Next chunk prepends these bytes so
    /// multi-byte codepoints (emoji, em-dash, etc.) emit intact instead of
    /// being turned into U+FFFD by the JSON encoder.
    utf8_tail: [4]u8 = undefined,
    utf8_tail_len: u8 = 0,

    /// FrameSink-compatible write that delegates to the error-returning
    /// sendFrameFn, setting client_gone on failure. Used as the inner
    /// sink for PacedFrameSink so pacing delays apply before each send.
    fn sinkWrite(ptr: *anyopaque, frame: []const u8) void {
        const self: *LiveSseCtx = @ptrCast(@alignCast(ptr));
        self.sendFrameFn(self.stream_ptr, frame) catch {
            self.client_gone.* = true;
        };
    }

    fn frameSink(self: *LiveSseCtx) gateway_run_events.FrameSink {
        return .{ .ptr = @ptrCast(self), .writeFn = sinkWrite };
    }
};

const LiveProviderRoundResetObserver = struct {
    inner: observability.Observer,
    live_seq: *usize,

    const vtable = observability.Observer.VTable{
        .record_event = recordEvent,
        .record_metric = recordMetric,
        .flush = flush,
        .name = name,
    };

    fn observer(self: *LiveProviderRoundResetObserver) observability.Observer {
        return .{
            .ptr = @ptrCast(self),
            .vtable = &vtable,
        };
    }

    fn resolve(ptr: *anyopaque) *LiveProviderRoundResetObserver {
        return @ptrCast(@alignCast(ptr));
    }

    fn recordEvent(ptr: *anyopaque, event: *const observability.ObserverEvent) void {
        const self = resolve(ptr);
        switch (event.*) {
            .turn_stage => |stage| {
                if (std.mem.eql(u8, stage.stage, "build_provider_messages")) {
                    self.live_seq.* = 0;
                }
            },
            else => {},
        }
        self.inner.recordEvent(event);
    }

    fn recordMetric(ptr: *anyopaque, metric: *const observability.ObserverMetric) void {
        const self = resolve(ptr);
        self.inner.recordMetric(metric);
    }

    fn flush(ptr: *anyopaque) void {
        const self = resolve(ptr);
        self.inner.flush();
    }

    fn name(_: *anyopaque) []const u8 {
        return "live_provider_round_reset";
    }
};

/// Returns the index up to which `bytes` is safe to emit as UTF-8. If the
/// tail contains an incomplete multi-byte codepoint, returns the byte index
/// of the incomplete lead byte; everything before that is complete. Caller
/// should hold back `bytes[ret..]` and prepend it to the next chunk.
fn utf8SafeEmitLen(bytes: []const u8) usize {
    if (bytes.len == 0) return 0;
    // UTF-8: ≤4 bytes per codepoint, so the tail can hold at most 3
    // continuation bytes before the missing lead byte. Walk backward that
    // far at most.
    var i: usize = bytes.len;
    var cont_count: usize = 0;
    // `cont_count <= 3` is critical: a 4-byte codepoint has 3 continuation
    // bytes after its lead byte, so we must allow one more iteration
    // AFTER walking past 3 continuations to actually inspect the lead.
    while (i > 0 and cont_count <= 3) {
        const b = bytes[i - 1];
        if ((b & 0b1000_0000) == 0) {
            // ASCII byte — codepoint self-contained, safe to emit to end.
            return bytes.len;
        }
        if ((b & 0b1100_0000) == 0b1000_0000) {
            // Continuation byte — walk further back.
            i -= 1;
            cont_count += 1;
            continue;
        }
        // Lead byte. Determine expected codepoint length from its high bits.
        const expected: usize = if ((b & 0b1111_1000) == 0b1111_0000)
            4
        else if ((b & 0b1111_0000) == 0b1110_0000)
            3
        else if ((b & 0b1110_0000) == 0b1100_0000)
            2
        else
            1; // malformed lead byte; treat as single
        const available = bytes.len - (i - 1);
        if (available < expected) {
            // Incomplete codepoint — hold back from the lead byte onward.
            return i - 1;
        }
        return bytes.len;
    }
    // Three continuation bytes in a row without a lead — malformed. Hold
    // them back; the next chunk may provide the lead (or they stay as
    // bad input, but that's not something we can fix here).
    return i;
}

fn liveStreamCallback(ctx_ptr: *anyopaque, chunk: providers.StreamChunk) void {
    const ctx: *LiveSseCtx = @ptrCast(@alignCast(ctx_ptr));
    if (ctx.client_gone.*) return; // client disconnected — skip remaining tokens

    if (chunk.is_final) {
        // Stream end. If the UTF-8 tail still holds an incomplete sequence,
        // drop it — provider truncated mid-codepoint and emitting garbage
        // bytes would just become U+FFFD at the frontend.
        ctx.utf8_tail_len = 0;
        return;
    }
    if (chunk.delta.len == 0) return; // empty/keep-alive chunks

    // Prepend any held tail bytes so a multi-byte codepoint that straddled
    // the provider's chunk boundary is stitched back together before we
    // emit anything.
    var merged: std.ArrayListUnmanaged(u8) = .empty;
    defer merged.deinit(ctx.allocator);
    if (ctx.utf8_tail_len > 0) {
        merged.appendSlice(ctx.allocator, ctx.utf8_tail[0..ctx.utf8_tail_len]) catch return;
    }
    merged.appendSlice(ctx.allocator, chunk.delta) catch return;
    ctx.utf8_tail_len = 0;

    const emit_len = utf8SafeEmitLen(merged.items);
    const remaining = merged.items[emit_len..];
    if (remaining.len > 0 and remaining.len <= ctx.utf8_tail.len) {
        @memcpy(ctx.utf8_tail[0..remaining.len], remaining);
        ctx.utf8_tail_len = @intCast(remaining.len);
    }

    if (emit_len == 0) return; // nothing complete to emit yet

    const frame = sseTokenFrame(ctx.allocator, merged.items[0..emit_len], ctx.seq.*) catch return;
    defer ctx.allocator.free(frame);
    if (ctx.paced_sink) |paced| {
        paced.sink().write(frame);
    } else {
        ctx.sendFrameFn(ctx.stream_ptr, frame) catch {
            ctx.client_gone.* = true;
            return;
        };
    }
    ctx.seq.* += 1;
}

fn handleApiChatStreamSseConnection(
    root_allocator: std.mem.Allocator,
    req_allocator: std.mem.Allocator,
    stream: anytype,
    raw_request: []const u8,
    method: []const u8,
    base_path: []const u8,
    state: *GatewayState,
    config_opt: ?*const Config,
    session_mgr_opt: ?*session_mod.SessionManager,
) bool {
    if (!std.mem.eql(u8, base_path, "/api/v1/chat/stream")) return false;

    const request_start_ms = std.time.milliTimestamp();
    if (!validateInternalServiceToken(raw_request, state)) {
        sendSseErrorResponse(stream, req_allocator, "401 Unauthorized", "unauthorized", "unauthorized");
        return true;
    }
    if (!std.mem.eql(u8, method, "POST")) {
        sendSseErrorResponse(stream, req_allocator, "405 Method Not Allowed", "method_not_allowed", "method not allowed");
        return true;
    }
    if (state.draining.load(.acquire)) {
        sendSseErrorResponse(stream, req_allocator, "503 Service Unavailable", "gateway_draining", "gateway draining, retry shortly");
        return true;
    }

    const body = extractBody(raw_request) orelse {
        sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "missing_body", "missing body");
        return true;
    };
    const header_user_id = extractZakiUserId(raw_request);
    const user_id = resolveGatewayRequestUserId(state, header_user_id, jsonStringField(body, "user_id"), true) catch |err| {
        const response = switch (err) {
            error.MissingUserId => .{ "400 Bad Request", "missing_user_id", "missing X-Zaki-User-Id" },
            error.UserCellUserMismatch => .{ "403 Forbidden", "wrong_user_cell", "request does not belong to this user cell" },
        };
        sendSseErrorResponse(stream, req_allocator, response[0], response[1], response[2]);
        return true;
    };
    if (state.role == .broker) {
        prepareBrokerUserForRouting(req_allocator, state, user_id) catch |err| {
            if (isIdentityUserNotFound(err)) {
                sendSseErrorResponse(stream, req_allocator, "404 Not Found", "unknown_user_id", "unknown user id");
                return true;
            }
            sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "provisioning_failed", "user provisioning failed");
            return true;
        };
        const target = extractRequestTarget(raw_request) orelse base_path;
        brokerProxyChatStreamSseConnection(
            req_allocator,
            stream,
            state,
            raw_request,
            method,
            target,
            user_id,
        );
        return true;
    }

    // ── S2.3 entitlement chokepoint 1: chat-stream entry ──────────────
    // Reject with 402 Payment Required when the caller's effective tier
    // is inactive (canceled past period_end, expired, past_due). The
    // resolver is populated by S2.1's provision-response path and S2.7's
    // Stripe revocation webhook; until those land the resolver returns
    // null, which we treat as the default `.pro/.active` fallback so
    // nothing breaks mid-sprint. See plan-v02 §6 and
    // docs/sprints/sprint-2.md for the enforcement chokepoint matrix.
    {
        const ent = entitlement_mod.resolveUserEntitlement(user_id) orelse entitlement_mod.Entitlement{};
        const now_unix = std.time.timestamp();
        if (!ent.canAct(now_unix)) {
            sendSseErrorResponse(
                stream,
                req_allocator,
                "402 Payment Required",
                "entitlement_inactive",
                "subscription inactive — update billing to continue",
            );
            return true;
        }
    }

    var user_ctx = resolveUserContext(req_allocator, state, user_id) catch {
        sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "invalid_user", "invalid user");
        return true;
    };
    defer user_ctx.deinit(req_allocator);

    var prep_guard = state.user_preparation_gate.acquire(user_ctx.user_id) catch {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "preparation_gate_failed", "user preparation gate failed");
        return true;
    };
    defer prep_guard.deinit();

    ensureUserDirectories(&user_ctx) catch {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "provisioning_failed", "user provisioning failed");
        return true;
    };

    ensureUserProvisioned(state, &user_ctx) catch |err| {
        if (isIdentityUserNotFound(err)) {
            sendSseErrorResponse(stream, req_allocator, "404 Not Found", "unknown_user_id", "unknown user id");
            return true;
        }
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "provisioning_failed", "user provisioning failed");
        return true;
    };
    scaffoldUserWorkspace(req_allocator, &user_ctx);
    prep_guard.release();

    var ownership_lock = maybeAcquireTenantOwnershipLock(req_allocator, state, user_ctx.user_id, user_ctx.user_root) catch {
        sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "tenant_lock_failed", "tenant ownership lock failed");
        return true;
    };
    defer ownership_lock.deinit();
    switch (ownership_lock) {
        .disabled => {},
        .acquired => {},
        .conflict => |*conflict| {
            recordTenantLockConflict(state, .chat_stream_sse);
            sendSseOwnershipLockConflictResponse(stream, req_allocator, conflict);
            return true;
        },
    }

    // V1.11 hardening (2026-05-07): native audio input. Frontend can POST
    // `{audio: <base64>, format: "webm"}` (or `{audio_url: ...}`) instead of
    // `{message: "..."}`. Backend transcribes via the configured STT
    // provider (Together/Groq/OpenAI Whisper) and feeds the transcript to
    // the agent as the user message — no two-round-trip from the FE.
    // The `voice_replies = inbound` path will then auto-emit TTS for the
    // reply because the inbound was audio (existing logic in agent loop).
    var transcribed_message: ?[]u8 = null;
    defer if (transcribed_message) |t| req_allocator.free(t);
    const message: []const u8 = blk: {
        if (jsonStringField(body, "message")) |m| break :blk m;
        if (jsonStringField(body, "text")) |m| break :blk m;
        // Audio path: only attempted when no text/message field present.
        if (jsonStringField(body, "audio")) |audio_b64| {
            if (audio_b64.len == 0) {
                sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "empty_audio", "empty audio data");
                return true;
            }
            // Cap base64 input at ~7.5MB raw (decodes to ~5.6MB audio).
            if (audio_b64.len > 10 * 1024 * 1024) {
                sendSseErrorResponse(stream, req_allocator, "413 Payload Too Large", "audio_too_large", "audio too large");
                return true;
            }
            const cfg = config_opt orelse {
                sendSseErrorResponse(stream, req_allocator, "503 Service Unavailable", "voice_not_configured", "voice not configured");
                return true;
            };
            if (!cfg.audio_media.enabled) {
                sendSseErrorResponse(stream, req_allocator, "503 Service Unavailable", "voice_not_enabled", "voice not enabled");
                return true;
            }
            const stt_provider = cfg.audio_media.provider;
            const stt_key = cfg.getProviderKey(stt_provider) orelse {
                sendSseErrorResponse(stream, req_allocator, "503 Service Unavailable", "voice_key_missing", "voice api key not configured");
                return true;
            };
            const audio_format = jsonStringField(body, "format") orelse "webm";
            const decoded_len = std.base64.standard.Decoder.calcSizeForSlice(audio_b64) catch {
                sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "invalid_base64", "invalid base64");
                return true;
            };
            const decoded = req_allocator.alloc(u8, decoded_len) catch {
                sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "alloc_failed", "alloc failed");
                return true;
            };
            defer req_allocator.free(decoded);
            std.base64.standard.Decoder.decode(decoded, audio_b64) catch {
                sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "invalid_base64", "invalid base64");
                return true;
            };
            const ts = std.time.milliTimestamp();
            var rand_bytes: [4]u8 = undefined;
            std.crypto.random.bytes(&rand_bytes);
            const rand_suffix: u32 = std.mem.readInt(u32, &rand_bytes, .little);
            var path_buf: [256]u8 = undefined;
            const tmp_path = std.fmt.bufPrint(&path_buf, "/tmp/nullalis_chat_stt_{d}_{x}.{s}", .{ ts, rand_suffix, audio_format }) catch {
                sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "path_build_failed", "path build failed");
                return true;
            };
            var z_buf: [257]u8 = undefined;
            const tmp_path_z = toSentinelPath(&z_buf, tmp_path) orelse {
                sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "path_too_long", "path too long");
                return true;
            };
            {
                const file = std.fs.createFileAbsolute(tmp_path_z, .{}) catch {
                    sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "tempfile_failed", "temp file write failed");
                    return true;
                };
                defer file.close();
                file.writeAll(decoded) catch {
                    sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "tempfile_failed", "temp file write failed");
                    return true;
                };
            }
            defer std.fs.deleteFileAbsolute(tmp_path_z) catch {};
            const endpoint = voice.resolveTranscriptionEndpoint(stt_provider, cfg.audio_media.base_url);
            const transcript = voice.transcribeFile(req_allocator, stt_key, endpoint, tmp_path, .{
                .model = cfg.audio_media.model,
                .language = cfg.audio_media.language,
            }) catch {
                sendSseErrorResponse(stream, req_allocator, "502 Bad Gateway", "transcription_failed", "transcription failed");
                return true;
            };
            if (transcript.len == 0) {
                req_allocator.free(transcript);
                sendSseErrorResponse(stream, req_allocator, "422 Unprocessable Entity", "empty_transcript", "transcription returned empty text");
                return true;
            }
            // Prefix with [voice] so the existing tts_mode=.inbound logic
            // detects it and (when voice_replies is on) emits TTS audio
            // for the reply automatically. Same convention as the
            // Telegram inbound voice path (see channels/telegram).
            const wrapped = std.fmt.allocPrint(req_allocator, "[voice] {s}", .{transcript}) catch {
                req_allocator.free(transcript);
                sendSseErrorResponse(stream, req_allocator, "500 Internal Server Error", "alloc_failed", "alloc failed");
                return true;
            };
            req_allocator.free(transcript);
            transcribed_message = wrapped;
            break :blk wrapped;
        }
        sendSseErrorResponse(stream, req_allocator, "400 Bad Request", "missing_message", "missing message or audio");
        return true;
    };

    var session_buf: [256]u8 = undefined;
    const require_explicit_session_key = if (config_opt) |cfg| cfg.gateway.require_explicit_chat_stream_session_key else true;
    const session_key = resolveChatStreamSessionKey(body, user_id, state.tenant_enabled, require_explicit_session_key, &session_buf) catch |err| {
        const rejection: ChatStreamSessionKeyRejection = switch (err) {
            error.InvalidSessionKey => .invalid,
            error.SessionKeyUserMismatch => .wrong_user,
            error.InvalidSessionLane => .invalid_lane,
            error.MissingSessionKey => .missing,
        };
        recordChatStreamSessionKeyRejection(state, rejection);
        const code: []const u8 = switch (err) {
            error.InvalidSessionKey => "invalid_session_key",
            error.SessionKeyUserMismatch => "session_key_user_mismatch",
            error.InvalidSessionLane => "invalid_session_lane",
            error.MissingSessionKey => "missing_session_key",
        };
        const msg: []const u8 = switch (err) {
            error.InvalidSessionKey => "invalid session_key",
            error.SessionKeyUserMismatch => "session_key must belong to the authenticated user",
            error.InvalidSessionLane => "session_key must use lane main|thread:<id>|task:<id>|cron:<id>",
            error.MissingSessionKey => "session_key is required",
        };
        sendSseErrorResponse(stream, req_allocator, "400 Bad Request", code, msg);
        return true;
    };
    _ = state.chat_stream_total.fetchAdd(1, .monotonic);
    recordChatStreamLane(state, session_key, user_id, state.tenant_enabled);
    var sse_stream = LockedSseStream(@TypeOf(stream)).init(stream);
    sse_stream.sendHeader("200 OK") catch return true;

    // V1.10-D / streaming-robustness — guarantee chunked-transfer
    // termination on EVERY exit path. `finish()` is idempotent (line
    // ~8490: atomic swap on `closed`, returns if already closed), so
    // this defer is safe even when the explicit finish below runs
    // first. Without this defer, a `sendFrame catch return true`
    // mid-stream leaves the chunked-transfer-encoding unterminated,
    // which the browser surfaces as ERR_INCOMPLETE_CHUNKED_ENCODING.
    // Observed live during V1.10 testing on 2026-05-06; root cause
    // for the "network error" mid-tool-call symptom ZAKI hit. Closes
    // the class, not just one occurrence. The catch logs but
    // doesn't propagate — defers can't propagate errors anyway, and
    // an already-broken stream means there's no client to surface to.
    defer {
        sse_stream.finish() catch |err| {
            log.warn("sse.finish_in_defer error={s} session={s} — chunked-transfer finalization may have failed", .{ @errorName(err), session_key });
            sse_stream.markClosed();
        };
    }

    const status_fallback = "event: status\ndata: {\"type\":\"statusResponse\",\"content\":\"Processing request\"}\n\n";
    const status_owned = sseStatusFrame(req_allocator, "Processing request") catch null;
    defer if (status_owned) |frame| req_allocator.free(frame);
    const status_frame: []const u8 = if (status_owned) |frame| frame else status_fallback;
    sse_stream.sendFrame(status_frame) catch return true;

    var keepalive = SseKeepalive(@TypeOf(sse_stream)).init(&sse_stream);
    const keepalive_thread: ?std.Thread = std.Thread.spawn(.{}, SseKeepalive(@TypeOf(sse_stream)).run, .{&keepalive}) catch null;
    var keepalive_joined = false;
    defer if (!keepalive_joined) {
        keepalive.stop();
        if (keepalive_thread) |thread| thread.join();
    };

    const chat_start_ms = std.time.milliTimestamp();

    // ── Delivery mode resolution (D-02, D-04) ──────────────────────
    const channel_name = "zaki_app"; // gateway SSE endpoint is always web client
    const delivery_mode = gateway_run_events.resolveDeliveryMode(channel_name);
    const is_live = std.mem.eql(u8, delivery_mode, "live");

    // In live mode, send reply_start BEFORE agent processing so the client
    // knows to expect progressive token delivery.
    if (is_live) {
        const live_reply_start = sseReplyStartFrame(req_allocator, "final_reply", "live", true) catch null;
        defer if (live_reply_start) |frame| req_allocator.free(frame);
        const live_rs_frame: []const u8 = if (live_reply_start) |frame| frame else "event: reply_start\ndata: {\"type\":\"reply_start\",\"stream_kind\":\"final_reply\",\"delivery_mode\":\"live\",\"live\":true}\n\n";
        sse_stream.sendFrame(live_rs_frame) catch return true;
    }

    // Set up live stream context for stream_callback (tokens piped directly to SSE)
    // PacedFrameSink wraps the SSE send with inter-chunk delays for human-pacing (D-03).
    var live_seq: usize = 0;
    const SseStreamType = LockedSseStream(@TypeOf(stream));
    var live_client_gone: bool = false;
    var live_ctx = LiveSseCtx{
        .stream_ptr = @ptrCast(&sse_stream),
        .sendFrameFn = SseStreamType.sendFrameErased,
        .allocator = req_allocator,
        .seq = &live_seq,
        .client_gone = &live_client_gone,
    };
    const pacing_delay = gateway_run_events.resolvePacingDelay(channel_name);
    var paced_sink = gateway_run_events.PacedFrameSink.init(live_ctx.frameSink(), pacing_delay);
    if (is_live and pacing_delay > 0) {
        live_ctx.paced_sink = &paced_sink;
    }
    var noop_progress_observer = observability.NoopObserver{};
    var live_provider_round_reset_observer = LiveProviderRoundResetObserver{
        .inner = noop_progress_observer.observer(),
        .live_seq = &live_seq,
    };
    var run_event_observer_impl = gateway_run_events.RunEventObserver{
        .inner = live_provider_round_reset_observer.observer(),
        .sink = live_ctx.frameSink(),
        .allocator = req_allocator,
    };
    const progress_observer = run_event_observer_impl.observer();

    const ReplyOutcome = union(enum) {
        ok: []const u8,
        err: struct { code: []const u8, msg: []const u8 },
    };
    const outcome: ReplyOutcome = blk: {
        if (state.tenant_enabled) {
            const cfg = config_opt orelse {
                _ = state.chat_stream_errors_total.fetchAdd(1, .monotonic);
                break :blk .{ .err = .{ .code = "tenant_config_missing", .msg = "tenant runtime unavailable" } };
            };
            const tenant_runtime = getTenantRuntime(state, cfg, &user_ctx) catch |err| {
                _ = state.chat_stream_errors_total.fetchAdd(1, .monotonic);
                if (err == error.ExecutionDelegated) {
                    break :blk .{ .err = .{ .code = "execution_delegated", .msg = "broker mode does not execute locally" } };
                } else {
                    break :blk .{ .err = .{ .code = "tenant_runtime_failed", .msg = "tenant runtime init failed" } };
                }
            };
            // Tenant runtime path: stream tokens directly to SSE for live delivery.
            break :blk .{ .ok = tenant_runtime.processMessage(
                session_key,
                message,
                .{
                    .channel = "zaki_app",
                    .is_group = false,
                },
                .{
                    .channel = "zaki_app",
                    .chat_id = session_key,
                    .is_group = false,
                    .is_dm = true,
                },
                progress_observer,
                if (is_live) liveStreamCallback else null,
                if (is_live) @ptrCast(&live_ctx) else null,
            ) catch {
                _ = state.chat_stream_errors_total.fetchAdd(1, .monotonic);
                break :blk .{ .err = .{ .code = "chat_failed", .msg = "chat failed" } };
            } };
        }
        if (session_mgr_opt) |sm| {
            break :blk .{ .ok = sm.processMessageWithContext(session_key, message, null, .{
                .message_turn_context = .{
                    .channel = "zaki_app",
                    .chat_id = session_key,
                    .is_group = false,
                    .is_dm = true,
                },
                .progress_observer = progress_observer,
                .stream_callback = if (is_live) liveStreamCallback else null,
                .stream_ctx = if (is_live) @ptrCast(&live_ctx) else null,
            }) catch {
                _ = state.chat_stream_errors_total.fetchAdd(1, .monotonic);
                break :blk .{ .err = .{ .code = "chat_failed", .msg = "chat failed" } };
            } };
        }
        break :blk .{ .ok = processIncomingMessage(root_allocator, message, session_key, user_id) catch {
            _ = state.chat_stream_errors_total.fetchAdd(1, .monotonic);
            break :blk .{ .err = .{ .code = "chat_failed", .msg = "chat failed" } };
        } };
    };
    keepalive.stop();
    if (keepalive_thread) |thread| thread.join();
    keepalive_joined = true;

    const reply = switch (outcome) {
        .ok => |value| value,
        .err => |err_payload| {
            sendLockedSseErrorFrames(&sse_stream, req_allocator, err_payload.code, err_payload.msg);
            return true;
        },
    };
    defer root_allocator.free(reply);

    // Determine if live streaming actually delivered tokens. If the provider
    // does not support streaming, live_seq stays 0 and we must fall back to
    // post-hoc chunking so the reply text still reaches the client.
    const live_streamed = is_live and live_seq > 0;

    // V1.11 (2026-05-07) — Tool-only-turn detection. When the agent loop
    // produced tool_calls but no final text reply (and the live stream
    // didn't deliver any tokens), pre-V1.11 behavior was to substitute a
    // fabricated placeholder string into the token stream as if it were
    // assistant text. That surfaced as a jarring placeholder line in the
    // chat UI ("[tools ran, no direct reply…]"). New behavior: emit a
    // structured `tool_only_summary` SSE event + flag the `done` frame
    // with `tool_only_turn:true`. The frontend renders an honest,
    // minimal "ZAKI ran tools" acknowledgment instead of fake prose.
    // The dead placeholder const was removed at v1.14.13 Step 5.
    //
    // Detection signal: empty reply on the success path. Genuine errors
    // hit the `.err` branch above, so an empty `.ok` reply is almost
    // always a tool_only_turn (the agent ran tools, hit max_tool_iterations
    // or a loop_detected exit, and didn't produce final text). ZAKI's
    // ObserverEvent.tool_only_turn already fired during the turn (see
    // src/agent/root.zig:3753); this is the gateway-side rendering
    // contract that pairs with it.
    const is_tool_only = reply.len == 0;

    // V1.11 hardening (2026-05-07) — audio_reply extraction for zaki_app.
    // The agent prepends `[AUDIO:/abs/path]\n` to TurnOutcome.text when
    // TTS synthesis fired (tts_audio + ttsAudioChannelSupported). For
    // Telegram the channel adapter unpacks this and sends a voice note;
    // for zaki_app the gateway is the channel — we emit a structured
    // `audio_reply` SSE event between the last token and `done`, then
    // strip the marker from the visible text so the FE doesn't render
    // the literal `[AUDIO:...]` string.
    var audio_emit: struct {
        path: ?[]const u8 = null,
        b64: ?[]u8 = null,
        format: []const u8 = "mp3",
        raw_bytes: usize = 0,
    } = .{};
    defer if (audio_emit.b64) |b| req_allocator.free(b);
    const payload_text: []const u8 = blk: {
        if (extractAudioReplyMarker(reply)) |marker| {
            // Best-effort: read the file, base64-encode. On any failure,
            // log + fall through to streaming the marker-stripped text
            // (the user still sees the reply text, just no audio).
            audio_emit.path = marker.audio_path;
            // Derive format from extension; default mp3.
            if (std.mem.lastIndexOfScalar(u8, marker.audio_path, '.')) |dot_idx| {
                const ext = marker.audio_path[dot_idx + 1 ..];
                if (ext.len > 0 and ext.len <= 8) audio_emit.format = ext;
            }
            var path_z_buf: [512]u8 = undefined;
            const path_z = toSentinelPath(&path_z_buf, marker.audio_path);
            if (path_z) |p| {
                if (std.fs.openFileAbsolute(p, .{})) |file| {
                    defer file.close();
                    if (file.readToEndAlloc(req_allocator, 8 * 1024 * 1024)) |bytes| {
                        defer req_allocator.free(bytes);
                        audio_emit.raw_bytes = bytes.len;
                        const b64_len = std.base64.standard.Encoder.calcSize(bytes.len);
                        if (req_allocator.alloc(u8, b64_len)) |b64_buf| {
                            _ = std.base64.standard.Encoder.encode(b64_buf, bytes);
                            audio_emit.b64 = b64_buf;
                        } else |err| {
                            log.warn("audio_reply alloc_failed err={s}", .{@errorName(err)});
                        }
                    } else |err| {
                        log.warn("audio_reply read_failed path={s} err={s}", .{ marker.audio_path, @errorName(err) });
                    }
                } else |err| {
                    log.warn("audio_reply open_failed path={s} err={s}", .{ marker.audio_path, @errorName(err) });
                }
                std.fs.deleteFileAbsolute(p) catch {};
            }
            break :blk marker.visible_text;
        }
        break :blk reply;
    };

    if (is_tool_only) {
        // Tool-only turn: emit structured event, skip placeholder chunking.
        const tool_only_fallback = "event: tool_only_summary\ndata: {\"type\":\"tool_only_summary\"}\n\n";
        const tool_only_owned = sseToolOnlySummaryFrame(req_allocator) catch null;
        defer if (tool_only_owned) |frame| req_allocator.free(frame);
        const tool_only_frame: []const u8 = if (tool_only_owned) |frame| frame else tool_only_fallback;
        sse_stream.sendFrame(tool_only_frame) catch return true;
    } else if (!live_streamed) {
        // ── Buffered replay / fallback path ────────────────────────
        // Used when: (a) delivery_mode is buffered_replay, or (b) live mode
        // but the provider didn't actually stream (non-streaming provider).
        if (!is_live) {
            // Only send reply_start in buffered mode (live already sent it above)
            const reply_start_fallback = "event: reply_start\ndata: {\"type\":\"reply_start\",\"stream_kind\":\"final_reply\",\"delivery_mode\":\"buffered_replay\",\"live\":false}\n\n";
            const reply_start_owned = sseReplyStartFrame(req_allocator, "final_reply", "buffered_replay", false) catch null;
            defer if (reply_start_owned) |frame| req_allocator.free(frame);
            const reply_start_frame: []const u8 = if (reply_start_owned) |frame| frame else reply_start_fallback;
            sse_stream.sendFrame(reply_start_frame) catch return true;
        }

        var start: usize = 0;
        var seq: usize = 0;
        while (start < payload_text.len) : (start += SSE_TOKEN_CHUNK_SIZE) {
            const end = @min(start + SSE_TOKEN_CHUNK_SIZE, payload_text.len);
            const token_owned = sseTokenFrame(req_allocator, payload_text[start..end], seq) catch {
                sendLockedSseErrorFrames(&sse_stream, req_allocator, "stream_encode_failed", "failed to encode token frame");
                return true;
            };
            defer req_allocator.free(token_owned);
            sse_stream.sendFrame(token_owned) catch return true;
            seq += 1;
        }
    }
    // Live mode with streaming provider: tokens already delivered via
    // liveStreamCallback during agent processing. No post-hoc chunking needed.

    // V1.11 hardening (2026-05-07) — emit audio_reply BEFORE done so the
    // FE plays it after the text reply settles. Frame is best-effort: if
    // extraction or read failed earlier, audio_emit.b64 is null and we
    // skip cleanly (text-only mode).
    if (audio_emit.b64) |b64| {
        const audio_frame = sseAudioReplyFrame(req_allocator, b64, audio_emit.format, audio_emit.raw_bytes) catch null;
        if (audio_frame) |frame| {
            defer req_allocator.free(frame);
            sse_stream.sendFrame(frame) catch {
                log.warn("audio_reply.send_failed session={s}", .{session_key});
            };
        }
    }

    // Always send done frame regardless of delivery mode. Tool-only turns
    // get the variant carrying `tool_only_turn:true` so the frontend can
    // distinguish a real done-with-text from a done-with-only-tools.
    const done_fallback = if (is_tool_only)
        "event: done\ndata: {\"type\":\"done\",\"tool_only_turn\":true}\n\n"
    else
        "event: done\ndata: {\"type\":\"done\"}\n\n";
    const done_owned = blk: {
        if (is_tool_only) {
            break :blk sseDoneFrameToolOnly(req_allocator, session_key, std.time.milliTimestamp()) catch null;
        }
        break :blk sseDoneFrame(req_allocator, session_key, std.time.milliTimestamp()) catch null;
    };
    defer if (done_owned) |frame| req_allocator.free(frame);
    const done_frame: []const u8 = if (done_owned) |frame| frame else done_fallback;
    sse_stream.sendFrame(done_frame) catch {
        sendLockedSseErrorFrames(&sse_stream, req_allocator, "stream_done_failed", "failed to emit done frame");
        return true;
    };
    sse_stream.finish() catch return true;

    const chat_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - chat_start_ms));
    const request_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - request_start_ms));
    log.info("chat.stream.complete user={s} session={s} chat_ms={d} sse_ms={d} total_ms={d}", .{
        user_id,
        session_key,
        chat_duration_ms,
        @as(u64, 0),
        request_duration_ms,
    });

    return true;
}

fn parseUserPath(base_path: []const u8) ?struct { user_id: []const u8, subpath: []const u8 } {
    const prefix = "/api/v1/users/";
    if (!std.mem.startsWith(u8, base_path, prefix)) return null;
    const rest = base_path[prefix.len..];
    const slash = std.mem.indexOfScalar(u8, rest, '/') orelse return null;
    const user_id = rest[0..slash];
    if (!isValidIdentifier(user_id)) return null;
    return .{
        .user_id = user_id,
        .subpath = rest[slash + 1 ..],
    };
}

fn parseUserChannelBindingsSubpath(subpath: []const u8) ?struct {
    channel: []const u8,
    binding_id: ?[]const u8,
} {
    const prefix = "channels/";
    if (!std.mem.startsWith(u8, subpath, prefix)) return null;
    const rest = subpath[prefix.len..];
    const slash = std.mem.indexOfScalar(u8, rest, '/') orelse return null;
    const channel = rest[0..slash];
    if (!isValidIdentifier(channel)) return null;
    const tail = rest[slash + 1 ..];
    if (std.mem.eql(u8, tail, "bindings")) {
        return .{
            .channel = channel,
            .binding_id = null,
        };
    }
    const bindings_prefix = "bindings/";
    if (!std.mem.startsWith(u8, tail, bindings_prefix)) return null;
    const binding_id = tail[bindings_prefix.len..];
    if (!isValidIdentifier(binding_id)) return null;
    return .{
        .channel = channel,
        .binding_id = binding_id,
    };
}

fn resolveSecretPath(allocator: std.mem.Allocator, secrets_dir: []const u8, key: []const u8) ![]u8 {
    if (!isValidIdentifier(key)) return error.InvalidSecretKey;
    return std.fmt.allocPrint(allocator, "{s}/{s}", .{ secrets_dir, key });
}

fn generateWebhookSecretToken(allocator: std.mem.Allocator) ![]u8 {
    const alphabet = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_";
    var random_bytes: [24]u8 = undefined;
    std.crypto.random.bytes(&random_bytes);
    var out: [24]u8 = undefined;
    for (random_bytes, 0..) |b, i| {
        out[i] = alphabet[@as(usize, b) % alphabet.len];
    }
    return allocator.dupe(u8, out[0..]);
}

fn normalizeWebhookBaseUrl(allocator: std.mem.Allocator, base_url: []const u8) ![]u8 {
    var trimmed = std.mem.trim(u8, base_url, " \t\r\n");
    while (trimmed.len > 0 and trimmed[trimmed.len - 1] == '/') {
        trimmed = trimmed[0 .. trimmed.len - 1];
    }
    if (!std.mem.startsWith(u8, trimmed, "https://")) return error.WebhookUrlMustBeHttps;
    return allocator.dupe(u8, trimmed);
}

fn buildWebhookUrlForUser(allocator: std.mem.Allocator, base_url: []const u8, user_id: []const u8) ![]u8 {
    const normalized = try normalizeWebhookBaseUrl(allocator, base_url);
    defer allocator.free(normalized);
    return std.fmt.allocPrint(allocator, "{s}/webhook/telegram?user_id={s}", .{ normalized, user_id });
}

fn isLikelyTelegramBotToken(token: []const u8) bool {
    return telegram_token.is_likely_bot_token(token);
}

fn telegramApiUrl(allocator: std.mem.Allocator, bot_token: []const u8, method: []const u8) ![]u8 {
    return std.fmt.allocPrint(allocator, "https://api.telegram.org/bot{s}/{s}", .{ bot_token, method });
}

fn telegramApiCall(
    allocator: std.mem.Allocator,
    bot_token: []const u8,
    method: []const u8,
    body: []const u8,
) ![]u8 {
    const url = try telegramApiUrl(allocator, bot_token, method);
    defer allocator.free(url);
    const response = try http_util.request_with_mode(allocator, .{ .mode = .native_preferred }, .{
        .subsystem = .channels,
        .method = "POST",
        .url = url,
        .body = body,
        .headers = &.{"Content-Type: application/json"},
        .timeout_ms = 30_000,
        .max_response_bytes = 1024 * 1024,
    });
    return response.body;
}

// ═══════════════════════════════════════════════════════════════════════════
// Session CRUD Handlers (Phase 3.5 — Activation)
// ═══════════════════════════════════════════════════════════════════════════

/// Sentinel response for JSON serialization failures (IN-02: single source of truth).
const response_build_err: RouteResponse = .{
    .status = "500 Internal Server Error",
    .body = "{\"error\":\"response_build_failed\"}",
};

/// Finalize a JSON buffer into a RouteResponse body. On OOM the buffer is freed
/// and response_build_err is returned.
fn finalizeJsonBuf(allocator: std.mem.Allocator, buf: *std.ArrayListUnmanaged(u8)) RouteResponse {
    const body = buf.toOwnedSlice(allocator) catch {
        buf.deinit(allocator);
        return response_build_err;
    };
    return .{ .body = body };
}

// ── Task query endpoints (WP2.2) ──────────────────────────────────────
// Read-only GET surface over the canonical TaskDelivery. Creation and
// cancellation remain in-band via the agent tool surface (task_spawn /
// task_stop); this HTTP surface exists so UI clients can poll task state
// without driving a tool call.

fn serializeTaskEntryJson(w: anytype, entry: *const tasks_mod.TaskEntry) !void {
    try w.writeAll("{\"task_id\":\"");
    try w.writeAll(&entry.task_id);
    try w.writeAll("\",\"description\":\"");
    try jsonEscapeInto(w, entry.description);
    try w.writeAll("\",\"status\":\"");
    try w.writeAll(entry.status.toSlice());
    try w.writeAll("\",\"owner_session\":\"");
    try jsonEscapeInto(w, entry.owner_session);
    try w.print("\",\"created_at_ms\":{d},\"updated_at_ms\":{d}", .{
        entry.created_at_ms,
        entry.updated_at_ms,
    });
    if (entry.result_summary) |rs| {
        try w.writeAll(",\"result_summary\":\"");
        try jsonEscapeInto(w, rs);
        try w.writeByte('"');
    }
    if (entry.error_message) |em| {
        try w.writeAll(",\"error_message\":\"");
        try jsonEscapeInto(w, em);
        try w.writeByte('"');
    }
    try w.writeByte('}');
}

fn handleTaskList(
    allocator: std.mem.Allocator,
    method: []const u8,
    delivery_opt: ?*tasks_mod.TaskDelivery,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    // No delivery resolved (tenant runtime not yet materialized) → empty list.
    const delivery = delivery_opt orelse return .{ .body = "{\"tasks\":[]}" };

    const entries = delivery.listTasksSnapshot(allocator) catch return response_build_err;
    defer allocator.free(entries);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"tasks\":[") catch return response_build_err;
    var first = true;
    for (entries) |*entry| {
        if (!first) w.writeAll(",") catch return response_build_err;
        first = false;
        serializeTaskEntryJson(w, entry) catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleTaskGet(
    allocator: std.mem.Allocator,
    method: []const u8,
    task_id: []const u8,
    delivery_opt: ?*tasks_mod.TaskDelivery,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    // Input validation: non-empty, bounded length, no control characters.
    if (task_id.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing task_id\"}" };
    }
    if (task_id.len > 64) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"task_id too long\"}" };
    }
    for (task_id) |c| {
        if (c < 0x20 or c == 0x7f or c == '/') {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid task_id\"}" };
        }
    }

    const delivery = delivery_opt orelse return .{ .status = "404 Not Found", .body = "{\"error\":\"task_not_found\"}" };
    const snap = delivery.getTaskSnapshot(task_id) orelse return .{ .status = "404 Not Found", .body = "{\"error\":\"task_not_found\"}" };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    serializeTaskEntryJson(w, &snap) catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

// ── Task stop endpoint (WP2.5) ────────────────────────────────────────
// POST /api/v1/users/{user_id}/tasks/{task_id}/stop
//
// Queued-only REST cancellation. Semantics mirror the in-chat `task_stop`
// tool: the canonical SubagentManager.cancelQueued is the only mutation
// path. Running tasks cannot be interrupted in v0.1 — 409 is returned
// rather than pretending to kill a running task. The route never
// materializes a tenant runtime on demand; missing runtime/manager → 404.

/// Parse a canonical task id of the form `task_<11 lowercase hex digits>`
/// into the numeric SubagentManager id. Returns null for any malformed
/// input (wrong prefix, wrong length, non-hex char, uppercase hex).
fn parseCanonicalTaskId(task_id: []const u8) ?u64 {
    const prefix = "task_";
    if (task_id.len != tasks_mod.ledger.TASK_ID_LEN) return null;
    if (!std.mem.startsWith(u8, task_id, prefix)) return null;
    const hex = task_id[prefix.len..];
    if (hex.len != tasks_mod.ledger.TASK_ID_LEN - prefix.len) return null;
    for (hex) |c| {
        const is_digit = c >= '0' and c <= '9';
        const is_lower_hex = c >= 'a' and c <= 'f';
        if (!is_digit and !is_lower_hex) return null;
    }
    return std.fmt.parseInt(u64, hex, 16) catch null;
}

fn handleTaskStop(
    allocator: std.mem.Allocator,
    method: []const u8,
    task_id: []const u8,
    subagent_manager_opt: ?*subagent_mod.SubagentManager,
    delivery_opt: ?*tasks_mod.TaskDelivery,
) RouteResponse {
    if (!std.mem.eql(u8, method, "POST")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    // Input validation mirrors handleTaskGet: non-empty, bounded, no
    // control chars or slashes. Keeps the surface consistent across
    // the three task endpoints.
    if (task_id.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing task_id\"}" };
    }
    if (task_id.len > 64) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"task_id too long\"}" };
    }
    for (task_id) |c| {
        if (c < 0x20 or c == 0x7f or c == '/') {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid task_id\"}" };
        }
    }

    const numeric_id = parseCanonicalTaskId(task_id) orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"malformed task_id\"}" };
    };

    // No subagent manager materialized for this tenant yet → the task
    // cannot exist as far as this route is concerned. We never create
    // a runtime on demand to answer a stop request.
    const mgr = subagent_manager_opt orelse {
        return .{ .status = "404 Not Found", .body = "{\"error\":\"task_not_found\"}" };
    };

    const outcome = mgr.cancelQueued(numeric_id);
    switch (outcome) {
        .cancelled => {
            // Prefer the updated canonical TaskRecord snapshot so
            // clients see timestamps + full entry shape. Fallback to a
            // minimal payload if the delivery mirror is not attached.
            if (delivery_opt) |delivery| {
                if (delivery.getTaskSnapshot(task_id)) |snap| {
                    var out: std.ArrayListUnmanaged(u8) = .empty;
                    defer out.deinit(allocator);
                    const w = out.writer(allocator);
                    serializeTaskEntryJson(w, &snap) catch return response_build_err;
                    return finalizeJsonBuf(allocator, &out);
                }
            }
            var out: std.ArrayListUnmanaged(u8) = .empty;
            defer out.deinit(allocator);
            const w = out.writer(allocator);
            w.writeAll("{\"task_id\":\"") catch return response_build_err;
            jsonEscapeInto(w, task_id) catch return response_build_err;
            w.writeAll("\",\"status\":\"cancelled\"}") catch return response_build_err;
            return finalizeJsonBuf(allocator, &out);
        },
        .running => return .{
            .status = "409 Conflict",
            .body = "{\"error\":\"task_running\",\"message\":\"running tasks cannot be interrupted in v0.1\"}",
        },
        .terminal => return .{
            .status = "409 Conflict",
            .body = "{\"error\":\"task_terminal\",\"message\":\"task already terminal\"}",
        },
        .not_found => return .{
            .status = "404 Not Found",
            .body = "{\"error\":\"task_not_found\"}",
        },
    }
}

// ── Scheduled-jobs read-only endpoint (V1.11 — 2026-05-07) ───────────
// GET /api/v1/users/{user_id}/jobs returns the user's scheduled cron
// jobs (recurring + one-shot) so the frontend can surface them in the
// settings / scheduled-tasks UI. The agent's `schedule` tool is the
// canonical create/cancel path today (natural language: "remind me at
// 8am every weekday"); this endpoint exposes the resulting state for
// READ. Mutations stay under the agent for now — when the FE adds a
// "delete this job" button, we can add DELETE here without needing
// to redesign the read shape.
//
// Backed by `zaki_state.getJobsJson(user_id)` which already returns
// the canonical job rows as a serialized JSON array (jobs_table → JSONB
// via SQL); we just wrap it in `{"jobs": ...}` so the response shape
// matches the rest of the API (e.g., /tasks returns `{"tasks":[...]}`).
//
// Empty array when the user has no scheduled jobs OR when state isn't
// running on Postgres (degraded backend). The FE renders an empty-state
// card in either case — no need to surface "backend degraded" in the UI.
fn handleJobList(
    allocator: std.mem.Allocator,
    method: []const u8,
    state_mgr_opt: ?*zaki_state_mod.Manager,
    user_id: i64,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    // No state manager (file-state degraded mode) → empty list.
    const state_mgr = state_mgr_opt orelse return .{ .body = "{\"jobs\":[]}" };

    const jobs_json = state_mgr.getJobsJson(allocator, user_id) catch |err| {
        log.warn("jobs.list failed user_id={d} err={s}", .{ user_id, @errorName(err) });
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"jobs_list_failed\"}" };
    };
    defer allocator.free(jobs_json);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"jobs\":") catch return response_build_err;
    // jobs_json is already a serialized JSON array — splice it in raw.
    // Defense-in-depth: empty result from getJobsJson should be "[]" but
    // null-coalesce just in case the schema ever returns NULL.
    if (jobs_json.len == 0) {
        w.writeAll("[]") catch return response_build_err;
    } else {
        w.writeAll(jobs_json) catch return response_build_err;
    }
    w.writeAll("}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

// ── Usage read-only endpoint (WP2.3) ──────────────────────────────────
// GET /api/v1/users/{user_id}/usage returns a snapshot of UsageRuntime
// for the user. It is READ-ONLY: it never materializes a tenant runtime
// to answer the read. When no runtime exists for the user we return a
// zero summary. Provider pricing is not wired in v0.1 — cost_available
// is reported as false unless a non-zero cost has been accumulated
// (currently never from the agent path), matching the /cost slash
// command semantics.

fn serializeUsageReportJson(w: anytype, rpt: *const usage_runtime_mod.UsageReport) !void {
    try w.print(
        "{{\"session_total_tokens\":{d},\"session_input_tokens\":{d},\"session_output_tokens\":{d},\"session_cost_usd\":{d:.6},\"turn_count\":{d},\"models\":[",
        .{
            rpt.session_total_tokens,
            rpt.session_input_tokens,
            rpt.session_output_tokens,
            rpt.session_cost_usd,
            rpt.turn_count,
        },
    );
    for (rpt.model_breakdown, 0..) |m, i| {
        if (i > 0) try w.writeByte(',');
        try w.writeAll("{\"model\":\"");
        try jsonEscapeInto(w, m.model);
        try w.print(
            "\",\"input_tokens\":{d},\"output_tokens\":{d},\"total_tokens\":{d},\"cost_usd\":{d:.6},\"turn_count\":{d}}}",
            .{
                m.input_tokens,
                m.output_tokens,
                m.total_tokens,
                m.cost_usd,
                m.turn_count,
            },
        );
    }
    try w.writeAll("],\"cost_available\":");
    try w.writeAll(if (rpt.session_cost_usd > 0.0) "true" else "false");
    try w.writeByte('}');
}

// GET /api/v1/users/{user_id}/diagnostics/context
// GET /api/v1/users/{user_id}/diagnostics/memory-doctor
//
// Read-only structured diagnostics. Mirrors the /context detail and /memory
// doctor slash commands but returns JSON for the frontend PowerUserSheet.
// Never materializes a session on demand — a GET before any agent activity
// returns `{"active": false}`. When the user's main-lane session exists we
// produce the report from its agent state.

const agent_context_report = @import("agent/context_report.zig");
const agent_root = @import("agent/root.zig");
const mem_lifecycle_diag = @import("memory/lifecycle/diagnostics.zig");

fn handleUserDiagnosticsContext(
    allocator: std.mem.Allocator,
    method: []const u8,
    session_mgr_opt: ?*session_mod.SessionManager,
    scoped_user_id: []const u8,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    const session_mgr = session_mgr_opt orelse return .{
        .body = "{\"active\":false,\"reason\":\"session_manager_unavailable\"}",
    };

    var key_buf: [zaki_session.SessionIdentity.MAX_KEY_LEN + 1]u8 = undefined;
    const session_key = zaki_session.userMainSessionKey(&key_buf, scoped_user_id);

    const session = session_mgr.getIfPresent(session_key) orelse return .{
        .body = "{\"active\":false,\"reason\":\"no_active_session\"}",
    };

    session.mutex.lock();
    defer session.mutex.unlock();

    const report = agent_context_report.fromAgent(&session.agent);
    const inner = agent_context_report.formatJson(allocator, report) catch return response_build_err;
    defer allocator.free(inner);

    // Wrap so the frontend can distinguish an active-session payload from
    // the no-session envelope above.
    const body = std.fmt.allocPrint(allocator, "{{\"active\":true,\"report\":{s}}}", .{inner}) catch return response_build_err;
    return .{ .body = body };
}

fn handleUserDiagnosticsMemoryDoctor(
    allocator: std.mem.Allocator,
    method: []const u8,
    session_mgr_opt: ?*session_mod.SessionManager,
    scoped_user_id: []const u8,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    const session_mgr = session_mgr_opt orelse return .{
        .body = "{\"active\":false,\"reason\":\"session_manager_unavailable\"}",
    };

    var key_buf: [zaki_session.SessionIdentity.MAX_KEY_LEN + 1]u8 = undefined;
    const session_key = zaki_session.userMainSessionKey(&key_buf, scoped_user_id);

    const session = session_mgr.getIfPresent(session_key) orelse return .{
        .body = "{\"active\":false,\"reason\":\"no_active_session\"}",
    };

    session.mutex.lock();
    defer session.mutex.unlock();

    const rt_opt: ?*memory_mod.MemoryRuntime = if (@hasField(@TypeOf(session.agent), "mem_rt"))
        session.agent.mem_rt
    else
        null;
    const rt = rt_opt orelse return .{
        .body = "{\"active\":true,\"runtime\":false,\"reason\":\"memory_runtime_not_configured\"}",
    };

    const diag_report = mem_lifecycle_diag.diagnose(rt);
    // Memory diagnostics doesn't yet have a JSON formatter — wrap the
    // human-readable text in a JSON envelope so frontend can display it
    // today. Structured JSON for memory-doctor is a follow-up that should
    // mirror agent_context_report.formatJson's pattern.
    const text = mem_lifecycle_diag.formatReport(diag_report, allocator) catch return response_build_err;
    defer allocator.free(text);

    var buf: std.ArrayListUnmanaged(u8) = .empty;
    defer buf.deinit(allocator);
    const w = buf.writer(allocator);
    w.writeAll("{\"active\":true,\"runtime\":true,\"report_text\":\"") catch return response_build_err;
    jsonEscapeInto(w, text) catch return response_build_err;
    w.writeAll("\"}") catch return response_build_err;

    return finalizeJsonBuf(allocator, &buf);
}

fn handleUserUsage(
    allocator: std.mem.Allocator,
    method: []const u8,
    usage_rt_opt: ?*usage_runtime_mod.UsageRuntime,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    // No tenant runtime materialized yet → zero summary (static body).
    const usage_rt = usage_rt_opt orelse return .{
        .body = "{\"session_total_tokens\":0,\"session_input_tokens\":0,\"session_output_tokens\":0,\"session_cost_usd\":0.000000,\"turn_count\":0,\"models\":[],\"cost_available\":false}",
    };

    const rpt = usage_rt.report(allocator) catch return response_build_err;
    defer rpt.deinit();

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    serializeUsageReportJson(w, &rpt) catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

// ── Run trace read-only endpoints (WP4.2) ─────────────────────────────
// GET /api/v1/users/{user_id}/traces            → list of run ids
// GET /api/v1/users/{user_id}/traces/{run_id}   → sanitized event timeline
//
// Mirrors the usage/task read contract: the route never materializes a
// tenant runtime on demand. Missing runtime → empty list for the
// collection; 404 for a specific run. Run ids are validated the same
// way task_ids are: non-empty, bounded length, no control chars or
// slashes. Only sanitized fields already exposed over SSE are
// serialized — no provider API details, no raw tool payloads.

fn isValidRunId(run_id: []const u8) bool {
    if (run_id.len == 0 or run_id.len > 128) return false;
    for (run_id) |c| {
        if (c < 0x20 or c == 0x7f or c == '/') return false;
    }
    return true;
}

fn serializeTraceEventJson(
    w: anytype,
    evt: *const run_trace_store_mod.TraceEvent,
) !void {
    try w.writeAll("{\"kind\":\"");
    try jsonEscapeInto(w, evt.kind.toSlice());
    try w.print("\",\"ts_ms\":{d}", .{evt.ts_ms});
    if (evt.phase) |v| {
        try w.writeAll(",\"phase\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.tool) |v| {
        try w.writeAll(",\"tool\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.tool_use_id) |v| {
        try w.writeAll(",\"tool_use_id\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.label) |v| {
        try w.writeAll(",\"label\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.risk_level) |v| {
        try w.writeAll(",\"risk_level\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.status) |v| {
        try w.writeAll(",\"status\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.task_id) |v| {
        try w.writeAll(",\"task_id\":\"");
        try jsonEscapeInto(w, v);
        try w.writeAll("\"");
    }
    if (evt.success) |v| try w.print(",\"success\":{s}", .{if (v) "true" else "false"});
    if (evt.duration_ms) |v| try w.print(",\"duration_ms\":{d}", .{v});
    if (evt.iteration) |v| try w.print(",\"iteration\":{d}", .{v});
    if (evt.exit_code) |v| try w.print(",\"exit_code\":{d}", .{v});
    if (evt.usage_tokens) |v| try w.print(",\"usage_tokens\":{d}", .{v});
    try w.writeAll("}");
}

fn handleTraceList(
    allocator: std.mem.Allocator,
    method: []const u8,
    store_opt: ?*run_trace_store_mod.RunTraceStore,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    const store = store_opt orelse return .{ .body = "{\"traces\":[]}" };

    var index = store.listRuns(allocator) catch return response_build_err;
    defer index.deinit();

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"traces\":[") catch return response_build_err;
    for (index.entries, 0..) |entry, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        w.writeAll("{\"run_id\":\"") catch return response_build_err;
        jsonEscapeInto(w, entry.run_id) catch return response_build_err;
        w.print(
            "\",\"event_count\":{d},\"first_event_ms\":{d},\"last_event_ms\":{d},\"truncated\":{s}}}",
            .{
                entry.event_count,
                entry.first_event_ms,
                entry.last_event_ms,
                if (entry.truncated) "true" else "false",
            },
        ) catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleTraceGet(
    allocator: std.mem.Allocator,
    method: []const u8,
    run_id: []const u8,
    store_opt: ?*run_trace_store_mod.RunTraceStore,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    if (run_id.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing run_id\"}" };
    }
    if (!isValidRunId(run_id)) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid run_id\"}" };
    }

    const store = store_opt orelse return .{
        .status = "404 Not Found",
        .body = "{\"error\":\"run_not_found\"}",
    };

    const snap_opt = store.snapshotRun(allocator, run_id) catch return response_build_err;
    var snap = snap_opt orelse return .{
        .status = "404 Not Found",
        .body = "{\"error\":\"run_not_found\"}",
    };
    defer snap.deinit();

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"run_id\":\"") catch return response_build_err;
    jsonEscapeInto(w, snap.run_id) catch return response_build_err;
    w.print(
        "\",\"first_event_ms\":{d},\"last_event_ms\":{d},\"truncated\":{s},\"events\":[",
        .{
            snap.first_event_ms,
            snap.last_event_ms,
            if (snap.truncated) "true" else "false",
        },
    ) catch return response_build_err;
    for (snap.events, 0..) |*evt, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        serializeTraceEventJson(w, evt) catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleSessionList(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    session_mgr_opt: ?*session_mod.SessionManager,
    state_mgr: ?*zaki_state_mod.Manager,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"sessions\":[") catch return response_build_err;
    var first = true;

    // Track keys already emitted (owned copies to avoid dangling pointers after mutex release)
    var seen_keys: std.StringHashMapUnmanaged(void) = .{};
    defer {
        var kit = seen_keys.keyIterator();
        while (kit.next()) |key| allocator.free(@constCast(key.*));
        seen_keys.deinit(allocator);
    }

    // Phase 1: Live in-memory sessions — normalized field shape matching Phase 2
    if (session_mgr_opt) |mgr| {
        const session_identity = @import("session/identity.zig");
        mgr.mutex.lock();
        defer mgr.mutex.unlock();

        var it = mgr.sessions.iterator();
        while (it.next()) |entry| {
            if (!session_identity.isOwnedBy(entry.key_ptr.*, user_id)) continue;
            const session = entry.value_ptr.*;
            if (!first) w.writeAll(",") catch return response_build_err;
            first = false;
            // Normalized shape: session_key, title, message_count, last_active (int), live
            w.writeAll("{\"session_key\":\"") catch return response_build_err;
            jsonEscapeInto(w, entry.key_ptr.*) catch return response_build_err;
            w.writeAll("\",\"title\":\"") catch return response_build_err;
            // Derive title from session key for live sessions
            const key_str = entry.key_ptr.*;
            if (std.mem.endsWith(u8, key_str, ":main")) {
                w.writeAll("Main") catch return response_build_err;
            } else {
                // Extract thread slug from key: agent:zaki-bot:user:42:thread:abc → abc
                if (std.mem.lastIndexOf(u8, key_str, ":")) |idx| {
                    jsonEscapeInto(w, key_str[idx + 1 ..]) catch return response_build_err;
                } else {
                    w.writeAll("Session") catch return response_build_err;
                }
            }
            // Truthful runtime fields (Codex 2026-04-29 — frontend session
            // truth). Pending approvals: single-slot model (agent stores one
            // PendingToolApproval at a time), so the count is 0 or 1.
            // last_channel: origin_channel is set when the session was
            // anchored to an inbound channel; null if web/REST-only.
            const live_mode = session.agent.execution_mode.toSlice();
            const live_pending: u8 = if (session.agent.pending_tool_approval != null) 1 else 0;
            const live_pressure: u8 = blk: {
                if (session.agent.token_limit == 0) break :blk 0;
                const pct = @divTrunc(session.agent.tokensUsed() * 100, session.agent.token_limit);
                break :blk if (pct > 100) 100 else @as(u8, @intCast(pct));
            };
            w.print("\",\"message_count\":{d},\"last_active\":{d},\"live\":true,\"mode\":\"{s}\",\"pending_approval_count\":{d},\"context_pressure_percent\":{d},\"last_channel\":", .{
                session.turn_count,
                session.last_active,
                live_mode,
                live_pending,
                live_pressure,
            }) catch return response_build_err;
            if (session.origin_channel) |ch| {
                w.writeAll("\"") catch return response_build_err;
                jsonEscapeInto(w, ch) catch return response_build_err;
                w.writeAll("\"") catch return response_build_err;
            } else {
                w.writeAll("null") catch return response_build_err;
            }
            w.writeAll("}") catch return response_build_err;
            // Store owned copy of key (safe after mutex release)
            const key_copy = allocator.dupe(u8, entry.key_ptr.*) catch continue;
            seen_keys.put(allocator, key_copy, {}) catch allocator.free(key_copy);
        }
    }

    // Phase 2: Persisted sessions from Postgres (survives eviction + pod restart)
    if (state_mgr) |mgr| {
        const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch 0;
        if (numeric_user_id > 0) {
            if (mgr.listUserSessions(allocator, numeric_user_id)) |persisted| {
                defer {
                    for (persisted) |*info| info.deinit(allocator);
                    allocator.free(persisted);
                }
                for (persisted) |info| {
                    if (seen_keys.get(info.session_key) != null) continue;
                    if (!first) w.writeAll(",") catch return response_build_err;
                    first = false;
                    w.writeAll("{\"session_key\":\"") catch return response_build_err;
                    jsonEscapeInto(w, info.session_key) catch return response_build_err;
                    w.writeAll("\",\"title\":\"") catch return response_build_err;
                    jsonEscapeInto(w, info.title) catch return response_build_err;
                    w.print("\",\"message_count\":{d},\"last_active\":\"", .{info.message_count}) catch return response_build_err;
                    jsonEscapeInto(w, info.last_active) catch return response_build_err;
                    // Evicted/persisted sessions: runtime fields are null.
                    // UI uses these nulls + live=false as the explicit
                    // "inactive session" signal to disable mode/approval
                    // controls cleanly. The mode endpoint requires a live
                    // agent process, so attempting POST /mode on these
                    // returns 404; the frontend should never offer the
                    // control in the first place when live=false.
                    w.writeAll("\",\"live\":false,\"mode\":null,\"pending_approval_count\":null,\"context_pressure_percent\":null,\"last_channel\":null}") catch return response_build_err;
                }
            } else |_| {}
        }
    }

    w.writeAll("]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleSessionAction(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    rest: []const u8,
    session_mgr_opt: ?*session_mod.SessionManager,
    raw_request: []const u8,
    state_mgr_opt: ?*zaki_state_mod.Manager,
) RouteResponse {
    // Parse: {session_key} or {session_key}/{action}
    // Session keys use colons not slashes, so last slash separates key from action.
    var session_key: []const u8 = rest;
    var action: ?[]const u8 = null;
    if (std.mem.lastIndexOfScalar(u8, rest, '/')) |slash| {
        const tail = rest[slash + 1 ..];
        // Only treat as action if it's a known action keyword
        if (isSessionAction(tail)) {
            session_key = rest[0..slash];
            action = tail;
        }
    }

    if (session_key.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing session_key\"}" };
    }

    // Input validation: cap length and reject control characters (CR/LF/null)
    // to match chat stream path validation and prevent log injection.
    if (session_key.len > 255) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"session_key too long\"}" };
    }
    for (session_key) |c| {
        if (c < 0x20 or c == 0x7f) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid session_key\"}" };
        }
    }

    // Ownership check: session must belong to this user
    const session_identity = @import("session/identity.zig");
    if (!session_identity.isOwnedBy(session_key, user_id)) {
        return .{ .status = "403 Forbidden", .body = "{\"error\":\"session_not_owned\"}" };
    }

    const mgr = session_mgr_opt orelse return .{ .status = "404 Not Found", .body = "{\"error\":\"no_session_manager\"}" };

    if (action == null) {
        // GET /sessions/{key} — session info
        if (std.mem.eql(u8, method, "GET")) {
            return handleSessionGet(allocator, mgr, session_key, state_mgr_opt, user_id);
        }
        // DELETE /sessions/{key} — destroy session
        if (std.mem.eql(u8, method, "DELETE")) {
            return handleSessionDelete(allocator, mgr, session_key, state_mgr_opt, user_id);
        }
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    const act = action.?;

    if (std.mem.eql(u8, act, "compact")) {
        if (!std.mem.eql(u8, method, "POST")) return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        return handleSessionCompact(allocator, mgr, session_key);
    }
    if (std.mem.eql(u8, act, "context")) {
        if (!std.mem.eql(u8, method, "GET")) return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        return handleSessionContext(allocator, mgr, session_key);
    }
    if (std.mem.eql(u8, act, "export")) {
        if (!std.mem.eql(u8, method, "POST") and !std.mem.eql(u8, method, "GET")) return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        return handleSessionExport(allocator, mgr, session_key);
    }
    if (std.mem.eql(u8, act, "history")) {
        if (!std.mem.eql(u8, method, "GET")) return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        return handleSessionHistory(allocator, mgr, session_key);
    }
    if (std.mem.eql(u8, act, "approve")) {
        if (!std.mem.eql(u8, method, "POST")) return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        return handleSessionApprove(allocator, mgr, session_key, raw_request);
    }
    if (std.mem.eql(u8, act, "mode")) {
        if (!std.mem.eql(u8, method, "POST")) return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        return handleSessionMode(allocator, mgr, session_key, raw_request);
    }

    return .{ .status = "404 Not Found", .body = "{\"error\":\"unknown_session_action\"}" };
}

fn isSessionAction(s: []const u8) bool {
    const actions = [_][]const u8{ "compact", "context", "export", "history", "approve", "mode" };
    for (actions) |a| {
        if (std.mem.eql(u8, s, a)) return true;
    }
    return false;
}

/// POST /api/v1/users/:id/sessions/:key/mode
/// Body: {"mode":"plan|execute|review|background"}
/// Sets the active session's execution mode by routing through the existing
/// `/mode` slash command (commands.zig is the single truth path). Powers the
/// in-thread Plan|Execute|Review segmented control in the V1.5 UX.
fn handleSessionMode(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
    raw_request: []const u8,
) RouteResponse {
    // Extract body. raw_request is the full HTTP request; find the body after
    // the empty line separator. Same pattern handleSessionApprove uses via
    // validateApproveInput.
    const body_marker = "\r\n\r\n";
    const body = if (std.mem.indexOf(u8, raw_request, body_marker)) |idx|
        raw_request[idx + body_marker.len ..]
    else
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing body\"}" };

    // Parse the mode field. Keep it tight — we only want one valid string.
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_json\"}" };
    defer parsed.deinit();
    if (parsed.value != .object) return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_body\"}" };
    const mode_v = parsed.value.object.get("mode") orelse
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_mode\"}" };
    if (mode_v != .string) return .{ .status = "400 Bad Request", .body = "{\"error\":\"mode_not_string\"}" };
    const mode = mode_v.string;
    // Whitelist matches commands.zig::handleModeCommand acceptance set.
    const valid_modes = [_][]const u8{ "plan", "execute", "review", "background" };
    var ok = false;
    for (valid_modes) |m| {
        if (std.mem.eql(u8, mode, m)) {
            ok = true;
            break;
        }
    }
    if (!ok) return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_mode\"}" };

    // Same active_refs pin pattern as handleSessionApprove: prevent eviction
    // between get and processMessage.
    mgr.mutex.lock();
    const session = mgr.sessions.get(session_key) orelse {
        mgr.mutex.unlock();
        return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
    };
    session.active_refs += 1;
    mgr.mutex.unlock();

    // Route through the existing /mode slash command — single truth path.
    const command = std.fmt.allocPrint(allocator, "/mode {s}", .{mode}) catch {
        mgr.mutex.lock();
        if (session.active_refs > 0) session.active_refs -= 1;
        mgr.mutex.unlock();
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"command_build_failed\"}" };
    };
    defer allocator.free(command);

    const result = mgr.processMessage(session_key, command, null) catch {
        mgr.mutex.lock();
        if (session.active_refs > 0) session.active_refs -= 1;
        mgr.mutex.unlock();
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"mode_change_failed\"}" };
    };

    mgr.mutex.lock();
    if (session.active_refs > 0) session.active_refs -= 1;
    mgr.mutex.unlock();

    defer allocator.free(result);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"mode\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    jsonEscapeInto(w, mode) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    w.writeAll("\",\"message\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    jsonEscapeInto(w, result) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    w.writeAll("\"}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    return .{ .body = out.toOwnedSlice(allocator) catch
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" } };
}

fn handleSessionGet(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
    state_mgr_opt: ?*zaki_state_mod.Manager,
    user_id: []const u8,
) RouteResponse {
    // Lock escalation: mgr.mutex → session.mutex → release mgr.mutex
    mgr.mutex.lock();
    const live_session_opt = mgr.sessions.get(session_key);
    if (live_session_opt) |session| {
        session.mutex.lock();
        mgr.mutex.unlock();
        defer session.mutex.unlock();

        return renderLiveSessionDetail(allocator, session_key, session);
    }
    // RAM miss — release manager mutex before any DB work.
    mgr.mutex.unlock();

    // Persisted-session fallback (Codex 2026-04-29 — frontend session truth).
    // Without this, evicted sessions visible in the list but no longer in
    // RAM 404 here, breaking the UI's "click into the session" flow. With
    // it, we return live=false + null runtime fields so the UI can render
    // the detail page (history loads via /sessions/:key/history just fine,
    // already DB-backed) and disable mode/approval controls cleanly.
    if (state_mgr_opt) |state_mgr| {
        const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch 0;
        if (numeric_user_id > 0) {
            if (state_mgr.listUserSessions(allocator, numeric_user_id)) |persisted| {
                defer {
                    for (persisted) |*info| info.deinit(allocator);
                    allocator.free(persisted);
                }
                for (persisted) |info| {
                    if (!std.mem.eql(u8, info.session_key, session_key)) continue;
                    return renderPersistedSessionDetail(allocator, info);
                }
            } else |_| {}
        }
    }

    return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
}

/// Live (RAM) session detail. Caller holds session.mutex.
fn renderLiveSessionDetail(
    allocator: std.mem.Allocator,
    session_key: []const u8,
    session: *session_mod.Session,
) RouteResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    const mode_str = session.agent.execution_mode.toSlice();
    const pending_count: u8 = if (session.agent.pending_tool_approval != null) 1 else 0;
    const pressure_percent: u8 = blk: {
        if (session.agent.token_limit == 0) break :blk 0;
        const pct = @divTrunc(session.agent.tokensUsed() * 100, session.agent.token_limit);
        break :blk if (pct > 100) 100 else @as(u8, @intCast(pct));
    };

    w.writeAll("{\"session_key\":\"") catch return response_build_err;
    jsonEscapeInto(w, session_key) catch return response_build_err;
    w.print("\",\"live\":true,\"created_at\":{d},\"last_active\":{d},\"turn_count\":{d},\"history_len\":{d},\"mode\":\"{s}\",\"pending_approval_count\":{d},\"context_pressure_percent\":{d},\"last_channel\":", .{
        session.created_at,
        session.last_active,
        session.turn_count,
        session.agent.historyLen(),
        mode_str,
        pending_count,
        pressure_percent,
    }) catch return response_build_err;

    if (session.origin_channel) |ch| {
        w.writeAll("\"") catch return response_build_err;
        jsonEscapeInto(w, ch) catch return response_build_err;
        w.writeAll("\"") catch return response_build_err;
    } else {
        w.writeAll("null") catch return response_build_err;
    }

    // pending_approvals: array of 0 or 1 item. Single-slot model in the
    // agent — matches PendingToolApproval struct at agent/root.zig:1387.
    // arguments_json deliberately omitted (can be large; tool_call_id +
    // reason + risk_level are sufficient for the approval UI).
    w.writeAll(",\"pending_approvals\":[") catch return response_build_err;
    if (session.agent.pending_tool_approval) |pending| {
        w.print("{{\"id\":{d},\"tool\":\"", .{pending.id}) catch return response_build_err;
        jsonEscapeInto(w, pending.tool_name) catch return response_build_err;
        w.writeAll("\",\"reason\":\"") catch return response_build_err;
        jsonEscapeInto(w, pending.reason) catch return response_build_err;
        w.writeAll("\",\"risk_level\":\"") catch return response_build_err;
        jsonEscapeInto(w, pending.risk_level.toSlice()) catch return response_build_err;
        w.writeAll("\"}") catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

/// Persisted (DB-only, evicted from RAM) session detail. Returns the
/// inactive-session shape the UI uses to disable runtime controls.
fn renderPersistedSessionDetail(
    allocator: std.mem.Allocator,
    info: zaki_state_mod.SessionInfo,
) RouteResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"session_key\":\"") catch return response_build_err;
    jsonEscapeInto(w, info.session_key) catch return response_build_err;
    w.writeAll("\",\"live\":false,\"title\":\"") catch return response_build_err;
    jsonEscapeInto(w, info.title) catch return response_build_err;
    w.print("\",\"message_count\":{d},\"last_active\":\"", .{info.message_count}) catch return response_build_err;
    jsonEscapeInto(w, info.last_active) catch return response_build_err;
    // Runtime fields all null — UI uses these as the explicit signal to
    // disable the in-thread Plan|Execute|Review control, hide approval
    // badges, etc. History remains accessible via /sessions/:key/history
    // which is DB-backed and works for evicted sessions today.
    w.writeAll("\",\"mode\":null,\"pending_approval_count\":null,\"context_pressure_percent\":null,\"last_channel\":null,\"pending_approvals\":[]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleSessionDelete(
    _: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
    state_mgr_opt: ?*zaki_state_mod.Manager,
    user_id_str: []const u8,
) RouteResponse {
    // Durable session delete (2026-04-28, Nova directive): pre-fix, this
    // handler only acted on RAM-live sessions. If a session was evicted
    // (or never live in this process), DELETE returned 404, and the next
    // GET /sessions read it back from {schema}.sessions and showed it
    // again — "ghost" sessions. ALSO: it called persistSessionCheckpoint
    // on delete, which is backwards (writes to durable store ON
    // destruction).
    //
    // Now: two phases.
    //   Phase 1 — live evict: if RAM has the session, remove it (no
    //   checkpoint write — that was the backwards bug). Skip if absent.
    //   Phase 2 — durable delete: regardless of live presence, call
    //   state_mgr.deleteSession to purge messages + completion_events +
    //   autosaved memory + sessions row. This is what makes the UI
    //   refresh actually stay quiet.
    // Return success when EITHER phase saw something. 404 only when
    // both live AND durable found nothing.

    var existed_live: bool = false;
    var live_in_use: bool = false;

    // Phase 1: live evict (best-effort)
    {
        mgr.mutex.lock();
        if (mgr.sessions.get(session_key)) |session| {
            // Guard: refuse to evict a session with an active turn
            // (active_refs > 0) or an active reader (session.mutex held).
            // Prevents use-after-free. Durable delete is still safe to
            // attempt below — it doesn't touch live state.
            if (session.active_refs > 0 or !session.mutex.tryLock()) {
                live_in_use = true;
                mgr.mutex.unlock();
            } else {
                _ = mgr.sessions.fetchRemove(session_key);
                mgr.mutex.unlock();
                // NOTE: NO persistSessionCheckpoint("api_delete") — that
                // was the bug (write-on-delete). Just teardown.
                session.mutex.unlock();
                session.deinit(mgr.allocator);
                mgr.allocator.destroy(session);
                existed_live = true;
            }
        } else {
            mgr.mutex.unlock();
        }
    }

    // If live session was in-use, refuse — caller can retry later.
    if (live_in_use) {
        return .{ .status = "409 Conflict", .body = "{\"error\":\"session_in_use\"}" };
    }

    // Phase 2: durable delete (best-effort; success even if absent)
    var existed_durable: bool = false;
    if (state_mgr_opt) |smgr| {
        const numeric_user_id = std.fmt.parseInt(i64, user_id_str, 10) catch 0;
        if (numeric_user_id > 0) {
            // We don't have a row-count signal from deleteSession (would
            // require widening the API). Treat success as "may have
            // existed"; combined with live evict, this gives us
            // 404-only-when-truly-absent semantics without false
            // positives in the deleted-twice case.
            smgr.deleteSession(numeric_user_id, session_key) catch |err| {
                log.warn("session.delete.durable_failed user={s} key={s} err={s}", .{
                    user_id_str, session_key, @errorName(err),
                });
                // Don't fail the whole delete on durable error if we
                // already evicted live — partial success is preferable
                // to "delete left state behind."
                if (!existed_live) {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"durable_delete_failed\"}" };
                }
            };
            existed_durable = true;
        }
    }

    if (!existed_live and !existed_durable) {
        return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
    }

    return .{ .body = "{\"status\":\"deleted\"}" };
}

fn handleSessionCompact(
    _: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
) RouteResponse {
    // Lock escalation: mgr.mutex → session.mutex → release mgr.mutex
    // (prevents use-after-free if eviction runs between unlock and lock)
    mgr.mutex.lock();
    const session = mgr.sessions.get(session_key) orelse {
        mgr.mutex.unlock();
        return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
    };
    session.mutex.lock();
    mgr.mutex.unlock();
    defer session.mutex.unlock();
    const compacted = session.agent.manualCompactHistory() catch {
        // Compaction failed (e.g. provider unavailable) — checkpoint instead
        session.agent.persistSessionCheckpoint("api_compact_fallback");
        return .{ .body = "{\"status\":\"checkpoint_only\",\"compacted\":false}" };
    };
    if (compacted) {
        session.agent.persistSessionCheckpoint("api_compact");
    }
    return .{ .body = if (compacted) "{\"status\":\"compacted\",\"compacted\":true}" else "{\"status\":\"no_change\",\"compacted\":false}" };
}

fn handleSessionContext(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
) RouteResponse {
    mgr.mutex.lock();
    const session = mgr.sessions.get(session_key) orelse {
        mgr.mutex.unlock();
        return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
    };
    // Hold session mutex while reading agent state to prevent races with active turns
    session.mutex.lock();
    mgr.mutex.unlock();
    defer session.mutex.unlock();

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    const agent = &session.agent;
    const tokens_used = agent.tokensUsed();
    // Normalized 0-100 pressure for the in-thread context-state badge in the
    // V1.5 UX. Frontend buckets into normal/warning/near_limit per its own
    // thresholds (recommended: 0-50 normal, 51-75 warning, >75 near_limit).
    // Clamped at 100 so a stale token_limit field can't produce >100 values.
    const pressure_percent: u8 = blk: {
        if (agent.token_limit == 0) break :blk 0;
        const pct = @divTrunc(tokens_used * 100, agent.token_limit);
        if (pct > 100) break :blk 100;
        break :blk @intCast(pct);
    };
    w.print("{{\"history_len\":{d},\"tokens_used\":{d},\"max_history\":{d},\"token_limit\":{d},\"context_pressure_percent\":{d}}}", .{
        agent.historyLen(),
        tokens_used,
        agent.max_history_messages,
        agent.token_limit,
        pressure_percent,
    }) catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

/// Max messages serialized per export/history request to prevent OOM from huge sessions.
const SESSION_EXPORT_MAX_MESSAGES: usize = 10_000;

/// Shared helper: serialize history pairs as a JSON array of {role, content} objects.
/// Caps output at SESSION_EXPORT_MAX_MESSAGES to prevent unbounded memory growth.
fn writeHistoryMessagesJson(w: anytype, history: []const @import("agent/root.zig").Agent.HistoryPair) !void {
    const capped = if (history.len > SESSION_EXPORT_MAX_MESSAGES) history[0..SESSION_EXPORT_MAX_MESSAGES] else history;
    for (capped, 0..) |entry, i| {
        if (i > 0) try w.writeAll(",");
        try w.writeAll("{\"role\":\"");
        try w.writeAll(entry.role);
        try w.writeAll("\",\"content\":\"");
        try jsonEscapeInto(w, entry.content);
        try w.writeAll("\"}");
    }
    if (history.len > SESSION_EXPORT_MAX_MESSAGES) {
        try w.writeAll(",{\"role\":\"system\",\"content\":\"[truncated — ");
        var trunc_buf: [64]u8 = undefined;
        const trunc_msg = std.fmt.bufPrint(&trunc_buf, "{d} of {d} messages shown]\"}}", .{ SESSION_EXPORT_MAX_MESSAGES, history.len }) catch "export truncated]\"}";
        try w.writeAll(trunc_msg);
    }
}

/// Serialize session history messages to a JSON array string while holding
/// session.mutex. getHistory() returns borrowed content pointers that are
/// only valid while the lock is held — we MUST serialize before releasing.
fn buildSessionMessagesJson(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
) struct { json: ?[]u8, err: ?RouteResponse } {
    mgr.mutex.lock();
    const session = mgr.sessions.get(session_key) orelse {
        mgr.mutex.unlock();
        return .{ .json = null, .err = .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" } };
    };
    session.mutex.lock();
    mgr.mutex.unlock();
    defer session.mutex.unlock();

    const history = session.agent.getHistory(allocator) catch {
        return .{ .json = null, .err = .{ .status = "500 Internal Server Error", .body = "{\"error\":\"history_read_failed\"}" } };
    };
    defer allocator.free(history);

    // Serialize while session.mutex is held — content pointers are valid here.
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    const w = buf.writer(allocator);
    writeHistoryMessagesJson(w, history) catch {
        buf.deinit(allocator);
        return .{ .json = null, .err = response_build_err };
    };
    const json = buf.toOwnedSlice(allocator) catch {
        buf.deinit(allocator);
        return .{ .json = null, .err = response_build_err };
    };
    return .{ .json = json, .err = null };
}

fn handleSessionExport(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
) RouteResponse {
    const built = buildSessionMessagesJson(allocator, mgr, session_key);
    if (built.err) |err_resp| return err_resp;
    const messages_json = built.json.?;
    defer allocator.free(messages_json);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"session_key\":\"") catch return response_build_err;
    jsonEscapeInto(w, session_key) catch return response_build_err;
    w.writeAll("\",\"messages\":[") catch return response_build_err;
    w.writeAll(messages_json) catch return response_build_err;
    w.writeAll("]}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleSessionHistory(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
) RouteResponse {
    // Try in-memory first (live session with full history)
    const built = buildSessionMessagesJson(allocator, mgr, session_key);
    if (built.json) |messages_json| {
        defer allocator.free(messages_json);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        defer out.deinit(allocator);
        const w = out.writer(allocator);
        w.writeAll("{\"messages\":[") catch return response_build_err;
        w.writeAll(messages_json) catch return response_build_err;
        w.writeAll("]}") catch return response_build_err;
        return finalizeJsonBuf(allocator, &out);
    }

    // Fallback: load from persistent session store (evicted/restored sessions)
    if (mgr.session_store) |store| {
        const entries = store.loadMessages(allocator, session_key) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"history_load_failed\"}" };
        };
        defer {
            for (entries) |entry| {
                allocator.free(entry.role);
                allocator.free(entry.content);
            }
            allocator.free(entries);
        }

        var out: std.ArrayListUnmanaged(u8) = .empty;
        defer out.deinit(allocator);
        const w = out.writer(allocator);
        w.writeAll("{\"messages\":[") catch return response_build_err;
        for (entries, 0..) |entry, i| {
            if (i > 0) w.writeAll(",") catch return response_build_err;
            w.writeAll("{\"role\":\"") catch return response_build_err;
            jsonEscapeInto(w, entry.role) catch return response_build_err;
            w.writeAll("\",\"content\":\"") catch return response_build_err;
            jsonEscapeInto(w, entry.content) catch return response_build_err;
            w.writeAll("\"}") catch return response_build_err;
        }
        w.writeAll("]}") catch return response_build_err;
        return finalizeJsonBuf(allocator, &out);
    }

    return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
}

/// Pure input validation for session approve requests. Does not touch session
/// state — safe to call without a SessionManager. Returns the parsed `approved`
/// bool on success, or a RouteResponse error on validation failure.
/// WR-02 fix: extracted so tests can validate input without passing undefined mgr.
fn validateApproveInput(raw_request: []const u8) union(enum) { approved: bool, err: RouteResponse } {
    const body = extractBody(raw_request) orelse return .{ .err = .{
        .status = "400 Bad Request",
        .body = "{\"error\":\"missing body\"}",
    } };
    const approved = jsonBoolField(body, "approved") orelse return .{ .err = .{
        .status = "400 Bad Request",
        .body = "{\"error\":\"missing approved field\"}",
    } };
    return .{ .approved = approved };
}

fn handleSessionApprove(
    allocator: std.mem.Allocator,
    mgr: *session_mod.SessionManager,
    session_key: []const u8,
    raw_request: []const u8,
) RouteResponse {
    const validated = validateApproveInput(raw_request);
    const approved = switch (validated) {
        .approved => |v| v,
        .err => |e| return e,
    };

    // Pin session with active_refs to prevent eviction between check and processMessage.
    // processMessage calls getOrCreate internally, which would silently mint a new
    // session if the original was evicted — defeating the existence guard.
    mgr.mutex.lock();
    const session = mgr.sessions.get(session_key) orelse {
        mgr.mutex.unlock();
        return .{ .status = "404 Not Found", .body = "{\"error\":\"session_not_found\"}" };
    };
    session.active_refs += 1; // Pin — eviction skips active_refs > 0
    mgr.mutex.unlock();

    // Route the decision through the existing slash command handler.
    // This keeps approval logic in one place (commands.zig).
    const command = if (approved) "/approve allow-once" else "/approve deny";
    const result = mgr.processMessage(session_key, command, null) catch {
        // Unpin on error path
        mgr.mutex.lock();
        if (session.active_refs > 0) session.active_refs -= 1;
        mgr.mutex.unlock();
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"approval_failed\"}" };
    };

    // Unpin after successful processing
    mgr.mutex.lock();
    if (session.active_refs > 0) session.active_refs -= 1;
    mgr.mutex.unlock();

    defer allocator.free(result);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"status\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    w.writeAll(if (approved) "approved" else "denied") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    w.writeAll("\",\"message\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    jsonEscapeInto(w, result) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    w.writeAll("\"}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    return .{ .body = out.toOwnedSlice(allocator) catch
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" } };
}

// ── /brain/graph — V1.5 day-2 task 2B ──────────────────────────────
//
// GET /api/v1/users/:user_id/brain/graph
//
// Returns a navigable memory graph for the user: nodes (memory entries)
// + edges (session, semantic, reference). Powers the frontend `/brain`
// page that lets users SEE and trust their memory.
//
// Edge types:
//   • session   — chain pattern within a session (memory_a → memory_b
//                 ordered by created_at). Cap 50 edges per session.
//   • semantic  — pgvector cosine similarity > 0.7. Single SQL query
//                 via VectorStore.pairwiseSimilarities (task 2A).
//                 Falls back gracefully when pgvector unavailable
//                 (`semantic_degraded: true` in response).
//   • reference — regex `memory:[a-zA-Z0-9_-]+` parsed from content;
//                 emitted only when target is in the returned node set.
//
// Bi-temporal correctness: nodes come from `listMemories` which already
// filters `valid_to IS NULL OR valid_to > now()` (task 1). Semantic
// edges use the node-key set as input, so superseded memories never
// appear as edge endpoints. Reference edges are resolved against the
// same node set.
//
// Auth: tenant + user-scoped; mirrors `/sessions` pattern. Numeric
// user_id parsed from path; cross-tenant access impossible by
// construction.
//
// Query params:
//   ?since=<unix>           — lower bound on created_at; default unbounded
//   ?max_nodes=<int>        — cap node count, default 500, max 2000
//   ?node_kinds=<csv>       — filter by category (core,daily,...);
//                             default all categories
//
// Response shape (defined in `docs/frontend-vision-brief.md`):
//   {
//     "nodes": [{ "id", "kind", "created_at", "session_id", "summary",
//                 "valid_to" }],
//     "edges": [
//       { "type": "session",   "source", "target" },
//       { "type": "semantic",  "source", "target", "weight" },
//       { "type": "reference", "source", "target" }
//     ],
//     "trimmed": bool,                    — true when corpus > max_nodes
//     "total_skipped": int,               — nodes elided by cap
//     "total_nodes_in_corpus": int,       — full corpus size before cap
//     "semantic_degraded": bool           — true when pgvector unavailable
//   }

/// Memory keys today use `[a-zA-Z0-9_:./-]+` so this regex pattern is
/// sufficient. The reference-edge parser scans memory content for the
/// `memory:<key>` token (no spaces inside the key), then resolves to
/// keys present in the returned node set.
const BRAIN_REF_PREFIX = "memory:";
const BRAIN_DEFAULT_MAX_NODES: u32 = 500;
const BRAIN_MAX_MAX_NODES: u32 = 2000;
const BRAIN_SEMANTIC_THRESHOLD: f32 = 0.7;
const BRAIN_SESSION_EDGE_CAP_PER_SESSION: usize = 50;
// V1.11 hardening (2026-05-08, FE spec #7) — bumped 200 → 1000.
// Pre-fix the brain orphan rail and graph node summaries truncated
// mid-word at ~196 chars (the next-codepoint boundary inside 200).
// FE-visible bug: orphan summary read "I'll be here when you ge"
// cut mid-word. Agent summaries are typically 1-3 sentences;
// 1000 covers everything without bloating the JSON response shape
// (a 500-node graph at 1000 chars/summary = ~500KB worst case,
// still well under MAX_BODY_SIZE 30MB).
const BRAIN_SUMMARY_CHARS: usize = 1000;

/// V1.5 day-2 review fix — round a length down to the last full UTF-8
/// codepoint boundary at or before `max`. Without this, the `summary`
/// field of `/brain/graph` and `/brain/timeline` responses would split
/// mid-codepoint for Arabic / Chinese / emoji content (any byte
/// sequence where the 200th byte falls inside a multi-byte codepoint),
/// producing invalid UTF-8 in the JSON body. Frontend `JSON.parse()`
/// would throw on the response.
///
/// Algorithm: walk back from `max` while the byte at that position is
/// a UTF-8 continuation byte (0b10xxxxxx). UTF-8 is self-synchronizing
/// so the lead byte we land on is the start of a codepoint; truncating
/// just before it gives a valid UTF-8 prefix.
///
/// When `content.len <= max` the input is already short enough; return
/// `content.len`. When `max == 0` return 0.
fn brainTruncateUtf8Boundary(content: []const u8, max: usize) usize {
    if (content.len <= max) return content.len;
    if (max == 0) return 0;
    var len = max;
    // UTF-8 continuation bytes start with 0b10. Walk back until we land
    // on a non-continuation byte (lead byte or ASCII).
    while (len > 0 and (content[len] & 0b1100_0000) == 0b1000_0000) : (len -= 1) {}
    return len;
}
const BRAIN_SEMANTIC_MAX_PAIRS: u32 = 5000;

const BrainNode = struct {
    key: []const u8, // borrowed from MemoryEntry — do not free
    kind: []const u8, // borrowed (category.toString()) — do not free
    session_id: ?[]const u8, // borrowed — do not free
    created_at: i64,
    summary: []const u8, // borrowed (slice of content) — do not free
    valid_to: ?i64,
};

const BrainSessionEdge = struct {
    source: []const u8, // borrowed
    target: []const u8, // borrowed
};

const BrainRefEdge = struct {
    source: []const u8, // borrowed
    target: []const u8, // borrowed
};

/// V1.6 commit 5b.3 (WR-2) — typed atomic-fact edges. Connect memories
/// that share a `subject` per their metadata JSONB. The label is the
/// predicate so the FE can render the relationship verbatim ("PREFERS",
/// "DEPLOYS_TO", "BIRTHDAY", etc.). Strings are duped from the
/// metadata_map's parsed JSON values — owned by the caller.
const BrainTypedEdge = struct {
    source: []u8, // owned — duped from metadata
    target: []u8, // owned
    predicate: []u8, // owned
    // V1.11 (2026-05-07) — surface real edge strength to the frontend.
    // The DB stores per-edge `confidence` (LLM extractor's certainty,
    // 0..1) and `weight` (vote count from re-extractions / community
    // detection). Both are already populated by findEdgesByKeys; the
    // gateway used to drop them. Exposing them lets the brain graph
    // layout pull strong (high confidence × weight) edges tighter and
    // weak ones farther — actual data instead of the predicate-type
    // heuristic the FE was using.
    confidence: f64,
    weight: f64,

    fn deinit(self: *const BrainTypedEdge, allocator: std.mem.Allocator) void {
        allocator.free(self.source);
        allocator.free(self.target);
        allocator.free(self.predicate);
    }
};

fn freeBrainTypedEdges(allocator: std.mem.Allocator, edges: []BrainTypedEdge) void {
    for (edges) |e| e.deinit(allocator);
    allocator.free(edges);
}

fn isBrainRefKeyChar(ch: u8) bool {
    return std.ascii.isAlphanumeric(ch) or ch == '_' or ch == '-' or ch == ':' or ch == '.' or ch == '/';
}

/// Parse `node_kinds` CSV (e.g. "core,daily") and return true if `kind`
/// is included. When `csv` is null, all kinds are included.
fn brainKindAllowed(csv: ?[]const u8, kind: []const u8) bool {
    const list = csv orelse return true;
    var it = std.mem.tokenizeScalar(u8, list, ',');
    while (it.next()) |entry| {
        if (std.mem.eql(u8, entry, kind)) return true;
    }
    return false;
}

/// Build session edges: chain pattern within each session_id group.
/// Within a group, entries are sorted by created_at ASC and emitted as
/// a→b, b→c, ... up to BRAIN_SESSION_EDGE_CAP_PER_SESSION per session.
/// Caller owns the returned slice.
fn buildBrainSessionEdges(
    allocator: std.mem.Allocator,
    nodes: []const BrainNode,
) ![]BrainSessionEdge {
    // Bucket nodes by session_id.
    var by_session: std.StringHashMapUnmanaged(std.ArrayListUnmanaged(usize)) = .{};
    defer {
        var it = by_session.iterator();
        while (it.next()) |entry| {
            entry.value_ptr.deinit(allocator);
        }
        by_session.deinit(allocator);
    }

    for (nodes, 0..) |n, idx| {
        const sid = n.session_id orelse continue;
        if (sid.len == 0) continue;
        const gop = try by_session.getOrPut(allocator, sid);
        if (!gop.found_existing) {
            gop.value_ptr.* = .{};
        }
        try gop.value_ptr.append(allocator, idx);
    }

    var edges: std.ArrayListUnmanaged(BrainSessionEdge) = .{};
    errdefer edges.deinit(allocator);

    var it = by_session.iterator();
    while (it.next()) |entry| {
        const indices = entry.value_ptr.items;
        if (indices.len < 2) continue;

        // Sort indices by created_at ascending (timeline order).
        std.mem.sort(usize, indices, nodes, struct {
            fn lt(ctx: []const BrainNode, a: usize, b: usize) bool {
                return ctx[a].created_at < ctx[b].created_at;
            }
        }.lt);

        // Emit chain edges, capped per session.
        const cap = @min(indices.len - 1, BRAIN_SESSION_EDGE_CAP_PER_SESSION);
        var i: usize = 0;
        while (i < cap) : (i += 1) {
            try edges.append(allocator, .{
                .source = nodes[indices[i]].key,
                .target = nodes[indices[i + 1]].key,
            });
        }
    }

    // V1.5 day-2 review fix: deterministic edge ordering. The hashmap
    // iteration above is non-deterministic across runs, so the order
    // edges land in the slice depends on hashmap iteration. Sort by
    // (source, target) so the same input → same output bytes — needed
    // for response caching, ETags, deterministic test comparisons.
    const final = try edges.toOwnedSlice(allocator);
    std.mem.sort(BrainSessionEdge, final, {}, struct {
        fn lt(_: void, a: BrainSessionEdge, b: BrainSessionEdge) bool {
            const src_cmp = std.mem.order(u8, a.source, b.source);
            if (src_cmp != .eq) return src_cmp == .lt;
            return std.mem.order(u8, a.target, b.target) == .lt;
        }
    }.lt);
    return final;
}

/// Scan memory content for `memory:<key>` references. When the target
/// key is in `node_keys`, emit a reference edge. Source < target
/// canonicalization NOT enforced for reference edges (they are
/// directional — "X references Y" is not symmetric). Caller owns the
/// returned slice.
fn buildBrainReferenceEdges(
    allocator: std.mem.Allocator,
    nodes: []const BrainNode,
    contents: []const []const u8,
    node_keys: *std.StringHashMapUnmanaged(void),
    metadata_json_map: ?*const std.StringHashMapUnmanaged([]u8),
) ![]BrainRefEdge {
    std.debug.assert(nodes.len == contents.len);

    var edges: std.ArrayListUnmanaged(BrainRefEdge) = .{};
    errdefer edges.deinit(allocator);

    // Track edges already emitted from this source to avoid duplicate
    // edges when the same target is referenced via BOTH content marker
    // AND metadata.references. Key format: "src||tgt".
    var seen: std.StringHashMapUnmanaged(void) = .{};
    defer {
        var sit = seen.iterator();
        while (sit.next()) |e| allocator.free(e.key_ptr.*);
        seen.deinit(allocator);
    }

    for (nodes, contents) |source_node, content| {
        // ── Path 1: regex over content (legacy + agent-emitted markers) ──
        var i: usize = 0;
        while (i + BRAIN_REF_PREFIX.len < content.len) {
            const remaining = content[i..];
            const idx = std.mem.indexOf(u8, remaining, BRAIN_REF_PREFIX) orelse break;
            const start = i + idx + BRAIN_REF_PREFIX.len;
            // Walk until we hit a non-key character.
            var end = start;
            while (end < content.len and isBrainRefKeyChar(content[end])) : (end += 1) {}
            if (end > start) {
                const candidate = content[start..end];
                // Self-reference is meaningless; skip.
                if (!std.mem.eql(u8, candidate, source_node.key)) {
                    if (node_keys.get(candidate) != null) {
                        const seen_key = try std.fmt.allocPrint(allocator, "{s}||{s}", .{ source_node.key, candidate });
                        if (!seen.contains(seen_key)) {
                            try seen.put(allocator, seen_key, {});
                            try edges.append(allocator, .{
                                .source = source_node.key,
                                .target = candidate, // borrowed from content
                            });
                        } else {
                            allocator.free(seen_key);
                        }
                    }
                }
            }
            i = end;
        }

        // ── Path 2: V1.5 day-3 — `metadata.references` JSON array ──
        // Compose memories store provenance in JSONB metadata column
        // (clean separation: synthesis content is pure, references
        // canonical in metadata). Parse the JSON, extract `references`
        // array, emit edges (with same dangling-prevention + self-loop
        // skip + dedup as the regex path).
        if (metadata_json_map) |map| {
            const meta_json = map.get(source_node.key) orelse continue;
            const parsed = std.json.parseFromSlice(std.json.Value, allocator, meta_json, .{}) catch continue;
            defer parsed.deinit();
            const obj = switch (parsed.value) {
                .object => |o| o,
                else => continue,
            };
            const refs_val = obj.get("references") orelse continue;
            const refs_arr = switch (refs_val) {
                .array => |a| a,
                else => continue,
            };
            for (refs_arr.items) |item| {
                const target = switch (item) {
                    .string => |s| s,
                    else => continue,
                };
                if (std.mem.eql(u8, target, source_node.key)) continue;
                if (node_keys.get(target) == null) continue;
                const seen_key = try std.fmt.allocPrint(allocator, "{s}||{s}", .{ source_node.key, target });
                if (seen.contains(seen_key)) {
                    allocator.free(seen_key);
                    continue;
                }
                try seen.put(allocator, seen_key, {});
                // `target` is borrowed from the parsed JSON which is
                // freed when `parsed.deinit()` runs at this iteration's
                // end. We need a borrowable pointer that outlives the
                // edge slice. Look up the canonical key in `node_keys`
                // — it was inserted from the BrainNode array which
                // outlives this function (handler-scope lifetime).
                var nk_it = node_keys.keyIterator();
                const canonical = while (nk_it.next()) |k| {
                    if (std.mem.eql(u8, k.*, target)) break k.*;
                } else continue;
                try edges.append(allocator, .{
                    .source = source_node.key,
                    .target = canonical,
                });
            }
        }
    }

    return edges.toOwnedSlice(allocator);
}

/// V1.14.12 (Memory audit Finding 2 fix, 2026-05-19) — `entity_<hex>`
/// targets are not stored in the `memories` table; they live in
/// `memory_entities` (coref-resolved IDs) or are synthesized hashes
/// (`deriveEntityKey` shape: `entity_<sha256(lower(name))[..16hex]>`).
/// Recognize either shape so the typed-edge filter allows edges from a
/// visible memory row to such a target; entity-side BrainNodes are
/// synthesized by the caller after `buildBrainTypedEdges` returns.
fn isEntityNodeKey(key: []const u8) bool {
    // Shape 1: hash fallback `entity_<16 hex>` (deriveEntityKey).
    if (std.mem.startsWith(u8, key, "entity_")) {
        const tail = key[7..];
        if (tail.len != 16) return false;
        for (tail) |ch| {
            const is_hex = (ch >= '0' and ch <= '9') or (ch >= 'a' and ch <= 'f');
            if (!is_hex) return false;
        }
        return true;
    }
    // Shape 2: coref-resolved random ID — 32 hex chars, no prefix.
    if (key.len != 32) return false;
    for (key) |ch| {
        const is_hex = (ch >= '0' and ch <= '9') or (ch >= 'a' and ch <= 'f');
        if (!is_hex) return false;
    }
    return true;
}

/// V1.7a-3 — typed-edge builder, materialized-table variant.
///
/// Reads typed edges from the canonical `memory_edges` table via
/// `state_mgr.findEdgesByKeys` (V1.6 cmt10), restricted to edges INCIDENT
/// to the `nodes[]` set the FE is rendering this turn. Then drops edges
/// whose OTHER endpoint is off-graph (visibility filter), applies the
/// rejected-predicate filter (defense-in-depth), and caps each source's
/// outbound edges at `BRAIN_TYPED_EDGE_CAP_PER_SOURCE` for hub-node
/// budget control.
///
/// V1.14.12 (Memory audit Finding 2 fix, 2026-05-19) — edges to
/// entity-shape targets (entity_<16hex> or 32-hex coref IDs) are
/// preserved instead of dropped. The caller synthesizes BrainNode-
/// kind="entity" entries for these targets so the FE has both endpoints.
/// Pre-fix, the strict "both endpoints in visible set" rule silently
/// dropped all typed edges from visible memory rows to entity refs,
/// making /brain/graph look empty even when extraction had populated
/// the edge table.
///
/// **Why findEdgesByKeys not listEdgesForUser:** post-cmt9.8 v1 used
/// listEdgesForUser, which scales with the user's TOTAL edge count.
/// For a tenant with 10K facts and dense extraction history, that's
/// 100K edges per render. findEdgesByKeys uses an indexed
/// `WHERE source_key = ANY($keys) OR target_key = ANY($keys)` so the
/// wire payload + scan scales with edges incident to visible nodes
/// (typically ≤ 5× node count for sparse semantic graphs). For 500
/// visible nodes that's ~2500 edges instead of 100000. cmt9.8 review
/// fix WR-5.
///
/// **Deployment prerequisite:** the V1.6 cmt16 backfill (`9d61aca`)
/// must have populated `memory_edges` from existing extraction metadata
/// triples. Tenants who skipped cmt16 backfill but kept JSONB metadata
/// will see `/brain/graph` typed-edges drop to empty until backfill runs.
/// New extraction writes go through extraction_persist which writes
/// both metadata and memory_edges — no drift on new data.
///
/// Why the swap matters:
///   - **Correctness:** edges come from extraction-time SVO triples
///     (real subject → object relations) instead of inferred-by-shared-
///     subject pairwise grouping. The old path could connect facts that
///     happened to share a subject string but weren't actually related;
///     the new path uses the actual edges extraction wrote.
///   - **Cost:** N × JSON-parse → 1 × indexed SQL with key-scoped
///     prefilter. memory_edges has indexes on (user_id, is_latest)
///     plus key columns; the scan is bounded by visible-node count.
///   - **Single source of truth:** /brain/graph + agent retrieval +
///     graph_expand BFS now all read from the same materialized edges.
///
/// Defense-in-depth: rejected predicates filtered here too. extraction_persist
/// already filters at write time, but future write paths could bypass it.
///
/// Caller owns the returned slice; free via `freeBrainTypedEdges`.
fn buildBrainTypedEdges(
    allocator: std.mem.Allocator,
    nodes: []const BrainNode,
    state_mgr: *zaki_state_mod.Manager,
    user_id: i64,
) ![]BrainTypedEdge {
    if (nodes.len == 0) return allocator.alloc(BrainTypedEdge, 0);

    // ── Build visible-key set + safe-keys list for SQL prefilter ────
    // findEdgesByKeys errors on NUL-containing keys (V1.6 cmt7-10
    // WARN-2). BrainNode.key is brain-hygiene-filtered upstream and
    // should never have NUL, but defense-in-depth: skip any that do.
    var visible: std.StringHashMapUnmanaged(void) = .{};
    defer visible.deinit(allocator);
    try visible.ensureTotalCapacity(allocator, @intCast(nodes.len));

    var safe_keys: std.ArrayListUnmanaged([]const u8) = .{};
    defer safe_keys.deinit(allocator);
    try safe_keys.ensureTotalCapacity(allocator, nodes.len);

    var nul_skipped: usize = 0;
    for (nodes) |n| {
        if (std.mem.indexOfScalar(u8, n.key, 0) != null) {
            nul_skipped += 1;
            continue;
        }
        try visible.put(allocator, n.key, {});
        try safe_keys.append(allocator, n.key);
    }
    if (nul_skipped > 0) {
        log.warn(
            "brain.typed_edges nul_skipped={d} total_nodes={d} — keys with embedded NUL filtered upstream of findEdgesByKeys",
            .{ nul_skipped, nodes.len },
        );
    }
    if (safe_keys.items.len == 0) return allocator.alloc(BrainTypedEdge, 0);

    // ── SQL-prefilter to edges incident to visible nodes (1 RT) ─────
    // findEdgesByKeys returns edges where source OR target is in keys.
    // We then filter to "both endpoints visible" in-memory.
    const incident_edges = try state_mgr.findEdgesByKeys(allocator, user_id, safe_keys.items);
    defer memory_mod.freeTypedEdges(allocator, incident_edges);

    if (incident_edges.len == 0) return allocator.alloc(BrainTypedEdge, 0);

    // ── Per-source cap counter so a hub doesn't dominate ─────────────
    // findEdgesByKeys returns weight-DESC, so iterating in that order
    // means the FIRST `cap` edges per source are the strongest; the cap
    // drops the LEAST salient outbound edges of an over-connected source.
    var per_source_count: std.StringHashMapUnmanaged(usize) = .{};
    defer per_source_count.deinit(allocator);

    var edges: std.ArrayListUnmanaged(BrainTypedEdge) = .{};
    errdefer {
        for (edges.items) |*e| e.deinit(allocator);
        edges.deinit(allocator);
    }

    for (incident_edges) |e| {
        // Source endpoint MUST be a visible memory row — edges from
        // hidden/off-graph sources would surface continuity-internal
        // connections the user shouldn't see.
        if (!visible.contains(e.source_key)) continue;
        // V1.14.12 (Memory audit Finding 2 fix, 2026-05-19) — target
        // is allowed to be either a visible memory row OR an entity-
        // shape key. Caller materializes the entity side as a
        // BrainNode-kind="entity" so the FE has both endpoints. The
        // old strict "both endpoints visible" rule dropped every typed
        // edge from memory→entity_<hex>, making /brain/graph look empty.
        if (!visible.contains(e.target_key) and !isEntityNodeKey(e.target_key)) continue;

        // Defense-in-depth predicate filter (matches old JSONB path).
        if (isRejectedExtractionPredicate(e.predicate)) continue;

        // Per-source cap. Indexed by source_key — a node showing up as
        // target of N edges is allowed; only outbound edges count toward
        // the cap.
        const slot = try per_source_count.getOrPut(allocator, e.source_key);
        if (!slot.found_existing) slot.value_ptr.* = 0;
        if (slot.value_ptr.* >= BRAIN_TYPED_EDGE_CAP_PER_SOURCE) continue;
        slot.value_ptr.* += 1;

        try edges.append(allocator, .{
            .source = try allocator.dupe(u8, e.source_key),
            .target = try allocator.dupe(u8, e.target_key),
            .predicate = try allocator.dupe(u8, e.predicate),
            .confidence = e.confidence,
            .weight = e.weight,
        });
    }

    // Deterministic ordering: sort by (source, target, predicate) for stable
    // JSON output across requests with the same underlying edge set. The
    // predicate tiebreaker matters when memory_edges allows multiple
    // predicates between the same (source, target) pair (current schema
    // permits this — uniqueness is on the full triple, not just the pair).
    std.mem.sort(BrainTypedEdge, edges.items, {}, struct {
        fn lt(_: void, x: BrainTypedEdge, y: BrainTypedEdge) bool {
            const cmp_src = std.mem.order(u8, x.source, y.source);
            if (cmp_src != .eq) return cmp_src == .lt;
            const cmp_tgt = std.mem.order(u8, x.target, y.target);
            if (cmp_tgt != .eq) return cmp_tgt == .lt;
            return std.mem.order(u8, x.predicate, y.predicate) == .lt;
        }
    }.lt);

    return edges.toOwnedSlice(allocator);
}

/// Defense-in-depth: same predicate blacklist as extraction_persist.
/// Mirrored here because gateway.zig can't import agent/extraction_persist
/// (would create a cycle: agent → memory → gateway → agent).
fn isRejectedExtractionPredicate(predicate: []const u8) bool {
    const rejected = [_][]const u8{
        "GREETED",      "SAID",         "ASKED",               "MENTIONED",           "REPLIED",
        "ACKNOWLEDGED", "EXPRESSED",    "INDICATED_READINESS", "IS_GETTING_STARTED",  "OFFERED_TO_WAIT",
        "PRIORITIZED",  "ADDRESSED_AS", "IS_UNKNOWN",          "EXPRESSED_READINESS", "INITIATED_CONVERSATION",
    };
    for (rejected) |p| if (std.mem.eql(u8, p, predicate)) return true;
    return false;
}

/// V1.7a-3 — per-source-key cap on rendered typed edges (was per-subject
/// cluster cap pre-cmt9.8). A single source node ("user_helix") can show
/// at most this many outbound edges in the graph; any beyond are dropped
/// in weight-DESC order (so the LEAST-salient outbound edges go first).
/// Bounds hub-node visual dominance without affecting incoming-edge count.
const BRAIN_TYPED_EDGE_CAP_PER_SOURCE: usize = 20;

// ── V1.5 day-4 — traversal-event logging helpers ───────────────────
//
// `/brain/graph` and `/brain/timeline` are the user's main windows
// into their memory. Logging the traversal events sets up V1.6's
// ADD/UPDATE/DELETE classifier with a learning signal — memories the
// user actively viewed are user-interesting; the classifier prefers
// them when ranking ADD vs DELETE candidates.
//
// Events land in the existing `memory_events` audit table with
// `event_type='traversal'`. Reuses Mem0 namespace pattern locked in
// V1.5 day-2 design (the classifier shares this table).
//
// Errors are non-fatal at the caller — the user-facing graph /
// timeline still ships even if the event-write fails. Logging gaps
// are preferable to user-visible 500s.

fn brainLogGraphView(
    allocator: std.mem.Allocator,
    state_mgr: *zaki_state_mod.Manager,
    user_id: i64,
    nodes: []const BrainNode,
    total_in_corpus: usize,
    trimmed: bool,
    semantic_degraded: bool,
) !void {
    var payload_buf: std.ArrayListUnmanaged(u8) = .empty;
    defer payload_buf.deinit(allocator);
    const pw = payload_buf.writer(allocator);
    try pw.writeAll("{\"action\":\"view_graph\",\"node_keys\":[");
    for (nodes, 0..) |n, i| {
        if (i > 0) try pw.writeAll(",");
        try pw.writeAll("\"");
        try jsonEscapeInto(pw, n.key);
        try pw.writeAll("\"");
    }
    try pw.print("],\"total_nodes_in_corpus\":{d},\"trimmed\":{s},\"semantic_degraded\":{s},\"viewed_at\":{d}}}", .{
        total_in_corpus,
        if (trimmed) "true" else "false",
        if (semantic_degraded) "true" else "false",
        std.time.timestamp(),
    });
    try state_mgr.insertTraversalEvent(user_id, payload_buf.items);
}

fn brainLogTimelineView(
    allocator: std.mem.Allocator,
    state_mgr: *zaki_state_mod.Manager,
    user_id: i64,
    entries: []const memory_mod.MemoryEntry,
    has_more: bool,
    cursor_used: bool,
) !void {
    var payload_buf: std.ArrayListUnmanaged(u8) = .empty;
    defer payload_buf.deinit(allocator);
    const pw = payload_buf.writer(allocator);
    try pw.writeAll("{\"action\":\"view_timeline\",\"entry_keys\":[");
    for (entries, 0..) |entry, i| {
        if (i > 0) try pw.writeAll(",");
        try pw.writeAll("\"");
        try jsonEscapeInto(pw, entry.key);
        try pw.writeAll("\"");
    }
    try pw.print("],\"has_more\":{s},\"cursor_used\":{s},\"viewed_at\":{d}}}", .{
        if (has_more) "true" else "false",
        if (cursor_used) "true" else "false",
        std.time.timestamp(),
    });
    try state_mgr.insertTraversalEvent(user_id, payload_buf.items);
}

fn handleBrainGraph(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }

    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };

    // ── Parse query params ────────────────────────────────────────
    const since_param = parseQueryParam(target, "since");
    const max_nodes_param = parseQueryParam(target, "max_nodes");
    const node_kinds_csv = parseQueryParam(target, "node_kinds");
    // V1.7a-8b filter extension — all three optional, AND-combined.
    const search_param = parseQueryParam(target, "search");
    const link_types_csv = parseQueryParam(target, "link_types");
    const exclude_orphans_param = parseQueryParam(target, "exclude_orphans");
    const semantic_min_weight_param = parseQueryParam(target, "semantic_min_weight");
    const exclude_orphans: bool = if (exclude_orphans_param) |s|
        (std.mem.eql(u8, s, "true") or std.mem.eql(u8, s, "1"))
    else
        false;

    const since: ?i64 = if (since_param) |s| std.fmt.parseInt(i64, s, 10) catch null else null;
    var max_nodes: u32 = if (max_nodes_param) |s|
        std.fmt.parseInt(u32, s, 10) catch {
            // Fail closed on malformed explicit caps. A literal shell token
            // like `max_nodes=$n` previously expanded to the 500-node default,
            // making manual smoke tests much heavier than intended.
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_max_nodes\"}" };
        }
    else
        BRAIN_DEFAULT_MAX_NODES;
    if (max_nodes == 0) max_nodes = BRAIN_DEFAULT_MAX_NODES;
    if (max_nodes > BRAIN_MAX_MAX_NODES) max_nodes = BRAIN_MAX_MAX_NODES;
    const semantic_threshold = blk: {
        const requested = if (semantic_min_weight_param) |s|
            std.fmt.parseFloat(f32, s) catch BRAIN_SEMANTIC_THRESHOLD
        else
            BRAIN_SEMANTIC_THRESHOLD;
        if (!std.math.isFinite(requested)) break :blk BRAIN_SEMANTIC_THRESHOLD;
        break :blk std.math.clamp(requested, BRAIN_SEMANTIC_THRESHOLD, 1.0);
    };

    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Fetch nodes ───────────────────────────────────────────────
    // listMemoriesBrainVisible applies BOTH the bi-temporal validity
    // filter (V1.5 day-2 task 1) AND the brain-hygiene filter
    // (V1.5.1 — hides agent bookkeeping like summary_latest,
    // session_checkpoint_*, autosave_*, tombstones). The user-facing
    // /brain/graph never sees machine-state artifacts.
    const all_entries = state_mgr.listMemoriesBrainVisible(allocator, numeric_user_id) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"memory_list_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, all_entries);

    // ── V1.7a-8b: search keep-set ─────────────────────────────────
    // When ?search= is present, intersect filter with recallMemories
    // (BM25 + key + content) — same DSL as /brain/search so the FE can
    // re-use the search box semantics. Built once before the filter loop.
    var search_keep_set: ?std.StringHashMapUnmanaged(void) = null;
    var search_seeds: ?[]memory_mod.MemoryEntry = null;
    defer if (search_seeds) |s| memory_mod.freeEntries(allocator, s);
    defer if (search_keep_set) |*s| s.deinit(allocator);
    if (search_param) |q| {
        if (q.len > 0 and q.len <= 512) {
            // Fetch a generous overshoot so the keep-set covers the corpus
            // before max_nodes cap. Bounded by BRAIN_MAX_MAX_NODES * 2.
            const overshoot: usize = @as(usize, BRAIN_MAX_MAX_NODES) * 2;
            if (state_mgr.recallMemories(allocator, numeric_user_id, q, overshoot, null)) |seeds| {
                search_seeds = seeds;
                var ks: std.StringHashMapUnmanaged(void) = .{};
                for (seeds) |e| ks.put(allocator, e.key, {}) catch break;
                search_keep_set = ks;
            } else |_| {
                // Search degrades to "no matches" — empty result. Better
                // than returning unfiltered (which would mislead the FE).
                search_keep_set = .{};
            }
        }
    }

    // ── V1.7a-8b: link_type set ──────────────────────────────────
    // Parse CSV like "preference,attribute" via parseLinkTypesCsv (helper
    // for unit-testability). Unknown tokens silently dropped; empty set
    // after parse means "filter to nothing" — fail closed to avoid the
    // surprise of an unknown filter string returning everything.
    var link_types_set: ?std.StringHashMapUnmanaged(void) = null;
    defer if (link_types_set) |*s| s.deinit(allocator);
    if (link_types_csv) |csv| {
        if (csv.len > 0) link_types_set = parseLinkTypesCsv(allocator, csv);
    }

    // ── V1.7a-8b: prefetch metadata for link_types filter ────────
    // Fetch metadata for the ENTIRE visible corpus when link_types is
    // active — we need it BEFORE the filter loop to decide which keys
    // pass. Bounded by V1's per-user corpus size; the existing post-cap
    // metadata fetch (lines below) stays for display-side concerns.
    var prefilter_metadata: ?std.StringHashMapUnmanaged([]u8) = null;
    defer if (prefilter_metadata) |*m| {
        var mit = m.iterator();
        while (mit.next()) |kv| {
            allocator.free(kv.key_ptr.*);
            allocator.free(kv.value_ptr.*);
        }
        m.deinit(allocator);
    };
    if (link_types_set != null) {
        if (allocator.alloc([]const u8, all_entries.len)) |keys_for_prefilter| {
            defer allocator.free(keys_for_prefilter);
            for (all_entries, 0..) |e, i| keys_for_prefilter[i] = e.key;
            if (state_mgr.listMemoriesMetadata(allocator, numeric_user_id, keys_for_prefilter)) |m| {
                prefilter_metadata = m;
            } else |_| {
                // No metadata → link_types filter degrades to "no matches"
                // (consistent with search degradation: don't silently bypass).
            }
        } else |_| {
            // OOM on the prefilter key buffer — leave prefilter_metadata
            // null so the link_types filter degrades to fail-closed below.
        }
    }

    // ── Filter (since + node_kinds + search + link_types) ─────────
    var filtered_indices: std.ArrayListUnmanaged(usize) = .{};
    defer filtered_indices.deinit(allocator);

    for (all_entries, 0..) |entry, idx| {
        const ts = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0;
        if (since) |lower| {
            if (ts < lower) continue;
        }
        const kind = entry.category.toString();
        if (!brainKindAllowed(node_kinds_csv, kind)) continue;
        // V1.7a-8b: search filter (intersection with recallMemories).
        if (search_keep_set) |ks| {
            if (!ks.contains(entry.key)) continue;
        }
        // V1.7a-8b: link_types filter (NODE-level; the source memory's
        // own categorization). Drops rows whose metadata.link_type isn't
        // in the requested set. When metadata is unavailable, drops the
        // row (fail-closed). Edge-level color-by-type is V-infinity FE
        // work — node-filter is the V1.7a parity move.
        if (link_types_set) |lts| {
            const md_opt = if (prefilter_metadata) |m| m.get(entry.key) else null;
            const lt_opt = extractLinkTypeFromMetadata(allocator, md_opt);
            if (lt_opt) |lt_str| {
                if (!lts.contains(lt_str)) continue;
            } else {
                continue;
            }
        }
        filtered_indices.append(allocator, idx) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
        };
    }

    const total_in_corpus: usize = filtered_indices.items.len;

    // Sort by created_at DESC (newest first) for stable cap behavior.
    std.mem.sort(usize, filtered_indices.items, all_entries, struct {
        fn gt(ctx: []memory_mod.MemoryEntry, a: usize, b: usize) bool {
            const a_ts = std.fmt.parseInt(i64, ctx[a].timestamp, 10) catch 0;
            const b_ts = std.fmt.parseInt(i64, ctx[b].timestamp, 10) catch 0;
            return a_ts > b_ts;
        }
    }.gt);

    const trimmed = total_in_corpus > max_nodes;
    const node_count: usize = @min(total_in_corpus, max_nodes);
    const total_skipped: usize = total_in_corpus - node_count;

    // ── Build BrainNode array ─────────────────────────────────────
    const nodes = allocator.alloc(BrainNode, node_count) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
    };
    defer allocator.free(nodes);
    const contents = allocator.alloc([]const u8, node_count) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
    };
    defer allocator.free(contents);

    for (filtered_indices.items[0..node_count], 0..) |entry_idx, i| {
        const entry = all_entries[entry_idx];
        const ts = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0;
        // V1.5 day-2 review fix: UTF-8-safe summary truncation. Naive
        // byte slice could split a codepoint for non-English content
        // (Arabic/Chinese/emoji) and produce invalid JSON.
        const summary_len = brainTruncateUtf8Boundary(entry.content, BRAIN_SUMMARY_CHARS);
        nodes[i] = .{
            .key = entry.key,
            .kind = entry.category.toString(),
            .session_id = entry.session_id,
            .created_at = ts,
            .summary = entry.content[0..summary_len],
            .valid_to = entry.valid_to,
        };
        contents[i] = entry.content;
    }

    // Build a key set for reference-edge dangling-prevention.
    var node_keys: std.StringHashMapUnmanaged(void) = .{};
    defer node_keys.deinit(allocator);
    for (nodes) |n| {
        node_keys.put(allocator, n.key, {}) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
        };
    }

    // ── Build session edges ───────────────────────────────────────
    const session_edges = buildBrainSessionEdges(allocator, nodes) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"session_edges_failed\"}" };
    };
    defer allocator.free(session_edges);

    // ── Build semantic edges (pairwise via vector store) ─────────
    var vector_store_opt: ?memory_mod.VectorStore = null;
    {
        state.tenant_runtime_mutex.lock();
        defer state.tenant_runtime_mutex.unlock();
        if (state.tenant_runtimes.get(user_id)) |runtime| {
            if (runtime.mem_rt) |*rt| {
                vector_store_opt = rt._vector_store;
            }
        }
    }

    var semantic_edges: []memory_mod.vector_store.EdgeResult = &.{};
    var semantic_degraded = false;
    if (vector_store_opt) |vs| {
        // Build keys array for pairwise call.
        const keys = allocator.alloc([]const u8, node_count) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
        };
        defer allocator.free(keys);
        for (nodes, 0..) |n, i| keys[i] = n.key;

        semantic_edges = vs.pairwiseSimilarities(
            allocator,
            numeric_user_id,
            keys,
            semantic_threshold,
            BRAIN_SEMANTIC_MAX_PAIRS,
        ) catch blk: {
            semantic_degraded = true;
            break :blk &.{};
        };
    } else {
        semantic_degraded = true;
    }
    defer memory_mod.vector_store.freeEdgeResults(allocator, semantic_edges);

    // ── Build reference edges (regex over content + metadata.references) ─
    // V1.5 day-3: also batch-load `metadata` JSONB for the cap'd node set.
    // Compose memories store provenance in metadata.references rather
    // than content markers; the builder reads both paths and dedupes.
    var metadata_map: std.StringHashMapUnmanaged([]u8) = .{};
    defer {
        var it = metadata_map.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.*);
        }
        metadata_map.deinit(allocator);
    }
    {
        // Build a key slice from nodes to pass to listMemoriesMetadata.
        const keys_for_metadata = allocator.alloc([]const u8, node_count) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
        };
        defer allocator.free(keys_for_metadata);
        for (nodes, 0..) |n, i| keys_for_metadata[i] = n.key;
        // Errors here are non-fatal — graph still ships with regex-only
        // reference edges (V1.5 day-2 behavior).
        if (state_mgr.listMemoriesMetadata(allocator, numeric_user_id, keys_for_metadata)) |result_map| {
            metadata_map = result_map;
        } else |_| {
            // Keep metadata_map empty; reference-edge builder degrades
            // gracefully (regex path still fires).
        }
    }

    const ref_edges = buildBrainReferenceEdges(allocator, nodes, contents, &node_keys, &metadata_map) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"ref_edges_failed\"}" };
    };
    defer allocator.free(ref_edges);

    // ── V1.7a-9d: per-node community_id + community_name lookup ────
    // Two batched fetches (cheap): (1) per-node community_id from
    // memories.community_id, (2) per-id name from memory_communities.
    // Both DEGRADE gracefully — if either fails, nodes emit
    // community_id:null + community_name:null and the FE falls back to
    // un-clustered rendering. Communities require a recompute via
    // POST /brain/communities/recompute (or scheduled background job)
    // to populate; cold-start tenants with no recompute yet see all-null.
    const community_keys = allocator.alloc([]const u8, node_count) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
    };
    defer allocator.free(community_keys);
    for (nodes, 0..) |n, i| community_keys[i] = n.key;
    var community_id_map = state_mgr.getMemoryCommunityIds(allocator, numeric_user_id, community_keys) catch std.StringHashMapUnmanaged(i32){};
    defer {
        var cit = community_id_map.keyIterator();
        while (cit.next()) |k| allocator.free(k.*);
        community_id_map.deinit(allocator);
    }
    // Build community_id → name map from listCommunities (one round trip
    // covers all clusters; cheap at typical 5-20 communities per user).
    var community_name_map: std.AutoHashMapUnmanaged(i32, []const u8) = .{};
    defer community_name_map.deinit(allocator);
    var community_summaries: []memory_mod.CommunitySummary = &.{};
    defer memory_mod.freeCommunitySummaries(allocator, community_summaries);
    if (state_mgr.listCommunities(allocator, numeric_user_id)) |summaries| {
        community_summaries = summaries;
        for (community_summaries) |s| {
            if (s.name) |n| community_name_map.put(allocator, s.community_id, n) catch {};
        }
    } else |_| {
        // Names degrade to null; community_id still emits.
    }

    // V1.7a-3 — typed atomic-fact edges from the materialized
    // memory_edges table (V1.6 cmt7 + cmt16 backfill). Was: parse JSONB
    // metadata per visible node and pairwise-group by subject. Now: one
    // SQL fetch + visibility filter + per-source cap. Same single-source-
    // of-truth as agent retrieval and graph_expand BFS.
    // Empty result when no edges exist for the user (graceful degrade for
    // tenants with no V1.6 extraction history yet).
    const empty_typed: []BrainTypedEdge = &.{};
    const typed_edges = buildBrainTypedEdges(allocator, nodes, state_mgr, numeric_user_id) catch empty_typed;
    defer freeBrainTypedEdges(allocator, typed_edges);

    // ── V1.14.12 (Memory audit Finding 2 fix, 2026-05-19) ─────────────
    // Synthesize entity-side BrainNodes for entity-shape targets in the
    // typed-edge set. Pre-fix, edges from a visible memory row to an
    // entity_<hex> target were dropped because the target wasn't in
    // `nodes[]`. Now buildBrainTypedEdges keeps those edges; we look up
    // each unique entity target's name via findEntitiesByKeys and emit
    // a kind="entity" node so the FE has both endpoints to render.
    //
    // Hash-fallback shape (entity_<16hex> from extraction_persist.
    // deriveEntityKey) has no memory_entities row — use the key itself
    // as a synthetic label.
    var entity_keys_dedupe: std.StringHashMapUnmanaged(void) = .{};
    defer entity_keys_dedupe.deinit(allocator);
    var entity_keys_list: std.ArrayListUnmanaged([]const u8) = .{};
    defer entity_keys_list.deinit(allocator);
    for (typed_edges) |e| {
        if (!isEntityNodeKey(e.target)) continue;
        const gop = entity_keys_dedupe.getOrPut(allocator, e.target) catch continue;
        if (!gop.found_existing) entity_keys_list.append(allocator, e.target) catch continue;
    }
    const entity_rows_alloc = state_mgr.findEntitiesByKeys(allocator, numeric_user_id, entity_keys_list.items) catch &[_]memory_mod.EntityRow{};
    defer {
        for (entity_rows_alloc) |*r| r.deinit(allocator);
        allocator.free(entity_rows_alloc);
    }
    // Map id → name for fast label lookup. Entity refs not present in the
    // result fall back to the key itself as a label.
    var entity_name_map: std.StringHashMapUnmanaged([]const u8) = .{};
    defer entity_name_map.deinit(allocator);
    for (entity_rows_alloc) |r| entity_name_map.put(allocator, r.id, r.name) catch {};

    // ── V1.6 commit 4 — compute per-node importance score ────────────
    //
    // Sized for FE node-radius rendering (M1 from spec §4.3). Count
    // edges incident on each node across all FOUR edge types (session,
    // semantic, reference, typed), then compose with recency_decay.
    // Recomputed per request — cheap at 500-node cap, stays fresh.
    const importance_scores = allocator.alloc(f64, node_count) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
    };
    defer allocator.free(importance_scores);
    // V1.7a-8b: visibility gate consumed by JSON emission below. Populated
    // inside the degree block (where `degree` is in scope). Behavior:
    //   exclude_orphans=true  → only nodes with degree > 0 are added
    //   exclude_orphans=false → every visible node is added (no-op gate)
    var displayed_keys: std.StringHashMapUnmanaged(void) = .{};
    defer displayed_keys.deinit(allocator);
    {
        // Count incident edges per node-key in O(E + N) via hashmap pass.
        var degree: std.StringHashMapUnmanaged(usize) = .{};
        defer degree.deinit(allocator);
        for (session_edges) |e| {
            const a_entry = degree.getOrPut(allocator, e.source) catch continue;
            if (!a_entry.found_existing) a_entry.value_ptr.* = 0;
            a_entry.value_ptr.* += 1;
            const b_entry = degree.getOrPut(allocator, e.target) catch continue;
            if (!b_entry.found_existing) b_entry.value_ptr.* = 0;
            b_entry.value_ptr.* += 1;
        }
        for (semantic_edges) |e| {
            const a_entry = degree.getOrPut(allocator, e.source_key) catch continue;
            if (!a_entry.found_existing) a_entry.value_ptr.* = 0;
            a_entry.value_ptr.* += 1;
            const b_entry = degree.getOrPut(allocator, e.target_key) catch continue;
            if (!b_entry.found_existing) b_entry.value_ptr.* = 0;
            b_entry.value_ptr.* += 1;
        }
        for (ref_edges) |e| {
            const a_entry = degree.getOrPut(allocator, e.source) catch continue;
            if (!a_entry.found_existing) a_entry.value_ptr.* = 0;
            a_entry.value_ptr.* += 1;
            const b_entry = degree.getOrPut(allocator, e.target) catch continue;
            if (!b_entry.found_existing) b_entry.value_ptr.* = 0;
            b_entry.value_ptr.* += 1;
        }
        // V1.6 commit 5b.3 (WR-2 + IN-3 closure) — typed edges count
        // toward node importance. Hub memories (e.g., shared subject
        // appearing in many facts) get higher importance score.
        for (typed_edges) |e| {
            const a_entry = degree.getOrPut(allocator, e.source) catch continue;
            if (!a_entry.found_existing) a_entry.value_ptr.* = 0;
            a_entry.value_ptr.* += 1;
            const b_entry = degree.getOrPut(allocator, e.target) catch continue;
            if (!b_entry.found_existing) b_entry.value_ptr.* = 0;
            b_entry.value_ptr.* += 1;
        }
        const now = std.time.timestamp();
        for (nodes, 0..) |n, i| {
            const edge_count: usize = if (degree.get(n.key)) |d| d else 0;
            importance_scores[i] = importance_mod.computeImportance(n.created_at, now, edge_count);
        }
        // V1.7a-8b — displayed_keys gates BOTH nodes and edges in the
        // JSON emission below. When exclude_orphans=true, a node with
        // degree=0 (after all edge-type filters above) is excluded and
        // edges with either endpoint excluded are also dropped (no
        // dangling). When exclude_orphans=false (default), every visible
        // node is in the set — the gate becomes a tautology and behavior
        // matches the pre-V1.7a-8b shape.
        for (nodes) |n| {
            if (exclude_orphans) {
                const deg: usize = if (degree.get(n.key)) |d| d else 0;
                if (deg == 0) continue;
            }
            displayed_keys.put(allocator, n.key, {}) catch {};
        }
        // V1.14.12 (Memory audit Finding 2 fix) — entity refs are always
        // displayed (they only exist as edge endpoints; degree=0 is
        // impossible by construction). Skip the orphan filter for them.
        for (entity_keys_list.items) |k| displayed_keys.put(allocator, k, {}) catch {};
    }

    // ── Build JSON response ──────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"nodes\":[") catch return response_build_err;
    var first_node_emitted = true;
    for (nodes, 0..) |n, i| {
        // V1.7a-8b: orphan filter (no-op when exclude_orphans=false).
        if (!displayed_keys.contains(n.key)) continue;
        if (!first_node_emitted) w.writeAll(",") catch return response_build_err;
        first_node_emitted = false;
        w.writeAll("{\"id\":\"") catch return response_build_err;
        jsonEscapeInto(w, n.key) catch return response_build_err;
        w.writeAll("\",\"kind\":\"") catch return response_build_err;
        jsonEscapeInto(w, n.kind) catch return response_build_err;
        w.print("\",\"created_at\":{d},\"session_id\":", .{n.created_at}) catch return response_build_err;
        if (n.session_id) |sid| {
            w.writeAll("\"") catch return response_build_err;
            jsonEscapeInto(w, sid) catch return response_build_err;
            w.writeAll("\"") catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"summary\":\"") catch return response_build_err;
        jsonEscapeInto(w, n.summary) catch return response_build_err;
        w.writeAll("\",\"valid_to\":") catch return response_build_err;
        if (n.valid_to) |vt| {
            w.print("{d}", .{vt}) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        // V1.6 commit 4 — M1 importance score (FE drives node-radius rendering).
        // 3 decimals = 1000 visually-distinct buckets, plenty for graph sizing.
        w.print(",\"importance\":{d:.3}", .{jsonSafeFloat(importance_scores[i])}) catch return response_build_err;
        // 5b-loose-ends-sweep IN-2: emit `display_label` for nodes that
        // have V1.6 extraction metadata (subject + predicate + object).
        // FE renders this instead of the raw `extracted_<unix>_<hex>`
        // key on hover/drilldown — gives a clean
        // "subject - predicate - object" label like
        // "user PREFERS Helix" or "Sara WORKS_AT designer" without
        // forcing the FE to parse the metadata blob.
        if (metadata_map.get(n.key)) |md_blob| {
            if (md_blob.len > 0) {
                if (std.json.parseFromSlice(std.json.Value, allocator, md_blob, .{})) |parsed| {
                    defer parsed.deinit();
                    if (parsed.value == .object) {
                        const subject_v = parsed.value.object.get("subject");
                        const predicate_v = parsed.value.object.get("predicate");
                        const object_v = parsed.value.object.get("object_key");
                        if (subject_v) |s| if (predicate_v) |p| if (object_v) |o| {
                            if (s == .string and p == .string and o == .string and
                                s.string.len > 0 and p.string.len > 0 and o.string.len > 0)
                            {
                                w.writeAll(",\"display_label\":\"") catch return response_build_err;
                                jsonEscapeInto(w, s.string) catch return response_build_err;
                                w.writeAll(" ") catch return response_build_err;
                                jsonEscapeInto(w, p.string) catch return response_build_err;
                                w.writeAll(" ") catch return response_build_err;
                                jsonEscapeInto(w, o.string) catch return response_build_err;
                                w.writeAll("\"") catch return response_build_err;
                            }
                        };
                    }
                } else |_| {
                    // metadata not JSON or malformed — silently skip the
                    // display_label; FE falls back to using key as label
                }
            }
        }
        // V1.7a-9d — community_id + community_name (both nullable). FE
        // colors nodes by community_id and shows the name in the cluster
        // legend. Cold-start tenants (no recompute yet) emit null/null
        // and the FE renders un-clustered.
        w.writeAll(",\"community_id\":") catch return response_build_err;
        if (community_id_map.get(n.key)) |cid| {
            w.print("{d}", .{cid}) catch return response_build_err;
            w.writeAll(",\"community_name\":") catch return response_build_err;
            if (community_name_map.get(cid)) |name| {
                json_util.appendJsonString(&out, allocator, name) catch return response_build_err;
            } else {
                w.writeAll("null") catch return response_build_err;
            }
        } else {
            w.writeAll("null,\"community_name\":null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }

    // V1.14.12 (Memory audit Finding 2 fix, 2026-05-19) — emit entity-
    // side nodes for the targets of typed edges that don't have a
    // memories-table row. Each gets kind="entity" so the FE can style
    // them distinctly. Label is the entity's display name from
    // memory_entities (when coref-resolved) or the key itself as a
    // synthetic fallback (hash-shape entity_<16hex>). importance=0 and
    // community fields null — entity refs are connection points, not
    // first-class memory rows.
    for (entity_keys_list.items) |ek| {
        if (!displayed_keys.contains(ek)) continue;
        if (!first_node_emitted) w.writeAll(",") catch return response_build_err;
        first_node_emitted = false;
        const label = entity_name_map.get(ek) orelse ek;
        w.writeAll("{\"id\":\"") catch return response_build_err;
        jsonEscapeInto(w, ek) catch return response_build_err;
        w.writeAll("\",\"kind\":\"entity\",\"created_at\":0,\"session_id\":null,\"summary\":\"") catch return response_build_err;
        jsonEscapeInto(w, label) catch return response_build_err;
        w.writeAll("\",\"valid_to\":null,\"importance\":0.000,\"community_id\":null,\"community_name\":null}") catch return response_build_err;
    }

    w.writeAll("],\"edges\":[") catch return response_build_err;
    var emitted_first_edge = true;
    for (session_edges) |e| {
        // V1.7a-8b: drop dangling edges when orphan filter excluded an endpoint.
        if (!displayed_keys.contains(e.source) or !displayed_keys.contains(e.target)) continue;
        if (!emitted_first_edge) w.writeAll(",") catch return response_build_err;
        emitted_first_edge = false;
        w.writeAll("{\"type\":\"session\",\"source\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.source) catch return response_build_err;
        w.writeAll("\",\"target\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.target) catch return response_build_err;
        w.writeAll("\"}") catch return response_build_err;
    }
    for (semantic_edges) |e| {
        if (!displayed_keys.contains(e.source_key) or !displayed_keys.contains(e.target_key)) continue;
        if (!emitted_first_edge) w.writeAll(",") catch return response_build_err;
        emitted_first_edge = false;
        w.writeAll("{\"type\":\"semantic\",\"source\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.source_key) catch return response_build_err;
        w.writeAll("\",\"target\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.target_key) catch return response_build_err;
        w.print("\",\"weight\":{d:.4}}}", .{jsonSafeFloatF32(e.similarity)}) catch return response_build_err;
    }
    for (ref_edges) |e| {
        if (!displayed_keys.contains(e.source) or !displayed_keys.contains(e.target)) continue;
        if (!emitted_first_edge) w.writeAll(",") catch return response_build_err;
        emitted_first_edge = false;
        w.writeAll("{\"type\":\"reference\",\"source\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.source) catch return response_build_err;
        w.writeAll("\",\"target\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.target) catch return response_build_err;
        w.writeAll("\"}") catch return response_build_err;
    }
    // V1.6 commit 5b.3 (WR-2) — typed atomic-fact edges with predicate
    // label. FE renders the predicate as the edge label (e.g.,
    // "PREFERS", "DEPLOYS_TO") so the user sees the relationship type.
    for (typed_edges) |e| {
        if (!displayed_keys.contains(e.source) or !displayed_keys.contains(e.target)) continue;
        if (!emitted_first_edge) w.writeAll(",") catch return response_build_err;
        emitted_first_edge = false;
        w.writeAll("{\"type\":\"typed\",\"source\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.source) catch return response_build_err;
        w.writeAll("\",\"target\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.target) catch return response_build_err;
        w.writeAll("\",\"predicate\":\"") catch return response_build_err;
        jsonEscapeInto(w, e.predicate) catch return response_build_err;
        // V1.11 (2026-05-07) — emit confidence + weight so the FE layout
        // can pull strong relations tight and weak ones loose.
        w.print("\",\"confidence\":{d:.3},\"weight\":{d:.3}}}", .{ jsonSafeFloat(e.confidence), jsonSafeFloat(e.weight) }) catch return response_build_err;
    }
    w.writeAll("]") catch return response_build_err;

    w.print(",\"trimmed\":{s},\"total_skipped\":{d},\"total_nodes_in_corpus\":{d},\"semantic_degraded\":{s}}}", .{
        if (trimmed) "true" else "false",
        total_skipped,
        total_in_corpus,
        if (semantic_degraded) "true" else "false",
    }) catch return response_build_err;

    // ── V1.5 day-4: log traversal event ───────────────────────────
    // Non-fatal — graph still ships if logging fails. The event feeds
    // the V1.6 classifier with "user-interesting" signal.
    brainLogGraphView(
        allocator,
        state_mgr,
        numeric_user_id,
        nodes,
        total_in_corpus,
        trimmed,
        semantic_degraded,
    ) catch |err| {
        log.warn("brain/graph traversal log failed user={d} err={s}", .{ numeric_user_id, @errorName(err) });
    };

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/search — V1.6 commit 12 (M2) ────────────────────────────
//
// GET /api/v1/users/:user_id/brain/search?q=<text>[&limit=N]
//
// Server-side keyword + lemmatized BM25 search across the user's
// brain-visible memories. Powers the `/brain` page search bar.
//
// Reuses state_mgr.recallMemories (3-signal scorer: key ILIKE + BM25 +
// content ILIKE), then post-filters via memory_root.isBrainVisibleKey
// to hide agent bookkeeping (continuity summaries, autosaves, tombstones).
// Same hygiene contract as /brain/graph.
//
// Pagination is intentionally NOT cursor-based (unlike /brain/timeline):
// search is single-shot top-N by relevance score, not chronological. The
// FE re-queries with a longer limit if the user wants more.
//
// Response shape mirrors /brain/graph nodes for FE consistency:
//   {"results":[{"key", "content", "category", "score", "valid_to"}],
//    "query":"<echoed>", "limit":N, "total_returned":N}

const BRAIN_SEARCH_DEFAULT_LIMIT: u32 = 20;
const BRAIN_SEARCH_MAX_LIMIT: u32 = 100;

fn handleBrainSearch(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }

    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };

    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Parse query params ────────────────────────────────────────
    const q_param = parseQueryParam(target, "q") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_query_param_q\"}" };
    };
    if (q_param.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"empty_query\"}" };
    }
    if (q_param.len > 512) {
        // Defense: cap query length so a multi-MB GET param doesn't blow up
        // the BM25 lemmatizer or downstream SQL parameter binding.
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"query_too_long\"}" };
    }

    var limit: u32 = if (parseQueryParam(target, "limit")) |s|
        std.fmt.parseInt(u32, s, 10) catch BRAIN_SEARCH_DEFAULT_LIMIT
    else
        BRAIN_SEARCH_DEFAULT_LIMIT;
    if (limit == 0) limit = BRAIN_SEARCH_DEFAULT_LIMIT;
    if (limit > BRAIN_SEARCH_MAX_LIMIT) limit = BRAIN_SEARCH_MAX_LIMIT;

    // ── Fetch with overshoot to compensate for hygiene-filter loss ─
    // recallMemories doesn't apply BRAIN_USER_KEY_FILTER (the agent's
    // retrieval path NEEDS continuity artifacts). Fetch 2× to give the
    // post-filter room without needing pagination, then trim to the
    // user's requested limit.
    const fetch_limit: usize = @as(usize, limit) * 2;
    const raw_entries = state_mgr.recallMemories(
        allocator,
        numeric_user_id,
        q_param,
        fetch_limit,
        null, // no session scope — search the whole user namespace
    ) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"search_query_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, raw_entries);

    // ── Post-filter via brain-visibility predicate ────────────────
    var filtered: std.ArrayListUnmanaged(memory_mod.MemoryEntry) = .empty;
    defer filtered.deinit(allocator);
    for (raw_entries) |e| {
        if (filtered.items.len >= limit) break;
        if (!memory_mod.isBrainVisibleKey(e.key)) continue;
        filtered.append(allocator, e) catch break;
    }

    // ── Build JSON response ──────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"query\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, q_param) catch return response_build_err;
    w.print(",\"limit\":{d},\"total_returned\":{d},\"results\":[", .{ limit, filtered.items.len }) catch return response_build_err;

    for (filtered.items, 0..) |entry, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        w.writeAll("{\"key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.key) catch return response_build_err;
        w.writeAll(",\"content\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.content) catch return response_build_err;
        w.writeAll(",\"category\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.category.toString()) catch return response_build_err;
        if (entry.score) |sc| {
            w.print(",\"score\":{d:.3}", .{jsonSafeFloat(sc)}) catch return response_build_err;
        } else {
            w.writeAll(",\"score\":null") catch return response_build_err;
        }
        if (entry.valid_to) |vt| {
            w.print(",\"valid_to\":{d}", .{vt}) catch return response_build_err;
        } else {
            w.writeAll(",\"valid_to\":null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/documents — V1.6 commit 15 ──────────────────────────────
//
// GET /api/v1/users/:user_id/brain/documents[?limit=N]
//
// Two-tier document view (supermemory parity). Each "document" is a
// session that has produced summaries, with aggregate metadata: count,
// latest timestamp, latest excerpt. The FE drills into a document to
// see the memories derived from that session.

const BRAIN_DOCS_DEFAULT_LIMIT: u32 = 20;
const BRAIN_DOCS_MAX_LIMIT: u32 = 100;

fn handleBrainDocuments(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    var limit: u32 = if (parseQueryParam(target, "limit")) |s|
        std.fmt.parseInt(u32, s, 10) catch BRAIN_DOCS_DEFAULT_LIMIT
    else
        BRAIN_DOCS_DEFAULT_LIMIT;
    if (limit == 0) limit = BRAIN_DOCS_DEFAULT_LIMIT;
    if (limit > BRAIN_DOCS_MAX_LIMIT) limit = BRAIN_DOCS_MAX_LIMIT;

    const docs = state_mgr.listBrainDocumentSummaries(allocator, numeric_user_id, limit) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"documents_query_failed\"}" };
    };
    defer memory_mod.freeBrainDocuments(allocator, docs);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.print("{{\"limit\":{d},\"total_returned\":{d},\"documents\":[", .{ limit, docs.len }) catch return response_build_err;
    for (docs, 0..) |d, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        w.writeAll("{\"session_id\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, d.session_id) catch return response_build_err;
        w.print(",\"summary_count\":{d},\"latest_at\":{d},\"latest_excerpt\":", .{ d.summary_count, d.latest_at_unix }) catch return response_build_err;
        json_util.appendJsonString(&out, allocator, d.latest_excerpt) catch return response_build_err;
        w.writeAll("}") catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/memory/{key} — V1.6 commit 13 (M3) ──────────────────────
//
// GET /api/v1/users/:user_id/brain/memory/:key
//
// Drilldown view for a single memory: full row + lifecycle context.
// Powers the FE per-fact detail page. Returns:
//   - The memory row itself (active or archived)
//   - All edges where this key is source OR target (graph context)
//   - Chronological event history (upsert / compose / demote /
//     edge_added / edge_closed) for the key
//   - Computed importance (recency × centrality, mirrors /brain/graph
//     formula)
//
// Bi-temporal: surfaces archived rows too (the drilldown should show
// the FULL history, not just what's currently active). The agent's
// retrieval path filters via MEMORIES_VALIDITY_FILTER; this UI path
// intentionally bypasses to support audit / "what did we used to know"
// inspection.

const BRAIN_MEMORY_EVENTS_LIMIT: u32 = 50;
const BRAIN_MEMORY_EDGES_LIMIT: usize = 50;

/// V1.11 hardening (2026-05-08) — RFC 3986 percent-decoder for path
/// segments. Brain memory keys legitimately contain `:` (date-ID pattern
/// `2026-04-05:1139`) which the FE correctly URL-encodes to `%3A`. The
/// brain detail handler used to compare the encoded literal against the
/// DB → 404. This decoder runs once at the route boundary so the rest
/// of the handler sees the canonical key.
///
/// Caller frees. Returns InvalidEncoding on malformed `%XX` sequences.
fn percentDecodePathSegment(allocator: std.mem.Allocator, encoded: []const u8) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.ensureTotalCapacity(allocator, encoded.len);
    var i: usize = 0;
    while (i < encoded.len) {
        const c = encoded[i];
        if (c == '%') {
            if (i + 2 >= encoded.len) return error.InvalidEncoding;
            const hi = std.fmt.charToDigit(encoded[i + 1], 16) catch return error.InvalidEncoding;
            const lo = std.fmt.charToDigit(encoded[i + 2], 16) catch return error.InvalidEncoding;
            try out.append(allocator, (hi << 4) | lo);
            i += 3;
        } else if (c == '+') {
            // Path segments don't use '+' for space (that's form-encoding),
            // but defense-in-depth: leave '+' as literal '+' in path keys.
            try out.append(allocator, '+');
            i += 1;
        } else {
            try out.append(allocator, c);
            i += 1;
        }
    }
    return out.toOwnedSlice(allocator);
}

fn handleBrainMemoryDetail(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    key_raw: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }

    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };

    // V1.11 hardening (2026-05-08, FE spec #6) — percent-decode the path
    // segment before length checks + DB query. Brain keys legitimately
    // contain ':' (date-ID pattern `2026-04-05:1139`) which the FE
    // encodes to `%3A` per RFC 3986. Pre-fix the handler queried the
    // encoded literal against the DB — every colon-bearing key 404'd.
    const key = percentDecodePathSegment(allocator, key_raw) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_key_encoding\"}" };
    };
    defer allocator.free(key);

    // M1 fix (2026-05-08, REVIEW-v1.11-day1) — reject NUL bytes in the
    // decoded key. libpq text format silently truncates parameters at
    // the first \0 → query for `realkey\0attackertail` resolves to
    // `realkey`, returning data for a different memory than the URL
    // names. Not a privilege bypass (isBrainVisibleKey runs on the full
    // decoded slice below) but a confusion vector worth closing.
    if (key.len == 0 or key.len > 256 or std.mem.indexOfScalar(u8, key, 0) != null) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_key\"}" };
    }

    // Hygiene: drilldown is a user-facing /brain surface — agent bookkeeping
    // (continuity summaries, autosaves, tombstones) must not be inspectable
    // via this URL even if the user crafts the path manually.
    if (!memory_mod.isBrainVisibleKey(key)) {
        return .{ .status = "404 Not Found", .body = "{\"error\":\"memory_not_found\"}" };
    }

    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Fetch the memory row ─────────────────────────────────────
    // V1.7a-5b: closes the prior TODO ("getMemoryAnyValidity ... doesn't
    // exist yet"). First try the validity-filtered path (live row); on
    // null, fall back to `getMemoryAnyValidity` which surfaces superseded
    // rows. This closes a real user-visible bug — when extraction's
    // contradiction judge invalidates a row mid-browse, the brain graph
    // already serialized the key into the FE state but `getMemory`
    // filters it out → drilldown 404. With the fallback the drilldown
    // returns 200 + the row + populated `valid_to` so the FE renders
    // it as archived rather than missing. Also advances spec §4.9
    // conformance toward the `valid_history` surface.
    //
    // Distinguish live vs archived via `memory.valid_to`: null=live,
    // non-null=archived/superseded. Only true-not-found returns 404.
    var archived: bool = false;
    const mem_opt = state_mgr.getMemory(allocator, numeric_user_id, key) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"memory_query_failed\"}" };
    };
    var memory = mem_opt orelse blk: {
        const fallback = state_mgr.getMemoryAnyValidity(allocator, numeric_user_id, key) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"memory_query_failed\"}" };
        };
        const m = fallback orelse {
            return .{ .status = "404 Not Found", .body = "{\"error\":\"memory_not_found\"}" };
        };
        archived = true;
        break :blk m;
    };
    defer memory.deinit(allocator);

    // ── Fetch metadata (subject/predicate/object) for the structured surface
    const keys_for_meta = [_][]const u8{key};
    var metadata_map = state_mgr.listMemoriesMetadata(allocator, numeric_user_id, &keys_for_meta) catch std.StringHashMapUnmanaged([]u8){};
    defer {
        var it = metadata_map.iterator();
        while (it.next()) |e| {
            allocator.free(e.key_ptr.*);
            allocator.free(e.value_ptr.*);
        }
        metadata_map.deinit(allocator);
    }
    const metadata_json: ?[]const u8 = if (metadata_map.get(key)) |m| m else null;

    // ── V1.6 cmt14 (M4): fetch source attribution (session + snippet)
    var source_opt = state_mgr.getMemorySource(allocator, numeric_user_id, key) catch null;
    defer if (source_opt) |*s| s.deinit(allocator);

    // ── Fetch edges where this key is source OR target ───────────
    const edge_keys = [_][]const u8{key};
    const empty_edges: []memory_mod.TypedEdge = &.{};
    const edges: []memory_mod.TypedEdge = state_mgr.findEdgesByKeys(allocator, numeric_user_id, &edge_keys) catch empty_edges;
    defer if (edges.len > 0) memory_mod.freeTypedEdges(allocator, edges);

    // ── Fetch chronological events for the key ───────────────────
    const empty_events: []memory_mod.MemoryEventRow = &.{};
    const events: []memory_mod.MemoryEventRow = state_mgr.listEventsForMemoryKey(
        allocator,
        numeric_user_id,
        key,
        BRAIN_MEMORY_EVENTS_LIMIT,
    ) catch empty_events;
    defer if (events.len > 0) memory_mod.freeMemoryEventRows(allocator, events);

    // ── Build JSON response ──────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"memory\":{") catch return response_build_err;
    w.writeAll("\"key\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, memory.key) catch return response_build_err;
    w.writeAll(",\"content\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, memory.content) catch return response_build_err;
    w.writeAll(",\"category\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, memory.category.toString()) catch return response_build_err;
    if (memory.session_id) |sid| {
        w.writeAll(",\"session_id\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, sid) catch return response_build_err;
    } else {
        w.writeAll(",\"session_id\":null") catch return response_build_err;
    }
    if (memory.valid_to) |vt| {
        w.print(",\"valid_to\":{d}", .{vt}) catch return response_build_err;
    } else {
        w.writeAll(",\"valid_to\":null") catch return response_build_err;
    }
    // V1.7a-5b — explicit `archived` flag complements `valid_to` for FE
    // convenience. True when the row was returned via the
    // `getMemoryAnyValidity` fallback (validity-filter would have hidden it).
    // FE uses this to render an "archived" badge / dimmer styling rather
    // than treating the drilldown as missing-data.
    w.print(",\"archived\":{s}", .{if (archived) "true" else "false"}) catch return response_build_err;
    if (metadata_json) |m| {
        w.print(",\"metadata\":{s}", .{m}) catch return response_build_err;
    } else {
        w.writeAll(",\"metadata\":null") catch return response_build_err;
    }
    // V1.7a-5 (spec seam 3) — surface link_type as a TOP-LEVEL field per
    // spec §4.9. Already lives inside metadata JSONB but lifting it to
    // the top of the memory object lets the FE render the category badge
    // without parsing metadata. Best-effort parse: if metadata is absent
    // or has no link_type key, emit null. Validates against the LinkType
    // enum so a malformed metadata blob can't inject an arbitrary string.
    {
        var link_type_str: ?[]const u8 = null;
        if (metadata_json) |m| {
            const parsed_meta = std.json.parseFromSlice(std.json.Value, allocator, m, .{}) catch null;
            defer if (parsed_meta) |p| p.deinit();
            if (parsed_meta) |p| {
                if (p.value == .object) {
                    if (p.value.object.get("link_type")) |lt_val| {
                        if (lt_val == .string) {
                            // Validate via enum — only emit if it's a known LinkType.
                            if (memory_mod.LinkType.fromString(lt_val.string)) |lt| {
                                link_type_str = lt.toString(); // canonical lowercase form
                            }
                        }
                    }
                }
            }
        }
        if (link_type_str) |s| {
            w.writeAll(",\"link_type\":") catch return response_build_err;
            json_util.appendJsonString(&out, allocator, s) catch return response_build_err;
        } else {
            w.writeAll(",\"link_type\":null") catch return response_build_err;
        }
    }
    // V1.6 cmt14 (M4) source attribution surface
    if (source_opt) |s| {
        w.writeAll(",\"source\":{") catch return response_build_err;
        if (s.session_id) |sid| {
            w.writeAll("\"session_id\":") catch return response_build_err;
            json_util.appendJsonString(&out, allocator, sid) catch return response_build_err;
        } else {
            w.writeAll("\"session_id\":null") catch return response_build_err;
        }
        if (s.snippet) |sn| {
            w.writeAll(",\"snippet\":") catch return response_build_err;
            json_util.appendJsonString(&out, allocator, sn) catch return response_build_err;
        } else {
            w.writeAll(",\"snippet\":null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    } else {
        w.writeAll(",\"source\":null") catch return response_build_err;
    }
    w.writeAll("},\"edges\":[") catch return response_build_err;

    const edge_cap: usize = @min(edges.len, BRAIN_MEMORY_EDGES_LIMIT);
    for (edges[0..edge_cap], 0..) |edge, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        w.writeAll("{\"source_key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, edge.source_key) catch return response_build_err;
        w.writeAll(",\"target_key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, edge.target_key) catch return response_build_err;
        w.writeAll(",\"predicate\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, edge.predicate) catch return response_build_err;
        w.print(",\"weight\":{d:.3},\"confidence\":{d:.3}", .{ jsonSafeFloat(edge.weight), jsonSafeFloat(edge.confidence) }) catch return response_build_err;
        w.writeAll("}") catch return response_build_err;
    }
    w.writeAll("],\"events\":[") catch return response_build_err;

    for (events, 0..) |evt, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        w.writeAll("{\"id\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, evt.id) catch return response_build_err;
        w.writeAll(",\"event_type\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, evt.event_type) catch return response_build_err;
        w.print(",\"created_at\":{d},\"payload\":{s}", .{ evt.created_at_unix, evt.payload_json }) catch return response_build_err;
        w.writeAll("}") catch return response_build_err;
    }
    w.writeAll("]}") catch return response_build_err;

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/timeline — V1.5 day-2 task 3 ────────────────────────────
//
// GET /api/v1/users/:user_id/brain/timeline
//
// Cursor-paginated chronological view of the user's memory entries.
// Powers the timeline panel on the frontend `/brain` page. Stable
// cursor pagination — new memories landing during pagination don't
// shuffle the page (cursor is `(created_at, id)` tuple, ordered DESC).
//
// Bi-temporal correctness inherited from listMemoriesTimeline (task 1
// validity filter applied at row level). Superseded entries never
// appear in the timeline.
//
// Query params (all optional):
//   ?cursor=<base64>     — opaque pagination cursor; null on first page
//   ?limit=<int>         — page size, default 50, max 200, min 1
//   ?from=<unix>         — lower bound on created_at
//   ?to=<unix>           — upper bound on created_at
//
// Response shape (defined in `docs/frontend-vision-brief.md`):
//   {
//     "entries": [
//       { "id", "key", "kind", "created_at", "session_id", "summary",
//         "valid_to" }
//     ],
//     "next_cursor": "<base64>" | null,   — null when has_more is false
//     "has_more": bool                     — true when entries.len == limit
//   }
//
// Cursor encoding: base64("<ts>:<id>"). Opaque to client; client just
// re-passes whatever next_cursor returned. If client changes from/to
// filters mid-pagination, the cursor still works (filter is re-applied
// alongside cursor predicate).

const BRAIN_TIMELINE_DEFAULT_LIMIT: u32 = 50;
const BRAIN_TIMELINE_MAX_LIMIT: u32 = 200;
const BRAIN_TIMELINE_SUMMARY_CHARS: usize = 200;

const TimelineCursor = struct {
    ts: i64,
    id: []u8, // owned

    pub fn deinit(self: *const TimelineCursor, allocator: std.mem.Allocator) void {
        allocator.free(self.id);
    }
};

/// Encode a cursor as base64("<ts>:<id>"). Caller owns the returned
/// slice. `id` is the memory row's PK; `ts` is the unix-second of
/// `created_at`. Together they form the canonical row-tuple position
/// used by `listMemoriesTimeline`.
fn encodeTimelineCursor(allocator: std.mem.Allocator, ts: i64, id: []const u8) ![]u8 {
    var raw_buf: std.ArrayListUnmanaged(u8) = .empty;
    defer raw_buf.deinit(allocator);
    try raw_buf.writer(allocator).print("{d}:{s}", .{ ts, id });
    const encoded_len = std.base64.standard.Encoder.calcSize(raw_buf.items.len);
    const out = try allocator.alloc(u8, encoded_len);
    _ = std.base64.standard.Encoder.encode(out, raw_buf.items);
    return out;
}

/// Decode a base64 cursor back to (ts, id). Returns null on any parse
/// error (invalid base64, missing colon, non-numeric ts) — caller
/// treats null as "start from newest" rather than failing the request.
fn decodeTimelineCursor(allocator: std.mem.Allocator, encoded: []const u8) ?TimelineCursor {
    const decoded_len = std.base64.standard.Decoder.calcSizeForSlice(encoded) catch return null;
    const decoded = allocator.alloc(u8, decoded_len) catch return null;
    defer allocator.free(decoded);
    std.base64.standard.Decoder.decode(decoded, encoded) catch return null;

    const colon = std.mem.indexOfScalar(u8, decoded, ':') orelse return null;
    const ts = std.fmt.parseInt(i64, decoded[0..colon], 10) catch return null;
    const id_slice = decoded[colon + 1 ..];
    if (id_slice.len == 0) return null;
    const id_owned = allocator.dupe(u8, id_slice) catch return null;
    return .{ .ts = ts, .id = id_owned };
}

fn handleBrainTimeline(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }

    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };

    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Parse query params ────────────────────────────────────────
    const cursor_param = parseQueryParam(target, "cursor");
    const limit_param = parseQueryParam(target, "limit");
    const from_param = parseQueryParam(target, "from");
    const to_param = parseQueryParam(target, "to");

    var limit: u32 = if (limit_param) |s|
        std.fmt.parseInt(u32, s, 10) catch BRAIN_TIMELINE_DEFAULT_LIMIT
    else
        BRAIN_TIMELINE_DEFAULT_LIMIT;
    if (limit == 0) limit = BRAIN_TIMELINE_DEFAULT_LIMIT;
    if (limit > BRAIN_TIMELINE_MAX_LIMIT) limit = BRAIN_TIMELINE_MAX_LIMIT;

    const from: ?i64 = if (from_param) |s| std.fmt.parseInt(i64, s, 10) catch null else null;
    const to: ?i64 = if (to_param) |s| std.fmt.parseInt(i64, s, 10) catch null else null;

    var cursor_opt: ?TimelineCursor = null;
    if (cursor_param) |c_str| {
        cursor_opt = decodeTimelineCursor(allocator, c_str);
        // Silent fallback to no-cursor when decode fails — caller treats
        // null as "start from newest", same shape as a first request.
    }
    defer if (cursor_opt) |c| c.deinit(allocator);

    const cursor_ts: ?i64 = if (cursor_opt) |c| c.ts else null;
    const cursor_id: ?[]const u8 = if (cursor_opt) |c| c.id else null;

    // ── Fetch entries ─────────────────────────────────────────────
    // listMemoriesTimeline applies bi-temporal validity filter
    // automatically. Returns up to `limit` entries newest-first.
    const entries = state_mgr.listMemoriesTimeline(
        allocator,
        numeric_user_id,
        cursor_ts,
        cursor_id,
        limit,
        from,
        to,
    ) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"timeline_query_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, entries);

    // ── Compute next_cursor ───────────────────────────────────────
    const has_more = entries.len == limit;
    var next_cursor: ?[]u8 = null;
    if (has_more and entries.len > 0) {
        const last = entries[entries.len - 1];
        const last_ts = std.fmt.parseInt(i64, last.timestamp, 10) catch 0;
        next_cursor = encodeTimelineCursor(allocator, last_ts, last.id) catch null;
    }
    defer if (next_cursor) |c| allocator.free(c);

    // ── Build JSON response ──────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"entries\":[") catch return response_build_err;
    for (entries, 0..) |entry, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        const ts = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0;
        // V1.5 day-2 review fix: UTF-8-safe truncation (see graph handler).
        const summary_len = brainTruncateUtf8Boundary(entry.content, BRAIN_TIMELINE_SUMMARY_CHARS);
        const summary = entry.content[0..summary_len];
        w.writeAll("{\"id\":\"") catch return response_build_err;
        jsonEscapeInto(w, entry.id) catch return response_build_err;
        w.writeAll("\",\"key\":\"") catch return response_build_err;
        jsonEscapeInto(w, entry.key) catch return response_build_err;
        w.writeAll("\",\"kind\":\"") catch return response_build_err;
        jsonEscapeInto(w, entry.category.toString()) catch return response_build_err;
        w.print("\",\"created_at\":{d},\"session_id\":", .{ts}) catch return response_build_err;
        if (entry.session_id) |sid| {
            w.writeAll("\"") catch return response_build_err;
            jsonEscapeInto(w, sid) catch return response_build_err;
            w.writeAll("\"") catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"summary\":\"") catch return response_build_err;
        jsonEscapeInto(w, summary) catch return response_build_err;
        w.writeAll("\",\"valid_to\":") catch return response_build_err;
        if (entry.valid_to) |vt| {
            w.print("{d}", .{vt}) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }
    w.writeAll("],\"next_cursor\":") catch return response_build_err;
    if (next_cursor) |c| {
        w.writeAll("\"") catch return response_build_err;
        jsonEscapeInto(w, c) catch return response_build_err;
        w.writeAll("\"") catch return response_build_err;
    } else {
        w.writeAll("null") catch return response_build_err;
    }
    w.print(",\"has_more\":{s}}}", .{
        if (has_more) "true" else "false",
    }) catch return response_build_err;

    // ── V1.5 day-4: log traversal event ───────────────────────────
    // Same shape as /brain/graph — non-fatal logging feeds the V1.6
    // classifier with user-attention signal.
    brainLogTimelineView(
        allocator,
        state_mgr,
        numeric_user_id,
        entries,
        has_more,
        cursor_opt != null,
    ) catch |err| {
        log.warn("brain/timeline traversal log failed user={d} err={s}", .{ numeric_user_id, @errorName(err) });
    };

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/communities — V1.7a-9d ───────────────────────────────────
//
// GET /api/v1/users/:user_id/brain/communities
//
// Lists community summaries for the user — one row per cluster with
// id, name (nullable when not yet named), source ('llm' or 'fallback'),
// member_count (live count, not stale cache value), and generated_at.
// Powers the FE cluster legend / community-rail UI.
//
// POST /api/v1/users/:user_id/brain/communities/recompute
//
// Manual trigger for community recompute. Synchronous (sub-2s for V1
// corpora). Returns RecomputeStats so the FE can show "5 clusters
// detected" toast. V1 ships with NULL LlmNamer (every community gets
// fallback "Cluster <id>"); a future commit wires the agent's LLM
// provider to produce real names without changing the endpoint shape.

const community_pipeline = @import("agent/community_pipeline.zig");
const community_llm_namer = @import("agent/community_llm_namer.zig");

fn handleBrainCommunities(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    const summaries = state_mgr.listCommunities(allocator, numeric_user_id) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"communities_query_failed\"}" };
    };
    defer memory_mod.freeCommunitySummaries(allocator, summaries);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"communities\":[") catch return response_build_err;
    for (summaries, 0..) |s, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        w.print("{{\"community_id\":{d},\"member_count\":{d},\"generated_at\":{d},\"name\":", .{
            s.community_id, s.member_count, s.generated_at_unix,
        }) catch return response_build_err;
        if (s.name) |n| {
            json_util.appendJsonString(&out, allocator, n) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"name_source\":") catch return response_build_err;
        if (s.name_source) |src| {
            json_util.appendJsonString(&out, allocator, src) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }
    w.print("],\"stats\":{{\"communities\":{d}}}}}", .{summaries.len}) catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleBrainCommunitiesRecompute(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    tenant_runtime: ?*TenantRuntime,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "POST")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // V1.7a-9 review WR-03 — concurrency guard. Two parallel POSTs would
    // double-do work + race on writes; mid-pipeline ingest churn could
    // produce internally-inconsistent community_ids. tryLock + 409 fast-
    // fails the second caller; first caller proceeds normally. Global
    // serialization is V1-acceptable (manual trigger, low frequency);
    // V1.7b multi-process scheduler can upgrade to per-user PG advisory
    // lock without changing the endpoint shape.
    if (!state.community_recompute_mutex.tryLock()) {
        return .{ .status = "409 Conflict", .body = "{\"error\":\"recompute_in_progress\"}" };
    }
    defer state.community_recompute_mutex.unlock();

    // V1.7-ship S1: build LlmNamer from the tenant runtime's provider
    // bundle. Sidecar (cheap-and-fast model designated for narration /
    // compaction / extraction) preferred; falls back to primary.
    // When tenant_runtime is null (PG-only test paths, cold-start, or
    // pre-tenant boot), pass null namer → pipeline writes fallback
    // "Cluster <id>" names (V1.7a-9c contract).
    var namer_ctx_storage: community_llm_namer.NamerCtx = undefined;
    var namer: ?community_pipeline.LlmNamer = null;
    if (tenant_runtime) |rt| {
        if (rt.provider_bundle.sidecarProvider()) |sidecar| {
            namer_ctx_storage = .{
                .provider = sidecar,
                .model = rt.provider_bundle.sidecarModelName(),
            };
            namer = community_llm_namer.make(&namer_ctx_storage);
        } else {
            namer_ctx_storage = .{
                .provider = rt.provider_bundle.provider(),
                .model = rt.config.default_model orelse "",
            };
            // Skip namer construction when default_model is empty — the
            // chatWithSystem call would fail; better to ship fallback
            // names than waste a round trip.
            if (namer_ctx_storage.model.len > 0) {
                namer = community_llm_namer.make(&namer_ctx_storage);
            }
        }
    }

    const stats = community_pipeline.recomputeCommunitiesForUser(
        allocator,
        state_mgr,
        numeric_user_id,
        namer,
        .{ .now_unix = std.time.timestamp() },
    ) catch |err| {
        log.warn("brain.communities.recompute_failed user={d} err={s}", .{ numeric_user_id, @errorName(err) });
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"recompute_failed\"}" };
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.print("{{\"stats\":{{\"edges_loaded\":{d},\"nodes_in_lpa\":{d},\"communities_found\":{d},\"members_assigned\":{d},\"llm_calls_succeeded\":{d},\"llm_calls_failed\":{d},\"fallback_names_written\":{d}}}}}", .{
        stats.edges_loaded,           stats.nodes_in_lpa,        stats.communities_found,
        stats.members_assigned,       stats.llm_calls_succeeded, stats.llm_calls_failed,
        stats.fallback_names_written,
    }) catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/orphans — V1.7a-8a ───────────────────────────────────────
//
// GET /api/v1/users/:user_id/brain/orphans[?limit=N]
//
// Lists brain-visible memories with NO active edges (incoming OR
// outgoing). Powers Obsidian's "show orphans" affordance — the rail
// next to the graph view that surfaces lost notes the user never
// connected to anything.
//
// Bi-temporal: applies validity filter to BOTH the memories table AND
// the memory_edges subquery. A row that LOST all its edges via
// supersession SHOULD appear here (it IS an orphan in the present,
// even if it had connections last week).
//
// Hygiene contract identical to /brain/graph.
//
// Response shape:
//   {
//     "orphans": [{"id", "key", "kind", "created_at", "session_id",
//                  "summary", "valid_to", "link_type"}],
//     "stats":   {"orphans": N, "limit": N}
//   }

const BRAIN_ORPHANS_DEFAULT_LIMIT: u32 = 200;
const BRAIN_ORPHANS_MAX_LIMIT: u32 = 1000;
const BRAIN_ORPHANS_SUMMARY_CHARS: usize = 200;

/// V1.11 hardening (2026-05-08, FE spec #2) — server-side self-node
/// picker. Powers focus-mode-as-primary on the brain page.
///
/// Picker heuristic (stable, deterministic):
///   1. listIdentityFacts(20) returns memories participating in
///      identity-class edges (NAME/IS/LIVES_IN/WORKS_AT/PREFERS etc).
///      Already-curated SQL at zaki_state.zig:3877.
///   2. Picker returns the FIRST result. listIdentityFacts orders by
///      created_at DESC so this is the most-recent identity fact —
///      typically the user's identity card / "boss" memory.
///   3. Cold-corpus fallback: empty list → 404 with `no_self_anchor`.
///      FE renders an empty-state hint ("ZAKI hasn't learned about you
///      yet — chat to seed your brain"). The FE agent's heuristic
///      (highest-importance core node) is intentionally NOT mirrored
///      server-side: in cold-corpus state there's no honest signal,
///      and empty-state is more truthful than a guess.
///
/// Stability contract: the same user, same corpus, two consecutive
/// calls return the same key. Identity facts only change on extraction
/// of a NEW identity-class edge — predictable + auditable.
///
/// Response shape:
///   200: {"memory": {"key", "summary", "kind", "valid_to"}}
///   404: {"error": "no_self_anchor"}
fn handleBrainMe(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // V1.11 follow-up (2026-05-08) — switched from listIdentityFacts[0]
    // to pickSelfAnchor (zaki_state.zig:3925), which ranks identity-class
    // edge SOURCE memories by outbound degree with `boss_identity`-prefix
    // tiebreaker. Pre-fix the picker took the most-recent identity fact
    // which on real corpora picked noisy facts ("Assistant is Agent
    // Zero" instead of the user's identity card). Source-degree ranking
    // anchors on whoever's the SOURCE of the most identity claims —
    // which is the user by definition.
    const me_opt = state_mgr.pickSelfAnchor(allocator, numeric_user_id) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"self_anchor_query_failed\"}" };
    };
    var me = me_opt orelse {
        return .{ .status = "404 Not Found", .body = "{\"error\":\"no_self_anchor\"}" };
    };
    defer me.deinit(allocator);

    const summary_len = brainTruncateUtf8Boundary(me.content, BRAIN_SUMMARY_CHARS);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"memory\":{\"key\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, me.key) catch return response_build_err;
    w.writeAll(",\"kind\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, me.category.toString()) catch return response_build_err;
    w.writeAll(",\"summary\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, me.content[0..summary_len]) catch return response_build_err;
    w.writeAll(",\"valid_to\":") catch return response_build_err;
    if (me.valid_to) |vt| {
        w.print("{d}", .{vt}) catch return response_build_err;
    } else {
        w.writeAll("null") catch return response_build_err;
    }
    w.writeAll("}}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &out);
}

fn handleBrainOrphans(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    var limit: u32 = if (parseQueryParam(target, "limit")) |s|
        std.fmt.parseInt(u32, s, 10) catch BRAIN_ORPHANS_DEFAULT_LIMIT
    else
        BRAIN_ORPHANS_DEFAULT_LIMIT;
    if (limit == 0) limit = BRAIN_ORPHANS_DEFAULT_LIMIT;
    if (limit > BRAIN_ORPHANS_MAX_LIMIT) limit = BRAIN_ORPHANS_MAX_LIMIT;

    const orphans = state_mgr.listOrphanMemories(allocator, numeric_user_id, limit) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"orphans_query_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, orphans);

    // ── Batched metadata fetch for link_type surface ──────────────
    var keys_buf: std.ArrayListUnmanaged([]const u8) = .empty;
    defer keys_buf.deinit(allocator);
    for (orphans) |e| keys_buf.append(allocator, e.key) catch {};

    var metadata_map = state_mgr.listMemoriesMetadata(allocator, numeric_user_id, keys_buf.items) catch std.StringHashMapUnmanaged([]u8){};
    defer {
        var mit = metadata_map.iterator();
        while (mit.next()) |kv| {
            allocator.free(kv.key_ptr.*);
            allocator.free(kv.value_ptr.*);
        }
        metadata_map.deinit(allocator);
    }

    // ── Build JSON ───────────────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"orphans\":[") catch return response_build_err;
    for (orphans, 0..) |entry, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        const created_at = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0;
        const summary_len = brainTruncateUtf8Boundary(entry.content, BRAIN_ORPHANS_SUMMARY_CHARS);
        w.writeAll("{\"id\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.id) catch return response_build_err;
        w.writeAll(",\"key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.key) catch return response_build_err;
        w.writeAll(",\"kind\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.category.toString()) catch return response_build_err;
        w.print(",\"created_at\":{d},\"session_id\":", .{created_at}) catch return response_build_err;
        if (entry.session_id) |sid| {
            json_util.appendJsonString(&out, allocator, sid) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"summary\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.content[0..summary_len]) catch return response_build_err;
        w.writeAll(",\"valid_to\":") catch return response_build_err;
        if (entry.valid_to) |vt| {
            w.print("{d}", .{vt}) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"link_type\":") catch return response_build_err;
        const md = if (metadata_map.get(entry.key)) |m| @as(?[]const u8, m) else null;
        if (extractLinkTypeFromMetadata(allocator, md)) |lt| {
            json_util.appendJsonString(&out, allocator, lt) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }
    w.print("],\"stats\":{{\"orphans\":{d},\"limit\":{d}}}}}", .{ orphans.len, limit }) catch return response_build_err;

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/local-graph — V1.7a-7 ────────────────────────────────────
//
// GET /api/v1/users/:user_id/brain/local-graph?center_key=<key>&depth=N[&max_nodes=M]
//
// N-hop local graph view from a center node — the half of Obsidian's
// graph value people actually use day-to-day. Wraps the existing
// `graph_expand.expandFromSeeds` BFS primitive (V1.6 cmt10) with one
// seed (the center_key) and emits a /brain/graph-compatible response
// shape so the FE renders with the same code (just a smaller subgraph).
//
// Validation:
//   - center_key required (400 missing_center_key)
//   - center_key must be brain-visible (400 hidden_center_key)
//   - center_key must exist as a live memory for this user (404
//     center_not_found) — uses validity-filtered getMemory; archived
//     center nodes don't make sense for "neighborhood right now"
//   - depth in [1, BRAIN_LOCAL_GRAPH_MAX_DEPTH (3)] — clamped, not 400
//   - max_nodes default 50, capped 200 (matches /brain/graph)
//
// Same hygiene contract as /brain/graph: post-filter neighborhood by
// `memory_root.isBrainVisibleKey` so continuity / autosave / tombstones
// never appear, AND drop edges whose endpoints aren't both brain-visible
// (no dangling edges into hidden bookkeeping).
//
// Response shape (subset of /brain/graph for FE re-use):
//   {
//     "center_key": "<key>",
//     "depth": N,
//     "nodes": [{"key", "kind", "hop_distance", "score", "summary",
//                "valid_to", "session_id", "link_type"}],
//     "edges": [{"source", "target", "predicate", "link_type", "weight"}],
//     "stats": {"nodes": N, "edges": M}
//   }

const BRAIN_LOCAL_GRAPH_MAX_DEPTH: u8 = 3;
const BRAIN_LOCAL_GRAPH_DEFAULT_DEPTH: u8 = 1;
const BRAIN_LOCAL_GRAPH_DEFAULT_MAX_NODES: usize = 50;
const BRAIN_LOCAL_GRAPH_MAX_MAX_NODES: usize = 200;
const BRAIN_LOCAL_GRAPH_SUMMARY_CHARS: usize = 200;

fn handleBrainLocalGraph(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Parse + validate params ───────────────────────────────────
    const center_key = parseQueryParam(target, "center_key") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_center_key\"}" };
    };
    if (center_key.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"empty_center_key\"}" };
    }
    if (center_key.len > 256) {
        // Defense: cap key length matching the schema's `key TEXT` and
        // typical fact_key (extracted_<16hex> = 27 chars).
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"center_key_too_long\"}" };
    }
    if (!memory_mod.isBrainVisibleKey(center_key)) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"hidden_center_key\"}" };
    }

    var depth: u8 = if (parseQueryParam(target, "depth")) |s|
        std.fmt.parseInt(u8, s, 10) catch BRAIN_LOCAL_GRAPH_DEFAULT_DEPTH
    else
        BRAIN_LOCAL_GRAPH_DEFAULT_DEPTH;
    if (depth == 0) depth = BRAIN_LOCAL_GRAPH_DEFAULT_DEPTH;
    if (depth > BRAIN_LOCAL_GRAPH_MAX_DEPTH) depth = BRAIN_LOCAL_GRAPH_MAX_DEPTH;

    var max_nodes: usize = if (parseQueryParam(target, "max_nodes")) |s|
        std.fmt.parseInt(usize, s, 10) catch BRAIN_LOCAL_GRAPH_DEFAULT_MAX_NODES
    else
        BRAIN_LOCAL_GRAPH_DEFAULT_MAX_NODES;
    if (max_nodes == 0) max_nodes = BRAIN_LOCAL_GRAPH_DEFAULT_MAX_NODES;
    if (max_nodes > BRAIN_LOCAL_GRAPH_MAX_MAX_NODES) max_nodes = BRAIN_LOCAL_GRAPH_MAX_MAX_NODES;

    // ── Verify center exists (live OR archived) ──────────────────
    //
    // V1.11 (2026-05-07) — Pre-V1.11 used `getMemory` which filters by
    // MEMORIES_VALIDITY_FILTER (valid_to IS NULL OR future). Archived
    // /superseded centers (e.g. memories the V1.10 truth-maintenance
    // sweep closed out) returned null → 404 → frontend "Failed to
    // load your brain" overlay. Surfaced when Nova clicked
    // `daughter_mia_birthday` (archived May 6 by the prose_survey
    // judge) from the time-scrubber's Archived list — a perfectly
    // valid drilldown intent that the API rejected.
    //
    // Brain page is an AUDIT surface, not a retrieval surface. The
    // user explicitly wants to see archived/superseded relationships
    // here; that's why the time scrubber lists Born + Archived. Same
    // philosophy as `/brain/memory/:key` (gateway.zig:12356-12382)
    // which already uses getMemory → getMemoryAnyValidity fallback.
    //
    // Switching to getMemoryAnyValidity directly: the local-graph
    // handler doesn't expose a "live vs archived" distinction in
    // its response (the BFS expansion via graph_expand surfaces
    // both live and archived nodes anyway), so the simpler
    // single-call form is correct here.
    {
        const center_row = state_mgr.getMemoryAnyValidity(allocator, numeric_user_id, center_key) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"center_lookup_failed\"}" };
        };
        if (center_row) |row| {
            row.deinit(allocator);
        } else {
            return .{ .status = "404 Not Found", .body = "{\"error\":\"center_not_found\"}" };
        }
    }

    // ── BFS expansion via the existing graph_expand primitive ────
    const seed_keys = [_][]const u8{center_key};
    const expand_config: graph_expand.ExpandConfig = .{
        .max_hops = depth,
        .max_nodes_per_hop = max_nodes,
    };
    var neighborhood = graph_expand.expandFromSeeds(
        allocator,
        state_mgr,
        numeric_user_id,
        &seed_keys,
        expand_config,
    ) catch |err| {
        log.warn("brain.local_graph.expand_failed user={d} center={s} depth={d} err={s}", .{
            numeric_user_id, center_key, depth, @errorName(err),
        });
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"expand_failed\"}" };
    };
    defer neighborhood.deinit(allocator);

    // ── Filter out hidden-key nodes / edges (hygiene contract) ───
    var visible_keys: std.StringHashMapUnmanaged(void) = .{};
    defer visible_keys.deinit(allocator);
    for (neighborhood.nodes) |n| {
        if (memory_mod.isBrainVisibleKey(n.key)) {
            visible_keys.put(allocator, n.key, {}) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
            };
        }
    }

    // ── Materialize content + category for visible nodes (1 SQL) ─
    var keys_for_fetch: std.ArrayListUnmanaged([]const u8) = .empty;
    defer keys_for_fetch.deinit(allocator);
    {
        var it = visible_keys.keyIterator();
        while (it.next()) |k| keys_for_fetch.append(allocator, k.*) catch {};
    }

    const node_rows = state_mgr.getMemoriesByKeys(allocator, numeric_user_id, keys_for_fetch.items) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"node_fetch_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, node_rows);

    // Index by key for O(1) lookup during emission.
    var rows_by_key: std.StringHashMapUnmanaged(*const memory_mod.MemoryEntry) = .{};
    defer rows_by_key.deinit(allocator);
    for (node_rows) |*r| rows_by_key.put(allocator, r.key, r) catch {};

    // ── Batched metadata fetch for link_type surface ─────────────
    var metadata_map = state_mgr.listMemoriesMetadata(allocator, numeric_user_id, keys_for_fetch.items) catch std.StringHashMapUnmanaged([]u8){};
    defer {
        var mit = metadata_map.iterator();
        while (mit.next()) |kv| {
            allocator.free(kv.key_ptr.*);
            allocator.free(kv.value_ptr.*);
        }
        metadata_map.deinit(allocator);
    }

    // ── Build JSON ───────────────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.writeAll("{\"center_key\":") catch return response_build_err;
    json_util.appendJsonString(&out, allocator, center_key) catch return response_build_err;
    w.print(",\"depth\":{d},\"nodes\":[", .{depth}) catch return response_build_err;

    var emitted_nodes: usize = 0;
    for (neighborhood.nodes) |n| {
        if (!visible_keys.contains(n.key)) continue;
        if (emitted_nodes > 0) w.writeAll(",") catch return response_build_err;
        emitted_nodes += 1;

        const row_opt = rows_by_key.get(n.key);
        w.writeAll("{\"key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, n.key) catch return response_build_err;
        w.print(",\"hop_distance\":{d},\"score\":{d:.3}", .{ n.hop_distance, jsonSafeFloat(n.score) }) catch return response_build_err;
        if (row_opt) |row| {
            w.writeAll(",\"kind\":") catch return response_build_err;
            json_util.appendJsonString(&out, allocator, row.category.toString()) catch return response_build_err;
            const summary_len = brainTruncateUtf8Boundary(row.content, BRAIN_LOCAL_GRAPH_SUMMARY_CHARS);
            w.writeAll(",\"summary\":") catch return response_build_err;
            json_util.appendJsonString(&out, allocator, row.content[0..summary_len]) catch return response_build_err;
            w.writeAll(",\"session_id\":") catch return response_build_err;
            if (row.session_id) |sid| {
                json_util.appendJsonString(&out, allocator, sid) catch return response_build_err;
            } else {
                w.writeAll("null") catch return response_build_err;
            }
            w.writeAll(",\"valid_to\":") catch return response_build_err;
            if (row.valid_to) |vt| {
                w.print("{d}", .{vt}) catch return response_build_err;
            } else {
                w.writeAll("null") catch return response_build_err;
            }
        } else {
            // Node was in BFS but row wasn't returned by getMemoriesByKeys
            // (e.g. validity-filtered). Emit minimal shape with nulls.
            w.writeAll(",\"kind\":null,\"summary\":null,\"session_id\":null,\"valid_to\":null") catch return response_build_err;
        }
        w.writeAll(",\"link_type\":") catch return response_build_err;
        const md = if (metadata_map.get(n.key)) |m| @as(?[]const u8, m) else null;
        if (extractLinkTypeFromMetadata(allocator, md)) |lt| {
            json_util.appendJsonString(&out, allocator, lt) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }

    w.writeAll("],\"edges\":[") catch return response_build_err;
    var emitted_edges: usize = 0;
    for (neighborhood.edges) |e| {
        // Drop dangling edges (either endpoint hidden) — same hygiene
        // contract as /brain/graph: never surface an edge that points to
        // a node we filtered out.
        if (!visible_keys.contains(e.source_key)) continue;
        if (!visible_keys.contains(e.target_key)) continue;
        if (emitted_edges > 0) w.writeAll(",") catch return response_build_err;
        emitted_edges += 1;

        w.writeAll("{\"source\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, e.source_key) catch return response_build_err;
        w.writeAll(",\"target\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, e.target_key) catch return response_build_err;
        w.writeAll(",\"predicate\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, e.predicate) catch return response_build_err;
        // V1.11 hardening (2026-05-08, FE spec #3) — emit confidence
        // alongside weight on local-graph edges to match the global-graph
        // contract. Pre-fix the FE had to synthesize confidence=1.0 in
        // BrainGraphView.edgeRelevance because local-graph dropped the
        // field, defeating the relevance-weighted layout for the local-
        // graph view (the high-leverage focus-mode pillar).
        w.print(",\"weight\":{d:.3},\"confidence\":{d:.3}", .{ jsonSafeFloat(e.weight), jsonSafeFloat(e.confidence) }) catch return response_build_err;
        // Edge-level link_type derived from predicate via the canonical
        // extraction_persist mapping (same predicate→7-category lookup
        // used at write time in V1.7a-5). Keeps the FE link_type surface
        // consistent across nodes (metadata-derived) and edges (predicate-
        // derived) — both flow through memory_mod.LinkType.toString().
        const edge_lt = extraction_persist.linkTypeForPredicate(e.predicate);
        w.writeAll(",\"link_type\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, edge_lt.toString()) catch return response_build_err;
        w.writeAll("}") catch return response_build_err;
    }
    w.print("],\"stats\":{{\"nodes\":{d},\"edges\":{d}}}}}", .{ emitted_nodes, emitted_edges }) catch return response_build_err;

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/diff — V1.7a-6 ──────────────────────────────────────────
//
// GET /api/v1/users/:user_id/brain/diff
//   ?date=YYYY-MM-DD                — UX form, midnight-to-midnight UTC
//   [&window_days=N]                — extends the window forward N days (default 1, cap 90)
//   ?from=<unix>&to=<unix>          — canonical form, half-open [from, to)
//
// Eleanor Konik's #1 obsidian-graph use case ("what changed on date X?").
// Two independent event streams over the same window:
//
//   births = memories whose `created_at` ∈ [from, to). NO validity filter
//            applied — a memory born and superseded inside the same
//            window appears here AND in deaths (the timeline is the
//            event log, not the row state).
//   deaths = memories whose `valid_to` ∈ [from, to) AND `valid_to IS NOT
//            NULL`. NO validity filter applied — we WANT archived rows
//            here (mirrors V1.7a-5b drilldown insight: surfacing what
//            *was* known is what makes diff useful).
//
// Both surfaces use BRAIN_USER_KEY_FILTER so agent bookkeeping (continuity
// summaries, autosaves, tombstones) stays hidden — same hygiene contract
// as /brain/graph.
//
// Response shape:
//   {
//     "window": {"from": <unix>, "to": <unix>, "date": "YYYY-MM-DD" | null,
//                "window_days": N},
//     "births": [{"id", "key", "kind", "created_at", "session_id",
//                 "summary", "valid_to", "link_type"}, ...],
//     "deaths": [{"id", "key", "kind", "valid_to", "session_id",
//                 "summary", "link_type"}, ...],
//     "stats":  {"births": N, "deaths": M}
//   }

const BRAIN_DIFF_MAX_WINDOW_DAYS: u32 = 90;
const BRAIN_DIFF_DEFAULT_WINDOW_DAYS: u32 = 1;
const BRAIN_DIFF_ROW_CAP: u32 = 500;
const BRAIN_DIFF_SUMMARY_CHARS: usize = 200;

/// Parse YYYY-MM-DD into the unix-second of midnight UTC on that date.
/// Returns null on any parse / validation error. Algorithm: Howard
/// Hinnant's days_from_civil (proleptic Gregorian, no DST/TZ math).
/// Range: 1970-01-01 .. 9999-12-31. Validates month-length per
/// Gregorian rules including leap years (Feb 29 only valid in leap
/// years; April/June/Sept/Nov capped at 30).
fn parseIsoDateUtc(s: []const u8) ?i64 {
    if (s.len != 10) return null;
    if (s[4] != '-' or s[7] != '-') return null;
    const y = std.fmt.parseInt(u32, s[0..4], 10) catch return null;
    const m = std.fmt.parseInt(u8, s[5..7], 10) catch return null;
    const d = std.fmt.parseInt(u8, s[8..10], 10) catch return null;
    if (y < 1970 or y > 9999) return null;
    if (m < 1 or m > 12) return null;
    if (d < 1 or d > 31) return null;
    // Validate day-of-month against Gregorian month length.
    const is_leap = (y % 4 == 0 and y % 100 != 0) or (y % 400 == 0);
    const days_in_month: u8 = switch (m) {
        1, 3, 5, 7, 8, 10, 12 => 31,
        4, 6, 9, 11 => 30,
        2 => if (is_leap) 29 else 28,
        else => unreachable,
    };
    if (d > days_in_month) return null;
    // Howard Hinnant days_from_civil — Gregorian, no DST/TZ.
    const yy: i64 = if (m <= 2) @as(i64, y) - 1 else @as(i64, y);
    const era: i64 = @divFloor(if (yy >= 0) yy else yy - 399, 400);
    const yoe: u64 = @intCast(yy - era * 400);
    const mp: u64 = if (m > 2) @as(u64, m) - 3 else @as(u64, m) + 9;
    const doy: u64 = (153 * mp + 2) / 5 + @as(u64, d) - 1;
    const doe: u64 = yoe * 365 + yoe / 4 - yoe / 100 + doy;
    const days: i64 = era * 146097 + @as(i64, @intCast(doe)) - 719468;
    return days * 86400;
}

/// V1.7a-8b — parse a comma-separated `link_types=` query value into a
/// set of canonical LinkType strings. Tokens are trimmed of surrounding
/// whitespace; case-insensitive (delegated to `LinkType.fromString`).
/// Unknown tokens silently dropped; duplicates collapse via the set.
///
/// Returns an EMPTY set (not null) when the CSV has no recognized
/// tokens — caller treats empty as "filter to nothing matched" so an
/// unknown filter string fails closed instead of bypassing the filter
/// (consistent with the search filter degradation).
///
/// Stored values are static slices from `LinkType.toString()` (string
/// literals) — no per-key heap allocation; only the hashmap header
/// allocates. Caller deinits the hashmap.
fn parseLinkTypesCsv(allocator: std.mem.Allocator, csv: []const u8) std.StringHashMapUnmanaged(void) {
    var s: std.StringHashMapUnmanaged(void) = .{};
    var it = std.mem.tokenizeScalar(u8, csv, ',');
    while (it.next()) |tok| {
        const trimmed = std.mem.trim(u8, tok, " \t");
        if (trimmed.len == 0) continue;
        if (memory_mod.LinkType.fromString(trimmed)) |lt| {
            s.put(allocator, lt.toString(), {}) catch break;
        }
    }
    return s;
}

/// Best-effort link_type extraction from a row's metadata JSONB.
/// Returns the canonical lowercase enum string, or null if absent /
/// malformed / not a known LinkType. Mirrors the same parse used in
/// handleBrainMemoryDetail at the top-level `link_type` field — keeping
/// both surfaces canonical via memory_mod.LinkType.fromString.
fn extractLinkTypeFromMetadata(allocator: std.mem.Allocator, metadata_json: ?[]const u8) ?[]const u8 {
    const m = metadata_json orelse return null;
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, m, .{}) catch return null;
    defer parsed.deinit();
    if (parsed.value != .object) return null;
    const lt_val = parsed.value.object.get("link_type") orelse return null;
    if (lt_val != .string) return null;
    const lt = memory_mod.LinkType.fromString(lt_val.string) orelse return null;
    return lt.toString();
}

fn handleBrainDiff(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    target: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "GET")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }
    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };
    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Resolve window ────────────────────────────────────────────
    // Priority: explicit from+to > date+window_days > today UTC.
    const date_param = parseQueryParam(target, "date");
    const window_days_param = parseQueryParam(target, "window_days");
    const from_param = parseQueryParam(target, "from");
    const to_param = parseQueryParam(target, "to");

    var window_days: u32 = if (window_days_param) |s|
        std.fmt.parseInt(u32, s, 10) catch BRAIN_DIFF_DEFAULT_WINDOW_DAYS
    else
        BRAIN_DIFF_DEFAULT_WINDOW_DAYS;
    if (window_days == 0) window_days = BRAIN_DIFF_DEFAULT_WINDOW_DAYS;
    if (window_days > BRAIN_DIFF_MAX_WINDOW_DAYS) window_days = BRAIN_DIFF_MAX_WINDOW_DAYS;

    var window_from: i64 = 0;
    var window_to: i64 = 0;
    var window_date_echo: ?[]const u8 = null;

    if (from_param != null and to_param != null) {
        const fp = std.fmt.parseInt(i64, from_param.?, 10) catch {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_from\"}" };
        };
        const tp = std.fmt.parseInt(i64, to_param.?, 10) catch {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_to\"}" };
        };
        // Reject pre-epoch values: the entire memory model is post-1970,
        // and validating non-negative is the cheapest way to make the
        // subsequent `tp - fp` subtraction overflow-proof under hostile
        // input (i64.min - i64.max would wrap silently).
        if (fp < 0 or tp < 0) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"window_pre_epoch\"}" };
        }
        if (tp <= fp) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"to_must_exceed_from\"}" };
        }
        // Cap canonical window to BRAIN_DIFF_MAX_WINDOW_DAYS to mirror the
        // date+window_days path — otherwise a malicious caller could
        // request decades of rows in one shot. With both operands ≥ 0
        // (validated above), `tp - fp` is in [0, i64.max] and cannot
        // overflow.
        const max_span: i64 = @as(i64, BRAIN_DIFF_MAX_WINDOW_DAYS) * 86400;
        if ((tp - fp) > max_span) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"window_too_large\"}" };
        }
        window_from = fp;
        window_to = tp;
        // window_days reported as derived rounded count (display-only).
        window_days = @intCast(@divTrunc(tp - fp + 86399, 86400));
    } else if (date_param) |dp| {
        const midnight = parseIsoDateUtc(dp) orelse {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_date_format\"}" };
        };
        window_from = midnight;
        window_to = midnight + @as(i64, window_days) * 86400;
        window_date_echo = dp;
    } else {
        // Default: today UTC. Compute midnight UTC of std.time.timestamp().
        const now: i64 = std.time.timestamp();
        const today_midnight = @divFloor(now, 86400) * 86400;
        window_from = today_midnight;
        window_to = today_midnight + @as(i64, window_days) * 86400;
    }

    // ── Fetch births + deaths ─────────────────────────────────────
    const births = state_mgr.listMemoryBirthsInWindow(
        allocator,
        numeric_user_id,
        window_from,
        window_to,
        BRAIN_DIFF_ROW_CAP,
    ) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"births_query_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, births);

    const deaths = state_mgr.listMemoryDeathsInWindow(
        allocator,
        numeric_user_id,
        window_from,
        window_to,
        BRAIN_DIFF_ROW_CAP,
    ) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"deaths_query_failed\"}" };
    };
    defer memory_mod.freeEntries(allocator, deaths);

    // ── Batch-fetch metadata for link_type surface ────────────────
    // One round trip covering both surfaces (births ∪ deaths key set).
    var key_set: std.StringHashMapUnmanaged(void) = .{};
    defer key_set.deinit(allocator);
    for (births) |e| key_set.put(allocator, e.key, {}) catch {};
    for (deaths) |e| key_set.put(allocator, e.key, {}) catch {};

    var keys_buf: std.ArrayListUnmanaged([]const u8) = .empty;
    defer keys_buf.deinit(allocator);
    {
        var it = key_set.keyIterator();
        while (it.next()) |k| keys_buf.append(allocator, k.*) catch {};
    }

    var metadata_map = state_mgr.listMemoriesMetadata(allocator, numeric_user_id, keys_buf.items) catch std.StringHashMapUnmanaged([]u8){};
    defer {
        var mit = metadata_map.iterator();
        while (mit.next()) |kv| {
            allocator.free(kv.key_ptr.*);
            allocator.free(kv.value_ptr.*);
        }
        metadata_map.deinit(allocator);
    }

    // ── Build JSON response ───────────────────────────────────────
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);

    w.print("{{\"window\":{{\"from\":{d},\"to\":{d},\"window_days\":{d},\"date\":", .{ window_from, window_to, window_days }) catch return response_build_err;
    if (window_date_echo) |dp| {
        json_util.appendJsonString(&out, allocator, dp) catch return response_build_err;
    } else {
        w.writeAll("null") catch return response_build_err;
    }
    w.writeAll("},\"births\":[") catch return response_build_err;
    for (births, 0..) |entry, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        const created_at = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0;
        const summary_len = brainTruncateUtf8Boundary(entry.content, BRAIN_DIFF_SUMMARY_CHARS);
        const summary = entry.content[0..summary_len];
        w.writeAll("{\"id\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.id) catch return response_build_err;
        w.writeAll(",\"key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.key) catch return response_build_err;
        w.writeAll(",\"kind\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.category.toString()) catch return response_build_err;
        w.print(",\"created_at\":{d},\"session_id\":", .{created_at}) catch return response_build_err;
        if (entry.session_id) |sid| {
            json_util.appendJsonString(&out, allocator, sid) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"summary\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, summary) catch return response_build_err;
        w.writeAll(",\"valid_to\":") catch return response_build_err;
        if (entry.valid_to) |vt| {
            w.print("{d}", .{vt}) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"link_type\":") catch return response_build_err;
        const md = if (metadata_map.get(entry.key)) |m| @as(?[]const u8, m) else null;
        if (extractLinkTypeFromMetadata(allocator, md)) |lt| {
            json_util.appendJsonString(&out, allocator, lt) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }
    w.writeAll("],\"deaths\":[") catch return response_build_err;
    for (deaths, 0..) |entry, i| {
        if (i > 0) w.writeAll(",") catch return response_build_err;
        const summary_len = brainTruncateUtf8Boundary(entry.content, BRAIN_DIFF_SUMMARY_CHARS);
        const summary = entry.content[0..summary_len];
        w.writeAll("{\"id\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.id) catch return response_build_err;
        w.writeAll(",\"key\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.key) catch return response_build_err;
        w.writeAll(",\"kind\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, entry.category.toString()) catch return response_build_err;
        w.writeAll(",\"valid_to\":") catch return response_build_err;
        if (entry.valid_to) |vt| {
            w.print("{d}", .{vt}) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"session_id\":") catch return response_build_err;
        if (entry.session_id) |sid| {
            json_util.appendJsonString(&out, allocator, sid) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll(",\"summary\":") catch return response_build_err;
        json_util.appendJsonString(&out, allocator, summary) catch return response_build_err;
        w.writeAll(",\"link_type\":") catch return response_build_err;
        const md = if (metadata_map.get(entry.key)) |m| @as(?[]const u8, m) else null;
        if (extractLinkTypeFromMetadata(allocator, md)) |lt| {
            json_util.appendJsonString(&out, allocator, lt) catch return response_build_err;
        } else {
            w.writeAll("null") catch return response_build_err;
        }
        w.writeAll("}") catch return response_build_err;
    }
    w.print("],\"stats\":{{\"births\":{d},\"deaths\":{d}}}}}", .{ births.len, deaths.len }) catch return response_build_err;

    return finalizeJsonBuf(allocator, &out);
}

// ── /brain/compose — V1.5 day-3 chunk 3C ────────────────────────────
//
// POST /api/v1/users/:user_id/brain/compose
//
// Synthesize 2+ existing memories into one consolidated fact with
// metadata-canonical provenance. Mirror of the `compose_memory` agent
// tool but exposed via HTTP for frontend `/brain` page (user clicks
// "synthesize these" on a graph selection).
//
// Differences from the tool path:
//   1. Server-side reference validation — every key in `references[]`
//      MUST exist as a memory for this user (rejects 400 on dangling).
//      Tool path trusts the agent; HTTP path trusts no one.
//   2. `synthesized_by` value is `"user"` instead of `"agent"` —
//      provenance shows the user did the consolidation. Frontend can
//      render distinct visual treatment (user-authored vs agent-
//      authored syntheses).
//   3. V1.5 caller provides synthesis text in the body. V1.6 will add
//      an alternative shape that accepts only `references[]` and
//      triggers an agent turn to do the synthesis (auto-compose UX).
//
// Request body:
//   {
//     "title": "...",
//     "content": "...",
//     "references": ["k1", "k2"],
//     "category": "core" | "daily" | "conversation" (default "core"),
//     "key": "..." (optional; auto-generated as compose:<hex> if omitted)
//   }
//
// Response (201 Created):
//   {
//     "key": "compose:abc123def456",
//     "synthesized_by": "user",
//     "references_count": 2,
//     "category": "core",
//     "composed_at": 1714521600
//   }
//
// Errors:
//   400 — invalid body / missing fields / bounds exceeded / dangling references
//   405 — non-POST method
//   500 — store-write failure
//   503 — state manager unavailable

const BRAIN_COMPOSE_MAX_TITLE_LEN: usize = 240;
const BRAIN_COMPOSE_MAX_CONTENT_LEN: usize = 50_000;
const BRAIN_COMPOSE_MIN_REFERENCES: usize = 2;
const BRAIN_COMPOSE_MAX_REFERENCES: usize = 50;
const BRAIN_COMPOSE_MAX_REF_KEY_LEN: usize = 256;
const BRAIN_COMPOSE_KEY_PREFIX = "compose:";

fn handleBrainCompose(
    allocator: std.mem.Allocator,
    method: []const u8,
    user_id: []const u8,
    raw_request: []const u8,
    state: *GatewayState,
) RouteResponse {
    if (!std.mem.eql(u8, method, "POST")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\",\"detail\":\"use POST to compose memory\"}" };
    }

    const numeric_user_id = std.fmt.parseInt(i64, user_id, 10) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };

    const state_mgr = state.zaki_state orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"state_manager_unavailable\"}" };
    };

    // ── Parse body ──
    const body = extractBody(raw_request) orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_body\"}" };
    };

    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_json\"}" };
    };
    defer parsed.deinit();

    const root_obj = switch (parsed.value) {
        .object => |o| o,
        else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"body_must_be_object\"}" },
    };

    // ── title ──
    const title_val = root_obj.get("title") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_title\"}" };
    };
    const title = switch (title_val) {
        .string => |s| std.mem.trim(u8, s, " \t\r\n"),
        else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"title_must_be_string\"}" },
    };
    if (title.len == 0) return .{ .status = "400 Bad Request", .body = "{\"error\":\"title_empty\"}" };
    if (title.len > BRAIN_COMPOSE_MAX_TITLE_LEN) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"title_too_long\"}" };
    }

    // ── content ──
    const content_val = root_obj.get("content") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_content\"}" };
    };
    const content = switch (content_val) {
        .string => |s| std.mem.trim(u8, s, " \t\r\n"),
        else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"content_must_be_string\"}" },
    };
    if (content.len == 0) return .{ .status = "400 Bad Request", .body = "{\"error\":\"content_empty\"}" };
    if (content.len > BRAIN_COMPOSE_MAX_CONTENT_LEN) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"content_too_long\"}" };
    }

    // ── references ──
    const refs_val = root_obj.get("references") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_references\"}" };
    };
    const refs = switch (refs_val) {
        .array => |a| a,
        else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"references_must_be_array\"}" },
    };
    if (refs.items.len < BRAIN_COMPOSE_MIN_REFERENCES) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"references_min_2\"}" };
    }
    if (refs.items.len > BRAIN_COMPOSE_MAX_REFERENCES) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"references_max_50\"}" };
    }
    // Collect borrowed slices for validation. Detect duplicates.
    var ref_keys = std.ArrayListUnmanaged([]const u8).empty;
    defer ref_keys.deinit(allocator);
    var ref_seen: std.StringHashMapUnmanaged(void) = .{};
    defer ref_seen.deinit(allocator);
    for (refs.items) |item| {
        const k = switch (item) {
            .string => |s| s,
            else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"references_must_be_strings\"}" },
        };
        if (k.len == 0 or k.len > BRAIN_COMPOSE_MAX_REF_KEY_LEN) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"reference_key_invalid\"}" };
        }
        if (ref_seen.contains(k)) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"duplicate_reference\"}" };
        }
        ref_seen.put(allocator, k, {}) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
        };
        ref_keys.append(allocator, k) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"oom\"}" };
        };
    }

    // ── Server-side reference validation ──
    // Every reference MUST exist as a memory for this user. Dangling
    // references would produce invisible edges in /brain/graph; reject
    // upfront so the user gets clear feedback.
    var existing = state_mgr.existsMemoryKeys(allocator, numeric_user_id, ref_keys.items) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"reference_check_failed\"}" };
    };
    defer {
        var it = existing.iterator();
        while (it.next()) |entry| allocator.free(entry.key_ptr.*);
        existing.deinit(allocator);
    }
    for (ref_keys.items) |k| {
        if (!existing.contains(k)) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"dangling_reference\",\"detail\":\"one or more references[] keys do not resolve to existing memories for this user\"}" };
        }
    }

    // ── category ──
    const cat_str = blk: {
        const v = root_obj.get("category") orelse break :blk "core";
        const s = switch (v) {
            .string => |str| str,
            else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"category_must_be_string\"}" },
        };
        break :blk s;
    };
    const category: memory_mod.MemoryCategory = if (std.mem.eql(u8, cat_str, "core"))
        .core
    else if (std.mem.eql(u8, cat_str, "daily"))
        .daily
    else if (std.mem.eql(u8, cat_str, "conversation"))
        .conversation
    else {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_category\"}" };
    };

    // ── key (auto-generated when not provided) ──
    // V1.5 day-3 review fix: user-provided keys MUST start with
    // BRAIN_COMPOSE_KEY_PREFIX. Without this guard, a caller could
    // POST a request with `key:"user_lang"` and OVERWRITE the user_lang
    // memory via the upsert's ON CONFLICT path. Prefix enforcement
    // isolates the compose-write namespace from other writers.
    var key_buf: [80]u8 = undefined;
    var key_owned: ?[]u8 = null;
    defer if (key_owned) |k| allocator.free(k);
    const memory_key: []const u8 = blk: {
        const v = root_obj.get("key");
        if (v) |kv| {
            const s = switch (kv) {
                .string => |str| std.mem.trim(u8, str, " \t\r\n"),
                else => return .{ .status = "400 Bad Request", .body = "{\"error\":\"key_must_be_string\"}" },
            };
            if (s.len == 0) return .{ .status = "400 Bad Request", .body = "{\"error\":\"key_empty\"}" };
            if (!std.mem.startsWith(u8, s, BRAIN_COMPOSE_KEY_PREFIX)) {
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"key_must_start_with_compose_prefix\",\"detail\":\"user-provided keys must start with 'compose:' to prevent overwriting unrelated memories\"}" };
            }
            const owned = allocator.dupe(u8, s) catch return response_build_err;
            key_owned = owned;
            break :blk owned;
        }
        var rand_buf: [8]u8 = undefined;
        std.crypto.random.bytes(&rand_buf);
        var hex_buf: [16]u8 = undefined;
        const hex = security_secrets_mod.hexEncode(&rand_buf, &hex_buf);
        const full = std.fmt.bufPrint(&key_buf, "{s}{s}", .{ BRAIN_COMPOSE_KEY_PREFIX, hex }) catch return response_build_err;
        const owned = allocator.dupe(u8, full) catch return response_build_err;
        key_owned = owned;
        break :blk owned;
    };

    // ── Build metadata JSON ──
    // Shape: {"synthesized_by":"user","references":["k1","k2"],"composed_at":<unix>}
    const ts = std.time.timestamp();
    var meta_buf: std.ArrayListUnmanaged(u8) = .empty;
    defer meta_buf.deinit(allocator);
    const mw = meta_buf.writer(allocator);
    mw.writeAll("{\"synthesized_by\":\"user\",\"references\":[") catch return response_build_err;
    for (ref_keys.items, 0..) |k, idx| {
        if (idx > 0) mw.writeAll(",") catch return response_build_err;
        mw.writeAll("\"") catch return response_build_err;
        jsonEscapeInto(mw, k) catch return response_build_err;
        mw.writeAll("\"") catch return response_build_err;
    }
    mw.print("],\"composed_at\":{d},\"title\":\"", .{ts}) catch return response_build_err;
    jsonEscapeInto(mw, title) catch return response_build_err;
    mw.writeAll("\"}") catch return response_build_err;

    // ── Write via state_mgr.upsertMemoryWithMetadata ──
    state_mgr.upsertMemoryWithMetadata(numeric_user_id, memory_key, content, category, null, meta_buf.items) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"compose_write_failed\"}" };
    };

    // ── Build success response ──
    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    const w = out.writer(allocator);
    w.writeAll("{\"key\":\"") catch return response_build_err;
    jsonEscapeInto(w, memory_key) catch return response_build_err;
    w.writeAll("\",\"synthesized_by\":\"user\",\"references_count\":") catch return response_build_err;
    w.print("{d}", .{ref_keys.items.len}) catch return response_build_err;
    w.writeAll(",\"category\":\"") catch return response_build_err;
    jsonEscapeInto(w, cat_str) catch return response_build_err;
    w.print("\",\"composed_at\":{d}}}", .{ts}) catch return response_build_err;

    var resp = finalizeJsonBuf(allocator, &out);
    resp.status = "201 Created";
    return resp;
}

// ── GDPR data purge handler (Sprint 7B — S7.6) ─────────────────────
//
// DELETE /api/v1/users/:user_id/data
// Body: {"confirm":"PURGE-USER-<user_id>"}
//
// Preconditions enforced by the surrounding handleApiRoute pipeline:
//   1. X-Internal-Token validated at handleApiRoute entry.
//   2. user_id resolved from path via parseUserPath + resolveGatewayPathUserId.
//   3. user_ctx provisioned + workspace dirs ensured.
//   4. **needs_write_lock fires for this route** — DELETE on subpath
//      "data" passes the `!GET and !raw_config_write_attempt` test, so
//      `maybeAcquireTenantOwnershipLock` runs before this handler. The
//      lock is held for the full purge duration via the deferred
//      `user_write_lock.deinit()` at the end of handleApiRoute.
//
// Why the lock matters here (Sprint 7B post-review check, 2026-04-25):
// without it, the gateway worker's maintenance loop or a concurrent
// config-write from another worker could invalidate `tenant_runtime`
// (and the borrowed `effective_session_mgr` / `vector_store` pointers
// we hand to `gdpr.purgeUser`) mid-orchestration → use-after-free.
// The ownership lock ensures the runtime stays alive for the duration
// of the purge. If a future refactor adjusts handleApiRoute's
// needs_write_lock predicate, this handler must grow its own lock.
//
// Body-level `confirm` gate is layer 2 of defense, binding destructive
// intent to the exact path user_id so a mis-routed curl (wrong path)
// fails before touching any storage.
fn handleGdprDataPurge(
    allocator: std.mem.Allocator,
    raw_request: []const u8,
    scoped_user_id: []const u8,
    state: *GatewayState,
    effective_session_mgr: ?*session_mod.SessionManager,
) RouteResponse {
    const numeric_user_id = parseNumericUserId(scoped_user_id) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
    };

    const body = extractBody(raw_request) orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_body\",\"detail\":\"expected {\\\"confirm\\\":\\\"PURGE-USER-<user_id>\\\"}\"}" };
    };
    const confirm = jsonStringField(body, "confirm") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_confirm\",\"detail\":\"expected {\\\"confirm\\\":\\\"PURGE-USER-<user_id>\\\"}\"}" };
    };
    const expected = std.fmt.allocPrint(allocator, "PURGE-USER-{s}", .{scoped_user_id}) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"confirm_build_failed\"}" };
    };
    defer allocator.free(expected);
    if (!std.mem.eql(u8, confirm, expected)) {
        return .{ .status = "401 Unauthorized", .body = "{\"error\":\"confirm_mismatch\",\"detail\":\"confirm must exactly equal PURGE-USER-<user_id> where <user_id> matches the URL path\"}" };
    }

    // Resolve vector store from the tenant runtime if available.
    // Holding the mutex briefly is fine: purgeUser itself does not need
    // the mutex — we just borrow the VectorStore handle, which is
    // retained by the runtime until the runtime is destroyed.
    var vector_store_opt: ?memory_mod.VectorStore = null;
    {
        state.tenant_runtime_mutex.lock();
        defer state.tenant_runtime_mutex.unlock();
        if (state.tenant_runtimes.get(scoped_user_id)) |runtime| {
            if (runtime.mem_rt) |*rt| {
                vector_store_opt = rt._vector_store;
            }
        }
    }

    // Build a /data/users root path we can point purgeUser at for the
    // filesystem step. We use the gateway's configured tenant_data_root
    // rather than user_ctx.user_root directly so a path-traversal attempt
    // via user_id cannot escape the tenant tree (parseNumericUserId above
    // already constrains user_id to digits, belt-and-suspenders).
    var report = gdpr_mod.purgeUser(.{
        .allocator = allocator,
        .zaki_state = state.zaki_state,
        .vector_store = vector_store_opt,
        .session_manager = effective_session_mgr,
        .users_root = state.tenant_data_root,
    }, numeric_user_id) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"purge_failed\"}" };
    };
    defer report.deinit(allocator);

    var resp: std.ArrayListUnmanaged(u8) = .empty;
    defer resp.deinit(allocator);
    const w = resp.writer(allocator);
    w.print(
        "{{\"status\":\"{s}\",\"sessions_evicted\":{d},\"sessions_skipped_active\":{d},\"pg_user_row_deleted\":{s},\"vector_rows_removed\":{d},\"filesystem_removed\":{s},\"errors\":[",
        .{
            if (report.fullySucceeded()) "ok" else "partial",
            report.sessions_evicted,
            report.sessions_skipped_active,
            if (report.pg_user_row_deleted) "true" else "false",
            report.vector_rows_removed,
            if (report.filesystem_removed) "true" else "false",
        },
    ) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    var first = true;
    for (report.errors.items) |e| {
        if (!first) w.writeAll(",") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
        first = false;
        w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
        jsonEscapeInto(w, e) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
        w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };
    }
    w.writeAll("]}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" };

    // Partial success still returns 200 with the body marking which
    // surfaces didn't fully purge. Full failure (allocator OOM etc.)
    // returned 500 above. 207 Multi-Status would be more RFC-accurate
    // but is non-standard in our gateway router.
    return .{ .body = resp.toOwnedSlice(allocator) catch
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response_build_failed\"}" } };
}

fn handleApiRoute(
    // D20 (2026-04-25): `root_allocator` was only used by the deleted
    // buffered chat/stream handler's `processIncomingMessage` fallback.
    // Kept as `_` so existing callers don't have to rewire their call
    // sites; can be removed entirely the next time this signature is
    // touched.
    _: std.mem.Allocator,
    req_allocator: std.mem.Allocator,
    raw_request: []const u8,
    method: []const u8,
    base_path: []const u8,
    state: *GatewayState,
    config_opt: ?*const Config,
    session_mgr_opt: ?*session_mod.SessionManager,
) RouteResponse {
    if (!validateInternalServiceToken(raw_request, state)) {
        return .{ .status = "401 Unauthorized", .body = "{\"error\":\"unauthorized\"}" };
    }

    if (std.mem.eql(u8, base_path, "/api/v1/users/provision")) {
        if (!std.mem.eql(u8, method, "POST")) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        }
        // S2.10 — Idempotency-Key dedupe on a high-value mutating route.
        // Duplicate POSTs from a retrying BFF or mobile client used to
        // re-run the provisioning pipeline (user_cell ensure, state
        // allocation, scaffold) end-to-end. With a key attached, the
        // second call short-circuits to an at-most-once ack.
        switch (checkIdempotency(state, req_allocator, raw_request)) {
            .duplicate => return .{ .status = "200 OK", .body = "{\"status\":\"duplicate\",\"detail\":\"already provisioned within idempotency window\"}" },
            .invalid => return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_idempotency_key\",\"detail\":\"Idempotency-Key must be 1..=256 bytes\"}" },
            .none, .new => {},
        }
        const body = extractBody(raw_request);
        const body_user_id = if (body) |b| jsonStringField(b, "user_id") else null;
        const user_id = resolveGatewayRequestUserId(state, extractZakiUserId(raw_request), body_user_id, false) catch |err| {
            return switch (err) {
                error.MissingUserId => .{ .status = "400 Bad Request", .body = "{\"error\":\"missing user_id\"}" },
                error.UserCellUserMismatch => .{ .status = "403 Forbidden", .body = "{\"error\":\"wrong_user_cell\"}" },
            };
        };
        if (state.role == .broker) {
            prepareBrokerUserForRouting(req_allocator, state, user_id) catch |err| {
                if (isIdentityUserNotFound(err)) {
                    return .{ .status = "404 Not Found", .body = "{\"error\":\"unknown_user_id\"}" };
                }
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state_provisioning_failed\"}" };
            };
            const target = extractRequestTarget(raw_request) orelse base_path;
            return brokerProxyApiRequest(
                req_allocator,
                state,
                raw_request,
                method,
                target,
                user_id,
                "application/json",
                "30",
            );
        }

        var user_ctx = resolveUserContext(req_allocator, state, user_id) catch {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
        };
        defer user_ctx.deinit(req_allocator);
        var prep_guard = state.user_preparation_gate.acquire(user_ctx.user_id) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"user preparation gate failed\"}" };
        };
        defer prep_guard.deinit();
        ensureUserDirectories(&user_ctx) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"workspace_bootstrap_failed\"}" };
        };
        ensureUserProvisioned(state, &user_ctx) catch |err| {
            if (isIdentityUserNotFound(err)) {
                return .{ .status = "404 Not Found", .body = "{\"error\":\"unknown_user_id\"}" };
            }
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state_provisioning_failed\"}" };
        };
        scaffoldUserWorkspace(req_allocator, &user_ctx);
        prep_guard.release();

        // S2.1 — install entitlement from BFF-provided billing fields.
        // The BFF now attaches `plan_tier`, `status`, and
        // `period_end_unix` to its provision request. We parse them
        // best-effort and update the in-memory resolver store; absent
        // fields collapse to `fromProvision`'s defaults (tier=free
        // when missing, status=expired when missing). The updated
        // entry is visible to the next chat-stream / tool-preflight /
        // scheduler-tick via the default resolver armed at startup.
        if (body) |b| {
            const bft_tier = jsonStringField(b, "plan_tier");
            const bft_status = jsonStringField(b, "status");
            const bft_period_end = jsonIntField(b, "period_end_unix");
            if (bft_tier != null or bft_status != null or bft_period_end != null) {
                const ent = entitlement_mod.Entitlement.fromProvision(bft_tier, bft_status, bft_period_end);
                entitlement_mod.installEntitlement(user_id, ent) catch |err| {
                    log.warn("entitlement.install_failed user={s} err={s}", .{ user_id, @errorName(err) });
                };
            }
        }

        return .{ .body = "{\"status\":\"provisioned\"}" };
    }

    // ── Channel Health endpoint (D-10) ───────────────────────────────
    if (std.mem.eql(u8, base_path, "/api/v1/channels/health")) {
        if (!std.mem.eql(u8, method, "GET")) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        }
        const snap = health.snapshot();
        // Build real channel health entries from config when available.
        // A temporary ChannelManager + ChannelRegistry are constructed so
        // collectConfiguredChannels populates the entry list that
        // aggregateChannelHealth reads (supervision state, failure counts).
        if (config_opt) |cfg| {
            var registry = channel_dispatch.ChannelRegistry.init(req_allocator);
            defer registry.deinit();
            const mgr = channel_manager.ChannelManager.init(req_allocator, cfg, &registry) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"health_manager_init_failed\"}" };
            };
            defer mgr.deinit();
            mgr.collectConfiguredChannels() catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"health_collect_failed\"}" };
            };
            const entries = channel_health_mod.aggregateChannelHealth(req_allocator, mgr) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"health_aggregate_failed\"}" };
            };
            defer req_allocator.free(entries);
            const json = channel_health_mod.formatHealthJson(
                req_allocator,
                entries,
                @intCast(snap.uptime_seconds),
            ) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"health_format_failed\"}" };
            };
            return .{ .body = json };
        }
        // No config available — return empty channels with uptime only.
        const json = channel_health_mod.formatHealthJson(
            req_allocator,
            &.{},
            @intCast(snap.uptime_seconds),
        ) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"health_format_failed\"}" };
        };
        return .{ .body = json };
    }

    // ── Security Review endpoint (D-12) ──────────────────────────────
    if (std.mem.eql(u8, base_path, "/api/v1/security/review")) {
        if (!std.mem.eql(u8, method, "GET")) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        }
        const sec_cfg: config_types.SecurityConfig = if (config_opt) |cfg| cfg.security else .{};
        const workspace_only: bool = if (config_opt) |cfg| cfg.autonomy.workspace_only else true;
        const max_actions: u32 = if (config_opt) |cfg| cfg.autonomy.max_actions_per_hour else 100;
        const pairing_enabled: bool = state.pairing_guard != null;

        const report = security_review_mod.runAllChecks(
            req_allocator,
            sec_cfg,
            workspace_only,
            max_actions,
            pairing_enabled,
        ) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"security_review_failed\"}" };
        };
        defer req_allocator.free(report.checks);

        const json = security_review_mod.formatReviewJson(req_allocator, report) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"review_format_failed\"}" };
        };
        return .{ .body = json };
    }

    const parsed = parseUserPath(base_path) orelse
        return .{ .status = "404 Not Found", .body = "{\"error\":\"not found\"}" };
    const scoped_user_id = resolveGatewayPathUserId(state, parsed.user_id) catch |err| {
        return switch (err) {
            error.MissingUserId => .{ .status = "400 Bad Request", .body = "{\"error\":\"missing user_id\"}" },
            error.UserCellUserMismatch => .{ .status = "403 Forbidden", .body = "{\"error\":\"wrong_user_cell\"}" },
        };
    };
    if (state.role == .broker) {
        prepareBrokerUserForRouting(req_allocator, state, scoped_user_id) catch |err| {
            if (isIdentityUserNotFound(err)) {
                return .{ .status = "404 Not Found", .body = "{\"error\":\"unknown_user_id\"}" };
            }
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state_provisioning_failed\"}" };
        };
        const target = extractRequestTarget(raw_request) orelse base_path;
        return brokerProxyApiRequest(
            req_allocator,
            state,
            raw_request,
            method,
            target,
            scoped_user_id,
            "application/json",
            "30",
        );
    }

    var user_ctx = resolveUserContext(req_allocator, state, scoped_user_id) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
    };
    defer user_ctx.deinit(req_allocator);
    var prep_guard = state.user_preparation_gate.acquire(user_ctx.user_id) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"user preparation gate failed\"}" };
    };
    defer prep_guard.deinit();
    ensureUserDirectories(&user_ctx) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"workspace_bootstrap_failed\"}" };
    };
    ensureUserProvisioned(state, &user_ctx) catch |err| {
        if (isIdentityUserNotFound(err)) {
            return .{ .status = "404 Not Found", .body = "{\"error\":\"unknown_user_id\"}" };
        }
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state_provisioning_failed\"}" };
    };
    scaffoldUserWorkspace(req_allocator, &user_ctx);
    prep_guard.release();
    const raw_config_write_attempt = std.mem.eql(u8, parsed.subpath, "config") and !std.mem.eql(u8, method, "GET");
    const needs_write_lock = !std.mem.eql(u8, method, "GET") and !raw_config_write_attempt;
    var user_write_lock: ?OwnershipLockAcquireResult = null;
    if (needs_write_lock) {
        var acquired = maybeAcquireTenantOwnershipLock(req_allocator, state, user_ctx.user_id, user_ctx.user_root) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"tenant ownership lock failed\"}" };
        };
        switch (acquired) {
            .disabled => {},
            .acquired => {},
            .conflict => |*conflict| {
                recordTenantLockConflict(state, .api);
                defer acquired.deinit();
                return ownershipLockConflictJsonRouteResponse(req_allocator, conflict);
            },
        }
        user_write_lock = acquired;
    }
    defer if (user_write_lock) |*lock| lock.deinit();

    if (std.mem.eql(u8, parsed.subpath, "onboarding")) {
        if (std.mem.eql(u8, method, "GET")) {
            var onboarding_content: []u8 = undefined;
            if (state.zaki_state) |mgr| {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                onboarding_content = mgr.getOnboardingJson(req_allocator, user_id) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
                };
            } else {
                const onboarding_path = onboardingStatePath(req_allocator, user_ctx.user_root) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                };
                defer req_allocator.free(onboarding_path);
                onboarding_content = readFileOrDefault(req_allocator, onboarding_path, "{\"completed\":false,\"completed_at_s\":null}\n") catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
                };
            }
            defer req_allocator.free(onboarding_content);
            const summary = parseOnboardingStateSummary(onboarding_content);
            var telegram_readiness = NormalizedTelegramReadiness{};
            defer telegram_readiness.deinit(req_allocator);
            if (build_options.enable_channel_telegram) {
                telegram_readiness = loadNormalizedTelegramReadiness(req_allocator, state, scoped_user_id, &user_ctx) catch .{};
            }
            const heartbeat_enabled_normalized = loadNormalizedHeartbeatEnabled(req_allocator, state, scoped_user_id, user_ctx.heartbeat_path);
            const setup = buildOnboardingSetupResponse(
                req_allocator,
                scoped_user_id,
                summary,
                telegram_readiness,
                heartbeat_enabled_normalized,
                config_opt,
            ) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            };
            return .{ .body = setup };
        }

        if (std.mem.eql(u8, method, "PUT")) {
            const body = extractBody(raw_request) orelse "{}";
            if (jsonStringField(body, "bootstrap")) |value| {
                const p = workspaceFilePath(req_allocator, user_ctx.workspace_path, "BOOTSTRAP.md") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                defer req_allocator.free(p);
                writeFile(p, value) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            }
            if (jsonStringField(body, "identity")) |value| {
                const p = workspaceFilePath(req_allocator, user_ctx.workspace_path, "IDENTITY.md") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                defer req_allocator.free(p);
                writeFile(p, value) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            }
            if (jsonStringField(body, "user")) |value| {
                const p = workspaceFilePath(req_allocator, user_ctx.workspace_path, "USER.md") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                defer req_allocator.free(p);
                writeFile(p, value) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            }
            if (jsonStringField(body, "soul")) |value| {
                const p = workspaceFilePath(req_allocator, user_ctx.workspace_path, "SOUL.md") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                defer req_allocator.free(p);
                writeFile(p, value) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            }
            if (jsonStringField(body, "heartbeat")) |value| {
                const p = workspaceFilePath(req_allocator, user_ctx.workspace_path, "HEARTBEAT.md") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                defer req_allocator.free(p);
                writeFile(p, value) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            }

            const completed = jsonBoolField(body, "completed") orelse false;
            const completed_at_s = if (completed) std.time.timestamp() else @as(i64, 0);
            if (completed) {
                const bootstrap_path = workspaceFilePath(req_allocator, user_ctx.workspace_path, "BOOTSTRAP.md") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                defer req_allocator.free(bootstrap_path);
                std.fs.deleteFileAbsolute(bootstrap_path) catch |err| switch (err) {
                    error.FileNotFound => {},
                    else => return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"delete failed\"}" },
                };
            }

            var out: std.ArrayListUnmanaged(u8) = .empty;
            defer out.deinit(req_allocator);
            const w = out.writer(req_allocator);
            w.writeAll("{\"completed\":") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            w.writeAll(if (completed) "true" else "false") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            w.writeAll(",\"completed_at_s\":") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            if (completed) {
                w.print("{d}", .{completed_at_s}) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            } else {
                w.writeAll("null") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            }
            w.writeAll("}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            if (state.zaki_state) |mgr| {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                mgr.putOnboardingJson(user_id, out.items) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
                };
            } else {
                const onboarding_path = onboardingStatePath(req_allocator, user_ctx.user_root) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path failed\"}" };
                };
                defer req_allocator.free(onboarding_path);
                writeFile(onboarding_path, out.items) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
                };
            }
            return .{ .body = out.toOwnedSlice(req_allocator) catch "{\"status\":\"updated\"}" };
        }

        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "config")) {
        if (std.mem.eql(u8, method, "GET")) {
            const raw_content = if (state.zaki_state) |mgr| blk: {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                break :blk mgr.getConfigJson(req_allocator, user_id) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
                };
            } else blk: {
                break :blk readFileOrDefault(req_allocator, user_ctx.config_path, "{}\n") catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
                };
            };
            defer req_allocator.free(raw_content);
            const normalized = user_settings.normalizeTenantConfigJson(req_allocator, raw_content) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"normalize failed\"}" };
            };
            return .{ .body = normalized.json };
        }
        if (std.mem.eql(u8, method, "PATCH") or std.mem.eql(u8, method, "PUT")) {
            return .{ .status = "403 Forbidden", .body = "{\"error\":\"raw_config_writes_disabled\"}" };
        }
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "settings")) {
        const existing_config = if (state.zaki_state) |mgr| blk: {
            const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
            break :blk mgr.getConfigJson(req_allocator, user_id) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
            };
        } else blk: {
            break :blk readFileOrDefault(req_allocator, user_ctx.config_path, "{}\n") catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
            };
        };
        defer req_allocator.free(existing_config);

        if (std.mem.eql(u8, method, "GET")) {
            const settings = user_settings.resolveSettingsFromConfigJson(req_allocator, existing_config) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"settings resolution failed\"}" };
            };
            const body = user_settings.renderSettingsJson(req_allocator, settings) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            };
            return .{ .body = body };
        }

        if (std.mem.eql(u8, method, "PATCH") or std.mem.eql(u8, method, "PUT")) {
            const body = extractBody(raw_request) orelse "{}";
            const base_settings = user_settings.resolveSettingsFromConfigJson(req_allocator, existing_config) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"settings resolution failed\"}" };
            };
            const updated_settings = user_settings.applyPatchToSettingsJson(req_allocator, base_settings, body) catch |err| {
                const code = user_settings.errorCode(err);
                const err_body = std.fmt.allocPrint(req_allocator, "{{\"error\":\"{s}\"}}", .{code}) catch "{\"error\":\"invalid_payload\"}";
                return .{ .status = "400 Bad Request", .body = err_body };
            };
            const merged = user_settings.mergeSettingsIntoConfigJson(req_allocator, existing_config, updated_settings) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"merge failed\"}" };
            };
            defer req_allocator.free(merged);
            writeUserConfigJson(state, &user_ctx, scoped_user_id, merged) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            };
            // Mark for deferred destruction instead of immediate remove.
            // Prevents use-after-free if a concurrent request thread holds
            // a pointer to this TenantRuntime. The maintenance loop (1s)
            // will destroy it once no sessions have active turns.
            markTenantRuntimeForDestroy(state, scoped_user_id);
            const response = user_settings.renderSettingsJson(req_allocator, updated_settings) catch "{\"status\":\"updated\"}";
            return .{ .body = response };
        }

        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "heartbeat")) {
        if (std.mem.eql(u8, method, "GET")) {
            const enabled = loadNormalizedHeartbeatEnabled(req_allocator, state, scoped_user_id, user_ctx.heartbeat_path);
            const canonical_body = canonicalHeartbeatEnabledJson(req_allocator, enabled) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            };
            return .{ .body = canonical_body };
        }
        if (std.mem.eql(u8, method, "PUT")) {
            const body = extractBody(raw_request) orelse "{}\n";
            const enabled = jsonBoolField(body, "enabled") orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing enabled\"}",
            };
            const canonical_body = writeHeartbeatEnabledForUser(req_allocator, state, &user_ctx, scoped_user_id, enabled) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            };
            markTenantRuntimeForDestroy(state, scoped_user_id);
            return .{ .body = canonical_body };
        }
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "cron")) {
        if (std.mem.eql(u8, method, "GET")) {
            if (state.zaki_state) |mgr| {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                const content = mgr.getJobsJson(req_allocator, user_id) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
                };
                return .{ .body = content };
            }
            const content = readFileOrDefault(req_allocator, user_ctx.cron_path, "[]\n") catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"read failed\"}" };
            };
            return .{ .body = content };
        }
        if (std.mem.eql(u8, method, "POST") or std.mem.eql(u8, method, "PATCH") or std.mem.eql(u8, method, "PUT")) {
            const body = extractBody(raw_request) orelse "[]\n";
            if (state.zaki_state) |mgr| {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                mgr.replaceJobsJson(user_id, "main", body) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
                };
            } else {
                writeFile(user_ctx.cron_path, body) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
                };
            }
            return .{ .body = "{\"status\":\"updated\"}" };
        }
        if (std.mem.eql(u8, method, "DELETE")) {
            if (state.zaki_state) |mgr| {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                mgr.clearJobs(user_id) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
                };
            } else {
                writeFile(user_ctx.cron_path, "[]\n") catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
                };
            }
            return .{ .body = "{\"status\":\"deleted\"}" };
        }
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "secrets")) {
        if (!std.mem.eql(u8, method, "GET")) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        }
        if (state.zaki_state) |mgr| {
            const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
            const keys = mgr.listSecretKeys(req_allocator, user_id) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"list secrets failed\"}" };
            };
            defer {
                for (keys) |k| req_allocator.free(k);
                req_allocator.free(keys);
            }
            var resp: std.ArrayListUnmanaged(u8) = .empty;
            defer resp.deinit(req_allocator);
            const w = resp.writer(req_allocator);
            w.writeAll("{\"keys\":[") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            for (keys, 0..) |key, idx| {
                if (idx > 0) w.writeAll(",") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, key) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            }
            w.writeAll("]}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            return .{ .body = resp.toOwnedSlice(req_allocator) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" } };
        }
        return .{ .body = "{\"keys\":[]}" };
    }

    if (std.mem.startsWith(u8, parsed.subpath, "secrets/")) {
        // D8 (S2.12–S2.16) — hard replacement of the legacy
        // secrets/<key> surface. The old GET returned plaintext
        // (plan.md §3 explicit vulnerability); the old PUT/DELETE
        // mutated without confirmation. The new surface is
        // metadata-only + two-phase mutation gated by the
        // ConfirmationTokenStore (src/gateway/secret_vault.zig).
        // BFF callers that depended on the legacy GET-plaintext
        // behavior MUST migrate to caching the value at PUT time;
        // nullalis no longer reveals secrets post-save.
        //
        // Routes dispatched here:
        //   GET    secrets/<key>          → metadata (S2.12)
        //   POST   secrets/<key>/prepare  → confirmation token (S2.13)
        //   PUT    secrets/<key>          → write (S2.14, token required)
        //   DELETE secrets/<key>          → delete (S2.15, token required)
        //   GET    secrets/<key>/audit    → recent mutations (S2.16)
        const rest = parsed.subpath["secrets/".len..];
        const prepare_suffix = "/prepare";
        const audit_suffix = "/audit";

        const Route = union(enum) {
            prepare: []const u8, // inner is the secret key
            audit: []const u8,
            key_only: []const u8,
        };

        const route: Route = blk: {
            if (std.mem.endsWith(u8, rest, prepare_suffix) and rest.len > prepare_suffix.len) {
                break :blk .{ .prepare = rest[0 .. rest.len - prepare_suffix.len] };
            }
            if (std.mem.endsWith(u8, rest, audit_suffix) and rest.len > audit_suffix.len) {
                break :blk .{ .audit = rest[0 .. rest.len - audit_suffix.len] };
            }
            break :blk .{ .key_only = rest };
        };

        const secret_key: []const u8 = switch (route) {
            .prepare => |k| k,
            .audit => |k| k,
            .key_only => |k| k,
        };
        if (!isValidIdentifier(secret_key)) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_secret_key\"}" };
        }

        const mgr = state.zaki_state orelse {
            // Gated API requires DB-backed audit. File-only backends
            // can't satisfy the mutation audit contract; rather than
            // falling back silently we 503 so operators notice.
            return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"secret_vault_requires_state_backend\"}" };
        };
        const user_id_numeric = parseNumericUserId(scoped_user_id) catch {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
        };
        const actor_id = extractZakiUserId(raw_request);

        // S2.13 — POST secrets/<key>/prepare
        if (route == .prepare) {
            if (!std.mem.eql(u8, method, "POST")) {
                return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
            }
            const body = extractBody(raw_request) orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing_body\",\"detail\":\"expected {\\\"action\\\":\\\"put\\\"|\\\"delete\\\"}\"}",
            };
            const action_str = jsonStringField(body, "action") orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing_action\",\"detail\":\"expected \\\"put\\\" or \\\"delete\\\"\"}",
            };
            const action = secret_vault.SecretAction.fromSlice(action_str) orelse {
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_action\",\"detail\":\"must be \\\"put\\\" or \\\"delete\\\"\"}" };
            };

            var token_buf: [secret_vault.TOKEN_HEX_LEN]u8 = undefined;
            const token = state.secret_tokens.prepare(scoped_user_id, secret_key, action, &token_buf) catch {
                mgr.recordSecretMutation(user_id_numeric, secret_key, action.toSlice(), actor_id, "prepare_failed", null) catch {};
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"token_prepare_failed\"}" };
            };

            mgr.recordSecretMutation(user_id_numeric, secret_key, action.toSlice(), actor_id, "prepare_issued", null) catch {};

            const ttl = state.secret_tokens.ttl_secs;
            const expires_at = std.time.timestamp() + ttl;
            var resp: std.ArrayListUnmanaged(u8) = .empty;
            defer resp.deinit(req_allocator);
            const w = resp.writer(req_allocator);
            w.print("{{\"token\":\"{s}\",\"expires_at_unix\":{d},\"action\":\"{s}\"}}", .{ token, expires_at, action.toSlice() }) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            };
            return .{ .body = resp.toOwnedSlice(req_allocator) catch "{\"error\":\"response build failed\"}" };
        }

        // S2.16 — GET secrets/<key>/audit
        if (route == .audit) {
            if (!std.mem.eql(u8, method, "GET")) {
                return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
            }
            const records = mgr.listSecretMutations(req_allocator, user_id_numeric, 25) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"audit_read_failed\"}" };
            };
            defer {
                for (records) |r| r.deinit(req_allocator);
                req_allocator.free(records);
            }
            var resp: std.ArrayListUnmanaged(u8) = .empty;
            defer resp.deinit(req_allocator);
            const w = resp.writer(req_allocator);
            w.print("{{\"key\":\"{s}\",\"mutations\":[", .{secret_key}) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            };
            var first: bool = true;
            for (records) |r| {
                // Filter to the requested key only — the DB query pulls ALL
                // recent mutations for the user; the audit endpoint scopes
                // to one key. (Alternative would be a key-filtered query,
                // but the current list is capped at 100 rows total — cheap
                // to filter in memory.)
                if (!std.mem.eql(u8, r.key, secret_key)) continue;
                if (!first) w.writeAll(",") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                first = false;
                w.writeAll("{\"id\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, r.id) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"action\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, r.action) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"outcome\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, r.outcome) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"actor\":") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                if (r.actor) |a| {
                    w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                    jsonEscapeInto(w, a) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                    w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                } else {
                    w.writeAll("null") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                }
                w.print(",\"at_unix\":{d}}}", .{r.at_unix}) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            }
            w.writeAll("]}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            return .{ .body = resp.toOwnedSlice(req_allocator) catch "{\"error\":\"response build failed\"}" };
        }

        // route == .key_only — GET metadata / PUT / DELETE
        if (std.mem.eql(u8, method, "GET")) {
            // S2.12 — metadata only, NEVER reveal plaintext.
            const meta = mgr.getSecretMetadata(req_allocator, user_id_numeric, secret_key) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"metadata_read_failed\"}" };
            } orelse return .{ .status = "404 Not Found", .body = "{\"error\":\"secret_not_found\"}" };
            var resp: std.ArrayListUnmanaged(u8) = .empty;
            defer resp.deinit(req_allocator);
            const w = resp.writer(req_allocator);
            w.print("{{\"key\":\"{s}\",\"created_at_unix\":{d},\"updated_at_unix\":{d}}}", .{
                secret_key,
                meta.created_at_unix,
                meta.updated_at_unix,
            }) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            return .{ .body = resp.toOwnedSlice(req_allocator) catch "{\"error\":\"response build failed\"}" };
        }

        if (std.mem.eql(u8, method, "PUT")) {
            // S2.14 — write requires a prior prepare token for action=put.
            const body = extractBody(raw_request) orelse return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_body\"}" };
            const token = jsonStringField(body, "confirmation_token") orelse {
                mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "rejected_no_token", null) catch {};
                return .{ .status = "401 Unauthorized", .body = "{\"error\":\"confirmation_token_required\",\"detail\":\"call POST /secrets/<key>/prepare first\"}" };
            };
            const value = jsonStringField(body, "value") orelse {
                mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "rejected_no_value", null) catch {};
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_value\"}" };
            };

            switch (state.secret_tokens.consume(token, scoped_user_id, secret_key, .put)) {
                .ok => {},
                .not_found => {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "rejected_token_invalid", null) catch {};
                    return .{ .status = "401 Unauthorized", .body = "{\"error\":\"token_invalid\"}" };
                },
                .expired => {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "rejected_token_expired", null) catch {};
                    return .{ .status = "401 Unauthorized", .body = "{\"error\":\"token_expired\"}" };
                },
                .mismatch => {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "rejected_action_mismatch", null) catch {};
                    return .{ .status = "401 Unauthorized", .body = "{\"error\":\"token_action_mismatch\"}" };
                },
            }

            if (std.mem.eql(u8, secret_key, "telegram_bot_token")) {
                const normalized = normalizeTelegramBotToken(value);
                if (!isLikelyTelegramBotToken(normalized)) {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "rejected_invalid_format", "telegram_bot_token") catch {};
                    return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_telegram_bot_token\"}" };
                }
            }
            const write_value = if (std.mem.eql(u8, secret_key, "telegram_bot_token"))
                normalizeTelegramBotToken(value)
            else
                value;
            mgr.putSecret(user_id_numeric, secret_key, write_value) catch {
                mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "write_failed", null) catch {};
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write_failed\"}" };
            };
            mgr.recordSecretMutation(user_id_numeric, secret_key, "put", actor_id, "ok", null) catch {};
            return .{ .body = "{\"status\":\"updated\"}" };
        }

        if (std.mem.eql(u8, method, "DELETE")) {
            // S2.15 — delete requires a prior prepare token for action=delete.
            const body = extractBody(raw_request) orelse return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing_body\",\"detail\":\"expected {\\\"confirmation_token\\\":\\\"...\\\"}\"}" };
            const token = jsonStringField(body, "confirmation_token") orelse {
                mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "rejected_no_token", null) catch {};
                return .{ .status = "401 Unauthorized", .body = "{\"error\":\"confirmation_token_required\"}" };
            };

            switch (state.secret_tokens.consume(token, scoped_user_id, secret_key, .delete)) {
                .ok => {},
                .not_found => {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "rejected_token_invalid", null) catch {};
                    return .{ .status = "401 Unauthorized", .body = "{\"error\":\"token_invalid\"}" };
                },
                .expired => {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "rejected_token_expired", null) catch {};
                    return .{ .status = "401 Unauthorized", .body = "{\"error\":\"token_expired\"}" };
                },
                .mismatch => {
                    mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "rejected_action_mismatch", null) catch {};
                    return .{ .status = "401 Unauthorized", .body = "{\"error\":\"token_action_mismatch\"}" };
                },
            }

            const deleted = mgr.deleteSecret(user_id_numeric, secret_key) catch {
                mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "write_failed", null) catch {};
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"delete_failed\"}" };
            };
            if (!deleted) {
                mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "not_found", null) catch {};
                return .{ .status = "404 Not Found", .body = "{\"error\":\"secret_not_found\"}" };
            }
            mgr.recordSecretMutation(user_id_numeric, secret_key, "delete", actor_id, "ok", null) catch {};
            return .{ .body = "{\"status\":\"deleted\"}" };
        }

        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\"}" };
    }

    if (parseUserChannelBindingsSubpath(parsed.subpath)) |bindings_path| {
        const mgr = state.zaki_state orelse return .{
            .status = "501 Not Implemented",
            .body = "{\"error\":\"state backend does not support channel bindings\"}",
        };
        const user_id_numeric = parseNumericUserId(scoped_user_id) catch return .{
            .status = "400 Bad Request",
            .body = "{\"error\":\"invalid user\"}",
        };

        if (std.mem.eql(u8, method, "GET")) {
            if (bindings_path.binding_id != null) {
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"GET requires bindings collection path\"}" };
            }
            const bindings = mgr.listChannelIdentityBindings(req_allocator, user_id_numeric, bindings_path.channel) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"list bindings failed\"}" };
            };
            defer {
                for (bindings) |*entry| entry.deinit(req_allocator);
                req_allocator.free(bindings);
            }

            var resp: std.ArrayListUnmanaged(u8) = .empty;
            defer resp.deinit(req_allocator);
            const w = resp.writer(req_allocator);
            w.writeAll("{\"channel\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            jsonEscapeInto(w, bindings_path.channel) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            w.writeAll("\",\"items\":[") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            for (bindings, 0..) |entry, idx| {
                if (idx > 0) {
                    w.writeAll(",") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                }
                w.writeAll("{\"id\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, entry.id) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"account_id\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, entry.account_id) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"principal_key\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, entry.principal_key) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"scope_key\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                jsonEscapeInto(w, entry.scope_key) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                w.writeAll("\",\"thread_key\":") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                if (entry.thread_key) |thread_key| {
                    w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                    jsonEscapeInto(w, thread_key) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                    w.writeAll("\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                } else {
                    w.writeAll("null") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
                }
                w.writeAll("}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            }
            w.writeAll("]}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            return .{ .body = resp.toOwnedSlice(req_allocator) catch "{\"error\":\"response build failed\"}" };
        }

        if (std.mem.eql(u8, method, "POST")) {
            if (bindings_path.binding_id != null) {
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"POST requires bindings collection path\"}" };
            }
            const body = extractBody(raw_request) orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing body\"}",
            };
            const account_id = jsonStringField(body, "account_id") orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing account_id\"}",
            };
            const principal_key = jsonStringField(body, "principal_key") orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing principal_key\"}",
            };
            const scope_key = jsonStringField(body, "scope_key") orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"missing scope_key\"}",
            };
            const thread_key = jsonStringField(body, "thread_key");
            const peer_kind = jsonStringField(body, "peer_kind");
            const peer_id = jsonStringField(body, "peer_id");
            const metadata_json = jsonStringField(body, "metadata_json") orelse "{}";
            if (account_id.len == 0 or principal_key.len == 0 or scope_key.len == 0) {
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid binding fields\"}" };
            }
            const binding_id = mgr.upsertChannelIdentityBinding(
                req_allocator,
                user_id_numeric,
                bindings_path.channel,
                account_id,
                principal_key,
                scope_key,
                thread_key,
                peer_kind,
                peer_id,
                metadata_json,
            ) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"upsert binding failed\"}" };
            };
            defer req_allocator.free(binding_id);
            inbound_canonicalizer.invalidateCacheForIdentity(.{
                .channel = bindings_path.channel,
                .account_id = account_id,
                .principal_key = principal_key,
                .scope_key = scope_key,
                .thread_key = thread_key,
                .fallback_session_key = "",
            });

            var resp: std.ArrayListUnmanaged(u8) = .empty;
            defer resp.deinit(req_allocator);
            const rw = resp.writer(req_allocator);
            rw.writeAll("{\"status\":\"upserted\",\"id\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            jsonEscapeInto(rw, binding_id) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            rw.writeAll("\"}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
            return .{ .body = resp.toOwnedSlice(req_allocator) catch "{\"error\":\"response build failed\"}" };
        }

        if (std.mem.eql(u8, method, "DELETE")) {
            const binding_id = bindings_path.binding_id orelse return .{
                .status = "400 Bad Request",
                .body = "{\"error\":\"DELETE requires binding id\"}",
            };
            const deleted = mgr.deleteChannelIdentityBinding(user_id_numeric, binding_id) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"delete binding failed\"}" };
            };
            if (!deleted) return .{ .status = "404 Not Found", .body = "{\"error\":\"binding not found\"}" };
            inbound_canonicalizer.invalidateAllCache();
            return .{ .body = "{\"status\":\"deleted\"}" };
        }

        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "channels/telegram/connect")) {
        if (!std.mem.eql(u8, method, "POST")) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        }
        const body = extractBody(raw_request) orelse "{}";
        const secret_path = resolveSecretPath(req_allocator, user_ctx.secrets_dir, "telegram_bot_token") catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"secret path failed\"}" };
        };
        defer req_allocator.free(secret_path);
        const allow_from_override = jsonStringArrayFieldOwned(req_allocator, body, "allow_from");
        defer if (allow_from_override) |arr| {
            if (arr.len > 0) freeOwnedStringArray(req_allocator, arr);
        };

        const input_bot_token = jsonStringField(body, "bot_token");
        if (input_bot_token) |tok| {
            const normalized_tok = normalizeTelegramBotToken(tok);
            if (!isLikelyTelegramBotToken(normalized_tok)) {
                return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid bot_token\"}" };
            }
            if (state.zaki_state) |mgr| {
                const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
                mgr.putSecret(user_id, "telegram_bot_token", normalized_tok) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"failed storing bot token\"}" };
                };
                // Best-effort local fallback sync for degraded/local tenant runtime reads.
                _ = syncTelegramSecretFallbackBestEffort(secret_path, normalized_tok);
            } else {
                writeFile(secret_path, normalized_tok) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"failed storing bot token\"}" };
                };
            }
        }
        const bot_token_raw = readTrimmedSecretFile(req_allocator, secret_path) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"failed reading bot token\"}" };
        };
        defer if (state.zaki_state != null and bot_token_raw.len > 0) req_allocator.free(bot_token_raw);
        const bot_token = normalizeTelegramBotToken(bot_token_raw);
        if (bot_token.len == 0) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing bot_token\"}" };
        }
        if (!isLikelyTelegramBotToken(bot_token)) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid bot_token\"}" };
        }
        const account_id = jsonStringField(body, "account_id") orelse state.telegram_account_id;
        if (!isValidIdentifier(account_id)) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid account_id\"}" };
        }
        const allow_from: []const []const u8 = if (allow_from_override) |items|
            items
        else if (state.telegram_allow_from.len > 0)
            state.telegram_allow_from
        else
            &.{};

        const webhook_url = blk: {
            if (jsonStringField(body, "webhook_url")) |url| break :blk req_allocator.dupe(u8, url) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"alloc failed\"}" };
            };
            if (jsonStringField(body, "webhook_base_url")) |base_url| {
                break :blk buildWebhookUrlForUser(req_allocator, base_url, scoped_user_id) catch {
                    return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid webhook_base_url (https required)\"}" };
                };
            }
            if (extractHeader(raw_request, "X-Webhook-Base-Url")) |base_header| {
                break :blk buildWebhookUrlForUser(req_allocator, std.mem.trim(u8, base_header, " \t\r\n"), scoped_user_id) catch {
                    return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid X-Webhook-Base-Url (https required)\"}" };
                };
            }
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing webhook_url or webhook_base_url\"}" };
        };
        defer req_allocator.free(webhook_url);
        if (!std.mem.startsWith(u8, webhook_url, "https://")) {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"webhook_url must use https\"}" };
        }

        const webhook_secret_token = blk: {
            if (jsonStringField(body, "webhook_secret_token")) |provided| {
                const normalized = normalizeTelegramSecretToken(provided);
                if (normalized.len >= 8) break :blk req_allocator.dupe(u8, normalized) catch {
                    return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"alloc failed\"}" };
                };
            }
            break :blk generateWebhookSecretToken(req_allocator) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"secret generation failed\"}" };
            };
        };
        defer req_allocator.free(webhook_secret_token);

        const drop_pending_updates = jsonBoolField(body, "drop_pending_updates") orelse false;
        var payload: std.ArrayListUnmanaged(u8) = .empty;
        defer payload.deinit(req_allocator);
        const pw = payload.writer(req_allocator);
        pw.writeAll("{\"url\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"payload build failed\"}" };
        jsonEscapeInto(pw, webhook_url) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"payload build failed\"}" };
        pw.writeAll("\",\"secret_token\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"payload build failed\"}" };
        jsonEscapeInto(pw, webhook_secret_token) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"payload build failed\"}" };
        pw.print("\",\"drop_pending_updates\":{s}}}", .{if (drop_pending_updates) "true" else "false"}) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"payload build failed\"}" };
        };

        const set_webhook_resp = telegramApiCall(req_allocator, bot_token, "setWebhook", payload.items) catch {
            return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram setWebhook request failed\"}" };
        };
        if (!(jsonBoolField(set_webhook_resp, "ok") orelse false)) {
            return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram setWebhook rejected\"}" };
        }

        const get_webhook_resp = telegramApiCall(req_allocator, bot_token, "getWebhookInfo", "{}") catch {
            return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram getWebhookInfo request failed\"}" };
        };
        if (!(jsonBoolField(get_webhook_resp, "ok") orelse false)) {
            return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram getWebhookInfo rejected\"}" };
        }
        if (jsonStringField(get_webhook_resp, "url")) |actual_url| {
            if (!std.mem.eql(u8, std.mem.trim(u8, actual_url, " \t\r\n"), webhook_url)) {
                return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram webhook url mismatch after connect\"}" };
            }
        }

        var state_payload: std.ArrayListUnmanaged(u8) = .empty;
        defer state_payload.deinit(req_allocator);
        const sw = state_payload.writer(req_allocator);
        sw.writeAll("{\"connected\":true,\"webhook_url\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        jsonEscapeInto(sw, webhook_url) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        sw.writeAll("\",\"webhook_secret_token\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        jsonEscapeInto(sw, webhook_secret_token) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        sw.writeAll("\",\"account_id\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        jsonEscapeInto(sw, account_id) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        sw.writeAll("\",\"allow_from\":") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        jsonWriteStringArray(sw, allow_from) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        sw.print(",\"connected_at\":{d}}}", .{std.time.timestamp()}) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"state build failed\"}" };
        if (state.zaki_state) |mgr| {
            const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
            mgr.putTelegramStateJson(user_id, state_payload.items) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            };
            // Best-effort local fallback sync for degraded/local tenant runtime reads.
            _ = syncTelegramStateFallbackBestEffort(user_ctx.telegram_path, state_payload.items);
        } else {
            writeTelegramFallbackStateFile(user_ctx.telegram_path, state_payload.items) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"write failed\"}" };
            };
        }

        var resp: std.ArrayListUnmanaged(u8) = .empty;
        defer resp.deinit(req_allocator);
        const rw = resp.writer(req_allocator);
        rw.writeAll("{\"status\":\"connected\",\"webhook_url\":\"") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
        jsonEscapeInto(rw, webhook_url) catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
        rw.writeAll("\",\"channel\":\"telegram\"}") catch return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"response build failed\"}" };
        return .{ .body = resp.toOwnedSlice(req_allocator) catch "{\"status\":\"connected\"}" };
    }

    if (std.mem.eql(u8, parsed.subpath, "channels/telegram/disconnect")) {
        const method_allowed = std.mem.eql(u8, method, "DELETE") or std.mem.eql(u8, method, "POST");
        if (!method_allowed) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
        }
        const body = extractBody(raw_request) orelse "{}";
        const secret_path = resolveSecretPath(req_allocator, user_ctx.secrets_dir, "telegram_bot_token") catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"secret path failed\"}" };
        };
        defer req_allocator.free(secret_path);
        const body_bot_token = jsonStringField(body, "bot_token");
        const stored_bot_token = if (state.zaki_state) |mgr| blk: {
            const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
            const secret_value = mgr.getSecret(req_allocator, user_id, "telegram_bot_token") catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"failed reading bot token\"}" };
            };
            break :blk secret_value orelse "";
        } else blk: {
            break :blk readFileOrDefault(req_allocator, secret_path, "") catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"failed reading bot token\"}" };
            };
        };
        defer if (state.zaki_state != null and stored_bot_token.len > 0 and body_bot_token == null) req_allocator.free(stored_bot_token);
        const token_raw = body_bot_token orelse stored_bot_token;
        const bot_token = std.mem.trim(u8, token_raw, " \t\r\n");
        if (bot_token.len > 0) {
            const drop_pending_updates = jsonBoolField(body, "drop_pending_updates") orelse false;
            const delete_payload = if (drop_pending_updates)
                "{\"drop_pending_updates\":true}"
            else
                "{\"drop_pending_updates\":false}";
            const delete_resp = telegramApiCall(req_allocator, bot_token, "deleteWebhook", delete_payload) catch {
                return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram deleteWebhook request failed\"}" };
            };
            if (!(jsonBoolField(delete_resp, "ok") orelse false)) {
                return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"telegram deleteWebhook rejected\"}" };
            }
        }

        if (state.zaki_state) |mgr| {
            const user_id = parseNumericUserId(scoped_user_id) catch return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid user\"}" };
            mgr.deleteTelegramState(user_id) catch {
                return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"disconnect failed\"}" };
            };
            _ = deleteTelegramFallbackFilesBestEffort(user_ctx.telegram_path, user_ctx.channel_state_path);
        } else {
            deleteTelegramFallbackFiles(user_ctx.telegram_path, user_ctx.channel_state_path) catch |err| {
                return .{ .status = "500 Internal Server Error", .body = switch (err) {
                    else => "{\"error\":\"disconnect failed\"}",
                } };
            };
        }
        return .{ .body = "{\"status\":\"disconnected\",\"channel\":\"telegram\"}" };
    }

    // ── Voice endpoints (Phase 3 — STT / TTS) ──────────────────────────
    if (std.mem.eql(u8, parsed.subpath, "voice/transcribe")) {
        return handleVoiceTranscribe(req_allocator, method, raw_request, config_opt);
    }
    if (std.mem.eql(u8, parsed.subpath, "voice/synthesize")) {
        return handleVoiceSynthesize(req_allocator, method, raw_request, config_opt);
    }

    // ── Attachments (Phase 3.9 — user file uploads) ─────────────────────
    // POST /api/v1/users/{id}/attachments
    // Body: {"filename":"<safe name>","content_b64":"<base64>"}
    // Writes to {workspace_path}/attachments/<safe_name>. Agent reads via
    // the file_read tool with path "attachments/<safe_name>".
    if (std.mem.eql(u8, parsed.subpath, "attachments")) {
        return handleAttachmentUpload(req_allocator, method, raw_request, &user_ctx);
    }

    // ── /brain/graph — V1.5 day-2 task 2B ────────────────────────────────
    // GET /api/v1/users/{id}/brain/graph[?since=<unix>&max_nodes=N&node_kinds=csv]
    // Returns nodes + edges (session, semantic, reference) for the user's
    // memory. Powers the frontend `/brain` page. Bi-temporal correctness:
    // listMemoriesBrainVisible filters superseded + agent bookkeeping.
    //
    // V1.5.1: ensure the tenant runtime is materialised before the handler
    // reads `state.tenant_runtimes` for the vector store. Without this,
    // `semantic_degraded` fires on the first request after a gateway
    // restart for any user who hasn't yet had an agent turn — the
    // hashmap is empty, vector_store_opt stays null, all semantic edges
    // disappear. Pay one-time cold-start (~500ms-2s) here so subsequent
    // requests are warm and edges render.
    if (std.mem.eql(u8, parsed.subpath, "brain/graph")) {
        if (config_opt) |cfg| {
            _ = getTenantRuntime(state, cfg, &user_ctx) catch |err| {
                log.warn("brain.graph.tenant_init_failed user={s} err={s} — semantic edges will degrade", .{ user_ctx.user_id, @errorName(err) });
            };
        }
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainGraph(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/timeline — V1.5 day-2 task 3 ──────────────────────────────
    // GET /api/v1/users/{id}/brain/timeline[?cursor=<b64>&limit=N&from=<unix>&to=<unix>]
    // Cursor-paginated chronological view of user's memory. Stable across
    // concurrent writes via `(created_at, id)` tuple cursor.
    if (std.mem.eql(u8, parsed.subpath, "brain/timeline")) {
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainTimeline(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/search — V1.6 commit 12 (M2) ──────────────────────────────
    // GET /api/v1/users/{id}/brain/search?q=<text>[&limit=N]
    // Server-side keyword + lemmatized BM25 search across brain-visible
    // memories. Same hygiene contract as /brain/graph (continuity / autosave /
    // tombstones hidden via memory_root.isBrainVisibleKey post-filter).
    if (std.mem.eql(u8, parsed.subpath, "brain/search")) {
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainSearch(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/documents — V1.6 commit 15 ────────────────────────────────
    // GET /api/v1/users/{id}/brain/documents[?limit=N]
    // Two-tier document view (supermemory parity). Each document = a session
    // that has produced summaries; aggregate of summary count, latest
    // timestamp, latest excerpt.
    if (std.mem.eql(u8, parsed.subpath, "brain/documents")) {
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainDocuments(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/diff — V1.7a-6 ────────────────────────────────────────────
    // GET /api/v1/users/{id}/brain/diff?date=YYYY-MM-DD[&window_days=N]
    // GET /api/v1/users/{id}/brain/diff?from=<unix>&to=<unix>
    // Temporal evolution surface (Eleanor Konik's #1 obsidian-graph use
    // case). Returns births (created_at in window) + deaths (valid_to in
    // window) as two independent event streams, with link_type surfaced
    // per-row. Same hygiene contract as /brain/graph.
    if (std.mem.eql(u8, parsed.subpath, "brain/diff")) {
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainDiff(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/local-graph — V1.7a-7 ─────────────────────────────────────
    // GET /api/v1/users/{id}/brain/local-graph?center_key=<key>&depth=N[&max_nodes=M]
    // N-hop local subgraph from a center node — wraps the existing
    // graph_expand BFS (V1.6 cmt10) with one seed and emits a /brain/graph-
    // compatible response shape so the FE renders with the same code.
    // Same hygiene contract as /brain/graph; rejects archived center.
    if (std.mem.eql(u8, parsed.subpath, "brain/local-graph")) {
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainLocalGraph(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/orphans — V1.7a-8a ────────────────────────────────────────
    // GET /api/v1/users/{id}/brain/orphans[?limit=N]
    // Brain-visible memories with NO active edges. Powers the FE orphan
    // rail. Bi-temporal: applies validity filter to BOTH memories and
    // memory_edges so a row that LOST all its edges via supersession
    // surfaces as an orphan in the present.
    if (std.mem.eql(u8, parsed.subpath, "brain/orphans")) {
        const brain_target = extractRequestTarget(raw_request) orelse base_path;
        return handleBrainOrphans(req_allocator, method, scoped_user_id, brain_target, state);
    }

    // ── /brain/me — V1.11 hardening (2026-05-08, FE spec #2) ─────────────
    // GET /api/v1/users/{id}/brain/me
    //
    // Returns the canonical "this is the user" memory. Powers focus-mode-
    // as-primary in the brain page (TheBrain pattern): a stable anchor
    // for the centered-graph view. FE pre-fix used a degree heuristic
    // that was brittle (turn-to-turn churn shifted the pick); server-side
    // selection is stable because the picker reads identity-class edges
    // (NAME/IS/LIVES_IN/WORKS_AT/PREFERS/etc — see listIdentityFacts) and
    // returns the highest-confidence one.
    //
    // Response shape:
    //   { key, summary, kind, valid_to, importance }  on hit
    //   { error: "no_self_anchor" }                   on 404 (cold corpus)
    if (std.mem.eql(u8, parsed.subpath, "brain/me")) {
        return handleBrainMe(req_allocator, method, scoped_user_id, state);
    }

    // ── /brain/communities — V1.7a-9d ────────────────────────────────────
    // GET  /api/v1/users/{id}/brain/communities             — list summaries
    // POST /api/v1/users/{id}/brain/communities/recompute   — manual trigger
    // V1.7-ship S1: recompute now wires the agent's sidecar provider as
    // the LlmNamer (replacing the V1 fallback "Cluster <id>" names with
    // real "Engineering work" / "Daily routines" / etc.). When tenant
    // runtime cannot be resolved (PG-only test paths, pre-tenant boot),
    // we pass null and the pipeline degrades to fallback names — same
    // behavior as V1.7a-9d shipped.
    if (std.mem.eql(u8, parsed.subpath, "brain/communities")) {
        return handleBrainCommunities(req_allocator, method, scoped_user_id, state);
    }
    if (std.mem.eql(u8, parsed.subpath, "brain/communities/recompute")) {
        const tenant_runtime: ?*TenantRuntime = blk: {
            if (config_opt) |cfg| {
                if (getTenantRuntime(state, cfg, &user_ctx)) |rt| {
                    break :blk rt;
                } else |err| {
                    log.warn("brain.communities.recompute_tenant_lookup_failed user={s} err={s} — falling back to NULL namer", .{ user_ctx.user_id, @errorName(err) });
                    break :blk null;
                }
            }
            break :blk null;
        };
        return handleBrainCommunitiesRecompute(req_allocator, method, scoped_user_id, tenant_runtime, state);
    }

    // ── /brain/memory/{key} — V1.6 commit 13 (M3) ────────────────────────
    // GET /api/v1/users/{id}/brain/memory/{key}
    // Drilldown view: full memory row + edges + chronological event history.
    // Powers the FE per-fact detail page. Same hygiene contract as
    // /brain/graph (returns 404 for hidden keys).
    if (std.mem.startsWith(u8, parsed.subpath, "brain/memory/")) {
        const key_raw = parsed.subpath["brain/memory/".len..];
        // Strip trailing query string if present (the route parser
        // typically separates this, but guard for safety).
        const qmark = std.mem.indexOfScalar(u8, key_raw, '?');
        const key = if (qmark) |q| key_raw[0..q] else key_raw;
        return handleBrainMemoryDetail(req_allocator, method, scoped_user_id, key, state);
    }

    // ── /brain/compose — V1.5 day-3 chunk 3C ─────────────────────────────
    // POST /api/v1/users/{id}/brain/compose
    // Body: { title, content, references[], category?, key? }
    // Synthesizes 2+ existing memories into one consolidated fact with
    // server-validated provenance. Mirror of the `compose_memory` agent
    // tool but exposes the capability to the frontend `/brain` page.
    if (std.mem.eql(u8, parsed.subpath, "brain/compose")) {
        return handleBrainCompose(req_allocator, method, scoped_user_id, raw_request, state);
    }

    // ── Session CRUD endpoints (Phase 3.5) ──────────────────────────────
    // In tenant mode, the per-worker session_mgr_opt is null. Resolve the
    // tenant runtime's session manager via the user ID lookup instead.
    const effective_session_mgr: ?*session_mod.SessionManager = session_mgr_opt orelse blk: {
        state.tenant_runtime_mutex.lock();
        defer state.tenant_runtime_mutex.unlock();
        if (state.tenant_runtimes.get(scoped_user_id)) |runtime| {
            break :blk &runtime.session_mgr;
        }
        break :blk null;
    };
    if (std.mem.eql(u8, parsed.subpath, "sessions")) {
        return handleSessionList(req_allocator, method, scoped_user_id, effective_session_mgr, state.zaki_state);
    }
    if (std.mem.startsWith(u8, parsed.subpath, "sessions/")) {
        const rest = parsed.subpath["sessions/".len..];
        return handleSessionAction(req_allocator, method, scoped_user_id, rest, effective_session_mgr, raw_request, state.zaki_state);
    }

    // ── GDPR data purge (Sprint 7B — S7.6) ──────────────────────────────
    // DELETE /api/v1/users/:id/data removes every trace of the user
    // across postgres, pgvector, filesystem, and the session cache.
    //
    // Defense in depth:
    //  1. `X-Internal-Token` header (enforced at handleApiRoute entry).
    //  2. Body must include `{"confirm":"PURGE-USER-<id>"}` where `<id>`
    //     matches the path user_id — so a mis-routed operator request
    //     (wrong user in URL) fails the body check and purges nothing.
    //  3. DELETE verb only; any other method returns 405.
    //
    // Not 2-phase token (like the secret vault): this endpoint is for
    // operators holding the internal service token, not for frontend
    // users. Adding a prepare step would only slow the operator without
    // raising the effective security bar — they already hold the
    // single credential that gates every other /api/v1/* call. If this
    // surface is ever exposed to end-users, upgrade to the secret-vault
    // prepare/consume pattern (see D26 in the deferred register).
    if (std.mem.eql(u8, parsed.subpath, "data")) {
        if (!std.mem.eql(u8, method, "DELETE")) {
            return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method_not_allowed\",\"detail\":\"use DELETE to purge user data\"}" };
        }
        return handleGdprDataPurge(req_allocator, raw_request, scoped_user_id, state, effective_session_mgr);
    }

    // ── Task query endpoints (WP2.2) ────────────────────────────────────
    // Resolve the per-tenant TaskDelivery by looking up the tenant runtime.
    // We do NOT materialize a runtime on demand — a GET that arrives before
    // any agent work has happened for this user simply sees no tasks.
    if (std.mem.eql(u8, parsed.subpath, "tasks") or std.mem.startsWith(u8, parsed.subpath, "tasks/")) {
        // Look up both task_delivery and subagent_manager under a single
        // tenant_runtime_mutex acquisition, then release the mutex before
        // invoking cancelQueued (which takes manager-internal locks and,
        // for the cancelled path, delivery-internal locks). This avoids
        // lock-order inversion with the maintenance/prune path while
        // preserving the "no runtime materialization on demand" invariant
        // of WP2.2/WP2.3.
        var effective_task_delivery: ?*tasks_mod.TaskDelivery = null;
        var effective_subagent_mgr: ?*subagent_mod.SubagentManager = null;
        {
            state.tenant_runtime_mutex.lock();
            defer state.tenant_runtime_mutex.unlock();
            if (state.tenant_runtimes.get(scoped_user_id)) |runtime| {
                effective_task_delivery = runtime.task_delivery;
                effective_subagent_mgr = runtime.subagent_manager;
            }
        }
        if (std.mem.eql(u8, parsed.subpath, "tasks")) {
            return handleTaskList(req_allocator, method, effective_task_delivery);
        }
        const rest = parsed.subpath["tasks/".len..];
        // Route /tasks/{task_id}/stop BEFORE the generic /tasks/{task_id}
        // GET so a canonical id that happens to end with `/stop` style
        // sub-path is dispatched to the stop handler (WP2.5).
        const stop_suffix = "/stop";
        if (rest.len > stop_suffix.len and std.mem.endsWith(u8, rest, stop_suffix)) {
            const stop_task_id = rest[0 .. rest.len - stop_suffix.len];
            return handleTaskStop(
                req_allocator,
                method,
                stop_task_id,
                effective_subagent_mgr,
                effective_task_delivery,
            );
        }
        return handleTaskGet(req_allocator, method, rest, effective_task_delivery);
    }

    // ── Scheduled-jobs list (V1.11 — 2026-05-07) ────────────────────────
    // GET /api/v1/users/{id}/jobs — surfaces the user's cron jobs so the
    // frontend can render a "Scheduled" panel. Read-only for now; the
    // agent's `schedule` tool owns mutations.
    if (std.mem.eql(u8, parsed.subpath, "jobs")) {
        const numeric_user_id = parseNumericUserId(scoped_user_id) catch {
            return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid_user_id\"}" };
        };
        return handleJobList(req_allocator, method, state.zaki_state, numeric_user_id);
    }

    // ── Diagnostics (context detail + memory doctor) ────────────────────
    // Read-only per-user endpoints that mirror the /context detail and
    // /memory doctor slash commands as JSON for the frontend PowerUserSheet.
    // Never materialize a session on demand.
    if (std.mem.eql(u8, parsed.subpath, "diagnostics/context")) {
        return handleUserDiagnosticsContext(req_allocator, method, session_mgr_opt, scoped_user_id);
    }
    if (std.mem.eql(u8, parsed.subpath, "diagnostics/memory-doctor")) {
        return handleUserDiagnosticsMemoryDoctor(req_allocator, method, session_mgr_opt, scoped_user_id);
    }

    // ── Usage summary endpoint (WP2.3) ──────────────────────────────────
    // Resolve the per-tenant UsageRuntime. Mirrors the task-read contract:
    // we never create a tenant runtime on demand — a GET before the user
    // has any agent activity returns a zero summary.
    if (std.mem.eql(u8, parsed.subpath, "usage")) {
        const effective_usage_rt: ?*usage_runtime_mod.UsageRuntime = blk: {
            state.tenant_runtime_mutex.lock();
            defer state.tenant_runtime_mutex.unlock();
            if (state.tenant_runtimes.get(scoped_user_id)) |runtime| {
                break :blk runtime.usage_rt;
            }
            break :blk null;
        };
        return handleUserUsage(req_allocator, method, effective_usage_rt);
    }

    // ── Run trace read-only endpoints (WP4.2) ───────────────────────────
    // Resolve the per-tenant RunTraceStore without materializing a tenant
    // runtime on demand. Collection returns empty when no runtime exists;
    // a specific run_id returns 404.
    if (std.mem.eql(u8, parsed.subpath, "traces") or
        std.mem.startsWith(u8, parsed.subpath, "traces/"))
    {
        const effective_trace_store: ?*run_trace_store_mod.RunTraceStore = blk: {
            state.tenant_runtime_mutex.lock();
            defer state.tenant_runtime_mutex.unlock();
            if (state.tenant_runtimes.get(scoped_user_id)) |runtime| {
                break :blk runtime.trace_store;
            }
            break :blk null;
        };
        if (std.mem.eql(u8, parsed.subpath, "traces")) {
            return handleTraceList(req_allocator, method, effective_trace_store);
        }
        const run_id = parsed.subpath["traces/".len..];
        return handleTraceGet(req_allocator, method, run_id, effective_trace_store);
    }

    return .{ .status = "404 Not Found", .body = "{\"error\":\"not found\"}" };
}

// ════════════════════════════════════════════════════════════════════════════
// Voice helpers
// ════════════════════════════════════════════════════════════════════════════

/// Copy a path slice into a fixed buffer and null-terminate it.
/// Returns null if the path is too long for the buffer.
fn toSentinelPath(buf: []u8, path: []const u8) ?[:0]const u8 {
    if (path.len >= buf.len) return null;
    @memcpy(buf[0..path.len], path);
    buf[path.len] = 0;
    return buf[0..path.len :0];
}

// ════════════════════════════════════════════════════════════════════════════
// Voice: STT (transcribe) and TTS (synthesize) API handlers
// ════════════════════════════════════════════════════════════════════════════

/// POST /api/v1/users/{id}/voice/transcribe
/// Body: {"audio":"<base64>","format":"webm"} (format optional, default "webm")
/// Returns: {"text":"transcribed text"}
fn handleVoiceTranscribe(
    allocator: std.mem.Allocator,
    method: []const u8,
    raw_request: []const u8,
    config_opt: ?*const Config,
) RouteResponse {
    if (!std.mem.eql(u8, method, "POST")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    const cfg = config_opt orelse return .{
        .status = "503 Service Unavailable",
        .body = "{\"error\":\"voice not configured\"}",
    };
    if (!cfg.audio_media.enabled) {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"voice not enabled\"}" };
    }
    const provider_name = cfg.audio_media.provider;
    const api_key = cfg.getProviderKey(provider_name) orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"voice api key not configured\"}" };
    };
    const body = extractBody(raw_request) orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing body\"}" };
    };
    const audio_b64 = jsonStringField(body, "audio") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing audio field\"}" };
    };
    if (audio_b64.len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"empty audio data\"}" };
    }
    // Cap base64 input at ~7.5MB (decodes to ~5.6MB raw audio)
    if (audio_b64.len > 10 * 1024 * 1024) {
        return .{ .status = "413 Payload Too Large", .body = "{\"error\":\"audio too large\"}" };
    }

    const format = jsonStringField(body, "format") orelse "webm";

    // Decode base64 → raw audio bytes
    const decoded_len = std.base64.standard.Decoder.calcSizeForSlice(audio_b64) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid base64\"}" };
    };
    const decoded = allocator.alloc(u8, decoded_len) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"alloc failed\"}" };
    };
    defer allocator.free(decoded);
    std.base64.standard.Decoder.decode(decoded, audio_b64) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid base64\"}" };
    };

    // Write to temp file (timestamp + random suffix to prevent collisions)
    const ts = std.time.milliTimestamp();
    var rand_bytes: [4]u8 = undefined;
    std.crypto.random.bytes(&rand_bytes);
    const rand_suffix: u32 = std.mem.readInt(u32, &rand_bytes, .little);
    var path_buf: [256]u8 = undefined;
    const tmp_path = std.fmt.bufPrint(&path_buf, "/tmp/nullalis_stt_{d}_{x}.{s}", .{ ts, rand_suffix, format }) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path build failed\"}" };
    };
    var z_buf: [257]u8 = undefined;
    const tmp_path_z = toSentinelPath(&z_buf, tmp_path) orelse {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path too long\"}" };
    };
    {
        const file = std.fs.createFileAbsolute(tmp_path_z, .{}) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"temp file write failed\"}" };
        };
        defer file.close();
        file.writeAll(decoded) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"temp file write failed\"}" };
        };
    }
    defer std.fs.deleteFileAbsolute(tmp_path_z) catch {};

    // Call Whisper API
    const endpoint = voice.resolveTranscriptionEndpoint(provider_name, cfg.audio_media.base_url);
    const text = voice.transcribeFile(allocator, api_key, endpoint, tmp_path, .{
        .model = cfg.audio_media.model,
        .language = cfg.audio_media.language,
    }) catch {
        return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"transcription failed\"}" };
    };
    defer allocator.free(text);

    // Build JSON response
    var resp: std.ArrayListUnmanaged(u8) = .empty;
    defer resp.deinit(allocator);
    const w = resp.writer(allocator);
    w.writeAll("{\"text\":\"") catch return response_build_err;
    jsonEscapeInto(w, text) catch return response_build_err;
    w.writeAll("\"}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &resp);
}

/// Validate an attachment filename. Returns true if safe.
/// Allows: A-Z, a-z, 0-9, dot, dash, underscore, space. Max 200 chars.
/// Rejects: slashes, backslashes, null bytes, leading dot, empty.
fn isSafeAttachmentFilename(name: []const u8) bool {
    // SwissWatch (2026-04-28, Nova directive — last-mile polish):
    // relaxed validation. Per Nova: "fix the filename to be better and
    // allow all, why do we need this gate at all?" The gate exists ONLY
    // to prevent path-traversal exploits that could escape the
    // attachments/ directory and write to arbitrary filesystem paths.
    // Everything else (parens, brackets, accents, emoji, UTF-8) is
    // legitimate filesystem content and should pass through.
    //
    // Pre-fix rejected real-world image filenames like "image (1).png",
    // "Screenshot [2026].png", "café.jpg" — browser-saved files commonly
    // hit those chars.
    //
    // What stays blocked (path-traversal + system-corruption vectors):
    //   - empty or > 255 bytes (POSIX filesystem limit on most kernels)
    //   - leading '.' (hidden files; .env / .ssh / .config exfil bait)
    //   - any byte < 0x20 (control chars including null, CR, LF, tab)
    //   - 0x7f (DEL)
    //   - '/' or '\' (path separator → cross-directory write)
    //   - ".." anywhere (parent-traversal — even mid-name like
    //     "a..b/c" breaks the contract)
    if (name.len == 0 or name.len > 255) return false;
    if (name[0] == '.') return false; // no hidden files
    for (name) |c| {
        if (c < 0x20 or c == 0x7f) return false; // control chars
        if (c == '/' or c == '\\') return false; // path separators
    }
    // Reject ".." anywhere (path traversal). This covers "../foo",
    // "foo/../bar" (slash already blocked but be explicit), and
    // ambiguous cases like "a..b" being interpreted by some tools.
    if (std.mem.indexOf(u8, name, "..") != null) return false;
    return true;
}

/// POST /api/v1/users/{id}/attachments
/// Body: {"filename":"AddGrowth.pdf","content_b64":"<base64>"}
/// Writes decoded bytes to {workspace_path}/attachments/{filename}.
/// Returns: {"path":"attachments/<filename>","bytes":<n>}
///
/// Security:
/// - Filename must match isSafeAttachmentFilename (no /, no .., no hidden).
/// - Max decoded size: 20 MB (matches multimodal cap).
/// - Written under the user's own workspace directory (per-user isolation
///   already enforced by UserContext selection above this call).
fn handleAttachmentUpload(
    allocator: std.mem.Allocator,
    method: []const u8,
    raw_request: []const u8,
    user_ctx: *const UserContext,
) RouteResponse {
    if (!std.mem.eql(u8, method, "POST")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    const body = extractBody(raw_request) orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing body\"}" };
    };
    const filename = jsonStringField(body, "filename") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing filename\"}" };
    };
    if (!isSafeAttachmentFilename(filename)) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"unsafe filename\"}" };
    }
    const content_b64 = jsonStringField(body, "content_b64") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing content_b64\"}" };
    };
    // Cap base64 input at ~27MB (decodes to ~20MB raw). Matches MAX_BODY_SIZE minus headroom.
    if (content_b64.len > 27 * 1024 * 1024) {
        return .{ .status = "413 Payload Too Large", .body = "{\"error\":\"attachment too large\"}" };
    }

    const decoded_len = std.base64.standard.Decoder.calcSizeForSlice(content_b64) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid base64\"}" };
    };
    if (decoded_len > 20 * 1024 * 1024) {
        return .{ .status = "413 Payload Too Large", .body = "{\"error\":\"decoded size exceeds 20MB\"}" };
    }
    const decoded = allocator.alloc(u8, decoded_len) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"alloc failed\"}" };
    };
    defer allocator.free(decoded);
    std.base64.standard.Decoder.decode(decoded, content_b64) catch {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"invalid base64\"}" };
    };

    // Ensure {workspace}/attachments directory exists.
    const dir_path = std.fmt.allocPrint(allocator, "{s}/attachments", .{user_ctx.workspace_path}) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path build failed\"}" };
    };
    defer allocator.free(dir_path);
    std.fs.makeDirAbsolute(dir_path) catch |err| switch (err) {
        error.PathAlreadyExists => {},
        else => {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"attachments dir create failed\"}" };
        },
    };

    // Write file to {workspace}/attachments/{filename}.
    const file_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir_path, filename }) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path build failed\"}" };
    };
    defer allocator.free(file_path);

    {
        const file = std.fs.createFileAbsolute(file_path, .{ .truncate = true }) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"attachment write failed\"}" };
        };
        defer file.close();
        file.writeAll(decoded) catch {
            return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"attachment write failed\"}" };
        };
    }

    // Build response — return relative path the agent uses with file_read.
    const resp = std.fmt.allocPrint(
        allocator,
        "{{\"path\":\"attachments/{s}\",\"bytes\":{d}}}",
        .{ filename, decoded_len },
    ) catch "{\"error\":\"response build failed\"}";
    return .{ .body = resp };
}

/// POST /api/v1/users/{id}/voice/synthesize
/// Body: {"text":"hello","voice":"alloy","format":"mp3"} (voice/format optional)
/// Returns: {"audio":"<base64>","format":"mp3"}
fn handleVoiceSynthesize(
    allocator: std.mem.Allocator,
    method: []const u8,
    raw_request: []const u8,
    config_opt: ?*const Config,
) RouteResponse {
    if (!std.mem.eql(u8, method, "POST")) {
        return .{ .status = "405 Method Not Allowed", .body = "{\"error\":\"method not allowed\"}" };
    }
    const cfg = config_opt orelse return .{
        .status = "503 Service Unavailable",
        .body = "{\"error\":\"voice not configured\"}",
    };
    // TTS provider comes from agent config (often "openai" for speech synthesis
    // even if STT uses "groq"). Falls back to the default provider.
    const tts_provider = cfg.agent.tts_provider orelse cfg.default_provider;
    const api_key = cfg.getProviderKey(tts_provider) orelse {
        return .{ .status = "503 Service Unavailable", .body = "{\"error\":\"tts api key not configured\"}" };
    };
    const body = extractBody(raw_request) orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing body\"}" };
    };
    const text = jsonStringField(body, "text") orelse {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"missing text field\"}" };
    };
    if (std.mem.trim(u8, text, " \t\r\n").len == 0) {
        return .{ .status = "400 Bad Request", .body = "{\"error\":\"empty text\"}" };
    }
    // Cap text at 4096 chars (OpenAI TTS limit)
    if (text.len > 4096) {
        return .{ .status = "413 Payload Too Large", .body = "{\"error\":\"text too long (max 4096 chars)\"}" };
    }

    const voice_name = jsonStringField(body, "voice") orelse "alloy";
    const format = jsonStringField(body, "format") orelse "mp3";

    const audio_path = voice.synthesizeTextToTempAudio(allocator, tts_provider, api_key, text, .{
        .voice = voice_name,
        .format = format,
    }) catch {
        return .{ .status = "502 Bad Gateway", .body = "{\"error\":\"synthesis failed\"}" };
    };
    defer allocator.free(audio_path);

    // Read the generated audio file
    var path_z_buf: [512]u8 = undefined;
    const audio_path_z = toSentinelPath(&path_z_buf, audio_path) orelse {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"path too long\"}" };
    };

    const audio_file = std.fs.openFileAbsolute(audio_path_z, .{}) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"audio read failed\"}" };
    };
    defer audio_file.close();
    defer std.fs.deleteFileAbsolute(audio_path_z) catch {};

    const audio_data = audio_file.readToEndAlloc(allocator, 8 * 1024 * 1024) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"audio read failed\"}" };
    };
    defer allocator.free(audio_data);

    // Base64-encode the audio
    const b64_len = std.base64.standard.Encoder.calcSize(audio_data.len);
    const b64_buf = allocator.alloc(u8, b64_len) catch {
        return .{ .status = "500 Internal Server Error", .body = "{\"error\":\"alloc failed\"}" };
    };
    defer allocator.free(b64_buf);
    _ = std.base64.standard.Encoder.encode(b64_buf, audio_data);

    // Build JSON response
    var resp: std.ArrayListUnmanaged(u8) = .empty;
    defer resp.deinit(allocator);
    const w = resp.writer(allocator);
    w.writeAll("{\"audio\":\"") catch return response_build_err;
    w.writeAll(b64_buf) catch return response_build_err;
    w.writeAll("\",\"format\":\"") catch return response_build_err;
    jsonEscapeInto(w, format) catch return response_build_err;
    w.writeAll("\"}") catch return response_build_err;
    return finalizeJsonBuf(allocator, &resp);
}

const WebhookHandlerContext = struct {
    root_allocator: std.mem.Allocator,
    req_allocator: std.mem.Allocator,
    raw_request: []const u8,
    method: []const u8,
    target: []const u8,
    config_opt: ?*const Config,
    state: *GatewayState,
    session_mgr_opt: ?*session_mod.SessionManager,
    response_status: []const u8 = "200 OK",
    response_body: []const u8 = "",
    response_retry_after_secs: ?u16 = null,
};

const WebhookHandlerFn = *const fn (ctx: *WebhookHandlerContext) void;

const WebhookRouteDescriptor = struct {
    path: []const u8,
    handler: WebhookHandlerFn,
};

const webhook_route_descriptors = [_]WebhookRouteDescriptor{
    .{ .path = "/telegram", .handler = handleTelegramWebhookRoute },
    .{ .path = "/webhook/telegram", .handler = handleTelegramWebhookRoute },
    .{ .path = "/whatsapp", .handler = handleWhatsAppWebhookRoute },
    .{ .path = "/slack/events", .handler = handleSlackWebhookRoute },
    .{ .path = "/line", .handler = handleLineWebhookRoute },
    .{ .path = "/lark", .handler = handleLarkWebhookRoute },
};

fn findWebhookRouteDescriptor(path: []const u8) ?*const WebhookRouteDescriptor {
    for (&webhook_route_descriptors) |*desc| {
        if (std.mem.eql(u8, desc.path, path)) return desc;
    }
    return null;
}

fn handleTelegramWebhookRoute(ctx: *WebhookHandlerContext) void {
    if (!build_options.enable_channel_telegram) {
        ctx.response_status = "404 Not Found";
        ctx.response_body = "{\"error\":\"telegram channel disabled in this build\"}";
        return;
    }

    const is_post = std.mem.eql(u8, ctx.method, "POST");
    if (!is_post) {
        ctx.response_status = "405 Method Not Allowed";
        ctx.response_body = "{\"error\":\"method not allowed\"}";
        return;
    }

    var webhook_key_buf: [160]u8 = undefined;
    var webhook_rate_key: []const u8 = "telegram";
    if (ctx.state.tenant_enabled) {
        if (parseQueryParam(ctx.target, "user_id")) |user_id| {
            if (isValidIdentifier(user_id)) {
                webhook_rate_key = std.fmt.bufPrint(&webhook_key_buf, "telegram:{s}", .{user_id}) catch "telegram";
            }
        }
    }

    if (!ctx.state.rate_limiter.allowWebhook(ctx.state.allocator, webhook_rate_key)) {
        ctx.response_status = "429 Too Many Requests";
        ctx.response_body = "{\"error\":\"rate limited\"}";
        return;
    }
    _ = ctx.state.telegram_webhook_total.fetchAdd(1, .monotonic);

    const body = extractBody(ctx.raw_request);
    if (body) |b| {
        var tg_bot_token = ctx.state.telegram_bot_token;
        var tg_allow_from = ctx.state.telegram_allow_from;
        var tg_account_id = ctx.state.telegram_account_id;
        var tg_webhook_secret_token = ctx.state.telegram_webhook_secret_token;
        var tg_bot_token_owned: ?[]const u8 = null;
        var tg_proxy: ?[]const u8 = null;
        var scoped_user_id: ?[]const u8 = null;
        var use_shared_main = false;
        var tenant_channel_state_path: ?[]const u8 = null;
        var numeric_user_id_opt: ?i64 = null;
        defer if (tg_bot_token_owned) |tok| ctx.req_allocator.free(tok);
        defer if (tenant_channel_state_path) |p| ctx.req_allocator.free(p);
        var tenant_user_ctx: ?UserContext = null;
        defer if (tenant_user_ctx) |*value| value.deinit(ctx.req_allocator);
        if (selectTelegramConfig(ctx.config_opt, ctx.target)) |tg_cfg| {
            tg_bot_token = tg_cfg.bot_token;
            tg_allow_from = tg_cfg.allow_from;
            tg_account_id = tg_cfg.account_id;
            tg_webhook_secret_token = tg_cfg.webhook_secret_token orelse "";
            tg_proxy = tg_cfg.proxy;
        }

        if (ctx.state.tenant_enabled) {
            const user_id = parseQueryParam(ctx.target, "user_id") orelse {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "400 Bad Request";
                ctx.response_body = "{\"error\":\"missing user_id\"}";
                return;
            };
            if (!isValidIdentifier(user_id)) {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "400 Bad Request";
                ctx.response_body = "{\"error\":\"invalid user_id\"}";
                return;
            }
            scoped_user_id = user_id;
            use_shared_main = tenantTelegramUsesSharedMain(ctx.config_opt);

            tenant_user_ctx = resolveUserContext(ctx.req_allocator, ctx.state, user_id) catch {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "400 Bad Request";
                ctx.response_body = "{\"error\":\"invalid user\"}";
                return;
            };
            const user_ctx = &tenant_user_ctx.?;
            tenant_channel_state_path = ctx.req_allocator.dupe(u8, user_ctx.channel_state_path) catch null;
            const lock_wait_start_ms = std.time.milliTimestamp();
            var user_lock = maybeAcquireTenantOwnershipLock(ctx.req_allocator, ctx.state, user_ctx.user_id, user_ctx.user_root) catch |err| switch (err) {
                error.FileNotFound => {
                    _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                    ctx.response_status = "403 Forbidden";
                    ctx.response_body = "{\"error\":\"telegram user channel not connected\"}";
                    return;
                },
                else => {
                    _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                    ctx.response_status = "500 Internal Server Error";
                    ctx.response_body = "{\"error\":\"tenant ownership lock failed\"}";
                    return;
                },
            };
            const lock_wait_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - lock_wait_start_ms));
            log.info("telegram.webhook.stage stage=ownership_lock_wait user={s} duration_ms={d}", .{
                user_ctx.user_id,
                lock_wait_duration_ms,
            });
            defer user_lock.deinit();
            switch (user_lock) {
                .disabled => {},
                .acquired => {},
                .conflict => |*conflict| {
                    _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                    recordTenantLockConflict(ctx.state, .webhook);
                    ctx.response_status = "409 Conflict";
                    ctx.response_retry_after_secs = conflict.retryAfterSecs();
                    ctx.response_body = ownershipLockConflictJsonPayload(ctx.req_allocator, conflict) catch
                        "{\"error\":\"ownership_lock_conflict\",\"message\":\"user is active on another node, retry shortly\",\"retry_after_ms\":250,\"owner_instance_id\":null,\"lease_until_s\":null}";
                    return;
                },
            }

            const user_state = blk: {
                if (ctx.state.zaki_state) |mgr| {
                    const numeric_user_id = parseNumericUserId(user_id) catch {
                        _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                        ctx.response_status = "400 Bad Request";
                        ctx.response_body = "{\"error\":\"invalid user\"}";
                        return;
                    };
                    numeric_user_id_opt = numeric_user_id;
                    const raw_state = mgr.getTelegramStateJson(ctx.req_allocator, numeric_user_id) catch {
                        _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                        ctx.response_status = "403 Forbidden";
                        ctx.response_body = "{\"error\":\"telegram user channel not connected\"}";
                        return;
                    };
                    defer ctx.req_allocator.free(raw_state);
                    break :blk parseTelegramUserState(ctx.req_allocator, raw_state) catch {
                        _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                        ctx.response_status = "403 Forbidden";
                        ctx.response_body = "{\"error\":\"telegram user channel not connected\"}";
                        return;
                    };
                }
                break :blk loadTelegramUserState(ctx.req_allocator, user_ctx.telegram_path) catch {
                    _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                    ctx.response_status = "403 Forbidden";
                    ctx.response_body = "{\"error\":\"telegram user channel not connected\"}";
                    return;
                };
            };
            if (!user_state.connected) {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"telegram user channel not connected\"}";
                return;
            }

            if (user_state.account_id) |account_id| {
                tg_account_id = account_id;
            }
            if (user_state.allow_from.len > 0) {
                tg_allow_from = user_state.allow_from;
            }
            if (user_state.webhook_secret_token) |secret| {
                tg_webhook_secret_token = secret;
            }

            const tenant_bot_token = resolveTenantTelegramBotTokenForSend(
                ctx.req_allocator,
                user_ctx,
                ctx.state.zaki_state,
                numeric_user_id_opt,
            ) catch {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"missing telegram bot token\"}";
                return;
            };
            tg_bot_token_owned = tenant_bot_token;
            tg_bot_token = tenant_bot_token;

            if (tg_webhook_secret_token.len == 0) {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"missing telegram secret token\"}";
                return;
            }
        }

        if (tg_webhook_secret_token.len > 0) {
            const header_token = extractHeader(ctx.raw_request, "X-Telegram-Bot-Api-Secret-Token") orelse {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"missing telegram secret token\"}";
                return;
            };
            const expected_secret = normalizeTelegramSecretToken(tg_webhook_secret_token);
            const provided_secret = normalizeTelegramSecretToken(header_token);
            if (expected_secret.len == 0) {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"missing telegram secret token\"}";
                return;
            }
            // S7.13 — constant-time compare on attacker-controlled input.
            // `provided_secret` comes from the X-Telegram-Bot-Api-Secret-Token
            // header, which an attacker can manipulate one byte at a time.
            // `std.mem.eql` short-circuits on first mismatch — the wall-clock
            // time to reject leaks the position of the first differing byte,
            // which is enough to recover the expected secret byte-by-byte.
            // `constantTimeEq` (shared with the pairing verification path)
            // compares in time proportional to max(a.len, b.len) regardless
            // of content, closing that oracle.
            if (!constantTimeEq(provided_secret, expected_secret)) {
                _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"invalid telegram secret token\"}";
                return;
            }
        }

        if (jsonIntField(b, "update_id")) |update_id| {
            if (ctx.state.zaki_state != null and scoped_user_id != null) {
                const numeric_user_id = parseNumericUserId(scoped_user_id.?) catch {
                    ctx.response_status = "400 Bad Request";
                    ctx.response_body = "{\"error\":\"invalid user\"}";
                    return;
                };
                const is_new = ctx.state.zaki_state.?.recordTelegramUpdate(numeric_user_id, update_id) catch {
                    ctx.response_status = "500 Internal Server Error";
                    ctx.response_body = "{\"error\":\"telegram update dedupe failed\"}";
                    return;
                };
                if (!is_new) {
                    ctx.response_body = "{\"status\":\"duplicate\"}";
                    return;
                }
            } else {
                var key_buf: [192]u8 = undefined;
                const dedupe_scope = if (scoped_user_id) |uid| uid else tg_account_id;
                const key = std.fmt.bufPrint(&key_buf, "telegram:update:{s}:{d}", .{ dedupe_scope, update_id }) catch "telegram:update:invalid";
                if (!ctx.state.idempotency.recordIfNew(ctx.state.allocator, key)) {
                    ctx.response_body = "{\"status\":\"duplicate\"}";
                    return;
                }
            }
        }

        var webhook_transcriber = if (ctx.config_opt) |cfg|
            buildTelegramWebhookTranscriber(ctx.req_allocator, cfg)
        else
            TelegramWebhookTranscriber{};
        defer webhook_transcriber.deinit(ctx.req_allocator);

        const msg_text = telegramWebhookExtractInboundText(
            ctx.req_allocator,
            b,
            tg_bot_token,
            webhook_transcriber.transcriber,
            tg_proxy,
        );
        defer if (msg_text) |mt| ctx.req_allocator.free(mt);
        const chat_id = telegramChatId(ctx.req_allocator, b);
        const tg_authorized = telegramSenderAllowed(ctx.req_allocator, tg_allow_from, b);
        if (!tg_authorized) {
            _ = ctx.state.telegram_webhook_rejected_total.fetchAdd(1, .monotonic);
            ctx.response_body = "{\"status\":\"unauthorized\"}";
            return;
        }

        if (msg_text != null and chat_id != null) {
            if (ctx.state.zaki_state != null and scoped_user_id != null) {
                const numeric_user_id = parseNumericUserId(scoped_user_id.?) catch {
                    ctx.response_status = "400 Bad Request";
                    ctx.response_body = "{\"error\":\"invalid user\"}";
                    return;
                };
                ctx.state.zaki_state.?.recordTelegramChat(numeric_user_id, tg_account_id, chat_id.?) catch {};
                if (tenant_channel_state_path) |state_path| {
                    writeTelegramChannelState(ctx.req_allocator, state_path, tg_account_id, chat_id.?) catch {};
                }
            } else if (tenant_channel_state_path) |state_path| {
                writeTelegramChannelState(ctx.req_allocator, state_path, tg_account_id, chat_id.?) catch {};
            }
            var sender_buf: [32]u8 = undefined;
            const sender = telegramSenderIdentity(ctx.req_allocator, b, &sender_buf);
            var cid_buf: [32]u8 = undefined;
            const cid_str = std.fmt.bufPrint(&cid_buf, "{d}", .{chat_id.?}) catch "0";
            const is_group = telegramChatIsGroup(ctx.req_allocator, b);
            const peer_kind = if (is_group) "group" else "direct";

            if (tenant_user_ctx != null) {
                const cfg = ctx.config_opt orelse {
                    ctx.response_status = "500 Internal Server Error";
                    ctx.response_body = "{\"error\":\"tenant config missing\"}";
                    return;
                };
                // Keep tenant Telegram webhook handling synchronous for deterministic
                // delivery. Async queueing can acknowledge webhooks while worker-side
                // failures silently drop replies.

                var kb: [256]u8 = undefined;
                var thread_buf: [32]u8 = undefined;
                var lane_buf: [64]u8 = undefined;
                const tg_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg_opt| cfg_opt else null;
                const lane_resolution = resolveTenantTelegramLane(
                    ctx.req_allocator,
                    tg_cfg_opt,
                    use_shared_main,
                    scoped_user_id.?,
                    tg_account_id,
                    chat_id.?,
                    b,
                    &kb,
                    &thread_buf,
                    &lane_buf,
                );
                const fallback_session_key = lane_resolution.fallback_session_key;
                var identity_keys = channel_identity_key.build(
                    ctx.req_allocator,
                    "telegram",
                    sender,
                    cid_str,
                    lane_resolution.canonical_thread_key,
                ) catch {
                    ctx.response_status = "400 Bad Request";
                    ctx.response_body = "{\"error\":\"invalid telegram identity\"}";
                    return;
                };
                defer identity_keys.deinit(ctx.req_allocator);

                if (ctx.state.zaki_state != null and scoped_user_id != null and !is_group) {
                    const user_id_numeric = numeric_user_id_opt orelse parseNumericUserId(scoped_user_id.?) catch {
                        ctx.response_status = "400 Bad Request";
                        ctx.response_body = "{\"error\":\"invalid user\"}";
                        return;
                    };
                    const upsert_binding = ctx.state.zaki_state.?.upsertChannelIdentityBinding(
                        ctx.req_allocator,
                        user_id_numeric,
                        "telegram",
                        tg_account_id,
                        identity_keys.principal_key,
                        identity_keys.scope_key,
                        identity_keys.thread_key,
                        peer_kind,
                        cid_str,
                        "{\"source\":\"telegram_webhook\"}",
                    );
                    if (upsert_binding) |binding_id| {
                        ctx.req_allocator.free(binding_id);
                    } else |err| {
                        log.warn("telegram binding upsert failed: {}", .{err});
                    }
                    inbound_canonicalizer.invalidateCacheForIdentity(.{
                        .channel = "telegram",
                        .account_id = tg_account_id,
                        .principal_key = identity_keys.principal_key,
                        .scope_key = identity_keys.scope_key,
                        .thread_key = identity_keys.thread_key,
                        .fallback_session_key = "",
                    });
                }

                const canonicalize_start_ms = std.time.milliTimestamp();
                var canonical_decision = inbound_canonicalizer.canonicalizeInboundTurn(
                    ctx.req_allocator,
                    ctx.state.zaki_state,
                    cfg,
                    .{
                        .channel = "telegram",
                        .account_id = tg_account_id,
                        .principal_key = identity_keys.principal_key,
                        .scope_key = identity_keys.scope_key,
                        .thread_key = identity_keys.thread_key,
                        .fallback_session_key = fallback_session_key,
                        .lane = lane_resolution.lane,
                    },
                ) catch |err| {
                    log.warn("telegram canonicalization failed: {}", .{err});
                    ctx.response_status = "500 Internal Server Error";
                    ctx.response_body = "{\"error\":\"canonicalization_failed\"}";
                    return;
                };
                const canonicalize_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - canonicalize_start_ms));
                log.info("telegram.webhook.stage stage=canonicalization user={s} duration_ms={d} lane={s} decision={s}", .{
                    scoped_user_id.?,
                    canonicalize_duration_ms,
                    switch (lane_resolution.lane) {
                        .main => "main",
                        .thread => "thread",
                        .task => "task",
                        .cron => "cron",
                    },
                    switch (canonical_decision.kind) {
                        .canonical => "canonical",
                        .degraded_compat => "degraded_compat",
                        .strict_reject => "strict_reject",
                    },
                });
                defer canonical_decision.deinit(ctx.req_allocator);

                const sk = blk: {
                    switch (canonical_decision.kind) {
                        .strict_reject => {
                            const send_start_ms = std.time.milliTimestamp();
                            sendTelegramReply(
                                ctx.req_allocator,
                                tg_bot_token,
                                chat_id.?,
                                "This Telegram chat is not mapped to your tenant user yet. Reconnect Telegram from the app, then retry.",
                            ) catch |err| {
                                log.warn("telegram strict reject reply send failed: {}", .{err});
                            };
                            const send_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - send_start_ms));
                            log.info("telegram.webhook.stage stage=telegram_send user={s} duration_ms={d} path=strict_reject", .{
                                scoped_user_id.?,
                                send_duration_ms,
                            });
                            const reject_body = std.fmt.allocPrint(
                                ctx.req_allocator,
                                "{{\"error\":\"strict_identity_reject\",\"code\":\"{s}\"}}",
                                .{canonical_decision.reason_code},
                            ) catch "{\"error\":\"strict_identity_reject\"}";
                            ctx.response_status = "403 Forbidden";
                            ctx.response_body = reject_body;
                            return;
                        },
                        .canonical, .degraded_compat => break :blk canonical_decision.session_key.?,
                    }
                };
                const tenant_runtime = getTenantRuntime(ctx.state, cfg, &tenant_user_ctx.?) catch |err| {
                    if (err == error.ExecutionDelegated) {
                        ctx.response_status = "503 Service Unavailable";
                        ctx.response_body = "{\"error\":\"execution_delegated\"}";
                    } else {
                        ctx.response_status = "500 Internal Server Error";
                        ctx.response_body = "{\"error\":\"tenant runtime init failed\"}";
                    }
                    return;
                };
                var typing_channel = channels.telegram.TelegramChannel.init(
                    ctx.req_allocator,
                    tg_bot_token,
                    &.{"*"},
                    &.{},
                    "open",
                );
                typing_channel.startTyping(cid_str) catch {};
                defer typing_channel.stopTyping(cid_str) catch {};
                const agent_turn_start_ms = std.time.milliTimestamp();
                const reply: ?[]const u8 = tenant_runtime.processMessage(
                    sk,
                    msg_text.?,
                    .{
                        .channel = "telegram",
                        .is_group = is_group,
                    },
                    .{
                        .channel = "telegram",
                        .account_id = tg_account_id,
                        .chat_id = cid_str,
                        .is_group = is_group,
                        .is_dm = !is_group,
                    },
                    null,
                    null, // Telegram: no streaming (buffered reply)
                    null,
                ) catch |err| blk: {
                    const agent_turn_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - agent_turn_start_ms));
                    log.info("telegram.webhook.stage stage=agent_turn user={s} duration_ms={d} ok=false", .{
                        scoped_user_id.?,
                        agent_turn_duration_ms,
                    });
                    if (tenant_user_ctx) |*send_user_ctx| {
                        const send_token = resolveTenantTelegramBotTokenForSend(
                            ctx.req_allocator,
                            send_user_ctx,
                            ctx.state.zaki_state,
                            numeric_user_id_opt,
                        ) catch |token_err| {
                            log.warn("telegram tenant token resolve before error-reply failed: {}", .{token_err});
                            break :blk null;
                        };
                        defer if (send_token.len > 0) ctx.req_allocator.free(send_token);
                        const send_start_ms = std.time.milliTimestamp();
                        sendTelegramReply(ctx.req_allocator, send_token, chat_id.?, userFacingAgentError(err)) catch |send_err| {
                            log.warn("telegram webhook error-reply send failed: {}", .{send_err});
                        };
                        const send_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - send_start_ms));
                        log.info("telegram.webhook.stage stage=telegram_send user={s} duration_ms={d} path=error_reply", .{
                            scoped_user_id.?,
                            send_duration_ms,
                        });
                    }
                    break :blk null;
                };
                if (reply != null) {
                    const agent_turn_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - agent_turn_start_ms));
                    log.info("telegram.webhook.stage stage=agent_turn user={s} duration_ms={d} ok=true", .{
                        scoped_user_id.?,
                        agent_turn_duration_ms,
                    });
                }
                if (reply) |r| {
                    defer ctx.root_allocator.free(r);
                    if (tenant_user_ctx) |*send_user_ctx| {
                        const send_token_opt: ?[]const u8 = blk: {
                            const send_token = resolveTenantTelegramBotTokenForSend(
                                ctx.req_allocator,
                                send_user_ctx,
                                ctx.state.zaki_state,
                                numeric_user_id_opt,
                            ) catch |token_err| {
                                log.warn("telegram tenant token resolve before reply failed: {}", .{token_err});
                                break :blk null;
                            };
                            break :blk send_token;
                        };
                        if (send_token_opt) |send_token| {
                            defer if (send_token.len > 0) ctx.req_allocator.free(send_token);
                            const send_start_ms = std.time.milliTimestamp();
                            sendTelegramReply(ctx.req_allocator, send_token, chat_id.?, r) catch |send_err| {
                                log.warn("telegram webhook reply send failed: {}", .{send_err});
                            };
                            const send_duration_ms: u64 = @intCast(@max(0, std.time.milliTimestamp() - send_start_ms));
                            log.info("telegram.webhook.stage stage=telegram_send user={s} duration_ms={d} path=success", .{
                                scoped_user_id.?,
                                send_duration_ms,
                            });
                        } else {
                            ctx.response_body = "{\"status\":\"received\"}";
                        }
                    }
                    ctx.response_body = "{\"status\":\"ok\"}";
                } else {
                    ctx.response_body = "{\"status\":\"received\"}";
                }
            } else if (ctx.state.event_bus) |eb| {
                var meta_buf: [320]u8 = undefined;
                const meta = std.fmt.bufPrint(&meta_buf, "{{\"account_id\":\"{s}\",\"peer_kind\":\"{s}\",\"peer_id\":\"{s}\"}}", .{
                    tg_account_id,
                    peer_kind,
                    cid_str,
                }) catch null;
                var kb: [256]u8 = undefined;
                const tg_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg| cfg else null;
                const sk = if (use_shared_main)
                    zaki_session.userMainSessionKey(&kb, scoped_user_id.?)
                else
                    telegramSessionKeyRouted(ctx.req_allocator, &kb, chat_id.?, b, tg_cfg_opt, tg_account_id);
                _ = publishToBus(eb, ctx.state.allocator, "telegram", sender, cid_str, msg_text.?, sk, meta);
                ctx.response_body = "{\"status\":\"ok\"}";
            } else if (ctx.session_mgr_opt) |sm| {
                var kb: [256]u8 = undefined;
                const tg_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg| cfg else null;
                const sk = if (use_shared_main)
                    zaki_session.userMainSessionKey(&kb, scoped_user_id.?)
                else
                    telegramSessionKeyRouted(ctx.req_allocator, &kb, chat_id.?, b, tg_cfg_opt, tg_account_id);
                const reply: ?[]const u8 = sm.processMessageWithToolContext(sk, msg_text.?, null, .{
                    .channel = "telegram",
                    .account_id = tg_account_id,
                    .chat_id = cid_str,
                    .is_group = is_group,
                    .is_dm = !is_group,
                }) catch |err| blk: {
                    if (tg_bot_token.len > 0) {
                        sendTelegramReply(ctx.req_allocator, tg_bot_token, chat_id.?, userFacingAgentError(err)) catch |send_err| {
                            log.warn("telegram webhook sync error-reply send failed: {}", .{send_err});
                        };
                    }
                    break :blk null;
                };
                if (reply) |r| {
                    defer ctx.root_allocator.free(r);
                    if (tg_bot_token.len > 0) {
                        sendTelegramReply(ctx.req_allocator, tg_bot_token, chat_id.?, r) catch |send_err| {
                            log.warn("telegram webhook sync reply send failed: {}", .{send_err});
                        };
                    }
                    ctx.response_body = "{\"status\":\"ok\"}";
                } else {
                    ctx.response_body = "{\"status\":\"received\"}";
                }
            } else {
                ctx.response_body = "{\"status\":\"received\"}";
            }
        } else {
            ctx.response_body = "{\"status\":\"ok\"}";
        }
    } else {
        ctx.response_body = "{\"status\":\"received\"}";
    }
}

fn handleWhatsAppWebhookRoute(ctx: *WebhookHandlerContext) void {
    if (!build_options.enable_channel_whatsapp) {
        ctx.response_status = "404 Not Found";
        ctx.response_body = "{\"error\":\"whatsapp channel disabled in this build\"}";
        return;
    }

    const is_get = std.mem.eql(u8, ctx.method, "GET");
    if (is_get) {
        const mode = parseQueryParam(ctx.target, "hub.mode");
        const token = parseQueryParam(ctx.target, "hub.verify_token");
        const challenge = parseQueryParam(ctx.target, "hub.challenge");
        var wa_verify_token = ctx.state.whatsapp_verify_token;
        if (selectWhatsAppConfig(ctx.config_opt, null, token)) |wa_cfg| {
            wa_verify_token = wa_cfg.verify_token;
        }

        if (mode != null and challenge != null and token != null and
            std.mem.eql(u8, mode.?, "subscribe") and
            wa_verify_token.len > 0 and
            std.mem.eql(u8, token.?, wa_verify_token))
        {
            ctx.response_body = challenge.?;
        } else {
            ctx.response_status = "403 Forbidden";
            ctx.response_body = "{\"error\":\"verification failed\"}";
        }
        return;
    }

    const is_post = std.mem.eql(u8, ctx.method, "POST");
    if (!is_post) {
        ctx.response_status = "405 Method Not Allowed";
        ctx.response_body = "{\"error\":\"method not allowed\"}";
        return;
    }

    if (!ctx.state.rate_limiter.allowWebhook(ctx.state.allocator, "whatsapp")) {
        ctx.response_status = "429 Too Many Requests";
        ctx.response_body = "{\"error\":\"rate limited\"}";
        return;
    }

    const wa_body = extractBody(ctx.raw_request);
    var wa_app_secret = ctx.state.whatsapp_app_secret;
    var wa_access_token = ctx.state.whatsapp_access_token;
    var wa_allow_from = ctx.state.whatsapp_allow_from;
    var wa_group_allow_from = ctx.state.whatsapp_group_allow_from;
    var wa_groups = ctx.state.whatsapp_groups;
    var wa_group_policy = ctx.state.whatsapp_group_policy;
    var wa_account_id = ctx.state.whatsapp_account_id;
    if (selectWhatsAppConfig(ctx.config_opt, wa_body, null)) |wa_cfg| {
        wa_app_secret = wa_cfg.app_secret orelse "";
        wa_access_token = wa_cfg.access_token;
        wa_allow_from = wa_cfg.allow_from;
        wa_group_allow_from = wa_cfg.group_allow_from;
        wa_groups = wa_cfg.groups;
        wa_group_policy = wa_cfg.group_policy;
        wa_account_id = wa_cfg.account_id;
    }

    const sig_header = extractHeader(ctx.raw_request, "X-Hub-Signature-256");
    if (wa_app_secret.len > 0) sig_check: {
        const sig = sig_header orelse {
            ctx.response_status = "403 Forbidden";
            ctx.response_body = "{\"error\":\"missing signature\"}";
            break :sig_check;
        };
        const body = wa_body orelse {
            ctx.response_body = "{\"status\":\"received\"}";
            break :sig_check;
        };
        if (!verifyWhatsappSignature(body, sig, wa_app_secret)) {
            ctx.response_status = "403 Forbidden";
            ctx.response_body = "{\"error\":\"invalid signature\"}";
            break :sig_check;
        }
        const wa_sender = jsonStringField(body, "from");
        const wa_is_group = whatsappIsGroupMessage(body);
        const wa_group_id = whatsappGroupId(body);
        if (!whatsappSenderAllowed(
            wa_sender,
            wa_is_group,
            wa_group_id,
            wa_allow_from,
            wa_group_allow_from,
            wa_groups,
            wa_group_policy,
        )) {
            ctx.response_body = "{\"status\":\"unauthorized\"}";
            break :sig_check;
        }
        const msg_text = jsonStringField(body, "text") orelse jsonStringField(body, "body") orelse
            channels.whatsapp.WhatsAppChannel.downloadMediaFromPayload(ctx.req_allocator, wa_access_token, body);
        if (msg_text) |mt| {
            var wa_key_buf: [256]u8 = undefined;
            const wa_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg| cfg else null;
            const wa_session_key = whatsappSessionKeyRouted(ctx.req_allocator, &wa_key_buf, body, wa_cfg_opt, wa_account_id);
            const wa_sender_id = wa_sender orelse "unknown";
            const wa_chat_target = whatsappReplyTarget(body);
            const wa_peer_kind = if (wa_is_group) "group" else "direct";
            const wa_peer_id = wa_group_id orelse wa_sender_id;

            if (ctx.state.event_bus) |eb| {
                var meta_buf: [384]u8 = undefined;
                const meta = std.fmt.bufPrint(&meta_buf, "{{\"account_id\":\"{s}\",\"peer_kind\":\"{s}\",\"peer_id\":\"{s}\"}}", .{
                    wa_account_id,
                    wa_peer_kind,
                    wa_peer_id,
                }) catch null;
                _ = publishToBus(eb, ctx.state.allocator, "whatsapp", wa_sender_id, wa_chat_target, mt, wa_session_key, meta);
                ctx.response_body = "{\"status\":\"received\"}";
            } else if (ctx.session_mgr_opt) |sm| {
                const reply: ?[]const u8 = sm.processMessageWithToolContext(wa_session_key, mt, null, .{
                    .channel = "whatsapp",
                    .account_id = wa_account_id,
                    .chat_id = wa_chat_target,
                    .is_group = wa_is_group,
                    .is_dm = !wa_is_group,
                }) catch |err| blk: {
                    ctx.response_body = userFacingAgentErrorJson(err);
                    break :blk null;
                };
                if (reply) |r| {
                    defer ctx.root_allocator.free(r);
                    ctx.response_body = ctx.req_allocator.dupe(u8, r) catch "{\"status\":\"received\"}";
                } else {
                    ctx.response_body = "{\"status\":\"received\"}";
                }
            } else {
                ctx.response_body = "{\"status\":\"received\"}";
            }
        } else {
            ctx.response_body = "{\"status\":\"received\"}";
        }
        return;
    }

    if (wa_body) |b| {
        const wa_sender = jsonStringField(b, "from");
        const wa_is_group = whatsappIsGroupMessage(b);
        const wa_group_id = whatsappGroupId(b);
        if (!whatsappSenderAllowed(
            wa_sender,
            wa_is_group,
            wa_group_id,
            wa_allow_from,
            wa_group_allow_from,
            wa_groups,
            wa_group_policy,
        )) {
            ctx.response_body = "{\"status\":\"unauthorized\"}";
            return;
        }
        const msg_text = jsonStringField(b, "text") orelse jsonStringField(b, "body") orelse
            channels.whatsapp.WhatsAppChannel.downloadMediaFromPayload(ctx.req_allocator, wa_access_token, b);
        if (msg_text) |mt| {
            var wa_key_buf: [256]u8 = undefined;
            const wa_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg| cfg else null;
            const wa_session_key = whatsappSessionKeyRouted(ctx.req_allocator, &wa_key_buf, b, wa_cfg_opt, wa_account_id);
            const wa_sender_ns = wa_sender orelse "unknown";
            const wa_chat_target_ns = whatsappReplyTarget(b);
            const wa_peer_kind = if (wa_is_group) "group" else "direct";
            const wa_peer_id = wa_group_id orelse wa_sender_ns;

            if (ctx.state.event_bus) |eb| {
                var meta_buf: [384]u8 = undefined;
                const meta = std.fmt.bufPrint(&meta_buf, "{{\"account_id\":\"{s}\",\"peer_kind\":\"{s}\",\"peer_id\":\"{s}\"}}", .{
                    wa_account_id,
                    wa_peer_kind,
                    wa_peer_id,
                }) catch null;
                _ = publishToBus(eb, ctx.state.allocator, "whatsapp", wa_sender_ns, wa_chat_target_ns, mt, wa_session_key, meta);
                ctx.response_body = "{\"status\":\"received\"}";
            } else if (ctx.session_mgr_opt) |sm| {
                const reply: ?[]const u8 = sm.processMessageWithToolContext(wa_session_key, mt, null, .{
                    .channel = "whatsapp",
                    .account_id = wa_account_id,
                    .chat_id = wa_chat_target_ns,
                    .is_group = wa_is_group,
                    .is_dm = !wa_is_group,
                }) catch |err| blk: {
                    ctx.response_body = userFacingAgentErrorJson(err);
                    break :blk null;
                };
                if (reply) |r| {
                    defer ctx.root_allocator.free(r);
                    ctx.response_body = ctx.req_allocator.dupe(u8, r) catch "{\"status\":\"received\"}";
                } else {
                    ctx.response_body = "{\"status\":\"received\"}";
                }
            } else {
                ctx.response_body = "{\"status\":\"received\"}";
            }
        } else {
            ctx.response_body = "{\"status\":\"received\"}";
        }
    } else {
        ctx.response_body = "{\"status\":\"received\"}";
    }
}

fn handleSlackWebhookRoute(ctx: *WebhookHandlerContext) void {
    if (!build_options.enable_channel_slack) {
        ctx.response_status = "404 Not Found";
        ctx.response_body = "{\"error\":\"slack channel disabled in this build\"}";
        return;
    }

    if (!std.mem.eql(u8, ctx.method, "POST")) {
        ctx.response_status = "405 Method Not Allowed";
        ctx.response_body = "{\"error\":\"method not allowed\"}";
        return;
    }
    if (!ctx.state.rate_limiter.allowWebhook(ctx.state.allocator, "slack")) {
        ctx.response_status = "429 Too Many Requests";
        ctx.response_body = "{\"error\":\"rate limited\"}";
        return;
    }

    const body = extractBody(ctx.raw_request) orelse {
        ctx.response_body = "{\"status\":\"received\"}";
        return;
    };

    const ts_header = extractHeader(ctx.raw_request, "X-Slack-Request-Timestamp");
    const sig_header = extractHeader(ctx.raw_request, "X-Slack-Signature");

    const slack_cfg = findSlackConfigForRequest(ctx.req_allocator, ctx.config_opt, ctx.target, body, ts_header, sig_header) orelse {
        if (hasSlackHttpEndpoint(ctx.config_opt, webhookBasePath(ctx.target))) {
            ctx.response_status = "403 Forbidden";
            ctx.response_body = "{\"error\":\"invalid signature\"}";
            return;
        }
        ctx.response_status = "404 Not Found";
        ctx.response_body = "{\"error\":\"slack account not configured\"}";
        return;
    };

    const parsed = std.json.parseFromSlice(std.json.Value, ctx.req_allocator, body, .{}) catch {
        ctx.response_body = "{\"status\":\"parse_error\"}";
        return;
    };
    defer parsed.deinit();
    if (parsed.value != .object) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }

    const payload_type = if (parsed.value.object.get("type")) |tv|
        if (tv == .string) tv.string else ""
    else
        "";

    if (std.mem.eql(u8, payload_type, "url_verification")) {
        const challenge = jsonStringField(body, "challenge") orelse "";
        if (challenge.len == 0) {
            ctx.response_body = "{\"status\":\"ok\"}";
            return;
        }
        const challenge_resp = jsonWrapChallenge(ctx.req_allocator, challenge) catch {
            ctx.response_body = "{\"status\":\"ok\"}";
            return;
        };
        ctx.response_body = challenge_resp;
        return;
    }

    if (!std.mem.eql(u8, payload_type, "event_callback")) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }

    const event_val = parsed.value.object.get("event") orelse {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    };
    if (event_val != .object) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }
    const event_obj = event_val.object;

    const event_type_val = event_obj.get("type") orelse {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    };
    if (event_type_val != .string) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }
    const event_type = event_type_val.string;
    if (!std.mem.eql(u8, event_type, "message") and !std.mem.eql(u8, event_type, "app_mention")) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }

    if (event_obj.get("subtype")) |subtype_val| {
        if (subtype_val == .string and subtype_val.string.len > 0) {
            ctx.response_body = "{\"status\":\"ok\"}";
            return;
        }
    }

    const user_val = event_obj.get("user") orelse {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    };
    if (user_val != .string or user_val.string.len == 0) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }
    const sender_id = user_val.string;

    const text_val = event_obj.get("text") orelse {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    };
    if (text_val != .string) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }
    const text = std.mem.trim(u8, text_val.string, " \t\r\n");
    if (text.len == 0) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }

    const channel_val = event_obj.get("channel") orelse {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    };
    if (channel_val != .string or channel_val.string.len == 0) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }
    const channel_id = channel_val.string;
    const is_dm = blk: {
        if (event_obj.get("channel_type")) |ct| {
            if (ct == .string and std.mem.eql(u8, ct.string, "im")) break :blk true;
        }
        break :blk channel_id.len > 0 and channel_id[0] == 'D';
    };

    var key_buf: [256]u8 = undefined;
    const fallback_session_key = slackSessionKeyRouted(
        ctx.req_allocator,
        &key_buf,
        slack_cfg.account_id,
        sender_id,
        channel_id,
        is_dm,
        ctx.config_opt,
    );
    var effective_session_key = fallback_session_key;
    var canonical_decision_opt: ?inbound_canonicalizer.CanonicalizationDecision = null;
    defer if (canonical_decision_opt) |*decision| decision.deinit(ctx.req_allocator);

    if (ctx.config_opt) |cfg| {
        const thread_raw = blk: {
            if (event_obj.get("thread_ts")) |thread_val| {
                if (thread_val == .string and std.mem.trim(u8, thread_val.string, " \t\r\n").len > 0) {
                    break :blk thread_val.string;
                }
            }
            break :blk null;
        };
        var identity_keys = channel_identity_key.build(
            ctx.req_allocator,
            "slack",
            sender_id,
            channel_id,
            thread_raw,
        ) catch {
            ctx.response_status = "400 Bad Request";
            ctx.response_body = "{\"error\":\"invalid slack identity\"}";
            return;
        };
        defer identity_keys.deinit(ctx.req_allocator);

        canonical_decision_opt = inbound_canonicalizer.canonicalizeInboundTurn(
            ctx.req_allocator,
            ctx.state.zaki_state,
            cfg,
            .{
                .channel = "slack",
                .account_id = slack_cfg.account_id,
                .principal_key = identity_keys.principal_key,
                .scope_key = identity_keys.scope_key,
                .thread_key = identity_keys.thread_key,
                .fallback_session_key = fallback_session_key,
                .lane = if (identity_keys.thread_key != null) .thread else .main,
            },
        ) catch |err| {
            log.warn("slack canonicalization failed: {}", .{err});
            ctx.response_status = "500 Internal Server Error";
            ctx.response_body = "{\"error\":\"canonicalization_failed\"}";
            return;
        };

        switch (canonical_decision_opt.?.kind) {
            .strict_reject => {
                const reject_body = std.fmt.allocPrint(
                    ctx.req_allocator,
                    "{{\"error\":\"strict_identity_reject\",\"code\":\"{s}\"}}",
                    .{canonical_decision_opt.?.reason_code},
                ) catch "{\"error\":\"strict_identity_reject\"}";
                ctx.response_status = "403 Forbidden";
                ctx.response_body = reject_body;
                return;
            },
            .canonical, .degraded_compat => {
                if (canonical_decision_opt.?.session_key) |canonical_session_key| {
                    effective_session_key = canonical_session_key;
                }
            },
        }
    }

    var policy_channel = channels.slack.SlackChannel.initFromConfig(ctx.req_allocator, slack_cfg.*);
    const envelope_bot_user_id = slackEnvelopeBotUserId(parsed.value.object);
    var allowed = policy_channel.shouldHandle(sender_id, is_dm, text, envelope_bot_user_id);
    if (!allowed and std.mem.eql(u8, event_type, "app_mention")) {
        allowed = channels.checkPolicy(policy_channel.policy, sender_id, is_dm, true);
    }
    if (!allowed) {
        ctx.response_body = "{\"status\":\"ok\"}";
        return;
    }

    if (ctx.state.event_bus) |eb| {
        var meta_buf: [384]u8 = undefined;
        const peer_kind = if (is_dm) "direct" else "channel";
        const peer_id = if (is_dm) sender_id else channel_id;
        const metadata = std.fmt.bufPrint(
            &meta_buf,
            "{{\"account_id\":\"{s}\",\"is_dm\":{s},\"channel_id\":\"{s}\",\"peer_kind\":\"{s}\",\"peer_id\":\"{s}\"}}",
            .{
                slack_cfg.account_id,
                if (is_dm) "true" else "false",
                channel_id,
                peer_kind,
                peer_id,
            },
        ) catch null;
        _ = publishToBus(eb, ctx.state.allocator, "slack", sender_id, channel_id, text, effective_session_key, metadata);
    } else if (ctx.session_mgr_opt) |sm| {
        const reply: ?[]const u8 = sm.processMessageWithToolContext(effective_session_key, text, null, .{
            .channel = "slack",
            .account_id = slack_cfg.account_id,
            .chat_id = if (is_dm) sender_id else channel_id,
            .is_group = !is_dm,
            .is_dm = is_dm,
            .mentioned = std.mem.eql(u8, event_type, "app_mention"),
        }) catch |err| blk: {
            var outbound_ch = channels.slack.SlackChannel.initFromConfig(ctx.req_allocator, slack_cfg.*);
            outbound_ch.sendMessage(channel_id, userFacingAgentError(err)) catch {};
            break :blk null;
        };
        if (reply) |r| {
            defer ctx.root_allocator.free(r);
            var outbound_ch = channels.slack.SlackChannel.initFromConfig(ctx.req_allocator, slack_cfg.*);
            outbound_ch.sendMessage(channel_id, r) catch {};
        }
    }

    ctx.response_body = "{\"status\":\"ok\"}";
}

fn linePeerMetadata(evt: channels.line.LineEvent, peer_buf: []u8) struct {
    kind: []const u8,
    id: []const u8,
} {
    const src_type = evt.source_type orelse "";
    if (std.mem.eql(u8, src_type, "group")) {
        return .{
            .kind = "group",
            .id = std.fmt.bufPrint(peer_buf, "group:{s}", .{evt.group_id orelse evt.user_id orelse "unknown"}) catch "group:unknown",
        };
    }
    if (std.mem.eql(u8, src_type, "room")) {
        return .{
            .kind = "group",
            .id = std.fmt.bufPrint(peer_buf, "room:{s}", .{evt.room_id orelse evt.user_id orelse "unknown"}) catch "room:unknown",
        };
    }
    return .{
        .kind = "direct",
        .id = evt.user_id orelse "unknown",
    };
}

fn handleLineWebhookRoute(ctx: *WebhookHandlerContext) void {
    if (!build_options.enable_channel_line) {
        ctx.response_status = "404 Not Found";
        ctx.response_body = "{\"error\":\"line channel disabled in this build\"}";
        return;
    }

    const is_post = std.mem.eql(u8, ctx.method, "POST");
    if (!is_post) {
        ctx.response_status = "405 Method Not Allowed";
        ctx.response_body = "{\"error\":\"method not allowed\"}";
        return;
    }
    if (!ctx.state.rate_limiter.allowWebhook(ctx.state.allocator, "line")) {
        ctx.response_status = "429 Too Many Requests";
        ctx.response_body = "{\"error\":\"rate limited\"}";
        return;
    }

    const body = extractBody(ctx.raw_request);
    if (body) |b| {
        var line_channel_secret = ctx.state.line_channel_secret;
        var line_access_token = ctx.state.line_access_token;
        var line_allow_from = ctx.state.line_allow_from;
        var line_account_id = ctx.state.line_account_id;

        const sig_header = extractHeader(ctx.raw_request, "X-Line-Signature");
        if (ctx.config_opt) |cfg| {
            const needs_signature = hasLineSecrets(cfg);
            if (needs_signature) {
                const sig = sig_header orelse {
                    ctx.response_status = "403 Forbidden";
                    ctx.response_body = "{\"error\":\"missing signature\"}";
                    return;
                };
                const matched_line_cfg = selectLineConfigBySignature(ctx.config_opt, b, sig) orelse {
                    ctx.response_status = "403 Forbidden";
                    ctx.response_body = "{\"error\":\"invalid signature\"}";
                    return;
                };
                line_channel_secret = matched_line_cfg.channel_secret;
                line_access_token = matched_line_cfg.access_token;
                line_allow_from = matched_line_cfg.allow_from;
                line_account_id = matched_line_cfg.account_id;
            } else if (cfg.channels.linePrimary()) |line_cfg| {
                line_channel_secret = line_cfg.channel_secret;
                line_access_token = line_cfg.access_token;
                line_allow_from = line_cfg.allow_from;
                line_account_id = line_cfg.account_id;
            }
        } else if (line_channel_secret.len > 0) {
            const sig = sig_header orelse {
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"missing signature\"}";
                return;
            };
            if (!channels.line.LineChannel.verifySignature(b, sig, line_channel_secret)) {
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"invalid signature\"}";
                return;
            }
        }

        const events = channels.line.LineChannel.parseWebhookEvents(ctx.req_allocator, b) catch {
            ctx.response_body = "{\"status\":\"parse_error\"}";
            return;
        };
        for (events) |evt| {
            if (line_allow_from.len > 0) {
                if (evt.user_id) |uid| {
                    if (!channels.isAllowed(line_allow_from, uid)) continue;
                } else continue;
            }
            if (evt.message_text) |text| {
                var kb: [128]u8 = undefined;
                const line_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg| cfg else null;
                const sk = lineSessionKeyRouted(ctx.req_allocator, &kb, evt, line_cfg_opt, line_account_id);
                const uid = evt.user_id orelse "unknown";
                const line_target = lineReplyTarget(evt);
                var peer_buf: [160]u8 = undefined;
                const line_peer = linePeerMetadata(evt, &peer_buf);

                if (ctx.state.event_bus) |eb| {
                    var meta_buf: [384]u8 = undefined;
                    const meta = std.fmt.bufPrint(&meta_buf, "{{\"account_id\":\"{s}\",\"peer_kind\":\"{s}\",\"peer_id\":\"{s}\"}}", .{
                        line_account_id,
                        line_peer.kind,
                        line_peer.id,
                    }) catch null;
                    _ = publishToBus(eb, ctx.state.allocator, "line", uid, line_target, text, sk, meta);
                } else if (ctx.session_mgr_opt) |sm| {
                    const reply: ?[]const u8 = sm.processMessageWithToolContext(sk, text, null, .{
                        .channel = "line",
                        .account_id = line_account_id,
                        .chat_id = line_target,
                        .is_group = std.mem.eql(u8, line_peer.kind, "group"),
                        .is_dm = std.mem.eql(u8, line_peer.kind, "direct"),
                    }) catch |err| blk: {
                        if (evt.reply_token) |rt| {
                            var line_ch = channels.line.LineChannel.init(ctx.req_allocator, .{
                                .access_token = line_access_token,
                                .channel_secret = line_channel_secret,
                            });
                            line_ch.replyMessage(rt, userFacingAgentError(err)) catch {};
                        }
                        break :blk null;
                    };
                    if (reply) |r| {
                        defer ctx.root_allocator.free(r);
                        if (evt.reply_token) |rt| {
                            var line_ch = channels.line.LineChannel.init(ctx.req_allocator, .{
                                .access_token = line_access_token,
                                .channel_secret = line_channel_secret,
                            });
                            line_ch.replyMessage(rt, r) catch {};
                        }
                    }
                }
            }
        }
        ctx.response_body = "{\"status\":\"ok\"}";
    } else {
        ctx.response_body = "{\"status\":\"received\"}";
    }
}

fn handleLarkWebhookRoute(ctx: *WebhookHandlerContext) void {
    if (!build_options.enable_channel_lark) {
        ctx.response_status = "404 Not Found";
        ctx.response_body = "{\"error\":\"lark channel disabled in this build\"}";
        return;
    }

    const is_post = std.mem.eql(u8, ctx.method, "POST");
    if (!is_post) {
        ctx.response_status = "405 Method Not Allowed";
        ctx.response_body = "{\"error\":\"method not allowed\"}";
        return;
    }
    if (!ctx.state.rate_limiter.allowWebhook(ctx.state.allocator, "lark")) {
        ctx.response_status = "429 Too Many Requests";
        ctx.response_body = "{\"error\":\"rate limited\"}";
        return;
    }

    const body = extractBody(ctx.raw_request) orelse {
        ctx.response_body = "{\"status\":\"received\"}";
        return;
    };
    var lark_verification_token = ctx.state.lark_verification_token;
    var lark_app_id = ctx.state.lark_app_id;
    var lark_app_secret = ctx.state.lark_app_secret;
    var lark_allow_from = ctx.state.lark_allow_from;
    var lark_account_id = ctx.state.lark_account_id;
    if (selectLarkConfig(ctx.config_opt, body)) |lark_cfg| {
        lark_verification_token = lark_cfg.verification_token orelse "";
        lark_app_id = lark_cfg.app_id;
        lark_app_secret = lark_cfg.app_secret;
        lark_allow_from = lark_cfg.allow_from;
        lark_account_id = lark_cfg.account_id;
    }

    if (std.mem.indexOf(u8, body, "\"url_verification\"") != null) {
        const challenge = jsonStringField(body, "challenge");
        if (challenge) |c| {
            const challenge_resp = jsonWrapChallenge(ctx.req_allocator, c) catch null;
            ctx.response_body = challenge_resp orelse "{\"status\":\"ok\"}";
        } else {
            ctx.response_body = "{\"status\":\"ok\"}";
        }
        return;
    }

    if (lark_verification_token.len > 0) {
        const payload_token = blk: {
            const parsed = std.json.parseFromSlice(std.json.Value, ctx.req_allocator, body, .{}) catch break :blk @as(?[]const u8, null);
            defer parsed.deinit();
            if (parsed.value != .object) break :blk @as(?[]const u8, null);
            const header = parsed.value.object.get("header") orelse break :blk @as(?[]const u8, null);
            if (header != .object) break :blk @as(?[]const u8, null);
            const token_val = header.object.get("token") orelse break :blk @as(?[]const u8, null);
            break :blk if (token_val == .string) ctx.req_allocator.dupe(u8, token_val.string) catch null else null;
        };
        if (payload_token) |pt| {
            if (!std.mem.eql(u8, pt, lark_verification_token)) {
                ctx.response_status = "403 Forbidden";
                ctx.response_body = "{\"error\":\"invalid verification token\"}";
                return;
            }
        }
    }

    var lark_ch = channels.lark.LarkChannel.init(
        ctx.req_allocator,
        lark_app_id,
        lark_app_secret,
        lark_verification_token,
        0,
        lark_allow_from,
    );
    const messages = lark_ch.parseEventPayload(ctx.req_allocator, body) catch {
        ctx.response_body = "{\"status\":\"parse_error\"}";
        return;
    };
    for (messages) |msg| {
        var kb: [128]u8 = undefined;
        const lark_cfg_opt: ?*const Config = if (ctx.config_opt) |cfg| cfg else null;
        const sk = larkSessionKeyRouted(ctx.req_allocator, &kb, msg, lark_cfg_opt, lark_account_id);

        if (ctx.state.event_bus) |eb| {
            var meta_buf: [320]u8 = undefined;
            const meta = std.fmt.bufPrint(&meta_buf, "{{\"account_id\":\"{s}\",\"peer_kind\":\"{s}\",\"peer_id\":\"{s}\"}}", .{
                lark_account_id,
                if (msg.is_group) "group" else "direct",
                msg.sender,
            }) catch null;
            _ = publishToBus(eb, ctx.state.allocator, "lark", msg.sender, msg.sender, msg.content, sk, meta);
        } else if (ctx.session_mgr_opt) |sm| {
            const reply: ?[]const u8 = sm.processMessageWithToolContext(sk, msg.content, null, .{
                .channel = "lark",
                .account_id = lark_account_id,
                .chat_id = msg.sender,
                .is_group = msg.is_group,
                .is_dm = !msg.is_group,
            }) catch |err| blk: {
                lark_ch.sendMessage(msg.sender, userFacingAgentError(err)) catch {};
                break :blk null;
            };
            if (reply) |r| {
                defer ctx.root_allocator.free(r);
                lark_ch.sendMessage(msg.sender, r) catch {};
            }
        }
    }
    ctx.response_body = "{\"status\":\"ok\"}";
}

const HTTP_RESPONSE_WRITE_TIMEOUT_MS: i32 = 30_000;

fn waitForHttpResponseWritable(stream: anytype) !void {
    const StreamType = @TypeOf(stream);
    const DeclType = switch (@typeInfo(StreamType)) {
        .pointer => |ptr| ptr.child,
        else => StreamType,
    };
    if (@hasDecl(DeclType, "waitWritable")) {
        return stream.waitWritable();
    }

    var fds = [_]std.posix.pollfd{.{
        .fd = stream.handle,
        .events = @intCast(std.posix.POLL.OUT),
        .revents = 0,
    }};
    const ready = try std.posix.poll(&fds, HTTP_RESPONSE_WRITE_TIMEOUT_MS);
    if (ready == 0) return error.ResponseWriteTimeout;
    const failure_mask: i16 = @intCast(std.posix.POLL.ERR | std.posix.POLL.HUP | std.posix.POLL.NVAL);
    if ((fds[0].revents & failure_mask) != 0) return error.BrokenPipe;
}

fn writeHttpResponseBytes(stream: anytype, bytes: []const u8) !void {
    var offset: usize = 0;
    while (offset < bytes.len) {
        const written = stream.write(bytes[offset..]) catch |err| {
            if (@as(anyerror, err) == error.WouldBlock) {
                try waitForHttpResponseWritable(stream);
                continue;
            }
            return err;
        };
        if (written == 0) return error.BrokenPipe;
        offset += written;
    }
}

fn sendHttpResponse(stream: anytype, status: []const u8, content_type: []const u8, body: []const u8) !void {
    var header_buf: [512]u8 = undefined;
    const header = try std.fmt.bufPrint(
        &header_buf,
        "HTTP/1.1 {s}\r\nContent-Type: {s}\r\nContent-Length: {d}\r\nConnection: close\r\n\r\n",
        .{ status, content_type, body.len },
    );
    try writeHttpResponseBytes(stream, header);
    if (body.len > 0) try writeHttpResponseBytes(stream, body);
}

fn sendHttpResponseRetryAfter(
    stream: anytype,
    status: []const u8,
    content_type: []const u8,
    body: []const u8,
    retry_after_secs: u16,
) !void {
    var header_buf: [640]u8 = undefined;
    const header = try std.fmt.bufPrint(
        &header_buf,
        "HTTP/1.1 {s}\r\nContent-Type: {s}\r\nContent-Length: {d}\r\nRetry-After: {d}\r\nConnection: close\r\n\r\n",
        .{ status, content_type, body.len, @max(@as(u16, 1), retry_after_secs) },
    );
    try writeHttpResponseBytes(stream, header);
    if (body.len > 0) try writeHttpResponseBytes(stream, body);
}

fn setListenerNonBlocking(server: *std.net.Server) void {
    const flags = std.posix.fcntl(server.stream.handle, std.posix.F.GETFL, 0) catch return;
    _ = std.posix.fcntl(server.stream.handle, std.posix.F.SETFL, flags | @as(u32, @bitCast(std.posix.O{ .NONBLOCK = true }))) catch {};
}

fn handleAcceptedConnection(
    allocator: std.mem.Allocator,
    config_opt: ?*const Config,
    state: *GatewayState,
    session_mgr_opt: ?*session_mod.SessionManager,
    conn: std.net.Server.Connection,
) void {
    defer conn.stream.close();
    configureRequestReadTimeout(conn.stream);

    // Per-request arena — all request-scoped allocations freed in one shot
    var arena = std.heap.ArenaAllocator.init(allocator);
    defer arena.deinit();
    const req_allocator = arena.allocator();

    const raw = readHttpRequest(req_allocator, conn.stream) catch |err| {
        switch (err) {
            error.RequestTooLarge => sendHttpResponse(conn.stream, "413 Payload Too Large", "application/json", "{\"error\":\"request too large\"}") catch {},
            error.InvalidContentLength => sendHttpResponse(conn.stream, "400 Bad Request", "application/json", "{\"error\":\"invalid content-length\"}") catch {},
            error.RequestTimeout => sendHttpResponse(conn.stream, "408 Request Timeout", "application/json", "{\"error\":\"request timeout\"}") catch {},
            else => sendHttpResponse(conn.stream, "400 Bad Request", "application/json", "{\"error\":\"invalid request\"}") catch {},
        }
        return;
    };
    _ = state.requests_total.fetchAdd(1, .monotonic);
    maybeLogDegradedStateWarning(state);

    // Parse first line: "METHOD /path HTTP/1.1\r\n"
    const first_line_end = std.mem.indexOf(u8, raw, "\r\n") orelse {
        sendHttpResponse(conn.stream, "400 Bad Request", "application/json", "{\"error\":\"malformed request\"}") catch {};
        return;
    };
    const first_line = raw[0..first_line_end];
    var parts = std.mem.splitScalar(u8, first_line, ' ');
    const method_str = parts.next() orelse {
        sendHttpResponse(conn.stream, "400 Bad Request", "application/json", "{\"error\":\"malformed request\"}") catch {};
        return;
    };
    const target = parts.next() orelse {
        sendHttpResponse(conn.stream, "400 Bad Request", "application/json", "{\"error\":\"malformed request\"}") catch {};
        return;
    };
    _ = state.in_flight_requests.fetchAdd(1, .acq_rel);
    defer _ = state.in_flight_requests.fetchSub(1, .acq_rel);

    // Simple routing — control endpoints + descriptor-driven channel webhooks + ZAKI API.
    const ControlRoute = enum { health, ready, webhook, pair, metrics, diagnostics, wake_heartbeat, invalidate_tenant_runtime_cache, cell_resolve, cell_ensure, cell_status, cell_drain, drain, undrain, shutdown, entitlements_revoke };
    const control_route_map = std.StaticStringMap(ControlRoute).initComptime(.{
        .{ "/health", .health },
        .{ "/ready", .ready },
        .{ "/webhook", .webhook },
        .{ "/pair", .pair },
        .{ "/metrics", .metrics },
        .{ "/internal/diagnostics", .diagnostics },
        .{ "/internal/wake-heartbeat", .wake_heartbeat },
        .{ "/internal/tenant-runtime-cache/invalidate", .invalidate_tenant_runtime_cache },
        .{ "/internal/cells/resolve", .cell_resolve },
        .{ "/internal/cells/ensure", .cell_ensure },
        .{ "/internal/cells/status", .cell_status },
        .{ "/internal/cells/drain", .cell_drain },
        .{ "/internal/drain", .drain },
        .{ "/internal/undrain", .undrain },
        .{ "/internal/shutdown", .shutdown },
        .{ "/internal/entitlements/revoke", .entitlements_revoke },
    });
    const base_path = if (std.mem.indexOfScalar(u8, target, '?')) |qi| target[0..qi] else target;
    const is_chat_stream_path = std.mem.eql(u8, base_path, "/api/v1/chat/stream");
    const is_chat_events_path = std.mem.eql(u8, base_path, "/api/v1/chat/events");
    const is_post = std.mem.eql(u8, method_str, "POST");
    var response_status: []const u8 = "200 OK";
    var response_body: []const u8 = "";
    var response_content_type: []const u8 = "application/json";
    var response_retry_after_secs: ?u16 = null;
    var pair_response_buf: [256]u8 = undefined;

    const is_internal_path = std.mem.startsWith(u8, base_path, "/internal/");
    const is_ops_path = std.mem.eql(u8, base_path, "/health") or
        std.mem.eql(u8, base_path, "/ready") or
        std.mem.eql(u8, base_path, "/metrics") or
        is_chat_stream_path or
        is_chat_events_path or
        is_internal_path;
    const overload_retry_after_secs: u16 = if (config_opt) |cfg|
        @max(@as(u16, 1), cfg.gateway.overload_retry_after_secs)
    else
        2;
    if (state.draining.load(.acquire) and !is_ops_path) {
        _ = state.drain_rejected_total.fetchAdd(1, .monotonic);
        sendHttpResponseRetryAfter(
            conn.stream,
            "503 Service Unavailable",
            "application/json",
            "{\"error\":\"draining\",\"retry_hint\":\"retry shortly\"}",
            overload_retry_after_secs,
        ) catch {};
        return;
    }

    if (is_chat_stream_path) {
        _ = handleApiChatStreamSseConnection(
            allocator,
            req_allocator,
            &conn.stream,
            raw,
            method_str,
            base_path,
            state,
            config_opt,
            session_mgr_opt,
        );
        return;
    } else if (is_chat_events_path) {
        _ = handleApiChatEventsSseConnection(
            allocator,
            req_allocator,
            &conn.stream,
            raw,
            method_str,
            base_path,
            state,
            config_opt,
            session_mgr_opt,
        );
        return;
    } else if (std.mem.startsWith(u8, base_path, "/api/v1/")) {
        const api_resp = handleApiRoute(
            allocator,
            req_allocator,
            raw,
            method_str,
            base_path,
            state,
            config_opt,
            session_mgr_opt,
        );
        response_status = api_resp.status;
        response_body = api_resp.body;
        response_content_type = api_resp.content_type;
        response_retry_after_secs = api_resp.retry_after_secs;
    } else if (findWebhookRouteDescriptor(base_path)) |desc| {
        var webhook_ctx = WebhookHandlerContext{
            .root_allocator = allocator,
            .req_allocator = req_allocator,
            .raw_request = raw,
            .method = method_str,
            .target = target,
            .config_opt = config_opt,
            .state = state,
            .session_mgr_opt = session_mgr_opt,
        };
        desc.handler(&webhook_ctx);
        response_status = webhook_ctx.response_status;
        response_body = webhook_ctx.response_body;
        response_retry_after_secs = webhook_ctx.response_retry_after_secs;
    } else if (hasSlackHttpEndpoint(config_opt, base_path)) {
        var webhook_ctx = WebhookHandlerContext{
            .root_allocator = allocator,
            .req_allocator = req_allocator,
            .raw_request = raw,
            .method = method_str,
            .target = target,
            .config_opt = config_opt,
            .state = state,
            .session_mgr_opt = session_mgr_opt,
        };
        handleSlackWebhookRoute(&webhook_ctx);
        response_status = webhook_ctx.response_status;
        response_body = webhook_ctx.response_body;
    } else if (control_route_map.get(base_path)) |route| switch (route) {
        .health => {
            response_body = if (isHealthOk()) "{\"status\":\"ok\"}" else "{\"status\":\"degraded\"}";
        },
        .ready => {
            if (state.draining.load(.acquire)) {
                response_status = "503 Service Unavailable";
                response_body = "{\"status\":\"draining\"}";
            } else {
                // v1.14.13 Step 5 — route /ready through the canonical
                // handleReady implementation (tested at 23492+) instead of
                // duplicating its logic inline. Allocations land in
                // req_allocator's arena and are freed when the request ends.
                const ready_resp = handleReady(req_allocator);
                response_status = ready_resp.http_status;
                response_body = ready_resp.body;
            }
        },
        .webhook => {
            if (!is_post) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else {
                const auth_header = extractHeader(raw, "Authorization");
                const bearer = if (auth_header) |ah| extractBearerToken(ah) else null;
                const pairing_guard = if (state.pairing_guard) |*guard| guard else null;
                if (!isWebhookAuthorized(pairing_guard, bearer)) {
                    response_status = "401 Unauthorized";
                    response_body = "{\"error\":\"unauthorized\"}";
                } else if (!state.rate_limiter.allowWebhook(state.allocator, "webhook")) {
                    response_status = "429 Too Many Requests";
                    response_body = "{\"error\":\"rate limited\"}";
                } else {
                    const body = extractBody(raw);
                    if (body) |b| {
                        const msg_text = jsonStringField(b, "message") orelse jsonStringField(b, "text") orelse b;
                        var sk_buf: [128]u8 = undefined;
                        const session_key = std.fmt.bufPrint(&sk_buf, "webhook:{s}", .{bearer orelse "anon"}) catch "webhook:anon";

                        if (state.event_bus) |eb| {
                            _ = publishToBus(eb, state.allocator, "webhook", bearer orelse "anon", session_key, msg_text, session_key, null);
                            response_body = "{\"status\":\"received\"}";
                        } else if (session_mgr_opt) |sm| {
                            const reply: ?[]const u8 = sm.processMessageWithToolContext(session_key, msg_text, null, .{
                                .channel = "webhook",
                                .chat_id = session_key,
                                .is_group = false,
                                .is_dm = true,
                            }) catch |err| blk: {
                                response_body = userFacingAgentErrorJson(err);
                                break :blk null;
                            };
                            if (reply) |r| {
                                defer allocator.free(r);
                                const json_resp = jsonWrapResponse(req_allocator, r) catch null;
                                response_body = json_resp orelse "{\"status\":\"received\"}";
                            } else {
                                response_body = "{\"status\":\"received\"}";
                            }
                        } else {
                            response_body = "{\"status\":\"received\"}";
                        }
                    } else {
                        response_body = "{\"status\":\"received\"}";
                    }
                }
            }
        },
        .pair => {
            if (!is_post) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!state.rate_limiter.allowPair(state.allocator, "pair")) {
                response_status = "429 Too Many Requests";
                response_body = "{\"error\":\"rate limited\"}";
            } else {
                if (state.pairing_guard) |*guard| {
                    const pairing_code = extractHeader(raw, "X-Pairing-Code");
                    switch (guard.attemptPair(pairing_code)) {
                        .paired => |token| {
                            defer allocator.free(token);
                            if (formatPairSuccessResponse(&pair_response_buf, token)) |pair_resp| {
                                response_body = pair_resp;
                            } else {
                                response_status = "500 Internal Server Error";
                                response_body = "{\"error\":\"pairing response failed\"}";
                            }
                        },
                        .missing_code => {
                            response_status = "400 Bad Request";
                            response_body = "{\"error\":\"missing X-Pairing-Code\"}";
                        },
                        .invalid_code => {
                            response_status = "401 Unauthorized";
                            response_body = "{\"error\":\"invalid pairing code\"}";
                        },
                        .already_paired => {
                            response_status = "409 Conflict";
                            response_body = "{\"error\":\"already paired\"}";
                        },
                        .disabled => {
                            response_status = "403 Forbidden";
                            response_body = "{\"error\":\"pairing disabled\"}";
                        },
                        .locked_out => {
                            response_status = "429 Too Many Requests";
                            response_body = "{\"error\":\"pairing locked out\"}";
                        },
                        .internal_error => {
                            response_status = "500 Internal Server Error";
                            response_body = "{\"error\":\"pairing failed\"}";
                        },
                    }
                } else {
                    response_status = "500 Internal Server Error";
                    response_body = "{\"error\":\"pairing unavailable\"}";
                }
            }
        },
        .metrics => {
            if (!std.mem.eql(u8, method_str, "GET")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else {
                response_body = metricsPayload(req_allocator, state) catch "# failed to render metrics\n";
                response_content_type = "text/plain; version=0.0.4";
            }
        },
        .diagnostics => {
            if (!std.mem.eql(u8, method_str, "GET")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!validateInternalServiceToken(raw, state)) {
                response_status = "401 Unauthorized";
                response_body = "{\"error\":\"unauthorized\"}";
            } else {
                const user_id = resolveGatewayOptionalUserId(state, extractHeader(raw, "X-Zaki-User-Id")) catch {
                    response_status = "403 Forbidden";
                    response_body = "{\"error\":\"wrong_user_cell\"}";
                    sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                    return;
                };
                response_body = internalDiagnosticsPayload(req_allocator, state, user_id) catch "{\"error\":\"diagnostics unavailable\"}";
            }
        },
        .wake_heartbeat => {
            if (!std.mem.eql(u8, method_str, "POST")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!validateInternalServiceToken(raw, state)) {
                response_status = "401 Unauthorized";
                response_body = "{\"error\":\"unauthorized\"}";
            } else {
                const body = extractBody(raw);
                const user_id_from_header = extractHeader(raw, "X-Zaki-User-Id");
                var user_id_owned: ?[]u8 = null;
                defer if (user_id_owned) |value| req_allocator.free(value);
                const requested_user_id = blk: {
                    if (body) |b| {
                        if (jsonStringField(b, "user_id")) |value| break :blk value;
                        if (jsonIntField(b, "user_id")) |value| {
                            user_id_owned = std.fmt.allocPrint(req_allocator, "{d}", .{value}) catch null;
                            break :blk user_id_owned;
                        }
                    }
                    break :blk user_id_from_header;
                };

                const user_id = resolveGatewayOptionalUserId(state, requested_user_id) catch {
                    response_status = "403 Forbidden";
                    response_body = "{\"error\":\"wrong_user_cell\"}";
                    sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                    return;
                };

                const reason = if (body) |b| jsonStringField(b, "reason") orelse "internal_wake_hook" else "internal_wake_hook";
                heartbeat_wake.enqueue(user_id, reason) catch {
                    response_status = "500 Internal Server Error";
                    response_body = "{\"error\":\"wake enqueue failed\"}";
                    sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                    return;
                };

                response_body = if (user_id) |uid|
                    std.fmt.allocPrint(req_allocator, "{{\"status\":\"queued\",\"user_id\":\"{s}\"}}", .{uid}) catch "{\"status\":\"queued\"}"
                else
                    "{\"status\":\"queued\",\"scope\":\"all\"}";
            }
        },
        .invalidate_tenant_runtime_cache => {
            if (!std.mem.eql(u8, method_str, "POST")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!validateInternalServiceToken(raw, state)) {
                response_status = "401 Unauthorized";
                response_body = "{\"error\":\"unauthorized\"}";
            } else {
                const request = parseTenantRuntimeInvalidationRequest(
                    req_allocator,
                    extractHeader(raw, "X-Zaki-User-Id"),
                    extractBody(raw),
                ) catch {
                    response_status = "400 Bad Request";
                    response_body = "{\"error\":\"invalid_payload\"}";
                    sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                    return;
                };
                defer request.deinit(req_allocator);

                var requested: usize = 0;
                var removed: usize = 0;
                var missing: usize = 0;
                // All HashMap access must be under the tenant_runtime_mutex.
                // This is an admin endpoint — immediate destruction is correct.
                state.tenant_runtime_mutex.lock();
                defer state.tenant_runtime_mutex.unlock();
                if (state.role == .user_cell and request.all) {
                    const pinned_user_id = state.pinned_user_id orelse {
                        response_status = "400 Bad Request";
                        response_body = "{\"error\":\"missing user_id\"}";
                        sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                        return;
                    };
                    requested = 1;
                    if (state.tenant_runtimes.get(pinned_user_id) != null) {
                        removeTenantRuntime(state, pinned_user_id);
                        removed = 1;
                    } else {
                        missing = 1;
                    }
                } else if (request.all) {
                    requested = state.tenant_runtimes.count();
                    removed = clearAllTenantRuntimes(state);
                } else {
                    requested = request.user_ids.len;
                    if (state.role == .user_cell) {
                        for (request.user_ids) |user_id| {
                            _ = resolveGatewayPathUserId(state, user_id) catch {
                                response_status = "403 Forbidden";
                                response_body = "{\"error\":\"wrong_user_cell\"}";
                                sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                                return;
                            };
                        }
                    }
                    for (request.user_ids) |user_id| {
                        if (resolveGatewayPathUserId(state, user_id)) |scoped_user_id| {
                            if (state.tenant_runtimes.get(scoped_user_id) != null) {
                                removeTenantRuntime(state, scoped_user_id);
                                removed += 1;
                            } else {
                                missing += 1;
                            }
                        } else |_| {
                            response_status = "403 Forbidden";
                            response_body = "{\"error\":\"wrong_user_cell\"}";
                            sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch {};
                            return;
                        }
                    }
                }

                response_body = std.fmt.allocPrint(
                    req_allocator,
                    "{{\"status\":\"ok\",\"requested\":{d},\"removed\":{d},\"missing\":{d},\"all\":{s}}}",
                    .{ requested, removed, missing, if (request.all) "true" else "false" },
                ) catch "{\"error\":\"response build failed\"}";
            }
        },
        .cell_resolve => {
            const response = handleBrokerCellControlRoute(req_allocator, state, raw, method_str, .resolve);
            response_status = response.status;
            response_body = response.body;
        },
        .cell_ensure => {
            const response = handleBrokerCellControlRoute(req_allocator, state, raw, method_str, .ensure);
            response_status = response.status;
            response_body = response.body;
        },
        .cell_status => {
            const response = handleBrokerCellControlRoute(req_allocator, state, raw, method_str, .status);
            response_status = response.status;
            response_body = response.body;
        },
        .cell_drain => {
            const response = handleBrokerCellControlRoute(req_allocator, state, raw, method_str, .drain);
            response_status = response.status;
            response_body = response.body;
        },
        .drain => {
            if (!std.mem.eql(u8, method_str, "POST")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!validateInternalServiceToken(raw, state)) {
                response_status = "401 Unauthorized";
                response_body = "{\"error\":\"unauthorized\"}";
            } else {
                state.draining.store(true, .release);
                response_body = "{\"status\":\"draining\"}";
            }
        },
        .undrain => {
            if (!std.mem.eql(u8, method_str, "POST")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!validateInternalServiceToken(raw, state)) {
                response_status = "401 Unauthorized";
                response_body = "{\"error\":\"unauthorized\"}";
            } else {
                state.draining.store(false, .release);
                state.shutdown_requested.store(false, .release);
                response_body = "{\"status\":\"ready\"}";
            }
        },
        .shutdown => {
            if (!std.mem.eql(u8, method_str, "POST")) {
                response_status = "405 Method Not Allowed";
                response_body = "{\"error\":\"method not allowed\"}";
            } else if (!validateInternalServiceToken(raw, state)) {
                response_status = "401 Unauthorized";
                response_body = "{\"error\":\"unauthorized\"}";
            } else {
                state.draining.store(true, .release);
                state.shutdown_requested.store(true, .release);
                state.closeAppEventSubscribers();
                response_body = "{\"status\":\"shutdown_requested\"}";
            }
        },
        // S2.7 — Stripe webhook revocation sink. zaki-prod's Stripe
        // handler translates `customer.subscription.deleted`,
        // `customer.subscription.updated` (status transitions),
        // `invoice.payment_failed`, and `charge.dispute.created` into
        // POSTs here. We parse the minimal billing tuple and update
        // the in-memory entitlement store; the next turn's preflight
        // (S2.4) / scheduler tick (S2.5) / chat-stream entry (S2.3)
        // reads the fresh value and blocks appropriately.
        .entitlements_revoke => {
            // D9 (2026-04-26) — extracted into testable function. The
            // switch arm now just composes the route response from the
            // structured result. See handleEntitlementsRevokeRequest
            // below + tests in the entitlements_revoke test cluster.
            const route_response = handleEntitlementsRevokeRequest(
                raw,
                state.internal_service_tokens,
                state.internal_auth_required,
                method_str,
            );
            response_status = route_response.status;
            response_body = route_response.body;
        },
    } else {
        response_status = "404 Not Found";
        response_body = "{\"error\":\"not found\"}";
    }

    if (response_retry_after_secs) |retry_secs| {
        sendHttpResponseRetryAfter(conn.stream, response_status, response_content_type, response_body, retry_secs) catch |err| {
            log.warn("http response write failed status={s} body_len={d} retry_after={d} err={s}", .{
                response_status,
                response_body.len,
                retry_secs,
                @errorName(err),
            });
        };
    } else {
        sendHttpResponse(conn.stream, response_status, response_content_type, response_body) catch |err| {
            log.warn("http response write failed status={s} body_len={d} err={s}", .{
                response_status,
                response_body.len,
                @errorName(err),
            });
        };
    }
}

const RequestQueue = struct {
    allocator: std.mem.Allocator,
    max_queued: usize,
    mutex: std.Thread.Mutex = .{},
    cond: std.Thread.Condition = .{},
    closed: bool = false,
    items: std.ArrayListUnmanaged(std.net.Server.Connection) = .empty,

    fn init(allocator: std.mem.Allocator, max_queued: usize) RequestQueue {
        return .{
            .allocator = allocator,
            .max_queued = max_queued,
        };
    }

    fn deinit(self: *RequestQueue) void {
        self.mutex.lock();
        defer self.mutex.unlock();
        for (self.items.items) |conn| conn.stream.close();
        self.items.deinit(self.allocator);
    }

    fn push(self: *RequestQueue, conn: std.net.Server.Connection) bool {
        self.mutex.lock();
        defer self.mutex.unlock();
        if (self.closed) return false;
        if (self.items.items.len >= self.max_queued) return false;
        self.items.append(self.allocator, conn) catch return false;
        self.cond.signal();
        return true;
    }

    fn popWait(self: *RequestQueue) ?std.net.Server.Connection {
        self.mutex.lock();
        defer self.mutex.unlock();
        while (self.items.items.len == 0 and !self.closed) {
            self.cond.wait(&self.mutex);
        }
        if (self.items.items.len == 0) return null;
        return self.items.orderedRemove(0);
    }

    fn len(self: *RequestQueue) usize {
        self.mutex.lock();
        defer self.mutex.unlock();
        return self.items.items.len;
    }

    fn close(self: *RequestQueue) void {
        self.mutex.lock();
        defer self.mutex.unlock();
        self.closed = true;
        self.cond.broadcast();
    }
};

const GatewayWorkerContext = struct {
    allocator: std.mem.Allocator,
    config_opt: ?*const Config,
    state: *GatewayState,
    session_mgr_opt: ?*session_mod.SessionManager,
    queue: *RequestQueue,
};

fn gatewayWorkerMain(ctx: *GatewayWorkerContext) void {
    while (true) {
        const conn = ctx.queue.popWait() orelse break;
        handleAcceptedConnection(ctx.allocator, ctx.config_opt, ctx.state, ctx.session_mgr_opt, conn);
    }
}

/// Run the HTTP gateway. Binds to host:port and serves HTTP requests.
/// Endpoints: GET /health, GET /ready, POST /pair, POST /webhook, GET|POST /whatsapp, POST /telegram, POST /slack/events, POST /line, POST /lark
/// If config_ptr is null, loads config internally (for backward compatibility).
pub fn run(allocator: std.mem.Allocator, host: []const u8, port: u16, config_ptr: ?*const Config, event_bus: ?*bus_mod.Bus) !void {
    return runWithRole(allocator, host, port, config_ptr, event_bus, .shared, null, null, null);
}

fn registerUserCellWithController(
    allocator: std.mem.Allocator,
    state: *const GatewayState,
) !void {
    if (state.role != .user_cell) return;
    const controller_url = state.controller_url orelse return;
    const user_id = state.pinned_user_id orelse return error.UserCellRequiresPinnedUser;
    const controller_token = firstConfiguredInternalServiceToken(state.internal_service_tokens) orelse
        return error.ControllerTokenMissing;
    const advertise_url = state.advertise_url orelse return error.UserCellRequiresAdvertiseUrl;
    const payload = try buildCellEnsurePayload(allocator, user_id, advertise_url);
    defer allocator.free(payload);

    const ensure_url = try controllerUrlWithPath(allocator, controller_url, "/internal/cells/ensure");
    defer allocator.free(ensure_url);
    const token_header = try std.fmt.allocPrint(allocator, "X-Internal-Token: {s}", .{controller_token});
    defer allocator.free(token_header);

    const response = try http_util.curlRequest(
        allocator,
        "POST",
        ensure_url,
        &[_][]const u8{
            "User-Agent: nullalis-user-cell/1.0",
            token_header,
            "Content-Type: application/json",
        },
        payload,
        null,
        "10",
    );
    defer allocator.free(response.body);

    if (response.status_code != 200) return error.ControllerRegistrationFailed;
}

const UserCellRegistrationContext = struct {
    state: *const GatewayState,
};

fn userCellRegistrationMain(ctx: *UserCellRegistrationContext) void {
    while (!ctx.state.shutdown_requested.load(.acquire)) {
        var slept_secs: u64 = 0;
        while (slept_secs < USER_CELL_REGISTRATION_REFRESH_SECS and !ctx.state.shutdown_requested.load(.acquire)) : (slept_secs += 1) {
            std.Thread.sleep(std.time.ns_per_s);
        }
        if (ctx.state.shutdown_requested.load(.acquire)) break;

        registerUserCellWithController(std.heap.page_allocator, ctx.state) catch |err| {
            log.warn("user cell controller re-registration failed: {}", .{err});
        };
    }
}

pub fn runWithRole(
    allocator: std.mem.Allocator,
    host: []const u8,
    port: u16,
    config_ptr: ?*const Config,
    event_bus: ?*bus_mod.Bus,
    role: GatewayRole,
    controller_url: ?[]const u8,
    advertise_url: ?[]const u8,
    pinned_user_id: ?[]const u8,
) !void {
    health.markComponentOk("gateway");

    if (role == .user_cell and pinned_user_id == null) {
        return error.UserCellRequiresPinnedUser;
    }
    if (role == .user_cell and controller_url != null and advertise_url == null) {
        return error.UserCellRequiresAdvertiseUrl;
    }

    var state = GatewayState.init(allocator);
    defer state.deinit();
    // S2.1 — arm the default entitlement resolver so the structural
    // gates wired in S2.3/S2.4/S2.5 actually consult a real store when
    // the BFF calls `/api/v1/users/provision` or Stripe pokes
    // `/internal/entitlements/revoke`. Before this call the resolver
    // is `null` and every gate falls back to the default
    // `Entitlement{}` (pro/active/unlimited) — the "nothing breaks
    // until S2.1 lights up" invariant that Sprint 2 relied on.
    entitlement_mod.useDefaultResolver(allocator);
    state.role = role;
    state.controller_url = controller_url;
    if (advertise_url) |value| {
        state.advertise_url = try normalizeAdvertiseUrl(allocator, value);
        state.advertise_url_owned = true;
    }
    if (pinned_user_id) |value| {
        state.pinned_user_id = try allocator.dupe(u8, value);
        state.pinned_user_id_owned = true;
    }
    state.event_bus = event_bus;

    var owned_config: ?Config = null;
    var config_opt: ?*const Config = null;
    if (config_ptr) |cfg| {
        config_opt = cfg;
    } else {
        owned_config = Config.load(allocator) catch null;
        if (owned_config) |*c| {
            config_opt = c;
        }
    }
    defer if (owned_config) |*c| c.deinit();
    if (role == .user_cell and config_opt == null) {
        return error.UserCellRequiresConfig;
    }

    // Provider runtime bundle (primary + reliability wrapper) must outlive the accept loop.
    var provider_bundle_opt: ?providers.runtime_bundle.RuntimeProviderBundle = null;
    var session_mgr_opt: ?session_mod.SessionManager = null;
    var tools_slice: []const tools_mod.Tool = &.{};
    var mem_rt: ?memory_mod.MemoryRuntime = null;
    var subagent_manager_opt: ?*subagent_mod.SubagentManager = null;
    var completion_router_opt: ?*SubagentCompletionRouter = null;
    var sec_tracker_opt: ?security.RateTracker = null;
    var sec_policy_opt: ?security.SecurityPolicy = null;
    var standalone_task_ledger: ?tasks_mod.TaskLedger = null;
    var standalone_task_delivery: ?tasks_mod.TaskDelivery = null;
    var standalone_usage_rt: ?usage_runtime_mod.UsageRuntime = null;
    var log_obs_gateway = observability.LogObserver{};
    var metrics_obs_gateway = LifecycleMetricsObserver{ .metrics = &state.lifecycle_metrics };
    var noop_obs_gateway = observability.NoopObserver{};
    var otel_obs_gateway_opt: ?observability.OtelObserver = observability.OtelObserver.fromEnv(allocator);
    defer if (otel_obs_gateway_opt) |*otel| otel.deinit();
    var gateway_observer_slots: [4]Observer = undefined;
    var gateway_observer_multi = observability.MultiObserver{ .observers = &.{} };
    const needs_local_agent = gatewayRoleNeedsLocalAgent(role, event_bus != null);

    if (config_opt) |cfg_ptr| {
        const cfg = cfg_ptr;
        if (role == .user_cell and !cfg.tenant.enabled) {
            return error.UserCellRequiresTenantMode;
        }
        var postgres_init_error: ?anyerror = null;
        state.rate_limiter = GatewayRateLimiter.init(
            cfg.gateway.pair_rate_limit_per_minute,
            cfg.gateway.webhook_rate_limit_per_minute,
        );
        state.idempotency = IdempotencyStore.init(cfg.gateway.idempotency_ttl_secs);
        state.pairing_guard = try PairingGuard.init(
            allocator,
            cfg.gateway.require_pairing,
            cfg.gateway.paired_tokens,
        );
        if (cfg.channels.telegramPrimary()) |tg_cfg| {
            state.telegram_bot_token = tg_cfg.bot_token;
            state.telegram_allow_from = tg_cfg.allow_from;
            state.telegram_account_id = tg_cfg.account_id;
            state.telegram_webhook_secret_token = tg_cfg.webhook_secret_token orelse "";
        }
        if (cfg.channels.whatsappPrimary()) |wa_cfg| {
            state.whatsapp_verify_token = wa_cfg.verify_token;
            state.whatsapp_app_secret = wa_cfg.app_secret orelse "";
            state.whatsapp_access_token = wa_cfg.access_token;
            state.whatsapp_allow_from = wa_cfg.allow_from;
            state.whatsapp_group_allow_from = wa_cfg.group_allow_from;
            state.whatsapp_groups = wa_cfg.groups;
            state.whatsapp_group_policy = wa_cfg.group_policy;
            state.whatsapp_account_id = wa_cfg.account_id;
        }
        if (cfg.channels.linePrimary()) |line_cfg| {
            state.line_channel_secret = line_cfg.channel_secret;
            state.line_access_token = line_cfg.access_token;
            state.line_allow_from = line_cfg.allow_from;
            state.line_account_id = line_cfg.account_id;
        }
        if (cfg.channels.larkPrimary()) |lark_cfg| {
            state.lark_verification_token = lark_cfg.verification_token orelse "";
            state.lark_app_id = lark_cfg.app_id;
            state.lark_app_secret = lark_cfg.app_secret;
            state.lark_allow_from = lark_cfg.allow_from;
            state.lark_account_id = lark_cfg.account_id;
        }
        const production_like_gateway = isProductionLikeGateway(cfg, host);
        const token_validation = validateInternalTokensForMode(
            cfg.gateway.internal_service_tokens,
            production_like_gateway,
        );
        state.internal_auth_required = production_like_gateway;
        state.internal_token_policy_ok = token_validation.ok;
        state.internal_token_configured = token_validation.configured;
        state.internal_token_policy_reason = token_validation.reason orelse "";
        if (production_like_gateway and !token_validation.ok) {
            log.err(
                "security_config_invalid reason={s} host={s} tenant_enabled={s} allow_public_bind={s}",
                .{
                    token_validation.reason orelse "unknown",
                    host,
                    if (cfg.tenant.enabled) "true" else "false",
                    if (cfg.gateway.allow_public_bind) "true" else "false",
                },
            );
            return error.SecurityConfigInvalid;
        }
        state.internal_service_tokens = cfg.gateway.internal_service_tokens;
        state.require_explicit_chat_stream_session_key = cfg.gateway.require_explicit_chat_stream_session_key;
        state.tenant_enabled = cfg.tenant.enabled;
        state.tenant_data_root = cfg.tenant.data_root;
        state.workspace_dir = cfg.workspace_dir;
        state.tenant_runtime_cache_max_users = cfg.tenant.runtime_cache_max_users;
        state.tenant_runtime_idle_ttl_secs = cfg.tenant.runtime_idle_ttl_secs;
        if (std.mem.eql(u8, cfg.state.backend, "postgres")) init_state: {
            const mgr = allocator.create(zaki_state_mod.Manager) catch break :init_state;
            mgr.* = zaki_state_mod.Manager.init(allocator, cfg.state) catch |err| {
                allocator.destroy(mgr);
                postgres_init_error = err;
                log.warn("zaki state init failed, falling back to file state: {}", .{err});
                break :init_state;
            };
            state.zaki_state = mgr;
        }
        if (cfg.tenant.enabled) {
            const owner_id = tenant_lock.resolveOwnerId(allocator) catch null;
            const lock_cfg = normalizeTenantOwnershipLockConfig(cfg.tenant);
            if (owner_id) |oid| {
                state.owner_instance_id = oid;
                state.owner_instance_id_owned = true;
                state.ownership_lock_enabled = true;
                state.ownership_lock_lease_secs = lock_cfg.lease_secs;
                state.ownership_lock_wait_ms = lock_cfg.wait_ms;
                state.ownership_lock_retry_min_ms = lock_cfg.retry_min_ms;
                state.ownership_lock_retry_max_ms = lock_cfg.retry_max_ms;
            } else {
                log.warn("tenant ownership lock disabled: failed to resolve owner id", .{});
                state.ownership_lock_enabled = false;
            }
        }

        // In daemon mode (`event_bus` is present), inbound processing is delegated to
        // the bus + channel runtime. Avoid creating a second local agent runtime here.
        if (needs_local_agent) {
            sec_tracker_opt = security.RateTracker.init(allocator, cfg.autonomy.max_actions_per_hour);
            sec_policy_opt = .{
                .autonomy = cfg.autonomy.level,
                .workspace_dir = cfg.workspace_dir,
                .workspace_only = cfg.autonomy.workspace_only,
                .allowed_commands = if (cfg.autonomy.allowed_commands.len > 0) cfg.autonomy.allowed_commands else &security.default_allowed_commands,
                .max_actions_per_hour = cfg.autonomy.max_actions_per_hour,
                .require_approval_for_medium_risk = cfg.autonomy.require_approval_for_medium_risk,
                .block_high_risk_commands = cfg.autonomy.block_high_risk_commands,
                .tracker = if (sec_tracker_opt) |*tracker| tracker else null,
            };
            provider_bundle_opt = try providers.runtime_bundle.RuntimeProviderBundle.init(allocator, cfg);

            if (provider_bundle_opt) |*bundle| {
                const provider_i: providers.Provider = bundle.provider();
                const resolved_api_key = bundle.primaryApiKey();
                const memory_cfg = normalizedLocalAgentMemoryConfig(cfg);

                // Optional memory backend.
                mem_rt = memory_mod.initRuntimeWithOptions(allocator, &memory_cfg, cfg.workspace_dir, .{
                    .providers = cfg.providers,
                    .search_api_key_override = resolved_api_key,
                });

                // V1.14.4 review HI-02 — same fail-loud rule applied
                // here as the tenant init path (line 1425). If the
                // SubagentManager exists, the completion router MUST
                // exist; otherwise subagent results vanish silently
                // (subagent.zig:709 path=none branch). `try` propagates
                // OOM up rather than silently degrading.
                const subagent_manager = allocator.create(subagent_mod.SubagentManager) catch null;
                if (subagent_manager) |mgr| {
                    mgr.* = subagent_mod.SubagentManager.init(allocator, cfg, event_bus, .{});
                    subagent_manager_opt = mgr;
                    completion_router_opt = try allocator.create(SubagentCompletionRouter);
                }

                // Task ledger + delivery + usage runtime (Phase 2)
                standalone_task_ledger = tasks_mod.TaskLedger.init(allocator);
                standalone_usage_rt = usage_runtime_mod.UsageRuntime.init(allocator);

                const mem_opt: ?memory_mod.Memory = if (mem_rt) |rt| rt.memory else null;
                gateway_observer_slots = .{
                    log_obs_gateway.observer(),
                    metrics_obs_gateway.observer(),
                    sentry_runtime.globalOrFallback().observer(),
                    if (otel_obs_gateway_opt) |*otel| otel.observer() else noop_obs_gateway.observer(),
                };
                gateway_observer_multi = .{ .observers = gateway_observer_slots[0..] };

                standalone_task_delivery = .{
                    .ledger = &(standalone_task_ledger.?),
                    .observer = gateway_observer_multi.observer(),
                };

                // Tools.
                tools_slice = tools_mod.allTools(allocator, cfg.workspace_dir, .{
                    .config = cfg,
                    .http_enabled = cfg.http_request.enabled,
                    .browser_enabled = cfg.browser.enabled,
                    .screenshot_enabled = true,
                    .composio_api_key = if (cfg.composio.enabled) cfg.composio.api_key else null,
                    .browser_open_domains = if (cfg.browser.allowed_domains.len > 0) cfg.browser.allowed_domains else null,
                    .agents = cfg.agents,
                    .fallback_api_key = resolved_api_key,
                    .event_bus = event_bus,
                    .tools_config = cfg.tools,
                    .allowed_paths = cfg.autonomy.allowed_paths,
                    .policy = if (sec_policy_opt) |*policy| policy else null,
                    .subagent_manager = subagent_manager_opt,
                    .task_delivery = if (standalone_task_delivery) |*d| d else null,
                }) catch &.{};

                var sm = session_mod.SessionManager.init(allocator, cfg, provider_i, tools_slice, mem_opt, gateway_observer_multi.observer(), if (mem_rt) |rt| rt.session_store else null, if (mem_rt) |*rt| rt.response_cache else null);
                if (sec_policy_opt) |*policy| {
                    sm.policy = policy;
                }
                if (standalone_usage_rt) |*urt| {
                    sm.usage_rt = urt;
                }
                if (mem_rt) |*rt| {
                    sm.mem_rt = rt;
                    tools_mod.bindMemoryRuntime(tools_slice, rt);
                }
                // iter27: transcript_read SessionStore binding (standalone gateway)
                tools_mod.bindSessionStore(tools_slice, if (mem_rt) |rt| rt.session_store else null);
                // N1: image_generate Together key
                tools_mod.bindImageGenerate(
                    tools_slice,
                    tools_mod.lookupProviderApiKey(cfg.providers, "together"),
                    "",
                );
                session_mgr_opt = sm;
                if (subagent_manager_opt) |mgr| {
                    if (standalone_task_delivery) |*td| {
                        mgr.attachTaskDelivery(td);
                    }
                    if (session_mgr_opt) |*session_mgr| {
                        if (completion_router_opt) |router| {
                            router.* = .{
                                .session_mgr = session_mgr,
                                .event_bus = event_bus,
                                .config = cfg,
                                .state = &state,
                            };
                            mgr.attachCompletionDelivery(@ptrCast(router), appendSubagentCompletionToGatewaySession);
                        }
                    }
                }
            }
        }

        applyStartupSelfCheck(&state, cfg, postgres_init_error);
        logStartupSelfCheck(&state);
    }
    if (state.pairing_guard == null) {
        state.pairing_guard = try PairingGuard.init(allocator, true, &.{});
    }
    defer if (provider_bundle_opt) |*bundle| bundle.deinit();
    defer if (mem_rt) |*rt| rt.deinit();
    defer if (subagent_manager_opt) |mgr| {
        mgr.deinit();
        allocator.destroy(mgr);
    };
    defer if (completion_router_opt) |router| allocator.destroy(router);
    defer if (tools_slice.len > 0) tools_mod.deinitTools(allocator, tools_slice);
    defer if (session_mgr_opt) |*sm| sm.deinit();
    defer if (standalone_task_ledger) |*ledger| ledger.deinit();
    defer if (standalone_usage_rt) |*urt| urt.deinit();
    defer if (sec_tracker_opt) |*tracker| tracker.deinit();

    // Resolve the listen address
    const addr = try std.net.Address.resolveIp(host, port);
    var server = try addr.listen(.{
        .reuse_address = true,
    });
    defer server.deinit();
    setListenerNonBlocking(&server);
    try registerUserCellWithController(allocator, &state);

    var user_cell_registration_ctx = UserCellRegistrationContext{
        .state = &state,
    };
    const user_cell_registration_thread = if (role == .user_cell and state.controller_url != null)
        try std.Thread.spawn(.{ .stack_size = 256 * 1024 }, userCellRegistrationMain, .{&user_cell_registration_ctx})
    else
        null;
    defer if (user_cell_registration_thread) |thread| {
        state.shutdown_requested.store(true, .release);
        thread.join();
    };

    var stdout_buf: [4096]u8 = undefined;
    var bw = std.fs.File.stdout().writer(&stdout_buf);
    const stdout = &bw.interface;
    try stdout.print("Gateway listening on {s}:{d}\n", .{ host, port });
    try stdout.flush();
    if (config_opt) |cfg| {
        // In daemon mode the parent already prints model/provider.
        if (config_ptr == null) cfg.printModelConfig();
    }
    if (state.pairing_guard) |*guard| {
        if (guard.pairingCode()) |code| {
            try stdout.print("Gateway pairing code: {s}\n", .{code});
            try stdout.flush();
        }
    }

    const max_workers: usize = if (config_opt) |cfg|
        @intCast(@max(@as(u16, 1), cfg.gateway.max_workers))
    else
        1;
    const max_queued_requests: usize = if (config_opt) |cfg|
        @intCast(@max(@as(u32, 1), cfg.gateway.max_queued_requests))
    else
        1024;
    const overload_retry_after_secs: u16 = if (config_opt) |cfg|
        @max(@as(u16, 1), cfg.gateway.overload_retry_after_secs)
    else
        2;

    var request_queue = RequestQueue.init(allocator, max_queued_requests);
    defer request_queue.deinit();

    var worker_contexts = try allocator.alloc(GatewayWorkerContext, max_workers);
    defer allocator.free(worker_contexts);
    var worker_threads = try allocator.alloc(std.Thread, max_workers);
    defer allocator.free(worker_threads);

    for (0..max_workers) |i| {
        worker_contexts[i] = .{
            .allocator = allocator,
            .config_opt = config_opt,
            .state = &state,
            .session_mgr_opt = if (session_mgr_opt) |*sm| sm else null,
            .queue = &request_queue,
        };
        worker_threads[i] = try std.Thread.spawn(
            .{ .stack_size = 512 * 1024 },
            gatewayWorkerMain,
            .{&worker_contexts[i]},
        );
    }
    defer {
        request_queue.close();
        for (worker_threads) |thread| thread.join();
    }

    var last_tenant_runtime_maintenance_s: i64 = 0;

    // Accept loop — one acceptor thread, bounded queue + worker pool.
    while (true) {
        if (state.shutdown_requested.load(.acquire) and
            state.in_flight_requests.load(.acquire) == 0 and
            request_queue.len() == 0)
        {
            break;
        }

        const conn = server.accept() catch |err| switch (err) {
            error.WouldBlock => {
                const now_s = std.time.timestamp();
                if (now_s - last_tenant_runtime_maintenance_s >= TENANT_RUNTIME_MAINTENANCE_INTERVAL_SECS) {
                    runTenantRuntimeMaintenance(&state, now_s);
                    last_tenant_runtime_maintenance_s = now_s;
                }
                std.Thread.sleep(50 * std.time.ns_per_ms);
                continue;
            },
            else => continue,
        };
        if (!request_queue.push(conn)) {
            _ = state.overload_rejected_total.fetchAdd(1, .monotonic);
            sendHttpResponseRetryAfter(
                conn.stream,
                "503 Service Unavailable",
                "application/json",
                "{\"error\":\"overloaded\",\"retry_hint\":\"retry shortly\"}",
                overload_retry_after_secs,
            ) catch {};
            conn.stream.close();
        }
    }
}

// ── Tests ────────────────────────────────────────────────────────

test "constants are set correctly" {
    try std.testing.expectEqual(@as(usize, 30 * 1024 * 1024), MAX_BODY_SIZE);
    try std.testing.expectEqual(@as(u64, 30), REQUEST_TIMEOUT_SECS);
    try std.testing.expectEqual(@as(u64, 60), RATE_LIMIT_WINDOW_SECS);
}

test "rate limiter allows up to limit" {
    var limiter = SlidingWindowRateLimiter.init(2, 60);
    defer limiter.deinit(std.testing.allocator);

    try std.testing.expect(limiter.allow(std.testing.allocator, "127.0.0.1"));
    try std.testing.expect(limiter.allow(std.testing.allocator, "127.0.0.1"));
    try std.testing.expect(!limiter.allow(std.testing.allocator, "127.0.0.1"));
}

test "rate limiter zero limit always allows" {
    var limiter = SlidingWindowRateLimiter.init(0, 60);
    defer limiter.deinit(std.testing.allocator);

    for (0..100) |_| {
        try std.testing.expect(limiter.allow(std.testing.allocator, "any-key"));
    }
}

test "rate limiter different keys are independent" {
    var limiter = SlidingWindowRateLimiter.init(1, 60);
    defer limiter.deinit(std.testing.allocator);

    try std.testing.expect(limiter.allow(std.testing.allocator, "ip-1"));
    try std.testing.expect(!limiter.allow(std.testing.allocator, "ip-1"));
    try std.testing.expect(limiter.allow(std.testing.allocator, "ip-2"));
}

test "gateway rate limiter blocks after limit" {
    var limiter = GatewayRateLimiter.init(2, 2);
    defer limiter.deinit(std.testing.allocator);

    try std.testing.expect(limiter.allowPair(std.testing.allocator, "127.0.0.1"));
    try std.testing.expect(limiter.allowPair(std.testing.allocator, "127.0.0.1"));
    try std.testing.expect(!limiter.allowPair(std.testing.allocator, "127.0.0.1"));
}

test "idempotency store rejects duplicate key" {
    var store = IdempotencyStore.init(30);
    defer store.deinit(std.testing.allocator);

    try std.testing.expect(store.recordIfNew(std.testing.allocator, "req-1"));
    try std.testing.expect(!store.recordIfNew(std.testing.allocator, "req-1"));
    try std.testing.expect(store.recordIfNew(std.testing.allocator, "req-2"));
}

test "idempotency store allows different keys" {
    var store = IdempotencyStore.init(300);
    defer store.deinit(std.testing.allocator);

    try std.testing.expect(store.recordIfNew(std.testing.allocator, "a"));
    try std.testing.expect(store.recordIfNew(std.testing.allocator, "b"));
    try std.testing.expect(store.recordIfNew(std.testing.allocator, "c"));
    try std.testing.expect(!store.recordIfNew(std.testing.allocator, "a"));
}

test "extractIdempotencyKey reads the header case-insensitively (S2.10)" {
    const raw1 = "POST /x HTTP/1.1\r\nIdempotency-Key: abc-123\r\nHost: h\r\n\r\n";
    try std.testing.expectEqualStrings("abc-123", extractIdempotencyKey(raw1).?);

    const raw2 = "POST /x HTTP/1.1\r\nidempotency-key: lower-case\r\nHost: h\r\n\r\n";
    try std.testing.expectEqualStrings("lower-case", extractIdempotencyKey(raw2).?);

    const raw3 = "POST /x HTTP/1.1\r\nHost: h\r\n\r\n";
    try std.testing.expect(extractIdempotencyKey(raw3) == null);
}

test "gateway module compiles" {
    // Compile-time check only
}

test "findWebhookRouteDescriptor resolves known webhook paths" {
    try std.testing.expect(findWebhookRouteDescriptor("/telegram") != null);
    try std.testing.expect(findWebhookRouteDescriptor("/webhook/telegram") != null);
    try std.testing.expect(findWebhookRouteDescriptor("/whatsapp") != null);
    try std.testing.expect(findWebhookRouteDescriptor("/slack/events") != null);
    try std.testing.expect(findWebhookRouteDescriptor("/line") != null);
    try std.testing.expect(findWebhookRouteDescriptor("/lark") != null);
    try std.testing.expect(findWebhookRouteDescriptor("/health") == null);
}

