        req_allocator,
        "PATCH /api/v1/users/1/settings HTTP/1.1\r\nHost: localhost\r\nX-Internal-Token: test-internal-token\r\nContent-Length: {d}\r\n\r\n{s}",
        .{ body.len, body },
    );

    const response = handleApiRoute(
        std.testing.allocator,
